-- Poems batch 346
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('cb13f096-8003-4bdf-8f64-e652b571aa15','雲臺治','張繼先','宋','宋诗','song-poetry','','[]','漢朝人與道翱翔，是處遺蹤屬靜方。',64,'全唐诗/poet.song.67000.json','["漢朝人與道翱翔，是處遺蹤屬靜方。", "烟外桃花非俗種，風前柏實有餘香。", "杖穿翠靄通深窅，舟駕洪波入渺茫。", "千八百年三十代，雲臺空碧珮琳琅。"]'),
('3ef156b4-fd03-4c21-86b3-1ef3a0f14507','濜口治','張繼先','宋','宋诗','song-poetry','','[]','真真相襲養真材，萬木深沉一水迴。',64,'全唐诗/poet.song.67000.json','["真真相襲養真材，萬木深沉一水迴。", "珠逞夜明秋浪定，磬含霜韵曉霞開。", "二仙已遠教誰遇，三粒還能待我來。", "若遣青童驗輪跡，斷烟無影落蒼苔。"]'),
('1f434fb7-1cf4-4192-ac6e-9fe237b5fd03','後城治','張繼先','宋','宋诗','song-poetry','','[]','近枕長河即化壇，擬超壇側到河干。',64,'全唐诗/poet.song.67000.json','["近枕長河即化壇，擬超壇側到河干。", "丹砂在地經冬暖，玉竹成林入夜寒。", "水鶴應思冥象外，山翁愁不到眉端。", "杖頭已指丹霞景，密有塵羅絡我難。"]'),
('1cc5b114-d78b-4769-b430-f46407653c14','公慕治','張繼先','宋','宋诗','song-poetry','','[]','一壇幽占萬松陰，意爲尋真特地深。',64,'全唐诗/poet.song.67000.json','["一壇幽占萬松陰，意爲尋真特地深。", "翳翳野雲披綠岸，時時疏雨灑青林。", "真圖未落前朝手，短褐堪求古聖心。", "鶴輦近過遊息處，桃花流水尚堪尋。"]'),
('6b8ff363-06c6-4200-9027-bc9bbf22f065','平岡治','張繼先','宋','宋诗','song-poetry','','[]','千松萬竹蔭真祠，多少尋真不記歸。',64,'全唐诗/poet.song.67000.json','["千松萬竹蔭真祠，多少尋真不記歸。", "枕石池臺全似古，穿雲溪澗一如飛。", "玄猿夜久鳴寥閴，黄鶴風高入太微。", "直自六天渾屏靜，聖功何代不皈依。"]'),
('29af0133-d217-4518-82f1-cca7764d75e5','主簿治','張繼先','宋','宋诗','song-poetry','','[]','映盡朝陽與暮霞，苦無軒冕送塵沙。',64,'全唐诗/poet.song.67000.json','["映盡朝陽與暮霞，苦無軒冕送塵沙。", "舊聞靈草千年種，近有幽人一兩家。", "彩鳳每來尋竹實，靈禽時復啄仙花。", "偉哉往昔輕騰客，豈有心貪五馬車。"]'),
('569539a0-4a0b-47bd-aefa-cb17cf284652','王局治','張繼先','宋','宋诗','song-poetry','','[]','座隅依約有餘香，威表如存動悚惶。',64,'全唐诗/poet.song.67000.json','["座隅依約有餘香，威表如存動悚惶。", "荀石並抽擎夭閼，金泉一带自汪洋。", "因談妙有開迷逕，真指無何入故鄉。", "季世孰能稽萬一，日隨諸境愈忙忙。"]'),
('36015bda-1810-4598-b8db-4273120e2572','北邙治','張繼先','宋','宋诗','song-poetry','','[]','滿壇明月化宮春，千古依依楊柳津。',64,'全唐诗/poet.song.67000.json','["滿壇明月化宮春，千古依依楊柳津。", "碧沼不容生俗物，玉毫寧復示儔人。", "幽尋已與三玄約，靜樂誰知一點親。", "世外清遊堪準擬，輪蹄無跡輾香塵。"]'),
('354481b6-4c3d-458e-857f-80769defc1a7','金丹詩四十八首  其一','張繼先','宋','宋诗','song-poetry','','[]','金鼎玄珠夜半功，紛紛五彩滿房中。',64,'全唐诗/poet.song.67000.json','["金鼎玄珠夜半功，紛紛五彩滿房中。", "只爲日月交加合，却被龜蛇取次攻。", "乍見容儀方恍惚，久看相貌即朦朧。", "慇懃爲報陽人道，此箇真空不是空。"]'),
('ede3f09f-31e4-47b0-b76f-163f24e99d84','金丹詩四十八首  其二','張繼先','宋','宋诗','song-poetry','','[]','假法人間有萬般，君宜求取紫金丹。',64,'全唐诗/poet.song.67000.json','["假法人間有萬般，君宜求取紫金丹。", "崑崙山上樓臺聳，北海爐中龍虎攢。", "此箇藥中爲貴寶，將來鍊就作天官。", "玉皇數下金玄詔，始信雲衢去不難。"]'),
('390be9e4-4a7b-4b59-970c-61dcdeeef27b','金丹詩四十八首  其三','張繼先','宋','宋诗','song-poetry','','[]','流俗紛紛不悟真，不知求己却求人。',64,'全唐诗/poet.song.67000.json','["流俗紛紛不悟真，不知求己却求人。", "只貪世上無窮色，忘却人間有限身。", "鼎內藥成堪益壽，水中金盡化輕塵。", "北邙山下纍纍土，總是人間不了民。"]'),
('75be93d2-efe8-42e7-9f5a-a2b0a0e1e77b','金丹詩四十八首  其四','張繼先','宋','宋诗','song-poetry','','[]','不覺年年撚指過，急如催浪轉長河。',64,'全唐诗/poet.song.67000.json','["不覺年年撚指過，急如催浪轉長河。", "鼎中日月知人少，世上陰陽識者多。", "盡爲資財損真性，皆因女色逐流波。", "□□半有歸泉路，忍把真元亂鬼魔。"]'),
('10464b37-a168-4b90-86c1-9e4c9ea70861','金丹詩四十八首  其五','張繼先','宋','宋诗','song-poetry','','[]','堪笑愚人被色縈，擬將呼吸要留精。',64,'全唐诗/poet.song.67000.json','["堪笑愚人被色縈，擬將呼吸要留精。", "神仙清靜方爲道，男女腥膻本俗情。", "穢濁豈堪充上品，還丹方可保長生。", "房中之術空傳世，迷殺寰中多少人。"]'),
('b02be381-a1f1-44dc-853d-e6395faa98c1','金丹詩四十八首  其六','張繼先','宋','宋诗','song-poetry','','[]','採陰丹法起何時，後漢劉晟亦自迷。',64,'全唐诗/poet.song.67000.json','["採陰丹法起何時，後漢劉晟亦自迷。", "不免輪迴歸復道，豈將淫慾益愚癡。", "狗豬行狀稱爲妙，神鬼陰謀不可欺。", "爭似無爲清靜道，一爐金就養嬰兒。"]'),
('db343a3b-cb1a-489c-8a45-cc468dcb4be6','金丹詩四十八首  其七','張繼先','宋','宋诗','song-poetry','','[]','嬰兒頭上戴蓮花，詐僞迷人亂似麻。',64,'全唐诗/poet.song.67000.json','["嬰兒頭上戴蓮花，詐僞迷人亂似麻。", "不道修行從一鼎，却言般運有三車。", "泥丸有路蒸方透，紫府無涯價莫加。", "爲勸塵中迷路者，好尋元本莫咨嗟。"]'),
('422c41e2-f66f-4dd4-9041-7ded59d5bf07','金丹詩四十八首  其八','張繼先','宋','宋诗','song-poetry','','[]','火急尋師指水金，依時用火採浮沉。',64,'全唐诗/poet.song.67000.json','["火急尋師指水金，依時用火採浮沉。", "九回照見如來相，一紀方開處士心。", "虎駕輒翻鉛易就，龍車推轉汞難禁。", "自從飲著醍醐酒，便覺身居紫府深。"]'),
('25aa8adb-26a7-42f9-89ce-2c46b96e264c','金丹詩四十八首  其九','張繼先','宋','宋诗','song-poetry','','[]','擾擾浮生一夢間，幾人回首鎖三關。',64,'全唐诗/poet.song.67000.json','["擾擾浮生一夢間，幾人回首鎖三關。", "黄婆壓定分全易，白虎飛來投下難。", "朱雀入爐三畝靜，黑龜伏鼎一生閑。", "昭昭妙理余知得，只欲藏機隠舊山。"]'),
('25065dcf-6088-4b5f-b87e-f0eba44009a5','金丹詩四十八首  其一○','張繼先','宋','宋诗','song-poetry','','[]','莫論仙骨莫求丹，此理玄玄有正門。',64,'全唐诗/poet.song.67000.json','["莫論仙骨莫求丹，此理玄玄有正門。", "迷者少能知返本，教人藉此以爲根。", "龜蛇大小宜頻給，日月精華且總吞。", "只自明師分剖後，難爲荒野作丘墳。"]'),
('dd28a3d7-6df9-46eb-a6fa-892819f72eda','金丹詩四十八首  其一一','張繼先','宋','宋诗','song-poetry','','[]','神仙妙用最難窺，學道多因慾道迷。',64,'全唐诗/poet.song.67000.json','["神仙妙用最難窺，學道多因慾道迷。", "向此若能明水火，這回方得識東西。", "真鉛莫把凡鉛雜，真婦休將世婦齊。", "離坎自交身自泰，恁時方見是夫妻。"]'),
('b7faf9aa-27a4-4616-9f84-4d8f8843f418','金丹詩四十八首  其一二','張繼先','宋','宋诗','song-poetry','','[]','黄芽至寶莫輕論，白雪通玄敢謾言。',64,'全唐诗/poet.song.67000.json','["黄芽至寶莫輕論，白雪通玄敢謾言。", "不是野人藏祕訣，大都仙藥俗難吞。", "浮沉卯酉玄分路，變化龜蛇別有門。", "萬萬學徒無一二，浪稱道友滿乾坤。"]'),
('051e07fd-bc2a-4fa4-87ad-4aee2d318c74','金丹詩四十八首  其一三','張繼先','宋','宋诗','song-poetry','','[]','存神認取本來身，此理幽玄可學人。',64,'全唐诗/poet.song.67000.json','["存神認取本來身，此理幽玄可學人。", "無漏實成除有漏，迷津纔出是通津。", "浮生難保千年壽，仙世輕翻萬劫春。", "堪嘆茫茫迷路者，甘將神作北邙塵。"]'),
('e0646757-1d07-41d9-bda3-8cab42ad3fc1','金丹詩四十八首  其一四','張繼先','宋','宋诗','song-poetry','','[]','學佛回心又學仙，兩頭捫摸不能專。',64,'全唐诗/poet.song.67000.json','["學佛回心又學仙，兩頭捫摸不能專。", "大都錯路生迷惑，便見迷途易變遷。", "得事只烹身上藥，癡心莫望火中蓮。", "但能求己兼求命，休說三千與大千。"]'),
('5a753f2c-824d-4961-848a-7216a4cd1c34','金丹詩四十八首  其一五','張繼先','宋','宋诗','song-poetry','','[]','氣龍津虎不難分，下手須從神定門。',64,'全唐诗/poet.song.67000.json','["氣龍津虎不難分，下手須從神定門。", "白雪鍊多齊日月，黄芽服久出乾坤。", "四神鼎內堪逃死，五色漿中可返魂。", "世上蜉蝣能幾許，莫將財色敗元根。"]'),
('e37c2084-04c2-4ca7-87c7-8d5c1fe546bc','金丹詩四十八首  其一六','張繼先','宋','宋诗','song-poetry','','[]','急認浮沉水內金，若能烹鍊鬼神欽。',64,'全唐诗/poet.song.67000.json','["急認浮沉水內金，若能烹鍊鬼神欽。", "四神守衛神爐固，九轉工夫轉色深。", "龍虎翻施雙入路，龜蛇騰焰兩邊侵。", "但知五色紛紛起，滿室熒煌可照心。"]'),
('a4f8ca7c-0eb9-4a92-8e55-bc1be14760f1','金丹詩四十八首  其一七','張繼先','宋','宋诗','song-poetry','','[]','周天火候誑凡人，胎息縈爲亦未真。',64,'全唐诗/poet.song.67000.json','["周天火候誑凡人，胎息縈爲亦未真。", "紫府聚金龍火種，崑丘走玉虎泉新。", "三蓮折處分神力，一子生時出俗塵。", "爲報忙忙求事者，真鉛真汞不離真。"]'),
('d08c83f3-78d9-4b80-88ac-837bb5ef0c4e','金丹詩四十八首  其一八','張繼先','宋','宋诗','song-poetry','','[]','崑崙宮裏紫金丹，不是仙材不可觀。',64,'全唐诗/poet.song.67000.json','["崑崙宮裏紫金丹，不是仙材不可觀。", "有分得餐延壽命，自然無戀免饑寒。", "虎龍銅汞庚辛鼎，大小龜蛇太乙壇。", "烹鍊一丸飛五彩，上天消息不爲難。"]'),
('d5abf09c-90bb-4f25-8e5a-919fc3d945fc','金丹詩四十八首  其一九','張繼先','宋','宋诗','song-poetry','','[]','勞生擾擾去如梭，火急修真逐鬼魔。',64,'全唐诗/poet.song.67000.json','["勞生擾擾去如梭，火急修真逐鬼魔。", "好把浮沉翻北海，莫將夢幻戀南柯。", "甲庚鼎內金非少，卯酉壇中土亦多。", "只自熒煌光一室，齋心服了脫微痾。"]'),
('df0dd9e9-d47f-418d-a529-af5cba45042f','金丹詩四十八首  其二○','張繼先','宋','宋诗','song-poetry','','[]','貪著浮名浮利身，不思光景走頻頻。',64,'全唐诗/poet.song.67000.json','["貪著浮名浮利身，不思光景走頻頻。", "只貪眼下紅顔好，不覺頭中白髮新。", "藥鼎堅牢延壽命，情思放恣損天真。", "勸君求取金丹訣，養箇嬰兒脫俗塵。"]'),
('1c52a80f-87e3-43de-a27e-246c84f32653','金丹詩四十八首  其二一','張繼先','宋','宋诗','song-poetry','','[]','瞥然光景幾時休，出入輪迴去復收。',64,'全唐诗/poet.song.67000.json','["瞥然光景幾時休，出入輪迴去復收。", "只爲貪癡緣底事，不思清靜學真修。", "虎龍便是昇天駕，鉛汞元爲出世舟。", "多少神仙哀俗輩，故留丹訣救凡流。"]'),
('39c23389-7c98-4cdb-a516-68419d08695c','金丹詩四十八首  其二二','張繼先','宋','宋诗','song-poetry','','[]','乘龍駕鶴不須驚，此是金丹一粒靈。',64,'全唐诗/poet.song.67000.json','["乘龍駕鶴不須驚，此是金丹一粒靈。", "五色雲龍騰海底，九回風虎到天庭。", "瓊花合處看壬癸，紫府交時藉丙丁。", "此理要明非下士，除非名是少微星。"]'),
('a0d69ce2-f78d-4872-9673-b7a979e0847c','金丹詩四十八首  其二三','張繼先','宋','宋诗','song-poetry','','[]','勞生擾擾疾如風，急殺三彭及五蟲。',64,'全唐诗/poet.song.67000.json','["勞生擾擾疾如風，急殺三彭及五蟲。", "不使狐狸侵藥竈，須教龍虎守真空。", "鼎中寶物時添火，腹內嬰兒貌轉豐。", "善女善男尋此語，莫貪花酒墮迷中。"]'),
('56716f63-7ff5-4b7d-8a53-6dd67fe11974','金丹詩四十八首  其二四','張繼先','宋','宋诗','song-poetry','','[]','大都奇怪惑人深，一見邪淫便動心。',64,'全唐诗/poet.song.67000.json','["大都奇怪惑人深，一見邪淫便動心。", "只是欹傾身內寶，何能堅固水中金。", "天堂有路無人到，地獄無門衆却尋。", "寄語世間男女道，收蹤火宅隠山林。"]'),
('66a94380-4573-4028-9d51-fb4205f5138d','金丹詩四十八首  其二五','張繼先','宋','宋诗','song-poetry','','[]','阿爾多淫上帝嗔，罰爲狐獸尾隨身。',64,'全唐诗/poet.song.67000.json','["阿爾多淫上帝嗔，罰爲狐獸尾隨身。", "只言五百年方變，豈謂三千日化神。", "雷火不知何處用，犬牙同此作教親。", "冤魔眷屬狐狸肖，變化妖容惑幾人。"]'),
('19d9dc0d-4b88-4fd2-b598-e7a817f6db18','金丹詩四十八首  其二六','張繼先','宋','宋诗','song-poetry','','[]','劉晨阮肇事多非，今日憑君子細推。',64,'全唐诗/poet.song.67000.json','["劉晨阮肇事多非，今日憑君子細推。", "謾使仙宮由色慾，却將紫府貯姦欺。", "洞中清浄難容雜，穴裏幽冥易變奇。", "大是世人迷不悟，幾人喪命爲狐狸。"]'),
('d48e759d-948e-464f-a94b-d484e05ee860','金丹詩四十八首  其二七','張繼先','宋','宋诗','song-poetry','','[]','子真壇下紫微邊，深夜風光俗好傳。',64,'全唐诗/poet.song.67000.json','["子真壇下紫微邊，深夜風光俗好傳。", "不道求鉛堪益壽，却言藥物可延年。", "仙丹未必離身內，人意何須立戶前。", "或是山精迷弄汝，故將雜色等閑看。"]'),
('7f8e66e2-fde4-476c-9866-6874b4289a66','金丹詩四十八首  其二八','張繼先','宋','宋诗','song-poetry','','[]','真鉛真汞最堪憑，此理昭昭却少行。',64,'全唐诗/poet.song.67000.json','["真鉛真汞最堪憑，此理昭昭却少行。", "白虎鼎中成玉液，螣蛇宮裏養金精。", "坎男離女分三位，日月東西合一程。", "若向此中尋得路，嬰兒相貌自然成。"]'),
('1c1fb3be-3185-48fc-81eb-5f44234f4ace','金丹詩四十八首  其二九','張繼先','宋','宋诗','song-poetry','','[]','金丹換骨不相欺，大抵凡流性易迷。',64,'全唐诗/poet.song.67000.json','["金丹換骨不相欺，大抵凡流性易迷。", "若使赤蛇騰海北，自然玉兔走天西。", "栽蓮使者行真水，種火龍王啟大蹊。", "好向此中尋搗鍊，飛騰只在一刀圭。"]'),
('49997e03-51f4-4483-a0b9-57485a2cebf8','金丹詩四十八首  其三○','張繼先','宋','宋诗','song-poetry','','[]','幸得修真趣理深，勤勤烹鍊水中金。',64,'全唐诗/poet.song.67000.json','["幸得修真趣理深，勤勤烹鍊水中金。", "若知紫府蓮堪種，始信崑崙路可尋。", "日月合來光上下，白青交後彩浮沉。", "自從得此真消息，榮辱人間總不侵。"]'),
('5e1fab10-dbfb-4a8b-ad84-f6ea7f6ca249','金丹詩四十八首  其三一','張繼先','宋','宋诗','song-poetry','','[]','少年何事學詩書，爭似求真保玉壺。',64,'全唐诗/poet.song.67000.json','["少年何事學詩書，爭似求真保玉壺。", "更不勞神遊赤水，只知存性養玄珠。", "鼎中日月何人有，爐內丹砂世所無。", "人笑此中多寂寞，此中寂寞與人殊。"]'),
('b4ca4f18-aec0-4773-8151-ce5f69f73dbf','金丹詩四十八首  其三二','張繼先','宋','宋诗','song-poetry','','[]','既悟今生與後生，何須苦苦强談禪。',64,'全唐诗/poet.song.67000.json','["既悟今生與後生，何須苦苦强談禪。", "華池水號昇天藥，金鼎蓮爲出世筌。", "下乎始知深妙妙，功成方見理玄玄。", "自從一得明師指，始信雲車出俗廛。"]'),
('df53d3cb-5383-416e-8e12-48a8aab12fc6','金丹詩四十八首  其三三','張繼先','宋','宋诗','song-poetry','','[]','三清門戶出無猜，自是凡夫不肯來。',64,'全唐诗/poet.song.67000.json','["三清門戶出無猜，自是凡夫不肯來。", "月魄日魂爲道路，虎泉蛇火作梯媒。", "三田勤固元精種，一鼎堅牢後却開。", "無質自然生有質，真胎能解結靈胎。"]'),
('95f14ce1-5b44-43ac-9c16-e46bf733f2d0','金丹詩四十八首  其三四','張繼先','宋','宋诗','song-poetry','','[]','絳橋行氣總爲非，自是凡夫著相迷。',64,'全唐诗/poet.song.67000.json','["絳橋行氣總爲非，自是凡夫著相迷。", "北海鼎爐分造化，南溟宮殿合天倪。", "虛無只就還丹力，恍惚身成妙道齊。", "若向浮生能見得，浮生只可比醯雞。"]'),
('c0305342-5554-4a84-8b7c-fed0f394e736','金丹詩四十八首  其三五','張繼先','宋','宋诗','song-poetry','','[]','塵寰道友萬千人，幾箇虛名幾箇真。',64,'全唐诗/poet.song.67000.json','["塵寰道友萬千人，幾箇虛名幾箇真。", "不悟汞鉛爲至寶，却將爐竈學燒銀。", "內中採藥方端的，外裏求丹謾苦辛。", "何況迷途有迷者，不爲自誤誤他人。"]'),
('11df5885-edf7-4ed0-9e25-723a959e1c86','金丹詩四十八首  其三六','張繼先','宋','宋诗','song-poetry','','[]','九真山下有華池，此水延年世不知。',64,'全唐诗/poet.song.67000.json','["九真山下有華池，此水延年世不知。", "金橘生成光色透，彈丸小大彩霞飛。", "送歸北海深藏密，般上南溟事怪奇。", "只候此中功力就，黄雲片片擁嬰兒。"]'),
('9382979a-2203-4dc5-9653-0f6b13152476','金丹詩四十八首  其三七','張繼先','宋','宋诗','song-poetry','','[]','九真山上接樓臺，日月浮生紫氣堆。',64,'全唐诗/poet.song.67000.json','["九真山上接樓臺，日月浮生紫氣堆。", "北海下生金芍藥，南溟宮産玉攻瑰。", "三清門戶三田奧，九轉工夫九轍回。", "當此鍊成無價寶，從教人笑我癡騃。"]'),
('99c9f7ea-9421-4b6f-8b52-db9747d875ac','金丹詩四十八首  其三八','張繼先','宋','宋诗','song-poetry','','[]','擾擾尋師苦苦忙，但求神水是仙鄉。',64,'全唐诗/poet.song.67000.json','["擾擾尋師苦苦忙，但求神水是仙鄉。", "熒煌一鼎鎔金汁，燦爛三田湛玉漿。", "夜半只知真火焥，房中不覺彩霞光。", "超凡一粒真堪重，始信蓬萊去路長。"]'),
('2e0f12af-94e8-4af4-87ed-f917e7e1d8d3','金丹詩四十八首  其三九','張繼先','宋','宋诗','song-poetry','','[]','鼎中大藥世難知，日月雙投姤不迷。',64,'全唐诗/poet.song.67000.json','["鼎中大藥世難知，日月雙投姤不迷。", "未必妙光方火棗，始思玄理號交梨。", "溶溶朱粉飛雲遠，湛湛神輝滿室齊。", "一紀烹煎纔得了，便乘鸞輅上天梯。"]'),
('0c85f752-4003-4314-9f5a-760359c7f90b','金丹詩四十八首  其四○','張繼先','宋','宋诗','song-poetry','','[]','隱跡人間數十年，不令衆覺種丹田。',64,'全唐诗/poet.song.67000.json','["隱跡人間數十年，不令衆覺種丹田。", "五行聚會生俄爾，一顆圓明出自然。", "湛湛神爐開白雪，依依鉛鼎瀉紅蓮。", "近來不覺浮名起，多被人來叩妙玄。"]'),
('80d7f1eb-2d30-4e4d-bef5-8bb35ddc848a','金丹詩四十八首  其四一','張繼先','宋','宋诗','song-poetry','','[]','金丹餌了骨毛輕，便覺蓬萊去有程。',64,'全唐诗/poet.song.67000.json','["金丹餌了骨毛輕，便覺蓬萊去有程。", "澄湛藥爐分玉粉，凄凉氣海徹三清。", "崑崙宮殿年年聳，紫府樓臺日日成。", "只此便乘雲鶴駕，笑人笑我學長生。"]'),
('38571a44-27c4-4625-91bb-fe78a6512bc1','金丹詩四十八首  其四二','張繼先','宋','宋诗','song-poetry','','[]','學道多多少悟真，真成便見自家身。',64,'全唐诗/poet.song.67000.json','["學道多多少悟真，真成便見自家身。", "三田有路縱橫去，萬類無緣變換因。", "土內養金金色重，鼎中進火火功新。", "若於財色全無動，便是蓬萊洞裏人。"]'),
('6f4e1b51-1bc7-49e5-bd23-00bdeaae218b','金丹詩四十八首  其四三','張繼先','宋','宋诗','song-poetry','','[]','忍辱多多日苦辛，閉門又被鬼偷精。',64,'全唐诗/poet.song.67000.json','["忍辱多多日苦辛，閉門又被鬼偷精。", "不知牢鎖丹田固，爭奈魂狂紫府傾。", "陽氣旋衰難保壽，陰邪浸長易消兵。", "勸君火急尋師去，莫爲冤魔破道情。"]'),
('de1702d8-85ee-4ad3-ab7b-e39144e0ec03','金丹詩四十八首  其四四','張繼先','宋','宋诗','song-poetry','','[]','只見神爐當子夜，豈知火力散陰邪。',64,'全唐诗/poet.song.67000.json','["只見神爐當子夜，豈知火力散陰邪。", "忽於金鼎凝寒玉，倏爾真身現彩霞。", "沆瀣露中分白雪，華池水內養黄芽。", "此中便見真消息，莫浪驅馳覓鹿車。"]'),
('f7558625-d056-4e24-8d7c-1040aa9b4350','金丹詩四十八首  其四五','張繼先','宋','宋诗','song-poetry','','[]','人有金丹可返魂，常流迷道不知吞。',64,'全唐诗/poet.song.67000.json','["人有金丹可返魂，常流迷道不知吞。", "朱禽若啟巖前地，白鹿須投海底門。", "欲得必先調氣馬，由來宜急鎖心猿。", "善男善女尋真訣，莫把形容化土墳。"]'),
('fb827cbb-a29b-4d16-8c40-c054921fc4dd','金丹詩四十八首  其四六','張繼先','宋','宋诗','song-poetry','','[]','靜坐焚香念念中，念中須見己形容。',64,'全唐诗/poet.song.67000.json','["靜坐焚香念念中，念中須見己形容。", "生成本藉鉛中汞，變化端由火裏龍。", "二八莫辭頻採造，一三還用苦交衝。", "此中有路通天去，可把塵蹤繼赤松。"]'),
('a8b15a2b-0a49-4f1f-b977-196459149cb8','金丹詩四十八首  其四七','張繼先','宋','宋诗','song-poetry','','[]','莫嫌野客漏機微，要接仁人至上蹊。',64,'全唐诗/poet.song.67000.json','["莫嫌野客漏機微，要接仁人至上蹊。", "悟者便從言下悟，迷途終是意中迷。", "甲庚一判龍歸左，卯酉雙投虎在西。", "若見玄玄玄裏事，不離真箇是夫妻。"]'),
('e8a2c878-028a-4b62-b725-4d1d752a7ef8','金丹詩四十八首  其四八','張繼先','宋','宋诗','song-poetry','','[]','我身我命與天齊，只得金丹便出迷。',64,'全唐诗/poet.song.67000.json','["我身我命與天齊，只得金丹便出迷。", "靈質長來居玉殿，聖胎生就步雲梯。", "蜉蝣世界何須戀，螮蝀衣裳不必携。", "烹鍊雖然勞日月，出塵宜假一刀圭。"]'),
('d16df3e7-3a1d-478c-b84f-68fbe865db20','雞','張繼先','宋','宋诗','song-poetry','','[]','雞德靈居五，峨冠鳳彩新。',24,'全唐诗/poet.song.67000.json','["雞德靈居五，峨冠鳳彩新。", "五更大張口，喚醒夢中人。"]'),
('054bed08-bf5b-445b-87f5-cec46ff4b068','鍊丹巖留題','張繼先','宋','宋诗','song-poetry','','[]','鶴來松有客，苔去石無衣。',24,'全唐诗/poet.song.67000.json','["鶴來松有客，苔去石無衣。", "黄金浮世在，白髮故人稀。"]'),
('b6cc5945-5f89-4e86-94ad-ecd03057825b','戲吟','張繼先','宋','宋诗','song-poetry','','[]','落魄正當年，人皆笑我顛。',24,'全唐诗/poet.song.67000.json','["落魄正當年，人皆笑我顛。", "乾坤時運動，滄海渺無邊。"]'),
('565dd305-9543-462e-be15-8ff62062b6fe','竹','張繼先','宋','宋诗','song-poetry','','[]','雨過江皋浄，風來庭檻清。',24,'全唐诗/poet.song.67000.json','["雨過江皋浄，風來庭檻清。", "此君故人好，入夜聽秋聲。"]'),
('f45e8f3d-172f-48fc-9e00-f3f7d78664a2','書林管轄扇','張繼先','宋','宋诗','song-poetry','','[]','九鸞陪玉獸，八鳳薦金芝。',24,'全唐诗/poet.song.67000.json','["九鸞陪玉獸，八鳳薦金芝。", "青童歌妙曲，玄女唱清詞。"]'),
('c93d1b3c-f155-4adc-9b18-abfc84319ce6','青城洞陽大人','張繼先','宋','宋诗','song-poetry','','[]','青城老洞翁，名籍丹臺上。',24,'全唐诗/poet.song.67000.json','["青城老洞翁，名籍丹臺上。", "日日誦黄庭，感得祥雲降。"]'),
('8c2a3234-10aa-4ee8-9d10-494207a35121','野軒偶書','張繼先','宋','宋诗','song-poetry','','[]','日月雙螢火，乾坤一鵲巢。',24,'全唐诗/poet.song.67000.json','["日月雙螢火，乾坤一鵲巢。", "野軒有凉戶，誰敢等閑敲。"]'),
('d3333e39-93a6-43ff-97b4-387d9d207570','題崇仙觀知足軒','張繼先','宋','宋诗','song-poetry','','[]','此性本無一物，涓水亦自圓明。',28,'全唐诗/poet.song.67000.json','["此性本無一物，涓水亦自圓明。", "借問先生足處，軒前月白風清。"]'),
('3571ab3a-ff2e-441a-bf30-9ecf09629690','靜室偶書','張繼先','宋','宋诗','song-poetry','','[]','貧有清風明月，富無紅粉膏脂。',28,'全唐诗/poet.song.67000.json','["貧有清風明月，富無紅粉膏脂。", "子午鳳朝元始，去來雷電相隨。"]'),
('1bc9b752-59d7-4b9d-9930-927672adee09','鍾','張繼先','宋','宋诗','song-poetry','','[]','金晶鑄就斗星懸，掛向瓊樓知幾年。',32,'全唐诗/poet.song.67000.json','["金晶鑄就斗星懸，掛向瓊樓知幾年。", "好是五更殘夢裏，一聲敲透白雲天。"]'),
('cb67a7c9-9564-4207-9c08-ca856d559f65','詠窗','張繼先','宋','宋诗','song-poetry','','[]','無意殷勤遮皓月，有心特地隔紅塵。',32,'全唐诗/poet.song.67000.json','["無意殷勤遮皓月，有心特地隔紅塵。", "從茲虛室長生白，占得桃源洞裏春。"]'),
('5f3b3ae4-b838-4f79-8ee1-1e836019a6a8','白菊','張繼先','宋','宋诗','song-poetry','','[]','陶家籬下未開時，曾得西風借力吹。',32,'全唐诗/poet.song.67000.json','["陶家籬下未開時，曾得西風借力吹。", "月影夜深籠素艷，分明殘雪兩三枝。"]'),
('56a5bcce-e134-4bb8-a1e7-6f801f9bcf26','題濯鼎泉','張繼先','宋','宋诗','song-poetry','','[]','幾千年浪碧澄澄，對景難忘我祖情。',32,'全唐诗/poet.song.67000.json','["幾千年浪碧澄澄，對景難忘我祖情。", "樂就也知曾借力，軒成方見不辜名。"]'),
('9ebddf5d-a781-4be2-8d1a-d2206185eec2','浩然子觀筇竹杖','張繼先','宋','宋诗','song-poetry','','[]','本是子猷園裏枝，今朝分取手中携。',32,'全唐诗/poet.song.67000.json','["本是子猷園裏枝，今朝分取手中携。", "自憐高節虛無物，野外山行得共伊。"]'),
('cbe25124-2bea-4fa8-a754-67f476402fe8','贈青城洞翁二首  其一','張繼先','宋','宋诗','song-poetry','','[]','神仙抱一養玄微，九載功成白日飛。',32,'全唐诗/poet.song.67000.json','["神仙抱一養玄微，九載功成白日飛。", "道在當人須順授，今朝何必祕天機。"]'),
('2a8ac371-b67e-4a6d-a27d-b5e8962f5d92','贈青城洞翁二首  其二','張繼先','宋','宋诗','song-poetry','','[]','人間久矣喜相倍，道術參同豈吝哉。',32,'全唐诗/poet.song.67000.json','["人間久矣喜相倍，道術參同豈吝哉。", "他日功成果輕舉，爲吾天上作梯媒。"]'),
('9ec4e6d2-5565-4fa9-80b0-f9923e69953f','妙應大師往錢塘欲予贈行','張繼先','宋','宋诗','song-poetry','','[]','太真宮室上方新，歸去先垂紫詔人。',32,'全唐诗/poet.song.67000.json','["太真宮室上方新，歸去先垂紫詔人。", "天目洞霄期過處，星冠應不冒風塵。"]'),
('0c926586-3911-4f92-a602-d4c030c3834c','庵居雜詠九首  其一','張繼先','宋','宋诗','song-poetry','','[]','甓瓦完齊土壁堅，籓籬周匝沒疏穿。',32,'全唐诗/poet.song.67000.json','["甓瓦完齊土壁堅，籓籬周匝沒疏穿。", "人來謾笑無華旆，風雨須教安穩眠。"]'),
('fbb79207-18a9-4608-9194-59f64b06bc19','庵居雜詠九首  其二','張繼先','宋','宋诗','song-poetry','','[]','庵前桃李春爭開，雪裏見花惟有梅。',32,'全唐诗/poet.song.67000.json','["庵前桃李春爭開，雪裏見花惟有梅。", "莫謂枝梢有分別，根本自異非人栽。"]'),
('bf3d8673-22b6-4c6d-b215-f936fc88af2c','庵居雜詠九首  其三','張繼先','宋','宋诗','song-poetry','','[]','春蠶絲盡即生蛾，秋燕雛成不泥窠。',32,'全唐诗/poet.song.67000.json','["春蠶絲盡即生蛾，秋燕雛成不泥窠。", "山雉經時藏窟穴，也能龍化入烟波。"]'),
('5f2561ab-f1c2-4f20-aad6-174ccd92f4bb','庵居雜詠九首  其四','張繼先','宋','宋诗','song-poetry','','[]','長松偃蹇不依林，枝榦高盤千畝陰。',32,'全唐诗/poet.song.67000.json','["長松偃蹇不依林，枝榦高盤千畝陰。", "昨夜酒醒風雨急，半空彷彿聽龍吟。"]'),
('faaac325-5b41-4a2b-b106-fb7e50cff652','庵居雜詠九首  其五','張繼先','宋','宋诗','song-poetry','','[]','南山雨過北山出，昨夜月明今日晴。',32,'全唐诗/poet.song.67000.json','["南山雨過北山出，昨夜月明今日晴。", "雲氣自舒還自捲，太虛萬古常清明。"]'),
('3c50ba3e-097c-4049-88bb-ea14fbd22a41','庵居雜詠九首  其六','張繼先','宋','宋诗','song-poetry','','[]','莫羨庵居景物清，須知樂自苦中生。',32,'全唐诗/poet.song.67000.json','["莫羨庵居景物清，須知樂自苦中生。", "山前盡日幽尋客，多說荒蹊不可行。"]'),
('6fd7271f-ba7d-431b-8e89-4d34613a7add','庵居雜詠九首  其七','張繼先','宋','宋诗','song-poetry','','[]','柴門雖謾不曾關，賓客從他自往還。',32,'全唐诗/poet.song.67000.json','["柴門雖謾不曾關，賓客從他自往還。", "連日山寒聲影絕，蒲團危坐更安閑。"]'),
('0e53b8f3-83a6-4d39-843b-0a3f11976928','庵居雜詠九首  其八','張繼先','宋','宋诗','song-poetry','','[]','晴日暖風時出游，冷烟凄雨便歸休。',32,'全唐诗/poet.song.67000.json','["晴日暖風時出游，冷烟凄雨便歸休。", "雲還樵斧溪邊牧，不似畸人得自由。"]'),
('47c9c13c-128d-42dd-aae4-0cea938609cf','庵居雜詠九首  其九','張繼先','宋','宋诗','song-poetry','','[]','鍾聲鼓聲朝夕鳴，茶烟炊烟先後生。',32,'全唐诗/poet.song.67000.json','["鍾聲鼓聲朝夕鳴，茶烟炊烟先後生。", "雲衣霞珮栖山客，兀兀窮年無一營。"]'),
('c72fb6f7-4541-4482-80a0-41872adb204f','寄元規','張繼先','宋','宋诗','song-poetry','','[]','白日未中氣色明，玉壺興入西源行。',32,'全唐诗/poet.song.67000.json','["白日未中氣色明，玉壺興入西源行。", "草堂羨我不共往，竹風爲汝致幽清。"]'),
('a988aeda-c26e-4068-a50b-5d2cc7a6dfcc','蓮花','張繼先','宋','宋诗','song-poetry','','[]','淡淡紅生細細香，半開人折寄山房。',32,'全唐诗/poet.song.67000.json','["淡淡紅生細細香，半開人折寄山房。", "只緣清浄超塵垢，頗似風流壓衆芳。"]'),
('6645a598-0422-4229-8b64-97c699d376ef','勉弟子還山頌','張繼先','宋','宋诗','song-poetry','','[]','昔劫因緣今劫會，昨日顔容今日改。',32,'全唐诗/poet.song.67000.json','["昔劫因緣今劫會，昨日顔容今日改。", "世間滄海盡桑田，慎勿重來呈傀儡。"]'),
('0b36d926-2e1d-4921-a615-dd9fe1ce48f4','示湯弟子','張繼先','宋','宋诗','song-poetry','','[]','子欲濟民非爲己，我貪修道不憂貧。',32,'全唐诗/poet.song.67000.json','["子欲濟民非爲己，我貪修道不憂貧。", "直須勉强方成業，只恐因循易老人。"]'),
('a20e37d5-fa07-4f61-acaa-67bd2ce08d8c','傳度後作','張繼先','宋','宋诗','song-poetry','','[]','道人願力如天溥，度盡衆生方自度。',32,'全唐诗/poet.song.67000.json','["道人願力如天溥，度盡衆生方自度。", "若還纖芥未蒙恩，我終不捨升天路。"]'),
('a2655ec8-7f4f-41d4-b864-36732388e1b6','送九龍徐正之歸麻姑','張繼先','宋','宋诗','song-poetry','','[]','步衝晴雪過前灘，鶴跡雲蹤孰可攀。',32,'全唐诗/poet.song.67000.json','["步衝晴雪過前灘，鶴跡雲蹤孰可攀。", "也似來時無一物，却疑歸去是三山。"]'),
('19cd0d32-b124-455a-9153-69b81a81bee3','對月分韵得清字','張繼先','宋','宋诗','song-poetry','','[]','碧霄澄徹素芒清，一片多情四海明。',32,'全唐诗/poet.song.67000.json','["碧霄澄徹素芒清，一片多情四海明。", "花院空庭冷香裏，羽人心膽欲寒生。"]'),
('f0b42638-5ae4-4ba9-82b3-2d6af8a9efa1','訪友不遇題','張繼先','宋','宋诗','song-poetry','','[]','庵裏人行庵外路，庵外人來庵裏坐。',32,'全唐诗/poet.song.67000.json','["庵裏人行庵外路，庵外人來庵裏坐。", "遮頭茅草欠堅牢，年年風雨年年破。"]'),
('37c34f12-6852-4709-bf20-7f560def4a33','遊洞霄','張繼先','宋','宋诗','song-poetry','','[]','洞霄深處日棲真，仙子親曾此致身。',32,'全唐诗/poet.song.67000.json','["洞霄深處日棲真，仙子親曾此致身。", "鳳闕有人來獻禮，溪聲山色愈增新。"]'),
('0ffbdac9-bdbb-41da-ad38-2b550013352b','詩一首','張繼先','宋','宋诗','song-poetry','','[]','白雲閑似我，我似白雲閑。',24,'全唐诗/poet.song.67000.json','["白雲閑似我，我似白雲閑。", "二物俱無心，逍遙天地間。"]'),
