('b486e09f-bf16-4054-b30e-1d3a831f05bd','孤山觀雪  其一','趙企','宋','宋诗','song-poetry','','[]','莫謂湖山景，尋常總一般。',24,'全唐诗/poet.song.67000.json','["莫謂湖山景，尋常總一般。", "欲窮清勝處，須向雪中看。"]'),
('30cdd20c-d818-4833-b892-a79abbd0b100','孤山觀雪  其二','趙企','宋','宋诗','song-poetry','','["\u897f\u6e56"]','乘興尋幽不怕寒，喜將山水雪中看。',32,'全唐诗/poet.song.67000.json','["乘興尋幽不怕寒，喜將山水雪中看。", "等閑哦出西湖句，自有清新上筆端。"]'),
('3ecbaabd-2a79-4fb2-86ec-731a260a6b00','別天台','趙企','宋','宋诗','song-poetry','','[]','携家隠青山，青山不我留。',156,'全唐诗/poet.song.67000.json','["携家隠青山，青山不我留。", "遣我出山去，再拜辭丹丘。", "王命急星火，駕言促西游。", "朝游白雲城，暮宿黄花洲。", "佳人牽我衣，挽斷不回頭。", "路傍立樵叟，問我何所求。", "長安美少年，氣概凌清秋。", "鸞臺與鳳閣，一一皆俊游。", "掉臂爾欲往，獨不愧且羞。", "此言真吾藥，口訥不易酬。", "我本麋鹿性，直與山林投。", "云何就冷局，歲月空悠悠。", "願公看我還，長歌賦歸休。"]'),
('fea9d098-9bf7-493a-9e51-ad791b792d17','題石橋','趙企','宋','宋诗','song-poetry','','[]','紺宇凌雲接太和，縈迴委曲過山阿。',64,'全唐诗/poet.song.67000.json','["紺宇凌雲接太和，縈迴委曲過山阿。", "靈峰散彩祥光滿，寶盞浮花景象多。", "瀑布迅從雙澗落，禪徒爭向一梁過。", "何當擺脫塵埃路，洗去人間萬事磨。"]'),
('e7882643-047e-46b0-a7ef-0b06deb9f2ee','題兜率寺','趙企','宋','宋诗','song-poetry','','[]','一到巾山眼界寬，招提直在翠微間。',64,'全唐诗/poet.song.67000.json','["一到巾山眼界寬，招提直在翠微間。", "黄鸝過處金穿柳，白鷺飛時雪點山。", "漁艇兩三隨月上，海帆八九趁潮還。", "歸時聽得梅花角，落日西城未掩關。"]'),
('3e71e5d8-3297-4e4f-9c1d-75ea18057a7c','題順感院','趙企','宋','宋诗','song-poetry','','[]','一上危梯一解顔，重崗複嶺四周環。',64,'全唐诗/poet.song.67000.json','["一上危梯一解顔，重崗複嶺四周環。", "山川盡出登臨外，天地都歸俯仰間。", "飛鳥直隨雙目斷，遊雲長與片心閒。", "文書了却無餘事，日午須來日落還。"]'),
('71f02ba6-7200-4b19-be8a-e39f5446d41b','題北山松軒','趙企','宋','宋诗','song-poetry','','[]','萬木有榮謝，此松無盛衰。',48,'全唐诗/poet.song.67000.json','["萬木有榮謝，此松無盛衰。", "夢闌秋韵起，棋罷午陰移。", "般匠顧不顧，秦君知未知。", "亭亭高節在，看取雪霜時。"]'),
('0211feff-537e-4b35-8db2-2b182a40aa7b','題顯孝南山寺','趙企','宋','宋诗','song-poetry','','[]','背日西來眼界明，隔溪遙見梵王城。',64,'全唐诗/poet.song.67000.json','["背日西來眼界明，隔溪遙見梵王城。", "旌旗夾道蔽山影，笳鼓入林聞谷聲。", "青鳥向人疑有意，白雲迎客不無情。", "夕陽臨水共歸去，明日紛紛塵事生。"]'),
('44d4d9e8-6d2e-4c6f-a90f-5d0d8ea1e889','雞冠花','趙企','宋','宋诗','song-poetry','','[]','秋光及物眼猶迷，著葉婆娑擬碧雞。',32,'全唐诗/poet.song.67000.json','["秋光及物眼猶迷，著葉婆娑擬碧雞。", "精采十分佯欲動，五更只欠一聲啼。"]'),
('dfd2c983-ed91-484e-a97a-d921a5a0edd9','櫻桃','趙企','宋','宋诗','song-poetry','','[]','王母階前種幾株，水晶簾外看如無。',32,'全唐诗/poet.song.67000.json','["王母階前種幾株，水晶簾外看如無。", "只應漢武金盤上，瀉得珊珊白露珠。"]'),
('1d040f86-832b-4aec-b7d4-67edb00569ea','萍','趙企','宋','宋诗','song-poetry','','[]','斑斑染黛色差勻，個個微圓類綠萍。',64,'全唐诗/poet.song.67000.json','["斑斑染黛色差勻，個個微圓類綠萍。", "不比榆錢鋪砌白，未饒荷葉點溪青。", "陶鎔盡出春工巧，磨就多應雨夜零。", "好與詩人買風月，何妨積貯滿空庭。"]'),
('216ebd51-d174-47e3-8fb5-471cc13f7012','秋日泛西湖','趙企','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖光山色共爭秋，一點塵埃無覓處。',32,'全唐诗/poet.song.67000.json','["湖光山色共爭秋，一點塵埃無覓處。", "沉沉水底見青天，畫舸直疑天上去。"]'),
('5ff6c937-e605-4480-b3e0-a8dcb328a6c5','泛湖晚歸','趙企','宋','宋诗','song-poetry','','[]','日脚掩西山，四面烟光起。',48,'全唐诗/poet.song.67000.json','["日脚掩西山，四面烟光起。", "片月落湖心，照破琉璃髓。", "水面天光闊，孤烟暝不收。", "休瞻一鈎月，挂起旅人愁。"]'),
('f3772759-123f-4a3d-806f-fab6e62ef2a5','宿普圓寺二首  其一','趙企','宋','宋诗','song-poetry','','[]','芒鞋侵曉踏青霜，九里松陰引興長。',64,'全唐诗/poet.song.67000.json','["芒鞋侵曉踏青霜，九里松陰引興長。", "雲霧淺深山變態，風烟舒卷水晶光。", "千岩寒月籠疏薄，一笛西風度渺茫。", "短艇不來人意懶，誰知搔首正相望。"]'),
('776ebbfa-7d4b-4d49-9e04-7ab75e65e844','宿普圓寺二首  其二','趙企','宋','宋诗','song-poetry','','[]','仙巾鶴氅與雲輕，晚出岩梯最上層。',64,'全唐诗/poet.song.67000.json','["仙巾鶴氅與雲輕，晚出岩梯最上層。", "複複隴頭歸去雁，陰陰松下遠來僧。", "風吹寒水光成疊，木落重巒碧有稜。", "行到湖邊歸興盡，畫橋臨水與誰凭。"]'),
('54cd092e-f183-423d-9b1e-c25dc2bc3451','泛舟晚出北關','趙企','宋','宋诗','song-poetry','','[]','舟泛寒塘靜，人歸一葉間。',48,'全唐诗/poet.song.67000.json','["舟泛寒塘靜，人歸一葉間。", "影疏行處柳，青遠望中山。", "道在身從老，詩窮意覺閑。", "到家秋斂足，有謂掩柴關。"]'),
('673b229f-b92b-49b5-a9f3-383cfa7b65c9','上竺真辯師','趙企','宋','宋诗','song-poetry','','[]','一別支公僅兩年，山房高隠尚恬然。',64,'全唐诗/poet.song.67000.json','["一別支公僅兩年，山房高隠尚恬然。", "心清已澈靈泉奧，行峻應磨峭壁堅。", "俗眼不來青障裏，孤峰誰認白雲邊。", "更期香火深寒夜，坐使飛花墜九天。"]'),
('41d5cbab-0dfd-4699-8c86-a8d7d3e3bc84','句  其一','趙企','宋','宋诗','song-poetry','','[]','愁從竹葉杯中去，老向菱花鏡裏來。',16,'全唐诗/poet.song.67000.json','["愁從竹葉杯中去，老向菱花鏡裏來。"]'),
('204b367f-feae-405a-8a0f-6e3e5b87e75e','句  其二','趙企','宋','宋诗','song-poetry','','[]','幾夜已生蝴蝶夢，三年辜負鷓鴣班。',16,'全唐诗/poet.song.67000.json','["幾夜已生蝴蝶夢，三年辜負鷓鴣班。"]'),
('f0a1b391-d71f-4184-a7f3-b5b12661b91f','句  其三','趙企','宋','宋诗','song-poetry','','[]','青鏡不覽一兩日，白髮又添三四莖。',16,'全唐诗/poet.song.67000.json','["青鏡不覽一兩日，白髮又添三四莖。"]'),
('73477a71-4152-4a5d-89bd-2b39bf14be3f','句  其四','趙企','宋','宋诗','song-poetry','','[]','青燈影冷棋三戰，紅火爐溫酒一盃。',16,'全唐诗/poet.song.67000.json','["青燈影冷棋三戰，紅火爐溫酒一盃。"]'),
('98a8ad5f-76a6-4884-8c85-66a12c80b3b3','句  其五','趙企','宋','宋诗','song-poetry','','[]','四山來不斷，一水去無窮。',12,'全唐诗/poet.song.67000.json','["四山來不斷，一水去無窮。"]'),
('9a4b541c-ad7e-421c-9a79-9242c4998f33','題自畫蘆雁','李膺仲','宋','宋诗','song-poetry','','[]','晚來無事理扁舟，喚起騷人漫浪愁。',32,'全唐诗/poet.song.67000.json','["晚來無事理扁舟，喚起騷人漫浪愁。", "過眼飛鴻三兩字，淡烟寒日荻花秋。"]'),
('cd279b4f-2472-4a8b-a031-9583ac94f66c','和吳公仲庶遊海雲寺','王霽','宋','宋诗','song-poetry','','[]','大帥新謠十五州，殘春摸石是遨頭。',64,'全唐诗/poet.song.67000.json','["大帥新謠十五州，殘春摸石是遨頭。", "氳氳喜氣隨民遍，冉冉風光盡日流。", "野俗只知觀讌賞，主人非獨爲嬉遊。", "晚迴都騎簫鼙引，觀稼郊原亦暫留。"]'),
('18727241-4f0a-468b-8b08-215de935a5c6','東湖  其一','王雲','宋','宋诗','song-poetry','','[]','湖景甲東城，亭臺相照清。',48,'全唐诗/poet.song.67000.json','["湖景甲東城，亭臺相照清。", "地分春色早，波動日華生。", "絕勝新圖展，涵虛古鑑明。", "綠楊烟岸側，風約釣舟橫。"]'),
('fb7ee7a2-75b4-4c1d-9c12-9982b225b265','東湖  其二','王雲','宋','宋诗','song-poetry','','[]','三月前頭二月天，湖亭雄絕富韶妍。',64,'全唐诗/poet.song.67000.json','["三月前頭二月天，湖亭雄絕富韶妍。", "石形卓砌虎蹲岸，檣影浸波龍卧淵。", "向日鮮明花曝錦，隨風零亂柳飛綿。", "春來此地堪行樂，誰共賞心張雅筵。"]'),
('1f39e7d0-ad8e-49bf-b550-5fa300d85fa5','贈大仰齊禪師','王雲','宋','宋诗','song-poetry','','[]','大仰古名剎，師居二紀中。',48,'全唐诗/poet.song.67000.json','["大仰古名剎，師居二紀中。", "本無一法說，須信萬緣空。", "體與大虛合，心將諸祖同。", "唐來三百載，不墜釋迦風。"]'),
('4009cac5-b474-4331-a538-ecb230eb268f','贈仰山簡老','王雲','宋','宋诗','song-poetry','','[]','簡師飛錫地，天外集雲峰。',48,'全唐诗/poet.song.67000.json','["簡師飛錫地，天外集雲峰。", "挐石松根瘦，歆窗竹影濃。", "山寒侵壞衲，澗響雜疏鐘。", "客問西來意，無言憑短筇。"]'),
('c899e2b4-9635-4be9-bab0-8611229ecf2c','題李都官道堂','王雲','宋','宋诗','song-poetry','','[]','高挂朝冠返故鄉，靜延真侶創新堂。',64,'全唐诗/poet.song.67000.json','["高挂朝冠返故鄉，靜延真侶創新堂。", "不容閒草依階砌，已許歸雲宿棟梁。", "愛客定須添酒病，惜春應未減詩狂。", "肯同阮巷分南北，松竹交陰隔蘚牆。"]'),
('33f281f2-7988-4a9d-b04f-b4f40dd23088','題張氏鍾秀閣','王雲','宋','宋诗','song-poetry','','[]','卜築䫫郊扉，登臨野趣宜。',48,'全唐诗/poet.song.67000.json','["卜築䫫郊扉，登臨野趣宜。", "鷗邊春浪間，草外碧雲低。", "畫憶王摩詰，詩漸杜拾遺。", "徘徊半樓月，殘夜水明時。"]'),
('b5780072-6877-4998-9c8b-418bf77d654a','句  其一','王雲','宋','宋诗','song-poetry','','[]','爲憐綠葉四時在，不可朱闌一日無。',16,'全唐诗/poet.song.67000.json','["爲憐綠葉四時在，不可朱闌一日無。"]'),
('d4304d8d-37a3-4fe5-a649-ca9374061780','句  其二','王雲','宋','宋诗','song-poetry','','[]','經夏地無暑，未寒泉有冰。',12,'全唐诗/poet.song.67000.json','["經夏地無暑，未寒泉有冰。"]'),
('14a5aa20-747a-42c9-b6be-7b691ec4f615','辭住持偈','釋如庵主','宋','宋诗','song-poetry','','[]','三十年來住此山，郡符何事到林間。',32,'全唐诗/poet.song.67000.json','["三十年來住此山，郡符何事到林間。", "休將瑣瑣塵寰事，換我一生閑又閑。"]'),
('465b4e8d-ea98-4fe8-8b87-60c365d59159','句  其一','釋思聰','宋','宋诗','song-poetry','','[]','千點亂山橫紫翠，一鈎新月掛黄昏。',16,'全唐诗/poet.song.67000.json','["千點亂山橫紫翠，一鈎新月掛黄昏。"]'),
('df310880-fbc9-4b7c-aa53-484dc371ba2e','句  其二','釋思聰','宋','宋诗','song-poetry','','[]','枇杷花發天欲雪，黄雀不飛枝上寒。',16,'全唐诗/poet.song.67000.json','["枇杷花發天欲雪，黄雀不飛枝上寒。"]'),
('0de778db-5a29-4e87-86dd-20909d974f4f','挽顧學正  其一','鄭居中','宋','宋诗','song-poetry','','[]','可惜病相如，誰尋封禪書。',48,'全唐诗/poet.song.67000.json','["可惜病相如，誰尋封禪書。", "雙親千里外，一葉九秋餘。", "風露翻歸旐，塵埃鎖故廬。", "虎丘山下路，會葬有鄉車。"]'),
('a8c286bc-e56d-42e6-8ab8-42c5e912aef5','挽顧學正  其二','鄭居中','宋','宋诗','song-poetry','','[]','廣文官舍冷如冰，幾歎朝衫脫未能。',64,'全唐诗/poet.song.67000.json','["廣文官舍冷如冰，幾歎朝衫脫未能。", "忽買春田埋玉地，猶懸絳帳讀書燈。", "佳名空綴仙都石，妙偈爭傳海寺僧。", "一幅粉旌春水漫，惜君誰不涕奔騰。"]'),
('ee7e7590-4f47-49f5-99ae-cddaca6816b4','句  其一','鄭居中','宋','宋诗','song-poetry','','[]','邱壑未應容謝傅，衮衣行見命周公。',16,'全唐诗/poet.song.67000.json','["邱壑未應容謝傅，衮衣行見命周公。"]'),
('d53f0036-082f-4291-b0ee-a6bab04b1a82','句  其二','鄭居中','宋','宋诗','song-poetry','','[]','自有薰風來解慍，更無箕舌巧爲讒。',16,'全唐诗/poet.song.67000.json','["自有薰風來解慍，更無箕舌巧爲讒。"]'),
('d310ff9c-b0d8-421e-a58c-42e1a0787e8c','句  其三','鄭居中','宋','宋诗','song-poetry','','[]','殿上神光瞻舜禹，壁間俊氣識伊萊。',16,'全唐诗/poet.song.67000.json','["殿上神光瞻舜禹，壁間俊氣識伊萊。"]'),
('360ab140-690c-4e1f-96bd-320221115812','句','楊存','宋','宋诗','song-poetry','','[]','月中丹桂輸先手，鏡裏朱顔正後生。',16,'全唐诗/poet.song.67000.json','["月中丹桂輸先手，鏡裏朱顔正後生。"]'),
('899a186b-cf41-43ed-86e8-7124678909ae','寄晁以道求嵩山長松','陳恬','宋','宋诗','song-poetry','','[]','松上花兮松下根，食之年貌與松鄰。',32,'全唐诗/poet.song.67000.json','["松上花兮松下根，食之年貌與松鄰。", "君今既是松間客，采送衰翁亦可人。"]'),
('96a94c37-de2c-499c-bc89-515d9e41837b','題畫扇','陳恬','宋','宋诗','song-poetry','','[]','萬里稻粱高興，誰將出入君懷。',28,'全唐诗/poet.song.67000.json','["萬里稻粱高興，誰將出入君懷。", "已訝天邊月上，更疑蘋末風來。"]'),
('75933014-f6c8-4fe9-b267-4cd998a4704a','子規','陳恬','宋','宋诗','song-poetry','','[]','暮春春已晚，不見子規飛。',24,'全唐诗/poet.song.67000.json','["暮春春已晚，不見子規飛。", "莫是無歸處，山禽不勸歸。"]'),
('75dc7a41-b731-48a3-a159-79ba68337862','謝葛汝州寧卿遺公庫酒肉薪米','陳恬','宋','宋诗','song-poetry','','[]','不是故人供祿米，初非縣令給豬肝。',32,'全唐诗/poet.song.67000.json','["不是故人供祿米，初非縣令給豬肝。", "養賢禮厚隆三簋，拜賜恩深艷一簞。"]'),
('ebfe9efc-0ff8-4b4a-ad9b-b9b8a7d16544','望天台山二絕  其一','陳恬','宋','宋诗','song-poetry','','[]','嵩陽不得到，華頂可徘徊。',24,'全唐诗/poet.song.67000.json','["嵩陽不得到，華頂可徘徊。", "當知吾性分，自有一天台。"]'),
('c361f1ea-4485-4b0d-b112-8dc780b501bd','望天台山二絕  其二','陳恬','宋','宋诗','song-poetry','','[]','氣驟烟雲速，風飛山嶽摧。',24,'全唐诗/poet.song.67000.json','["氣驟烟雲速，風飛山嶽摧。", "神遊八極表，何必訪天台。"]'),
('6c5d818c-1974-4f7b-bfaf-be316c22efb7','送南禪和尚東遷靈巖','陳恬','宋','宋诗','song-poetry','','[]','萬方剎境一珠輝，稽首如空無所依。',64,'全唐诗/poet.song.67000.json','["萬方剎境一珠輝，稽首如空無所依。", "汝浦共瞻雲獨往，靈巖遙佇錫東飛。", "烟霞隠現青蓮峙，龍象歡呼白拂揮。", "多謝禪耆來訪我，雙林風月靜相違。"]'),
('a0fc8170-bcb0-4276-88d8-b7e04bb8ddff','句  其一','陳恬','宋','宋诗','song-poetry','','[]','嵩陽讀水經。',6,'全唐诗/poet.song.67000.json','["嵩陽讀水經。"]'),
('3c532a19-5eee-4fd4-9cff-d4106c213b80','句  其二','陳恬','宋','宋诗','song-poetry','','[]','雪裏消磨一半春。',8,'全唐诗/poet.song.67000.json','["雪裏消磨一半春。"]'),
('d040e949-7a4a-484f-9ac5-dd23bbc00453','臨寂頌','釋顯嵩','宋','宋诗','song-poetry','','[]','八十年中常浩浩，宏開肆貨摩尼寶。',32,'全唐诗/poet.song.67000.json','["八十年中常浩浩，宏開肆貨摩尼寶。", "也無一箇共商量，不是山僧收鋪早。"]'),
('086051a1-51bb-456e-9ef5-36e2932e1f49','偈','釋顯嵩','宋','宋诗','song-poetry','','[]','昨日羅剎心，今朝菩薩面。',24,'全唐诗/poet.song.67000.json','["昨日羅剎心，今朝菩薩面。", "羅剎與菩薩，不隔一條綫。"]'),
('eb589e28-7c95-4062-8ab1-6de932ee0b07','方舍舟九江適會僕射相公道過二林得非所期相顧歎息輒爲長句用志勝遊且以敘別','許翰','宋','宋诗','song-poetry','','[]','公爲逐客向何州，我亦求家賦遠遊。',64,'全唐诗/poet.song.67000.json','["公爲逐客向何州，我亦求家賦遠遊。", "邂逅二林成晤賞，寂寥千古想風流。", "玉鏘溪堰凉吹榻，蓋偃松蘿翠滿樓。", "明日分携重迴首，鑪峰空見紫烟浮。"]'),
('1d77ac93-a048-4b57-ac59-d7011fd7ac28','奉和大觀文相公見寄古風','許翰','宋','宋诗','song-poetry','','[]','旃裘亂衣裳，風雨飄屋廬。',144,'全唐诗/poet.song.67000.json','["旃裘亂衣裳，風雨飄屋廬。", "南奔萬里空，脫死鋒鏑餘。", "翠華狩絕域，黄塵翳修塗。", "朝無嵇侍中，濺血霑誰裾。", "夷兒金束袍，漉蔌懸珊瑚。", "驕氣吞九州，投餌術已疏。", "公捐繞朝策，觀化聊據梧。", "鳳凰渺鴻乙，紫氛誰與俱。", "丘壑歲已晚，鍾鼎功未書。", "棄置委時運，超摇遊物初。", "此憂自古有，此樂絕世無。", "邂逅拯橫流，功成吾不居。"]'),
('02cfa7eb-aad6-4482-a8fb-245787c31705','三友篇贈珪老','許翰','宋','宋诗','song-poetry','','[]','平生我三友，四海吳李孫。',240,'全唐诗/poet.song.67000.json','["平生我三友，四海吳李孫。", "抱能不時施，戎馬生中原。", "孫既北隨難，落日黄塵昏。", "吳亦南投荒，蠻瘴愁朝暾。", "李今又去我，浮槎雜鼉黿。", "飛濤渺何極，海天相吐吞。", "蘧蘧遺此老，死生信乾坤。", "顛沛吳江渚，投依楚山樊。", "脩水抱蒼巔，劍氣埋雲根。", "翛然竹林下，乃有幽人存。", "神交跡兩忘，高風嫋孤旛。", "慰我念友心，方外得所敦。", "空寂湛禪悅，中有詩清溫。", "我亦忘世者，早窺治亂源。", "忠臣泣廟社，志士傷丘園。", "欲持一寸膠，往澄九河渾。", "晚知未得力，繙經委空言。", "迨此從君遊，始脫百憂繁。", "五君與六逸，歲久名方尊。", "他日竹菴東，更開支許軒。"]'),
('4ecc6873-88cd-4d08-b71c-69330803c954','艤舟大藤峽口武陵使至忽奉福唐珍牘附以古風招隠攬之欣聳有會初心而分閫之命下已久矣詠歎不已復次舊韵用寄惓惓冀一觀省','許翰','宋','宋诗','song-poetry','','[]','避兵窮嶺海，我豈文休孫。',240,'全唐诗/poet.song.67000.json','["避兵窮嶺海，我豈文休孫。", "慨彼鳴鳳郊，化爲逐鹿原。", "北吹戰塵腥，南接瘴霧昏。", "森然一彗孛，敢近六龍暾。", "轉舟大藤峽，脫死鱷與黿。", "纜裊蒼崖樹，落日銜未吞。", "忽得素書尺，若闚黄裳坤。", "招我以隠淪，雉澤遺塵樊。", "游心太易初，攟逐萬化根。", "耿光百世後，樂此不亡存。", "寧知虎符下，擁公萬旌旛。", "英威祖豫州，非心折王敦。", "從容謝東山，逆氣沮桓溫。", "自昔國其國，治忽信有源。", "豈容社稷鎮，端老孤獨園。", "至人心淑清，一爲斯民渾。", "胡騎却長嘯，晉史徒清言。", "武侯揮白羽，亦有軍務繁。", "要封鯨鯢觀，復睹宸極尊。", "功成去冥冥，與我俱鴻軒。"]'),
('88b9ccfc-7e03-459c-84cc-fd902b653396','辛亥三月繫舟瀟湘得邵武柳州二丞相正月初書撫事感懷寄此長句','許翰','宋','宋诗','song-poetry','','[]','回雁峰南楚越分，瀟湘烟水思離羣。',64,'全唐诗/poet.song.67000.json','["回雁峰南楚越分，瀟湘烟水思離羣。", "林寒欲暗他江浦，月出先明半嶺雲。", "客子無歸迷世路，故人不見隔兵氛。", "春風空寄相思字，寇鄧經綸早晚聞。"]'),
('45878f7a-1019-4c67-b4f3-9cec7e5b1f8f','題虎丘次蒲章二公韵  其一','王仲敏','宋','宋诗','song-poetry','','[]','松陰嵐影翠回環，盡在牆垣繚繞間。',64,'全唐诗/poet.song.67000.json','["松陰嵐影翠回環，盡在牆垣繚繞間。", "舟楫更無通別浦，烟霞曾不接他山。", "詩亡石在雲徒恨，劍去池荒水自閑。", "偷得公餘來一餉，遙城鐘鼓出催還。"]'),
('c25df1e9-b8f7-449c-b91a-9b7745e4651c','題虎丘次蒲章二公韵  其二','王仲敏','宋','宋诗','song-poetry','','[]','匆匆乘詔解行舟，早晚重來此地遊。',64,'全唐诗/poet.song.67000.json','["匆匆乘詔解行舟，早晚重來此地遊。", "今日湖山詩似杜，當年庠序學如丘。", "烟波初入朝宗浦，風月還思望海樓。", "紅旆碧幢留不住，空餘遺愛在南州。"]'),
('7ca6e3f0-b119-49d8-bf34-05012c1b7290','句','王仲敏','宋','宋诗','song-poetry','','[]','諢語銷忠骨鯁亡，此中空奏忒郎當。',16,'全唐诗/poet.song.67000.json','["諢語銷忠骨鯁亡，此中空奏忒郎當。"]'),
('ae1c1dfc-a7a4-4be7-bc6d-b62688073a7c','偈','錢蓋','宋','宋诗','song-poetry','','[]','稽首文殊師，昔爲七佛祖。',204,'全唐诗/poet.song.67000.json','["稽首文殊師，昔爲七佛祖。", "嘗發大悲願，廣度諸有情。", "念彼東北方，是爲清凉境。", "龍神五百俱，眷屬萬菩薩。", "設化於此土，示現無量光。", "聞者嘆希有，何况目所見。", "我於曩劫中，曾種種供養。", "今復得親近，瞻睹異於常。", "念無始劫來，有塵沙數罪。", "一獲光明相，釋然盡消滅。", "又念諸衆生，與我同體性。", "乘此勝妙力，離苦愁解脫。", "我今永歸依，敬禮發弘誓。", "願盡未來際，常居佛會中。", "一聞微妙音，即證無上道。", "十方虛空界，一切諸有情。", "盡願同我心，速悟無生忍。"]'),
('824c5d10-155a-46de-8ec2-8571caadf0c0','白雲亭  其一','林通','宋','宋诗','song-poetry','','[]','白雲亭構見浮圖，賢尹標名意有餘。',64,'全唐诗/poet.song.67000.json','["白雲亭構見浮圖，賢尹標名意有餘。", "閒抱石巖禪客座，影籠墨跡憲臺書。", "玎璫玉溜無停響，瀟洒琅玕不用疏。", "登賞已知情放佚，飄飄應喜類相如。"]'),
('a1dbaf55-5ded-4974-9d4c-92a3b73b9edb','白雲亭  其二','林通','宋','宋诗','song-poetry','','[]','雙溪會處創危亭，我愛亭成不異名。',64,'全唐诗/poet.song.67000.json','["雙溪會處創危亭，我愛亭成不異名。", "到此更誰分別派，同歸終見入東瀛。", "清輝黛染環簷色，幽響琴傳出澗聲。", "自信竹林林上美，剪裁今已屬賢明。"]'),
('67e099b4-684a-45a1-81e8-57e52d223184','九日亭','林通','宋','宋诗','song-poetry','','[]','危頂裁成九日亭，蓬瀛透出海峰青。',64,'全唐诗/poet.song.67000.json','["危頂裁成九日亭，蓬瀛透出海峰青。", "滿前細菊浮樽酒，四顧凝雲簇畫屏。", "月爲情多良夜至，人貪景勝醉魂醒。", "風流令尹江山主，此樂同民德已馨。"]'),
('479a3cfb-c4a0-4974-aeed-79e993e445c9','書郭子度壁','許梁','宋','宋诗','song-poetry','','[]','禁苑精廬是切鄰，衣巾雖舊不沾塵。',64,'全唐诗/poet.song.67000.json','["禁苑精廬是切鄰，衣巾雖舊不沾塵。", "鐘魚聲裏吟連晚，花柳香中醉過春。", "和玉重泥燒藥竈，買絲新接釣魚綸。", "繞湖十萬人家住，如此清閑有幾人。"]'),
('260ab07d-56bb-4ecf-b4c1-e6d39452702b','題雪竇和尚親書偈後','葛繁','宋','宋诗','song-poetry','','[]','真機昔振雲門路，祖席今多雪竇孫。',32,'全唐诗/poet.song.67000.json','["真機昔振雲門路，祖席今多雪竇孫。", "傳到慧林花果盛，須知葉落總歸根。"]'),
('dd1e0e4c-ca7d-49dc-9c94-103fb010067c','流花亭','高述','宋','宋诗','song-poetry','','[]','翬簷臨古岸，玉砌近重闉。',48,'全唐诗/poet.song.67000.json','["翬簷臨古岸，玉砌近重闉。", "指點尋仙路，留連勸酒人。", "水流還似舊，花落又逢春。", "客到此亭下，眷言休問津。"]'),
('bb3ae98d-4933-4a09-ac02-9b0302f663cc','賦玉溪寺石菖蒲','高述','宋','宋诗','song-poetry','','[]','玉溪石角尖如鋒，山泉噴浸碧玉龍。',96,'全唐诗/poet.song.67000.json','["玉溪石角尖如鋒，山泉噴浸碧玉龍。", "龍髯誰爲不可識，石上菖蒲拳碧茸。", "老根密節穿石瘦，細葉如林屯遠岫。", "百草爛死事潜萌，纖纖獨與冰霜鬭。", "玻璃瑪瑙春水寒，呼兒捧將持銅槃。", "年來青眼志未喪，喜君綠髮能衝冠。"]'),
('e28cbb75-f5fc-4525-87d0-5cdcfd82d276','玉溪曉步','高述','宋','宋诗','song-poetry','','[]','平生丘壑情，得此真忘形。',48,'全唐诗/poet.song.67000.json','["平生丘壑情，得此真忘形。", "摳衣跨石角，開道披林坰。", "日影曉峰翠，猿啼山柿青。", "三潭在何許，已約摸重屏。"]'),
('259086af-0a17-442c-92bc-b6042e30b1aa','句','高述','宋','宋诗','song-poetry','','[]','謫仙此酹月，郎官亦流風。',12,'全唐诗/poet.song.67000.json','["謫仙此酹月，郎官亦流風。"]'),
('1f0a1c01-eb25-443e-bfe4-8d2e7605cae5','句','藍奎','宋','宋诗','song-poetry','','[]','懶思身外無窮事，願讀人間未見書。',16,'全唐诗/poet.song.67000.json','["懶思身外無窮事，願讀人間未見書。"]'),
('4c6abae4-e3cc-4020-b4ce-2f07bfdf0bc0','遊日山','郭三益','宋','宋诗','song-poetry','','[]','洗光朝日上旋旋，瑞色分臨此地先。',64,'全唐诗/poet.song.67000.json','["洗光朝日上旋旋，瑞色分臨此地先。", "門迥帆收江市密，山深龍卧海潭圓。", "靜然柏子聽幽偈，閒立苔痕問小禪。", "莫訝潮平歸渡晚，斯遊有意已三年。"]'),
('57b9f994-b6a9-4f64-8b27-d8459d4b7245','流花亭','郭三益','宋','宋诗','song-poetry','','[]','面幽連野色，審曲带城闉。',48,'全唐诗/poet.song.67000.json','["面幽連野色，審曲带城闉。", "但見流花水，難尋避世人。", "蟠桃知幾熟，蘚洞謾長春。", "稅駕追前事，躊躇要路津。"]'),
('1d6fa3ae-f9f8-4b93-bec0-7968c4d740b3','韋羌山式公綠筠庵詩','郭三益','宋','宋诗','song-poetry','','[]','道人棲碧山，雲居在空曲。',120,'全唐诗/poet.song.67000.json','["道人棲碧山，雲居在空曲。", "十年海潮音，利物緣已熟。", "更尋妙高頂，超然具幽築。", "古木插空青，寒筠抱巖綠。", "時携貝葉書，步入深林讀。", "雲衣冷蕭條，靜對含烟玉。", "客來境非喧，客去境自足。", "宵眠護禪虎，晝引銜花鹿。", "庵中三昧語，藥我貪瞋毒。", "何當脫雙鳬，藜杖追高躅。"]'),
('d0f585a9-b5cd-4ac4-9def-6899fc0e4a40','題多福院分翠軒','郭三益','宋','宋诗','song-poetry','','[]','平生但愛山中寺，此日來看竹外山。',32,'全唐诗/poet.song.67000.json','["平生但愛山中寺，此日來看竹外山。", "心境頓開清浄想，客塵無復更相關。"]'),
('d371f893-5431-4510-ab6d-a7e933c72937','題廣度院','郭三益','宋','宋诗','song-poetry','','[]','羲和均四時，曜靈有急節。',120,'全唐诗/poet.song.67000.json','["羲和均四時，曜靈有急節。", "沈迷簿領書，坐歎春事歇。", "及茲新雨收，西郊軔初發。", "蒼頑山氣嘉，奔悍溪流活。", "風驚麥翻浪，水浄秧抽髮。", "漸窮蕭寺幽，頓使煩襟豁。", "蜂喧釀蜜翅，鳥落啼林血。", "高僧日無事，種朮畦畝闊。", "綠苗已紓紓，紫花行復結。", "吾欲訪長生，終歲期採擷。"]'),
('cd5f77b3-229f-4859-9f64-875835d398ee','題南嶽寺','郭三益','宋','宋诗','song-poetry','','["\u8861\u5c71"]','古木陰森梵帝家，簾泉一酌試新芽。',32,'全唐诗/poet.song.67000.json','["古木陰森梵帝家，簾泉一酌試新芽。", "官符星火催春焙，却使山僧怨白蛇。"]'),
('34691279-1947-4f88-b55f-a5c75cc53e13','題仙居南峰寺藍光軒','郭三益','宋','宋诗','song-poetry','','[]','山光竹影交寒輝，下有碧浸吹漣漪。',64,'全唐诗/poet.song.67000.json','["山光竹影交寒輝，下有碧浸吹漣漪。", "沙痕隠隠白鳥去，石聲鑿鑿扁舟歸。", "芝蘭發香禪味遠，雲霧吐秀人家稀。", "須知春事不可挽，杜鵑已繞林中飛。"]'),
('fc3039fa-0df5-4a0b-9e97-f49694ff0a33','句  其一','郭三益','宋','宋诗','song-poetry','','[]','曉鳥啼啞啞，游子初去家。',24,'全唐诗/poet.song.67000.json','["曉鳥啼啞啞，游子初去家。", "去家向何許，雪暗天一涯。"]'),
('0c064c2a-b481-4cd9-a305-4c5303033bb4','句  其二','郭三益','宋','宋诗','song-poetry','','[]','舉頭語天公，慇懃推日車。',12,'全唐诗/poet.song.67000.json','["舉頭語天公，慇懃推日車。"]'),
('f1fb1b44-f569-4ace-90f8-d2d2e2ef0f00','絕句二首  其一','孫發','宋','宋诗','song-poetry','','[]','林亭長夏愛濃陰，來引茶甌一散襟。',32,'全唐诗/poet.song.67000.json','["林亭長夏愛濃陰，來引茶甌一散襟。", "忽去却來蜂個個，自啼還住鳥深深。"]'),
('b3359d14-1984-45e5-90cd-1bf9854dce76','絕句二首  其二','孫發','宋','宋诗','song-poetry','','[]','山家一尺瀟湘石，掃盡雲腴齒頰清。',32,'全唐诗/poet.song.67000.json','["山家一尺瀟湘石，掃盡雲腴齒頰清。", "警破午窗箕潁夢，轉爲風外小松聲。"]'),
('013329b3-70df-49a0-bc46-dfaa46c3bcd0','截臂行','孫發','宋','宋诗','song-poetry','','[]','吾聞兩臂重於天下不可廢，知之不必子華子。',200,'全唐诗/poet.song.67000.json','["吾聞兩臂重於天下不可廢，知之不必子華子。", "愚民氣焚胸，一忿敢趨死。", "以死視四肢，截臂如去指。", "嗚呼巴陵之民何以有此風，疾痛利害人所同。", "甘心一臂捐糞壤，終身廢卧閭閻中。", "前年截臂渠得理，今年截臂吾亦爾。", "村南截臂殺平人，村北炰咻還比擬。", "虺虺民，虺虺民，用心若此非吾人。", "有冤自可次第訴，毒人何必殘其身。", "聞者莫驚喧，此弊吾能言。", "其初姑息吏，不與杜其源。", "嗟哉惡俗傷仁厚，明明有冤宜勿受。", "一姦不濟百姦消，共致和平俾在宥。"]'),
('fd37fc19-3042-4226-8c56-9ea8072fd758','書語集句詩譏一老生','孫實','宋','宋诗','song-poetry','','[]','孜孜爲善雞鳴起，先王之道斯爲美。',32,'全唐诗/poet.song.67000.json','["孜孜爲善雞鳴起，先王之道斯爲美。", "四十五十無聞焉，斯亦不足畏也已。"]'),
('c5b22b3d-abc6-47a4-a34f-6bd8b35cc92e','壓雲軒','孫實','宋','宋诗','song-poetry','','[]','絕頂地平易，軒窗風怒號。',48,'全唐诗/poet.song.67000.json','["絕頂地平易，軒窗風怒號。", "半空垂象緯，四面湧波濤。", "洞僻封苔蘚，泉深冷骨毛。", "登臨欲忘返，城市厭塵勞。"]'),
('88b9142d-8044-441b-ad32-23689846bfda','石橋','太史章','宋','宋诗','song-poetry','','[]','澗底輕雷噴玉泉，石橋僧度是何年。',64,'全唐诗/poet.song.67000.json','["澗底輕雷噴玉泉，石橋僧度是何年。", "靈峰斗隔人間世，真境潜分洞裏天。", "施食曾聞龍就掌，談空應有虎當筵。", "道猷雪涕非無謂，誰見湔腸掛木顛。"]'),
('8bb46226-759d-48d9-b856-103e7532d828','桐柏崇道觀','太史章','宋','宋诗','song-poetry','','[]','神僊隠居尚深渺，徑迂不欲與世通。',188,'全唐诗/poet.song.67000.json','["神僊隠居尚深渺，徑迂不欲與世通。", "必求峭拔出林杪，俯視左右環羣峰。", "飛泉不測源所自，瀑注一落千丈虹。", "步躋石磴旋盤折，翠蔭蒙密多長松。", "唐聞馬練師，晉傳葛仙翁。", "丹灰已死不復熾，獨有翰墨留遺蹤。", "定知華表立歸鶴，誰見靈湫藏蟄龍。", "白雲子，信亦稀，藐視聲利如塵泥。", "仕途捷徑非我樂，不死之鄉終欲歸。", "玉霄峰前烟撲撲，金庭宮外雲霏霏。", "哀猿嘯斷月不古，桃杏得春還滿枝。", "風馭寥寥何處在，孤墳棺殮只空衣。"]'),
('a9e52528-3644-465d-80a0-3e771496fe62','題幽石','太史章','宋','宋诗','song-poetry','','[]','痕疑神所鑿，不與衆巖俱。',48,'全唐诗/poet.song.67000.json','["痕疑神所鑿，不與衆巖俱。", "鎮地形何直，參天勢自孤。", "鶴栖喬木穩，猿攬古籐粗。", "欲得丹青手，和雲畫作圖。"]'),
('d2b37dd2-4b13-4985-8ffb-f1afc31c5c10','題望飛泉','太史章','宋','宋诗','song-poetry','','[]','既晴安得雨霏霏，百道流泉落翠微。',32,'全唐诗/poet.song.67000.json','["既晴安得雨霏霏，百道流泉落翠微。", "側帽試看繩引處，破烟千點濕人衣。"]'),
('3ba13005-09d4-48a8-bc98-ac1e9488f1b7','題宴坐石','太史章','宋','宋诗','song-poetry','','[]','白雲曾罩定中身，石上雲歸不見人。',32,'全唐诗/poet.song.67000.json','["白雲曾罩定中身，石上雲歸不見人。", "應有山神常守護，松風時爲埽埃塵。"]'),
('4326cc2c-84d7-40c9-950b-bb0a5075f0cb','月巖齋詩','李廌','宋','宋诗','song-poetry','','[]','南山之北，北山之南。',240,'全唐诗/poet.song.67000.json','["南山之北，北山之南。", "環岡繞嶺，紫翠相參。", "奔騰蹲蹴，萬里䮝驂。", "丘衍沃若，靈秀所涵。", "平巒蔽虧，餞日西崦。", "月生大東，錯落夕嵐。", "凝輝萬壑，澄若淵潭。", "有窶人室，架楹維三。", "其名實佳，佳哉月巖。", "窶人者何，贊皇之黔。", "伊誰名之，宗伯子瞻。", "嗟嗟窶人，天民之淹。", "昔也方將，愚妄所漸。", "喜功好名，虎穴屢探。", "輪殷緌墮，却戰猶酣。", "老不及人，綿力弗堪。", "飲冰食蘗，處約已甘。", "天匪靳予，事有莫兼。", "俾予有知，錫福則廉。", "餘齡數奇，展也不占。", "異時著書，雖俟桓譚。", "心勞用寡，遠愧周聃。", "今師農圃，穮蔉崇芟。", "年登歲樂，糠稗求饜。"]'),
('2cc3c325-211f-4faf-b2c3-79a62411e454','觀出日','李廌','宋','宋诗','song-poetry','','[]','蒼崖觀出日，依稀自扶桑。',156,'全唐诗/poet.song.67000.json','["蒼崖觀出日，依稀自扶桑。", "初如浴咸池，蒼蒼或凉凉。", "漸若賓暘谷，赫赫復煌煌。", "海濱升霞彩，貫地萬丈長。", "攝提御天衢，一照明萬方。", "不願發五色，不必呈九光。", "無用現重輪，無貴珥青黄。", "吾心願吾君，盛德如朝陽。", "照臨冒下土，威名燭無疆。", "不復迭而微，常進熾而昌。", "蟻行理雖切，丸跳比亦狂。", "病夫喜壯觀，蓬心遂恢張。", "異時環堵宮，但見生東牆。"]'),
('d8fa0366-4e35-463f-b237-b2f2666effa9','宿峻極中院','李廌','宋','宋诗','song-poetry','','[]','晨游開母祠，暮抵紫虛谷。',96,'全唐诗/poet.song.67000.json','["晨游開母祠，暮抵紫虛谷。", "千峰掛夕陽，猶指中寺宿。", "山空無人聲，暝色滿草木。", "亂石礙饑馬，荒榛走驚鹿。", "深林怪禽號，絕壑山鬼哭。", "照塗藉流螢，呻吟愧僮僕。", "乙夜扣禪扉，孤燈耿幽綠。", "猶疑夢寐中，對榻眠空屋。"]'),
('ac4c61b3-8257-4783-8128-b6ca0afe519d','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其一','李廌','宋','宋诗','song-poetry','','[]','陽崖轉窅窕，層林蔽重陰。',36,'全唐诗/poet.song.67000.json','["陽崖轉窅窕，層林蔽重陰。", "披榛過輿馬，緣雲得幽尋。", "坐覺真境寂，茲焉悟賞心。"]'),
('ae59915a-3ea8-44ab-849b-25d906efdcf2','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其二','李廌','宋','宋诗','song-poetry','','[]','平時崢嶸想，跼蹐在城郭。',36,'全唐诗/poet.song.67000.json','["平時崢嶸想，跼蹐在城郭。", "言登諸峰勝，幽情散寥廓。", "焉能乘海桴，終期老丘壑。"]'),
('1f97d734-6218-492c-a4e5-5633887af5a3','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其三','李廌','宋','宋诗','song-poetry','','[]','日背西嶺沒，月嚮東嶺生。',36,'全唐诗/poet.song.67000.json','["日背西嶺沒，月嚮東嶺生。", "殷霞未隠彩，皓露已舒明。", "斗柄坐可挹，政恐河漢傾。"]'),
('40ec1471-5723-4199-a30d-5dd55db9ea1b','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其四','李廌','宋','宋诗','song-poetry','','[]','微雲起前礎，出山忽紆餘。',36,'全唐诗/poet.song.67000.json','["微雲起前礎，出山忽紆餘。", "風吹去何之，閑意滿太虛。", "倚柱聊目送，我生何滯愚。"]'),
('bd84691d-47cc-4822-913f-cb34859c4eec','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其五','李廌','宋','宋诗','song-poetry','','[]','廛居倦喧卑，區中憎陿隘。',36,'全唐诗/poet.song.67000.json','["廛居倦喧卑，區中憎陿隘。", "游目宇宙間，山河真礪带。", "一嘯萬林端，呼風作天籟。"]'),
('55ad97cd-2ac7-49f7-a31f-244bc65558de','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其六','李廌','宋','宋诗','song-poetry','','[]','風回荔蘿香，意與塵氣別。',36,'全唐诗/poet.song.67000.json','["風回荔蘿香，意與塵氣別。", "杳杳雲際鐘，皎皎松上月。", "觸焉感幽處，蠟屐俟明發。"]'),
('44437409-2fa8-4daa-986a-57415a01abb5','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其七','李廌','宋','宋诗','song-poetry','','[]','陰磴頑雪積，老崖白雲深。',36,'全唐诗/poet.song.67000.json','["陰磴頑雪積，老崖白雲深。", "捫蘿陟鳥道，揚塵落喬林。", "下方有粟場，俯見歸飛禽。"]'),
('585ae6cf-b36b-43eb-8a4f-5bbb3687b02b','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其八','李廌','宋','宋诗','song-poetry','','[]','舍鞅陟層巘，老步獨多歎。',36,'全唐诗/poet.song.67000.json','["舍鞅陟層巘，老步獨多歎。", "笑談谷傳響，松聲遞蕭散。", "欲尋草堂池，土室無僧贊。"]'),
('b16b6b94-8b6a-4553-a6d3-2337d6e9cbe8','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其九','李廌','宋','宋诗','song-poetry','','[]','松風憩俗駕，撫心愧營營。',36,'全唐诗/poet.song.67000.json','["松風憩俗駕，撫心愧營營。", "登臨念勝土，烏用千載名。", "願與婦子俱，終焉住神清。"]'),
('463f462f-e8cb-4386-8ff6-230ebf471ee3','丙子歲三月十有二日遊嵩山宿峻極中院時天氣清朗山月甚明因以陰壑生虛籟月林散清影爲韵詩各六句  其一○','李廌','宋','宋诗','song-poetry','','[]','穿雲上虛無，彷彿凌倒景。',36,'全唐诗/poet.song.67000.json','["穿雲上虛無，彷彿凌倒景。", "微茫鴻鵠背，指點衆山頂。", "出日上扶桑，徘徊萬林影。"]'),
('8277d4a6-ce77-483b-a427-4f34425a4037','西郊','李廌','宋','宋诗','song-poetry','','[]','黄花作秋色，槁莢作秋聲。',96,'全唐诗/poet.song.67000.json','["黄花作秋色，槁莢作秋聲。", "殘春有秋意，奈此惻惻情。", "喬木點新翠，古壠集飄英。", "午風薰徑草，麥浪摇新晴。", "脂車逐勝士，訪友來西坰。", "苦汗泣瘦馬，流塵汙華纓。", "囅然發孤笑，屢醉輒屢醒。", "聊歌干旄篇，愧我未登瀛。"]'),
('8b8748ef-a33a-4925-bccc-907550339972','觀文恪王公樂道院巽亭在城上下臨潩水','李廌','宋','宋诗','song-poetry','','[]','氤氳蟠巽隅，崢嶸干斗魁。',168,'全唐诗/poet.song.67000.json','["氤氳蟠巽隅，崢嶸干斗魁。", "蕪城佳氣緬，茂林朱檻開。", "竹月靜蔭扃，松風綠摇盃。", "開軒清流度，隠几遙山來。", "恪公昔優游，弭節此裴回。", "言念平生容，翻然九泉哀。", "張老頌趙寢，雍門悲孟臺。", "歌榭奄凝塵，燕閣鬰生苔。", "侈靡一轉盼，金碧復成埃。", "獨無不忘者，安用爾爲哉。", "恪公古遺直，勁氣騰九垓。", "豈惟甘棠愛，將與故國偕。", "傳家有元凱，上客盡鄒枚。", "聊興勝士想，愧無能賦才。"]'),
('db22db72-4a41-4b09-8288-5d39aec9ba88','釣渚詩','李廌','宋','宋诗','song-poetry','','[]','釣渚平過水，筆溪清見底。',72,'全唐诗/poet.song.67000.json','["釣渚平過水，筆溪清見底。", "寒烟曉冥冥，白石明齒齒。", "目送歸鴻飛，游心志鱣鮪。", "手應心不疑，物我相諾唯。", "黄雀漫多驚，白鷗來自喜。", "之子未投竿，我來頻洗耳。"]'),
('2f5c86f0-d903-44df-b543-800bdf96ea75','盧巖','李廌','宋','宋诗','song-poetry','','[]','徵君邈已遠，舊隠鎖雲扃。',96,'全唐诗/poet.song.67000.json','["徵君邈已遠，舊隠鎖雲扃。", "欲知敬遺德，巖以姓爲名。", "永言配此山，千歲爲德星。", "雖無猿鶴在，空餘泉石清。", "想昔居此地，笑傲輕冠纓。", "入居伯夷室，出效子真耕。", "種德如古人，養育達周京。", "惟能抱永正，是豈其用卿。"]'),
('8a4fdd5b-babe-4f6c-9653-5698f14cadd1','黄楊林詩','李廌','宋','宋诗','song-poetry','','[]','黄楊性堅貞，枝葉亦剛愿。',48,'全唐诗/poet.song.67000.json','["黄楊性堅貞，枝葉亦剛愿。", "三十六旬久，增生但方寸。", "今何成修林，左右映烟蔓。", "良材豈一二，所期先愈鈍。"]'),
('83b56be8-6642-4448-a862-93a998d66c32','臨溪檜','李廌','宋','宋诗','song-poetry','','[]','青青弱草陰，猶能蔭寒魚。',72,'全唐诗/poet.song.67000.json','["青青弱草陰，猶能蔭寒魚。", "况乃葱蒨色，百尺映扶疏。", "月烟含清曠，水氣相吹噓。", "忽思大明宮，垂楊拂丹渠。", "豈無蒼翠色，飄颻映茅廬。", "日暮生幽寒，寂寞意何如。"]'),
('7f5c739c-ff35-4e55-8bf6-930c41458578','天封觀將軍柏','李廌','宋','宋诗','song-poetry','','[]','衛懿恃昌富，乘軒鶴有祿。',288,'全唐诗/poet.song.67000.json','["衛懿恃昌富，乘軒鶴有祿。", "貴鶴賤用民，身殘國顛覆。", "楚子惜名馬，終焉葬人腹。", "爵封東山松，侯比渭川竹。", "時輕官秩紊，辟妄作威福。", "無益害有益，褒賞逮禽畜。", "所美非美然，恩澤及草木。", "或譏將軍柏，無乃狃此俗。", "曷膺千鍾養，曷被三品服。", "不爲朝廷力，竊號委空谷。", "余知將軍心，非悅世人目。", "千年抱貞操，勁節無屈曲。", "不爲歲寒凋，守此萬仞綠。", "天武累此名，冥不知寵辱。", "雖不助柏敬，豈意慕軫轂。", "吾儕之小人，悟主惟欲速。", "盜功仍苟容，豈恥無道穀。", "潭潭居紫府，沉沉據華屋。", "貪恩謀子孫，占俸及僮僕。", "膏肓病天下，天下思食肉。", "朝爲四輔重，莫作三危逐。", "笙簫金谷宴，翣柳北邙哭。", "尚方屬鏤賜，朝服東市戮。", "君看古功臣，牖下死爲祝。"]'),
('0dafd8df-7468-4527-9b2e-1d77df188ac4','鳳凰臺','李廌','宋','宋诗','song-poetry','','[]','舜韶奏九成，鳳凰故來儀。',36,'全唐诗/poet.song.67000.json','["舜韶奏九成，鳳凰故來儀。", "漢徹方秦政，何乃悞至斯。", "爾非鷄與鶩，出處當慎時。"]'),
('8035b487-8c3d-4b4a-9cd7-7df833a584d6','送霍子侔還都','李廌','宋','宋诗','song-poetry','','[]','真人造區夏，民瘼傒以蘇。',288,'全唐诗/poet.song.67000.json','["真人造區夏，民瘼傒以蘇。", "戎衣振不格，力舉覆地盂。", "桓桓神武威，自信人未孚。", "當年羣嘯聚，劍立猶稱孤。", "天旋地機轉，曠谷吹塤竽。", "曈曈東方日，揚光扶桑隅。", "文明燭無疆，煌煌中天衢。", "曾孫太平君，稽古追唐虞。", "求賢用吉士，隠淪來真儒。", "股肱協帝躬，腹心懷良圖。", "庶事正絜矩，嘉言規典謨。", "欲將醍醐酪，沾濯瘍垢膚。", "又慮天下事，學古太殊塗。", "衆說折聖經，丹青久將渝。", "世稱淵華者，春秋華實敷。", "考之篤誠諶，熒熠皆穿窬。", "况復口耳學，擿埴冥索途。", "終身不知道，死矣如蟪蛄。", "無心時雨化，蠲逖狂狷迂。", "法言立定論，章章如璠瑜。", "專經務篤實，使士知所趨。", "欲皆抱道義，如孔丘之徒。", "士各重良貴，豈若乘風鳬。", "亦有倔彊輩，索足行深涂。"]'),
('d5768131-1d7f-4206-b5ff-8fe260cf1108','鹿門寺','李廌','宋','宋诗','song-poetry','','[]','蓬萊鹿門道，莽莽漢津渡。',288,'全唐诗/poet.song.67000.json','["蓬萊鹿門道，莽莽漢津渡。", "川塗兩緬邈，今古同此路。", "德公厭州里，翁媼是中去。", "風流可引想，千載豹隠霧。", "浩然遶城歸，羸馬琢妙句。", "宿草被荒丘，寒榛軼驚兔。", "昔我懷登臨，歲晏屬凝沍。", "茲遊愜于願，春仲忽云暮。", "杖策升翠麓，喟歎憐老步。", "冠雲得危亭，臨世濯凡趣。", "蒿薺俯青林，繡繪辨紅樹。", "他山照寸碧，迂江泫晞露。", "我生老憂患，胸次貯百慮。", "寓目宇宙間，猛省忘外慕。", "前瞻萬松嶺，翠壁屹相顧。", "輕飈觸纖柯，虛籟森已度。", "甓道繞危巔，爽氣襲籃轝。", "傳聞古道場，臺殿若鱗布。", "日者一昔災，楹棟皆若炬。", "壞垣積煨燼，况乃金碧處。", "山僧勤樸斲，堂構略已具。", "童奴一萬指，役作供指呼。", "當有鬼運牐，變現助持護。", "蹇予藏史後，道骨天所付。"]'),
('43d4ecbb-4f72-4d44-a6ad-c5f8d11137bd','四逸臺','李廌','宋','宋诗','song-poetry','','[]','異時常獨飲，對月成三人。',108,'全唐诗/poet.song.67000.json','["異時常獨飲，對月成三人。", "已喜三士遊，况遇金城辛。", "洧淵俯龍室，廢臺干白雲。", "委徑已就荒，九仞將遂湮。", "飄然如四鶴，躡屐披荆榛。", "北岡翻波濤，南岫列嶙峋。", "登臺與佳名，大筆書蒼珉。", "占此泉石清，坐使草木春。", "諸公廊廟材，我期茲隠淪。"]'),
('26f6c94f-a665-44c9-ac2f-96d1384c20c1','關侯廟','李廌','宋','宋诗','song-poetry','','[]','三方各虎踞，猛將皆成羣。',72,'全唐诗/poet.song.67000.json','["三方各虎踞，猛將皆成羣。", "屹然萬人敵，惟髯稱絕倫。", "仗節氣蓋世，橫矟勇冠軍。", "艱難戎馬間，感慨竹帛勛。", "鳳闕控蠻楚，廟食漢江濆。", "神遊舊戰地，庭樹起黄雲。"]'),
('af1befd3-f6b7-4263-9381-9098f6c44130','白馬寺詩','李廌','宋','宋诗','song-poetry','','[]','湠漫漢江皋，迤邐楚山岫。',84,'全唐诗/poet.song.67000.json','["湠漫漢江皋，迤邐楚山岫。", "衡門掩半麓，飛甍聳層搆。", "高林敞華榱，雙泉逗瑶甃。", "龜魚水中坻，牛馬飲殘溜。", "我卜關外居，此計春可就。", "參差菱荇香，猗儺參朮秀。", "行吟池上篇，來倒壺中酎。"]'),
('0efc8346-2d9e-4733-8006-249315b247e4','墨池','李廌','宋','宋诗','song-poetry','','[]','臨池苦學書，池水爲變色。',60,'全唐诗/poet.song.67000.json','["臨池苦學書，池水爲變色。", "終朝坐忘疲，揜卷每自得。", "滋靈蚌孕貴，飫餌魚腹溢。", "回堂映茂草，玄源潄白石。", "祗恐驪龍飛，蜿蜒上丹極。"]'),
('afe95725-4890-4819-8c50-d814fa6660bc','伍子胥廟','李廌','宋','宋诗','song-poetry','','[]','烈士可廟食，么麽可悲夫。',72,'全唐诗/poet.song.67000.json','["烈士可廟食，么麽可悲夫。", "誓心報荆郢，忍恥適江吳。", "功成期牖下，旋聞賜屬鏤。", "楚邦乃怨耦，宿憤嚮已攄。", "濤江厭波神，魂魄遊故都。", "存亡兩陳迹，無用愧包胥。"]'),
('660a00c4-54cf-4668-be63-b54c38d8845a','題廟','李廌','宋','宋诗','song-poetry','','[]','築巖傅胥靡，耕野莘老農。',96,'全唐诗/poet.song.67000.json','["築巖傅胥靡，耕野莘老農。", "倏來坐廟堂，談笑樹奇功。", "卯金運徂謝，孔明隠隆中。", "誰言一丘壑，卧此夭嬌龍。", "古來王佐才，中間千載空。", "之人輔玄德，真有宰相風。", "惜哉小用之，功烈不復東。", "嚮非三顧重，白首田舍翁。"]'),
('fa80a0be-da91-48c8-bb3c-234ca91aa6f1','華嚴庵','李廌','宋','宋诗','song-poetry','','[]','人生奧區中，猶如繭中蠶。',132,'全唐诗/poet.song.67000.json','["人生奧區中，猶如繭中蠶。", "欲窮無然心，足力有不堪。", "終南有五虎，銜牙坐耽耽。", "乃有忘軀人，臨穴已擬探。", "干將古寶劍，吹毛可揮䤴。", "亦有躁戾者，執刃求其鐔。", "所得計所傷，膽潰心憂惔。", "况夫愛見魔，悅如芻豢甘。", "大士獨了然，白月沉珠潭。", "獨造無僮僕，妙理去二三。", "至哉天下樂，端默坐草庵。"]'),
('23921828-1681-4ae7-b361-ea0315fa515a','岑使君牧襄陽受代還朝某同趙德麟謝公定潘仲寶皆餞於八疊驛酒中以西王母所謂山川悠遠白雲自出相期不老尚能復來各人分四字爲韵以送之某分得相期不老  其一','李廌','宋','宋诗','song-poetry','','[]','使臣撫南夏，萬夫久以望。',48,'全唐诗/poet.song.67000.json','["使臣撫南夏，萬夫久以望。", "道粹韵宇勝，德滿聲譽香。", "炳然龍虎文，瑑此金玉相。", "笑談府中居，無爲民自康。"]'),
('97c18780-e26c-4556-848d-c57d5a4afd65','岑使君牧襄陽受代還朝某同趙德麟謝公定潘仲寶皆餞於八疊驛酒中以西王母所謂山川悠遠白雲自出相期不老尚能復來各人分四字爲韵以送之某分得相期不老  其二','李廌','宋','宋诗','song-poetry','','[]','我生世寡與，所幸賢者知。',48,'全唐诗/poet.song.67000.json','["我生世寡與，所幸賢者知。", "徽中山川意，賞音有鍾期。", "荆楚非我里，從公甘棲遲。", "今茲復舍去，何以紓吾悲。"]'),
('5d8cfdb6-04c2-4974-a9b5-5b7ae85c01d4','岑使君牧襄陽受代還朝某同趙德麟謝公定潘仲寶皆餞於八疊驛酒中以西王母所謂山川悠遠白雲自出相期不老尚能復來各人分四字爲韵以送之某分得相期不老  其三','李廌','宋','宋诗','song-poetry','','[]','閭閻無居人，傾城餞賢守。',48,'全唐诗/poet.song.67000.json','["閭閻無居人，傾城餞賢守。", "擁車不得前，遮拜奉巵酒。", "民言荷恩勤，拊育踰父母。", "公不鄙我邦，端能再來不。"]'),
('f4a8b1a5-5378-4fb4-bce3-0e943d723d9c','岑使君牧襄陽受代還朝某同趙德麟謝公定潘仲寶皆餞於八疊驛酒中以西王母所謂山川悠遠白雲自出相期不老尚能復來各人分四字爲韵以送之某分得相期不老  其四','李廌','宋','宋诗','song-poetry','','[]','公如照乘珠，居朝作賢寶。',48,'全唐诗/poet.song.67000.json','["公如照乘珠，居朝作賢寶。", "公如三秀芝，後天錫難老。", "聿歸供奉班，漆簡探幽討。", "懸應念傖父，滄洲濯蘋藻。"]'),
('ab18934f-e3e4-4db6-a195-655a0775da6b','劉表廟','李廌','宋','宋诗','song-poetry','','[]','入自東郭門，言拜景升墓。',72,'全唐诗/poet.song.67000.json','["入自東郭門，言拜景升墓。", "墓樹半枯槎，冥冥立晨霧。", "鼎國昔未分，蕭牆梗天步。", "呼蒼復何用，龍卧獨不顧。", "紆餘檀溪水，黯慘蔡州路。", "登樓欲遣憂，君看仲宣賦。"]'),
('f4b8eb0a-81fc-4b34-b020-95a5f8e27422','故諫議大夫鮮于公欲作新堂以傳世譜名曰卓絕內相先生題其名曰蜀鮮于氏卓絕之堂某以此八字爲韵作八詩蓋鮮于公頃嘗俾某賦之而三子以求其詩故原其古而美其今以頌美之  其一','李廌','宋','宋诗','song-poetry','','[]','商朝有仁人，爲奴恥榮祿。',48,'全唐诗/poet.song.67000.json','["商朝有仁人，爲奴恥榮祿。", "九疇傳帝秘，八教清濊俗。", "苗裔散諸華，慶澤鍾左蜀。", "崢嶸多望人，冠冕稱盛族。"]'),
('6b6b9103-4a26-4df2-8fc7-9ffa0d8b32a7','故諫議大夫鮮于公欲作新堂以傳世譜名曰卓絕內相先生題其名曰蜀鮮于氏卓絕之堂某以此八字爲韵作八詩蓋鮮于公頃嘗俾某賦之而三子以求其詩故原其古而美其今以頌美之  其二','李廌','宋','宋诗','song-poetry','','[]','左蜀富山水，錦屏秀而鮮。',48,'全唐诗/poet.song.67000.json','["左蜀富山水，錦屏秀而鮮。", "卿雲常氤氳，佳氣所盤旋。", "藴此天地靈，並生文武賢。", "稱忠著甲令，節制控兩川。"]'),
('290a87ba-469f-4f8d-bcc7-5d808ebb6d9d','故諫議大夫鮮于公欲作新堂以傳世譜名曰卓絕內相先生題其名曰蜀鮮于氏卓絕之堂某以此八字爲韵作八詩蓋鮮于公頃嘗俾某賦之而三子以求其詩故原其古而美其今以頌美之  其三','李廌','宋','宋诗','song-poetry','','[]','天地西設險，劍外分野殊。',48,'全唐诗/poet.song.67000.json','["天地西設險，劍外分野殊。", "君家萬里侯，支郡許專誅。", "威名讋華夷，玉帛走易于。", "韡韡常棣華，煌煌駟馬車。"]'),
('7a9df63c-e53c-473d-9f57-52e6c699879b','故諫議大夫鮮于公欲作新堂以傳世譜名曰卓絕內相先生題其名曰蜀鮮于氏卓絕之堂某以此八字爲韵作八詩蓋鮮于公頃嘗俾某賦之而三子以求其詩故原其古而美其今以頌美之  其四','李廌','宋','宋诗','song-poetry','','[]','功高翊戴重，錫土仍命氏。',48,'全唐诗/poet.song.67000.json','["功高翊戴重，錫土仍命氏。", "蟬冕舊傳家，龍衮式增賁。", "誰云五世澤，久襲萬鍾貴。", "非惟頼先慶，奕葉藝忠義。"]'),
('abe09f9e-6c56-40eb-b512-1f86a2a99748','故諫議大夫鮮于公欲作新堂以傳世譜名曰卓絕內相先生題其名曰蜀鮮于氏卓絕之堂某以此八字爲韵作八詩蓋鮮于公頃嘗俾某賦之而三子以求其詩故原其古而美其今以頌美之  其五','李廌','宋','宋诗','song-poetry','','[]','隠居嗣徽猷，超世得古學。',48,'全唐诗/poet.song.67000.json','["隠居嗣徽猷，超世得古學。", "行藏合用舍，聞見守約卓。", "清風激頹波，精義興後覺。", "天子不得臣，鴻飛夐何邈。"]'),
('7023f9e8-8eae-4963-970a-b9b0430bd4bf','故諫議大夫鮮于公欲作新堂以傳世譜名曰卓絕內相先生題其名曰蜀鮮于氏卓絕之堂某以此八字爲韵作八詩蓋鮮于公頃嘗俾某賦之而三子以求其詩故原其古而美其今以頌美之  其六','李廌','宋','宋诗','song-poetry','','[]','先生王佐材，蚤歲常數奇。',48,'全唐诗/poet.song.67000.json','["先生王佐材，蚤歲常數奇。", "平生經綸志，白首初逢時。", "經營此堂久，乞身竚歸期。", "堂成不及登，魂氣今何之。"]'),
('a94c0536-0c83-4d46-84d6-cda362c32ae6','故諫議大夫鮮于公欲作新堂以傳世譜名曰卓絕內相先生題其名曰蜀鮮于氏卓絕之堂某以此八字爲韵作八詩蓋鮮于公頃嘗俾某賦之而三子以求其詩故原其古而美其今以頌美之  其七','李廌','宋','宋诗','song-poetry','','[]','諸孤皆妙稟，况乃承義方。',48,'全唐诗/poet.song.67000.json','["諸孤皆妙稟，况乃承義方。", "世濟商人美，各是萬夫望。", "拳拳奉先志，誅茆建崇堂。", "豈徒輪奐美，卓絕當未央。"]'),
('9e7d6566-1c91-4776-a8ea-032c1da9db09','故諫議大夫鮮于公欲作新堂以傳世譜名曰卓絕內相先生題其名曰蜀鮮于氏卓絕之堂某以此八字爲韵作八詩蓋鮮于公頃嘗俾某賦之而三子以求其詩故原其古而美其今以頌美之  其八','李廌','宋','宋诗','song-poetry','','[]','吾觀孔父鼎，知有名世哲。',48,'全唐诗/poet.song.67000.json','["吾觀孔父鼎，知有名世哲。", "英英大諫公，克世嗣前烈。", "翱翔金鑾坡，白首貫忠節。", "後昆有斯人，譜系愈卓絕。"]'),
('3b72cb74-341e-4330-ac2a-59209d33d56b','趙玿赴成都府廣都縣尉以送君南浦傷如之何爲韵送之作八首  其一','李廌','宋','宋诗','song-poetry','','[]','吾生常羈旅，送客情更重。',48,'全唐诗/poet.song.67000.json','["吾生常羈旅，送客情更重。", "嗟哉平生交，今復萬里送。", "愁端寓心目，往感接魂夢。", "窮途獨栖遲，直道竟何用。"]'),
('ea6f05a3-4cee-4554-8558-7a7c8479c83b','趙玿赴成都府廣都縣尉以送君南浦傷如之何爲韵送之作八首  其二','李廌','宋','宋诗','song-poetry','','[]','山河接巴徼，關塞斷秦雲。',48,'全唐诗/poet.song.67000.json','["山河接巴徼，關塞斷秦雲。", "誰爲萬里侯，節制錦江濆。", "彊項毋狥指，曲鈎難致君。", "勿因朝廷遠，俯首俗吏羣。"]'),
('01e9faf0-da4f-41aa-ba83-56422742b2a5','趙玿赴成都府廣都縣尉以送君南浦傷如之何爲韵送之作八首  其三','李廌','宋','宋诗','song-poetry','','[]','昔余旅長洲，寄傲碧江潭。',48,'全唐诗/poet.song.67000.json','["昔余旅長洲，寄傲碧江潭。", "十年客風埃，留滯困周南。", "冉冉老將至，兀兀漫窮探。", "故人各變化，漂零空自慚。"]'),
('a5745275-1971-413c-bc60-94e8aea9daa0','趙玿赴成都府廣都縣尉以送君南浦傷如之何爲韵送之作八首  其四','李廌','宋','宋诗','song-poetry','','[]','之子才如冰，不應常負弩。',48,'全唐诗/poet.song.67000.json','["之子才如冰，不應常負弩。", "勿爲爲貧謀，一意在阿堵。", "廣都綺縠地，當念珠還浦。", "惟廉可立身，勿使嗟供虜。"]'),
('8241856f-5d9b-45f9-97d9-45b7108e7f2a','趙玿赴成都府廣都縣尉以送君南浦傷如之何爲韵送之作八首  其五','李廌','宋','宋诗','song-poetry','','[]','翔風走塵沙，草樹正玄黄。',48,'全唐诗/poet.song.67000.json','["翔風走塵沙，草樹正玄黄。", "烟昏路漫漫，日冷雲蒼蒼。", "杜公作詩處，武侯近戰場。", "陳迹勿驚心，俯仰已堪傷。"]'),
('d57427c1-2bf2-4bb2-a297-7b6420f6dca1','趙玿赴成都府廣都縣尉以送君南浦傷如之何爲韵送之作八首  其六','李廌','宋','宋诗','song-poetry','','[]','蜀都藴奇氣，古今生英儒。',48,'全唐诗/poet.song.67000.json','["蜀都藴奇氣，古今生英儒。", "歌童選何武，狗監獻相如。", "煌煌直金馬，藹藹侍玉除。", "歸入芸香閣，無廢五車書。"]'),
('65d74cce-9c74-4221-9263-70bda38feed5','趙玿赴成都府廣都縣尉以送君南浦傷如之何爲韵送之作八首  其七','李廌','宋','宋诗','song-poetry','','[]','傾城愛勁竹，古士惟徽之。',48,'全唐诗/poet.song.67000.json','["傾城愛勁竹，古士惟徽之。", "而我獨愛君，不見即相思。", "今矧萬里游，動爲三歲期。", "索居念金蘭，惘然傷別離。"]'),
('36621af4-35e4-4b8b-9af7-f18c7894aa42','趙玿赴成都府廣都縣尉以送君南浦傷如之何爲韵送之作八首  其八','李廌','宋','宋诗','song-poetry','','[]','蜀山如鳥道，劍閣鬰嵯峨。',48,'全唐诗/poet.song.67000.json','["蜀山如鳥道，劍閣鬰嵯峨。", "嗟君正朱顔，奈此艱險何。", "秋雨峨眉道，春風濯錦波。", "青山一羸馬，古今應更多。"]'),
('809568b6-8ae7-4682-8c17-f029f242ffd2','秋日雜興  其一','李廌','宋','宋诗','song-poetry','','[]','悠悠東郭道，莽莽四海志。',48,'全唐诗/poet.song.67000.json','["悠悠東郭道，莽莽四海志。", "晨光晞高林，泫露泣征轡。", "巨防揚淥漪，哀泉赴橫衛。", "我生窘羈束，感歎撫消髀。"]'),
('a718ecb9-1c49-4712-be80-141cbcc57f87','秋日雜興  其二','李廌','宋','宋诗','song-poetry','','[]','青青陌上草，秋徂故應省。',48,'全唐诗/poet.song.67000.json','["青青陌上草，秋徂故應省。", "疾風試飄葉，寒露猶湛潁。", "冰霜來無時，爾命詎堅永。", "滋蕃奈爾何，咄咄臨此景。"]'),
('7ce2ed0c-6fb0-4e5d-ba8b-de982559abd7','秋日雜興  其三','李廌','宋','宋诗','song-poetry','','[]','昔喜馬少游，我馬仍款段。',48,'全唐诗/poet.song.67000.json','["昔喜馬少游，我馬仍款段。", "古云末路難，百里九十半。", "與爾皆調饑，欲速輒愈緩。", "長鳴徒勞爾，終愧籋雲汗。"]'),
('e476127d-f359-47c5-8158-0958f695a7ec','秋日雜興  其四','李廌','宋','宋诗','song-poetry','','[]','黍稷競登場，荏菽復滿疇。',48,'全唐诗/poet.song.67000.json','["黍稷競登場，荏菽復滿疇。", "我羹雖不糝，逢年亦解憂。", "太平豈無象，樂歲觀有秋。", "敢期飽糠覈，役車何當休。"]'),
('c5abcdc1-1fe6-45e7-95c3-de035593e2de','秋日雜興  其五','李廌','宋','宋诗','song-poetry','','[]','秬黍亙廣隰，整整萬戈矛。',48,'全唐诗/poet.song.67000.json','["秬黍亙廣隰，整整萬戈矛。", "旌旄亂風葉，森森疑戰秋。", "如聞高奴塞，將軍用世侯。", "勝筭應在目，願解西顧憂。"]'),
('d6d89127-b5a6-499b-ba74-5f2671af9294','秋日雜興  其六','李廌','宋','宋诗','song-poetry','','[]','芡珠乃籩實，鷄首真溪毛。',48,'全唐诗/poet.song.67000.json','["芡珠乃籩實，鷄首真溪毛。", "芥羽復丹幘，凌波競將號。", "蒼啄勝玄蠔，百琲轉含桃。", "驪頷有照乘，海夫得應勞。"]'),
('7770c02a-f4be-49ee-9a8f-e369d9c30e9b','秋日雜興  其七','李廌','宋','宋诗','song-poetry','','[]','摇摇平岡雪，芬薌蕎花白。',48,'全唐诗/poet.song.67000.json','["摇摇平岡雪，芬薌蕎花白。", "繁英未脫鄂，銳實已潜黑。", "速哉不踰時，幾何天地力。", "寒耕暑方耘，古人勤宿麥。"]'),
('94d269df-5598-4839-a74f-8298b7d33aaa','秋日雜興  其八','李廌','宋','宋诗','song-poetry','','[]','橫烟下平林，閑雲依袤嶺。',48,'全唐诗/poet.song.67000.json','["橫烟下平林，閑雲依袤嶺。", "寓想高鴻背，游目凌倒景。", "吁嗟老于行，末路未遑騁。", "晚歲竟如何，三歎心耿耿。"]'),
('455e9aa8-f4a5-4f8f-90d1-1987cdf6f9c2','汝華巖','李廌','宋','宋诗','song-poetry','','[]','道人居此巖，誦經歲云久。',36,'全唐诗/poet.song.67000.json','["道人居此巖，誦經歲云久。", "鬼神夜護持，空巖擊刁斗。", "吁嗟已成塵，藤蘿穿石牖。"]'),
('5b92fff1-86bd-4c4f-9105-b4fa9fd8a74d','與鄒浩志完會於王希聖家因話毗陵事是夕輒夢還松陵因述夢呈志完','李廌','宋','宋诗','song-poetry','','[]','客夢還松陵，寒江渺烟雨。',96,'全唐诗/poet.song.67000.json','["客夢還松陵，寒江渺烟雨。", "異時醉吟地，依然記洲渚。", "三高平生歡，彷彿遞賓主。", "十年扁舟興，一夕暫容與。", "此樂曾未央，覆瓿俄驚鼠。", "隙月鑑我帷，破窗風自語。", "展轉誰晤言，僮隸聊爾汝。", "吾生獨何事，寤寐仍羈旅。"]'),
('2d7c3f7b-0a0c-463e-991f-35c3b19a1a30','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其一','李廌','宋','宋诗','song-poetry','','[]','至人本無我，與世初無方。',48,'全唐诗/poet.song.67000.json','["至人本無我，與世初無方。", "彊從金鑾游，聊用示行藏。", "忠清秉全德，日月可爭光。", "振衣千載上，臨世濯滄浪。"]'),
('a43b836d-6ee9-452f-9936-1edb457dfe1b','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其二','李廌','宋','宋诗','song-poetry','','[]','至人孰可測，跨世富英量。',48,'全唐诗/poet.song.67000.json','["至人孰可測，跨世富英量。", "千齡遘治運，萬古真遐想。", "三台接布武，萬乘拱函丈。", "辭榮明光殿，乞身青天上。"]'),
('1c3dc184-b03a-4daa-bf88-ce7971fadd50','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其三','李廌','宋','宋诗','song-poetry','','[]','世人期公淺，云是真謫仙。',48,'全唐诗/poet.song.67000.json','["世人期公淺，云是真謫仙。", "願公老台鼎，白首冠貂蟬。", "爲之乃固有，弗爲愈知賢。", "清風不可挹，高高薄雲天。"]'),
('536f9256-99f6-4ca1-8c4d-2ce6fdf23b8f','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其四','李廌','宋','宋诗','song-poetry','','[]','紛紛競干祿，汩汩第謀身。',48,'全唐诗/poet.song.67000.json','["紛紛競干祿，汩汩第謀身。", "先生獨任重，憂道仍憂民。", "精誠貫白日，孤忠橫北辰。", "求之千載上，古亦鮮若人。"]'),
('66d4b19d-8c94-4481-98ac-66257d1d69fe','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其五','李廌','宋','宋诗','song-poetry','','[]','平生史鰌直，往歲展禽黜。',48,'全唐诗/poet.song.67000.json','["平生史鰌直，往歲展禽黜。", "青衫竄長沙，華鬢謁宣室。", "重光照八極，命世真賢出。", "奈何江湖去，獨爲蒼生卹。"]'),
('148934bd-9129-4901-bc9f-9db03f73bb8e','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其六','李廌','宋','宋诗','song-poetry','','[]','道德富瀛海，百谷輸浩渺。',48,'全唐诗/poet.song.67000.json','["道德富瀛海，百谷輸浩渺。", "雲夢吞什伯，坐映黄陂小。", "斯文再炳蔚，精義凌縹緲。", "典謨追灝噩，協氣充四表。"]'),
('a91a5842-09c0-4794-8b2d-04ce15eac4a7','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其七','李廌','宋','宋诗','song-poetry','','[]','周公非汲汲，仲尼豈皇皇。',48,'全唐诗/poet.song.67000.json','["周公非汲汲，仲尼豈皇皇。", "吾道無若人，孰能相維綱。", "古今異倫軌，英風自相望。", "下民今喁喁，造物太茫茫。"]'),
('e97af0b6-5e93-401d-8c7f-b467c2b2e880','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其八','李廌','宋','宋诗','song-poetry','','[]','造物雖茫茫，至人自囂囂。',48,'全唐诗/poet.song.67000.json','["造物雖茫茫，至人自囂囂。", "雖稽具瞻意，欲全千仞高。", "富貴一敝屣，功名兩鴻毛。", "獨知退爲樂，可憐夸者勞。"]'),
('e7620a7a-9eb2-4354-b92c-a1fa4860ea05','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其九','李廌','宋','宋诗','song-poetry','','[]','公去吾道辱，公來吾道榮。',48,'全唐诗/poet.song.67000.json','["公去吾道辱，公來吾道榮。", "生民繫休戚，國勢隨重輕。", "先生如九鼎，坐折姦宄萌。", "天如欲平治，用舍若爲情。"]'),
('786dde6f-180e-4266-9760-77269a89e656','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其一○','李廌','宋','宋诗','song-poetry','','[]','先生如蓍龜，萬事可告猶。',48,'全唐诗/poet.song.67000.json','["先生如蓍龜，萬事可告猶。", "勳業輕黄屋，得賢方解憂。", "念昔彙征日，民瘼庶有瘳。", "莫賦歸去來，衮衣或能留。"]'),
('96571d4f-14e5-4a2c-8c55-2ddc7fa988ea','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其一一','李廌','宋','宋诗','song-poetry','','[]','吳越控島夷，東南一都會。',48,'全唐诗/poet.song.67000.json','["吳越控島夷，東南一都會。", "淫風舊倡靡，懦俗無慷慨。", "除弊在躬行，報政可立待。", "類非俗吏能，千齡樹遺愛。"]'),
('aeb89e90-f1a2-4868-bc9a-2f2567b38032','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其一二','李廌','宋','宋诗','song-poetry','','[]','邇臣均勞逸，方面乃毗倚。',48,'全唐诗/poet.song.67000.json','["邇臣均勞逸，方面乃毗倚。", "細人怙權寵，補外習爲恥。", "餘杭股肱郡，湖山真信美。", "意雅如望之，肯效倪若水。"]'),
('1cf3e3ac-56f2-4568-8325-448de2e616eb','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其一三','李廌','宋','宋诗','song-poetry','','[]','小人雖嗜學，歲月空屢勤。',48,'全唐诗/poet.song.67000.json','["小人雖嗜學，歲月空屢勤。", "同門盡鴛鸞，登瀛校書芸。", "嗟余老西河，索居久離羣。", "從龍從上下，愧彼油油雲。"]'),
('a43530f4-5808-4ec8-b622-140b618c37f5','送杭州使君蘇內相先生某用先生舊詩方丈仙人出渺茫高情猶愛水雲鄉爲韵作古詩十四首  其一四','李廌','宋','宋诗','song-poetry','','[]','四海李元禮，龍門多俊良。',48,'全唐诗/poet.song.67000.json','["四海李元禮，龍門多俊良。", "英英郭有道，一揖遂生光。", "畫鷁凌雲波，仙舟水雲鄉。", "此心徒皦皦，千里共蒼蒼。"]'),
('c332b5b6-d35e-4a27-8d18-379a68c856e0','雨中宿超化寺','李廌','宋','宋诗','song-poetry','','[]','暴雨如建瓴，龍淵俄怒流。',48,'全唐诗/poet.song.67000.json','["暴雨如建瓴，龍淵俄怒流。", "逸哉我三士，冒雨探奇幽。", "古寺浮積壤，危若萍與漚。", "抱憂窮樂事，斗酒聊重留。"]'),
('298a1e88-ecc0-4d6d-a1b4-93de3495cd54','遊超化寺','李廌','宋','宋诗','song-poetry','','[]','常笑博望侯，老死窮河源。',216,'全唐诗/poet.song.67000.json','["常笑博望侯，老死窮河源。", "河源幾萬里，天派垂崑崙。", "支流播九逆，砥柱疏三門。", "行穿九地折，怒溢千里奔。", "樂彼洧水源，近且具茨根。", "寒泉發清池，藻鑑撓不渾。", "引爲琉璃陂，碧波媚蘋蘩。", "逶迤入王城，順下德可溫。", "全此上善性，利用豈無恩。", "下有萬艘濟，旁列千夫屯。", "持此安且靜，用鑑暴與昏。", "頃年時聞龍，淵室今應存。", "秉簡俗何陋，濟輿惠亦煩。", "誰知千載後，佛宮枕溪濆。", "喬木上參天，綠竹盈短垣。", "曾此埒金谷，神龍依祇園。", "物理自古今，興廢復何言。", "聊思鄭國僑，殊勝漢張騫。"]'),
('dc11803d-01a6-4466-8a37-fb69c25f7bf7','木文真人章聖朝合州進到其事甚怪至京其木中人呼萬歲者三詔賜崇福宮','李廌','宋','宋诗','song-poetry','','[]','犀視月通角，蟬想丸目入。',132,'全唐诗/poet.song.67000.json','["犀視月通角，蟬想丸目入。", "果臝祝螟蛉，天風化陰鶂。", "物變知品殊，尚可易形質。", "真人友造化，故與物爲一。", "持此誠與神，可貫金與石。", "何爲輒入木，厭世未肯出。", "衣冠儼如生，隠若陸顧筆。", "非同木居士，聾俗競禳祓。", "又非羅公遠，戲隠逞幻術。", "疑是青羊老，合江聊示迹。", "薄游附驛車，靈宮居二室。"]'),
('d8484cd3-aed4-4a7b-af50-18d6eaf2071c','西丘','李廌','宋','宋诗','song-poetry','','[]','西丘對秋風，蕭颯如原隰。',48,'全唐诗/poet.song.67000.json','["西丘對秋風，蕭颯如原隰。", "木落景扶疏，碧環天壁立。", "餘霞拂暮散，夕鳥寒更急。", "獨有松上鶴，不爲鸚鵡粒。"]'),
('5e242cb2-9234-4d92-b1b7-60b3dbdb2301','廌葺介堂元聿作詩某次韵','李廌','宋','宋诗','song-poetry','','[]','吾生一漂梗，觸焉泊東周。',132,'全唐诗/poet.song.67000.json','["吾生一漂梗，觸焉泊東周。", "十年歎流滯，吞默垂遠猷。", "胸中猶汪陂，萬頃蟠一甌。", "輿羽欺鎰金，寸木傲岑樓。", "圖南平生志，腐鼠詎能留。", "寸心徒自憞，雙鬢颯先秋。", "物理有否泰，奚爲久休囚。", "尚愛東方朔，處汙能若浮。", "悲鳴非不切，歲月老驊騮。", "莫笑掃一室，吾心若虛舟。", "會當掃天下，歸老卧滄洲。"]'),
('0d62b7fb-b060-4979-8058-7719219d2454','百葉梅','李廌','宋','宋诗','song-poetry','','[]','寒香本已清，真色初既好。',48,'全唐诗/poet.song.67000.json','["寒香本已清，真色初既好。", "誰私化工力，增綴愈妍巧。", "繁葩貯春意，幽姿照青昊。", "獨無和羹實，終應愧其表。"]'),
('0fce3241-4219-49e3-a8aa-e2939d288f09','夫人城','李廌','宋','宋诗','song-poetry','','[]','庸將昧奇正，乘鄣罕書勛。',84,'全唐诗/poet.song.67000.json','["庸將昧奇正，乘鄣罕書勛。", "我登夫人城，想見畚鍤勤。", "攻瑕既遇堅，坐制烏合羣。", "異時古烈婦，鮮以智勇聞。", "褒稱勵愚懦，敢諷賢令君。", "作傳續烈女，遠紹子政文。", "壁間畫葆羽，俾如娘子軍。"]'),
('3229e544-95d0-4800-b744-ad44a161c4b3','次和答張誾寄靈壽杖','李廌','宋','宋诗','song-poetry','','[]','我生職貧病，壯齡俄早衰。',48,'全唐诗/poet.song.67000.json','["我生職貧病，壯齡俄早衰。", "朱顔不少貸，白髮太先期。", "故人獨閔余，遠寄靈壽枝。", "老景知有頼，醒醉爲扶持。"]'),
('ee07a4e7-c416-4dd6-8c37-6863563b43a2','憶吾廬','李廌','宋','宋诗','song-poetry','','[]','繆挾經世策，蚤衰甘湮淪。',144,'全唐诗/poet.song.67000.json','["繆挾經世策，蚤衰甘湮淪。", "吾廬有佳趣，一廛良可親。", "茂林修竹地，青山白雲人。", "塵埃付捷徑，風波委要津。", "吾心如皦日，外物任浮雲。", "久厭牛馬走，欲令鷗鷺馴。", "歲月既荏苒，功名定因循。", "執鞭吾弗能，得乘豈所欣。", "畎畝樂可必，糟糠奚用勤。", "泥龜喜曳尾，生芻恥屢陳。", "束濕雖有術，末路復誰因。", "願爲海底泥，肯羨山上塵。"]'),
('ebb0c0c2-8b02-43fb-a86b-6b657813c9f0','谷隠飲中以采菱渡頭風起策杖村西日斜爲韵探得采頭二字  其一','李廌','宋','宋诗','song-poetry','','[]','東西南北人，志向各有在。',96,'全唐诗/poet.song.67000.json','["東西南北人，志向各有在。", "一言契所適，糾纏胡可解。", "英英坐上客，聲聞著寰海。", "婆娑諸侯邦，未去亮天縡。", "顧余寸有長，葑菲誤見采。", "山空佛宮冷，秉燭集飛蓋。", "笑歌觸松風，出谷作天籟。", "後夜風雨時，惟應鬼神會。"]'),
('e1a31fa6-bfcb-4ff2-867a-ced9303c013a','谷隠飲中以采菱渡頭風起策杖村西日斜爲韵探得采頭二字  其二','李廌','宋','宋诗','song-poetry','','[]','山川納商氣，凜凜天地秋。',96,'全唐诗/poet.song.67000.json','["山川納商氣，凜凜天地秋。", "草木將玄黄，詎肯烏我頭。", "蚤歲謬懷璧，轗𨎹轍欲周。", "富貴來無期，舍鞅息林丘。", "復棄農圃業，爲茲山水游。", "來尋彌天釋，軟語忘百憂。", "夜傾雙玉壺，禪詼互相酬。", "試澆磈磊胸，洗我千斛愁。"]'),
('e02ec57f-1b25-4869-9da3-e189fd26e907','會居易齋分韵','李廌','宋','宋诗','song-poetry','','[]','君子何樂胥，清夜以文會。',48,'全唐诗/poet.song.67000.json','["君子何樂胥，清夜以文會。", "篇章各紛拏，錦組貫珠貝。", "高譚生清風，石齒潄湍瀨。", "安得樓蘭肉，充庖餘炙膾。"]'),
('641ac1a8-031b-4396-a664-c0849160403a','啟母廟','李廌','宋','宋诗','song-poetry','','[]','帝武啟宗周，玄鳥濬哲商。',132,'全唐诗/poet.song.67000.json','["帝武啟宗周，玄鳥濬哲商。", "塗山配神禹，獨不嗣娥姜。", "異時天與賢，嗣子繄匪良。", "欲肇天與子，是用開厥祥。", "鈞臺享羣后，有扈誅叛方。", "誰令謳與訟，帝畀有夏昌。", "推此方朱均，巍巍真令王。", "伯陽指株李，阿衡降空桑。", "龍踞生漢祖，龍漦誕褒娼。", "石裂何足問，世語多荒唐。", "若比望夫山，雖怪猶有光。"]'),
('5b131e98-515a-4f7a-a1aa-7dee0fd7e27e','筆溪','李廌','宋','宋诗','song-poetry','','[]','張生古狂夫，草聖稱豪邁。',72,'全唐诗/poet.song.67000.json','["張生古狂夫，草聖稱豪邁。", "縱橫意有得，野馬御風快。", "醉醒忽驚神，自以不可再。", "乃知高世能，至理適有在。", "况夫窮年華，朝夕精揀汰。", "期茲筆溪水，色變崑崙派。"]'),
('36d16e21-2952-495c-a3ae-061af5289aa9','施柏花','李廌','宋','宋诗','song-poetry','','[]','佳花香藹藹，老栢意蕭蕭。',48,'全唐诗/poet.song.67000.json','["佳花香藹藹，老栢意蕭蕭。", "如何蒼翠質，許附繁柔條。", "仙人踏錦障，襯步武夷橋。", "願託歲寒心，凌虛上烟霄。"]'),
('058886c0-f8fc-4d77-a0ee-cd4ff8686328','偃柏','李廌','宋','宋诗','song-poetry','','[]','名園氣虛闊，怪栢獨凝偃。',84,'全唐诗/poet.song.67000.json','["名園氣虛闊，怪栢獨凝偃。", "高枝翳浮雲，翻然志飄遠。", "赤松來何遲，黄鶴去未返。", "蘇武遊虜庭，矜傲何蹇蹇。", "朔風吹寒枝，日暮羊在坂。", "乃疑高堅材，獨得造化本。", "蕭蕭古池上，不與凡木混。"]'),
('3f8a34bc-eeb6-43db-a0b0-614a70d245ea','霹靂琴','李廌','宋','宋诗','song-poetry','','[]','老桐初無異，憔悴輩散木。',144,'全唐诗/poet.song.67000.json','["老桐初無異，憔悴輩散木。", "良材固自信，終歲委空谷。", "孤根聽霜霰，厥命寄樵牧。", "雖云具宮徵，誰意望琴筑。", "天公憐冤憤，霹靂驅怪伏。", "蛟龍出蒼幹，電火燃裂腹。", "造物一愍弔，爲惠在反覆。", "神馳變廢物，瞻賞改舊目。", "裂爲君子琴，日奏太古曲。", "因知物興廢，尚爾轉禍福。", "志士抱孤操，來者怳未卜。", "壯年昧籌算，奚用定榮辱。"]'),
('1aa86350-0044-4cd2-85ef-c957f3f40837','同德麟諸公觀秋風閣自賦詩臺乘月汎江','李廌','宋','宋诗','song-poetry','','[]','虛閣凌縹緲，危臺俯湠漫。',228,'全唐诗/poet.song.67000.json','["虛閣凌縹緲，危臺俯湠漫。", "憑檻眺落景，倚柱送歸翰。", "空濛暝色合，戃怳天宇寬。", "皎皎明月上，炯炯青林端。", "寂歷四郊靜，陰森清夜闌。", "秉燭下草岸，迴船遵柳灘。", "繁星粲湛彩，白烟隠微瀾。", "夷猶放𤃩溜，闇澹數烟巒。", "絺衣凉風發，角巾滋露漙。", "心適醒亦狂，樂極清更歡。", "叩舷過龍室，抵掌驚水官。", "仍思爇犀炬，下欲窺蛟盤。", "風雲襲毛髮，冰雪澡肺肝。", "慨歎念前哲，興懷成壯觀。", "蹇予棄甽畝，放意遠遊般。", "合鞅昔徂歲，維舟今戒寒。", "佩服良友義，論言畏塗難。", "茲遊興不淺，冒險夜未安。", "風波彼何懼，忠信邪能奸。"]'),
('b7bd4d9e-9df0-46ce-9afe-8ca619357424','又九月十四日登秋風閣以餘霞散成綺澄江靜如練爲韵分得餘靜二字  其一','李廌','宋','宋诗','song-poetry','','[]','繆蹈江海迹，吾生靡懷居。',120,'全唐诗/poet.song.67000.json','["繆蹈江海迹，吾生靡懷居。", "役車窘陰雨，蒸腐敗衣袽。", "晨昏霤聲中，我懷何時舒。", "秋陽出頑雲，杲杲照我裾。", "言登秋風閣，乘興安可徐。", "猗紆下銅鞮，縹緲凌紫虛。", "錦葉眩林表，金包垂霜餘。", "棲苴寄榛莽，潦痕在菰蒲。", "我遊獲所適，况乃弗爲魚。", "放意宇宙間，所至皆吾廬。"]'),
('6935a6a7-d364-41a7-8a19-7f72a1b1449e','又九月十四日登秋風閣以餘霞散成綺澄江靜如練爲韵分得餘靜二字  其二','李廌','宋','宋诗','song-poetry','','[]','山客水不覿，烝雲日如甑。',84,'全唐诗/poet.song.67000.json','["山客水不覿，烝雲日如甑。", "陵陸混泥沙，黯慘度朝暝。", "晨霞送晴色，喜見天面瑩。", "江光劍歸匣，雲收四山靜。", "高閣眺空無，復見前日勝。", "回思困塗潦，戃怳如昔病。", "登臨勿太息，秋風漸焱勁。"]'),
('d8f70987-2fd0-4913-953c-c3ed78c49ffd','搗帛石','李廌','宋','宋诗','song-poetry','','[]','婺女織玄綃，欲作六銖衣。',36,'全唐诗/poet.song.67000.json','["婺女織玄綃，欲作六銖衣。", "空山搗寒月，傳聲徹雲閨。", "可笑綺縠女，不識砧與機。"]'),
('5f44a5a8-2f00-46b8-9a94-06f77ec258de','同德麟仲寶過謝公定酌酒賞菊以悲哉秋之爲氣蕭瑟八字探韵各賦二詩仍復相次八韵某分得哉蕭二字  其一','李廌','宋','宋诗','song-poetry','','[]','楚女唱桃葉，楚巫歌竹枝。',48,'全唐诗/poet.song.67000.json','["楚女唱桃葉，楚巫歌竹枝。", "壯士撫長鋏，語闌亦興悲。", "君看拱把松，中有千歲姿。", "蕣華不及夕，柯葉漫成籬。"]'),
('3eb6751f-b889-4d2b-9db3-656a8b2f1250','同德麟仲寶過謝公定酌酒賞菊以悲哉秋之爲氣蕭瑟八字探韵各賦二詩仍復相次八韵某分得哉蕭二字  其二','李廌','宋','宋诗','song-poetry','','[]','葳蕤晚秋菊，芬菲忽齊開。',48,'全唐诗/poet.song.67000.json','["葳蕤晚秋菊，芬菲忽齊開。", "緣階上古壘，粲若黄金臺。", "搔首念霜髮，擷英泛羽盃。", "頹齡恐能制，壽侯安在哉。"]'),
('d60d2f05-3385-4d30-8759-ec0b4b1fae1e','同德麟仲寶過謝公定酌酒賞菊以悲哉秋之爲氣蕭瑟八字探韵各賦二詩仍復相次八韵某分得哉蕭二字  其三','李廌','宋','宋诗','song-poetry','','[]','白髮諳冷暖，蒼皮貯陽秋。',48,'全唐诗/poet.song.67000.json','["白髮諳冷暖，蒼皮貯陽秋。", "中年已如此，一飽更何求。", "把菊悼飛葉，微行遵遠流。", "此非柴桑里，乃有淵明儔。"]'),
('fb637656-f5a5-4da2-920c-87a679ba2aab','同德麟仲寶過謝公定酌酒賞菊以悲哉秋之爲氣蕭瑟八字探韵各賦二詩仍復相次八韵某分得哉蕭二字  其四','李廌','宋','宋诗','song-poetry','','[]','痛飲可一石，寧辭手中巵。',48,'全唐诗/poet.song.67000.json','["痛飲可一石，寧辭手中巵。", "挹斗自斟酌，澆胸定爲宜。", "心如虎在圈，事若羊觸籬。", "執鞭吾弗能，放意從所之。"]'),
('f9566cd8-1e1f-4bb9-9bde-5b729ccec041','同德麟仲寶過謝公定酌酒賞菊以悲哉秋之爲氣蕭瑟八字探韵各賦二詩仍復相次八韵某分得哉蕭二字  其五','李廌','宋','宋诗','song-poetry','','[]','青松多陳根，女桑漫柔枝。',48,'全唐诗/poet.song.67000.json','["青松多陳根，女桑漫柔枝。", "虛心任寒暑，寧與鐵炭期。", "旨酒有妙致，青山多令姿。", "醉遊卧丘壑，於予復何爲。"]'),
('e4c07ba6-f1be-4647-9ca9-7bc08efe69ee','同德麟仲寶過謝公定酌酒賞菊以悲哉秋之爲氣蕭瑟八字探韵各賦二詩仍復相次八韵某分得哉蕭二字  其六','李廌','宋','宋诗','song-poetry','','[]','松菊徑勿荒，政欲善鋤治。',48,'全唐诗/poet.song.67000.json','["松菊徑勿荒，政欲善鋤治。", "參商菅蒯中，高韵自超異。", "區別雖少勤，寶此吾臭味。", "勿言大鈞中，與彼同一氣。"]'),
('1695a03e-5a26-4083-ac47-806b1d1ce508','同德麟仲寶過謝公定酌酒賞菊以悲哉秋之爲氣蕭瑟八字探韵各賦二詩仍復相次八韵某分得哉蕭二字  其七','李廌','宋','宋诗','song-poetry','','[]','霜風隕高木，零落臨艾蕭。',48,'全唐诗/poet.song.67000.json','["霜風隕高木，零落臨艾蕭。", "幽芳枝孤秀，華心慰無聊。", "堂中老元亮，日賦歸去謠。", "杖屨樂三徑，爲爾甘折腰。"]'),
('e7bfb19a-d188-47c5-a9c9-f6dbb563057c','同德麟仲寶過謝公定酌酒賞菊以悲哉秋之爲氣蕭瑟八字探韵各賦二詩仍復相次八韵某分得哉蕭二字  其八','李廌','宋','宋诗','song-poetry','','[]','風騷本無作，强爲憂患出。',48,'全唐诗/poet.song.67000.json','["風騷本無作，强爲憂患出。", "菊荒思卧陶，江渾歎沉屈。", "吾觀思王詩，復若清廟瑟。", "斯文幸未墜，且進盃中物。"]'),
('75c3c201-1eec-4f55-8a47-a6f2b538da18','神松嶺即岳神爲珪禪師一夕自北嶺移者','李廌','宋','宋诗','song-poetry','','[]','初聞百梁村，拔自天池井。',36,'全唐诗/poet.song.67000.json','["初聞百梁村，拔自天池井。", "今知萬松岡，一夕趨北嶺。", "顧茲挾山威，何心罔知警。"]'),
('94d402ba-6db5-44c1-9dbf-dbcd32de3d1d','二士避雨巖','李廌','宋','宋诗','song-poetry','','[]','遇險思共濟，胡粵無異心。',48,'全唐诗/poet.song.67000.json','["遇險思共濟，胡粵無異心。", "而我與夫子，義烈真斷金。", "陰崖避飛雨，羣龍方怒吟。", "巖中歌式微，相和相知音。"]'),
('8894bb4c-8a1b-43ee-af88-278016fd7fd2','送元聖庾縣丞之官泉南','李廌','宋','宋诗','song-poetry','','[]','漫郎老猗玗，紫芝于蒍于。',264,'全唐诗/poet.song.67000.json','["漫郎老猗玗，紫芝于蒍于。", "二元皆國器，位卑德有餘。", "嗟公有祖德，官况復不如。", "平生志引大，英爽凌太虛。", "胸中有武庫，羅列千卷書。", "攘臂班馬間，豈但突黄初。", "謂宜在妙齡，持橐承明廬。", "何爲沉下僚，蹭蹬青雲途。", "三調南曹選，雪霜稍侵鬚。", "又佩墨綬去，不得黄紙除。", "憐公批敕手，乃判稅與租。", "閱世悟休戚，勝負如梟盧。", "達人自通脫，於何較錙銖。", "平治不平氣，俛仰自走趨。", "剛忍素所遇，時乃烈丈夫。", "南安極南粵，控带荆與吳。", "南涯即滄海，北渡竟重湖。", "回首望嵩潁，邈焉天一隅。", "南州例卑濕，海錯富蟲魚。", "作客萬里外，善保千金軀。", "加餐慎興寢，三年賦歸歟。", "故園有老伴，林下要爲娛。"]'),
('367fe4d7-922a-43a0-912a-3dcad22b81e8','德麟約游西山某自酇來會行李阻脩成此詩','李廌','宋','宋诗','song-poetry','','[]','初無聲利想，獨有山水癖。',168,'全唐诗/poet.song.67000.json','["初無聲利想，獨有山水癖。", "慨然歲月逝，名山喜投跡。", "書來拜嘉招，吹火自蠟屐。", "戒期西山邑，奔命通書尺。", "君詩如齊楚，凜凜兩大國。", "吾詩比邾滕，惴惴甘服役。", "千里奉詩盟，敢愛股肱力。", "方舟絕清漢，舍棹上層壁。", "梅埡排青雲，四覽衆山脊。", "僮肩困負笈，馬喙不停息。", "趼足上崔嵬，欲進轍已植。", "喘喉如鼓橐，開闔振胸臆。", "仰愧升木猱，俯羨歸飛翼。", "天曛未敢止，行行望仙舄。"]'),
('4cd14093-66aa-4a64-8fa4-7611b8e750b4','見山岡詩','李廌','宋','宋诗','song-poetry','','[]','高岡勝虛閣，晚景澄寥廓。',48,'全唐诗/poet.song.67000.json','["高岡勝虛閣，晚景澄寥廓。", "遙潢浸廣野，危峰柱碧落。", "雲過半山陰，蟬聲夕陽薄。", "勤勤學飛仙，海上尋黄鶴。"]'),
('1117aa48-d8f9-4ed8-a290-6460ee166487','三醉石詩','李廌','宋','宋诗','song-poetry','','[]','伊昔三逸人，醉卧捫白雲。',36,'全唐诗/poet.song.67000.json','["伊昔三逸人，醉卧捫白雲。", "其間歐醉翁，翊戴建殊勛。", "山靈豈羨爾，應復勒移文。"]'),
('0e755ff6-1f7c-4700-9bcb-fbe8bb3320cc','中隠菴和趙孺韵','李廌','宋','宋诗','song-poetry','','[]','退之以文鳴，師友得侯喜。',168,'全唐诗/poet.song.67000.json','["退之以文鳴，師友得侯喜。", "聲名力與俱，雖尊未勇耳。", "黄池距青山，孰辨都與鄙。", "菴成誰振之，句出鬧如市。", "千仞寧我高，充實信吾美。", "坐令菴內人，前車云可軌。", "禮樂有先後，後進則君子。", "執方而昧圓，俱野那復史。", "伐柯固執柯，疇克求諸邇。", "蒸之既匪薪，采焉又非芑。", "近交韓與侯，步驟亦常耻。", "一醫消息盡，布毛自何起。", "要須六月息，不息不爲已。", "敢問二詩人，如何得意旨。"]'),
('5c61eaf4-ce5f-4c08-903e-8c195a74455d','答周行己相贈行己端慎太學諸生忌之','李廌','宋','宋诗','song-poetry','','[]','佳人寓雲端，餌霞服靈烟。',72,'全唐诗/poet.song.67000.json','["佳人寓雲端，餌霞服靈烟。", "舉手謝時人，信爾非我緣。", "誰令山中瓢，酌此闤闠泉。", "捨爾芝蘭薌，一染漸餘羶。", "鉛黄强爲容，孰竟謂子妍。", "眷焉反初素，此道自古然。"]'),
('ab938429-088f-4e18-a3eb-ff315e0fff03','習家池詩','李廌','宋','宋诗','song-poetry','','[]','言登峴椒亭，南望高陽池。',72,'全唐诗/poet.song.67000.json','["言登峴椒亭，南望高陽池。", "習君漢徹侯，種魚千石陂。", "川光涵翠阜，倒影媚清漪。", "伊昔典午世，山公已游嬉。", "子孫安在哉，獨樂寧可期。", "蕭蕭宰上木，長風蕩餘悲。"]'),
('da8b0a2e-4020-449a-85a6-bfaacd3d27cc','習鑿齒宅','李廌','宋','宋诗','song-poetry','','[]','習侯有世德，冠冕襲鵔鸃。',72,'全唐诗/poet.song.67000.json','["習侯有世德，冠冕襲鵔鸃。", "裔孫富六藝，鑿齒四海知。", "蘇嶺陟家山，高陽浮故池。", "著書山水間，秀發胸中奇。", "間從彌天釋，善戲間廋辭。", "尚友雖異代，斯人可夙期。"]'),
('3a20098b-efaf-4001-8de7-93e14af74474','龐德公宅詩','李廌','宋','宋诗','song-poetry','','[]','荆山雲蒼蒼，漢水波瀰瀰。',72,'全唐诗/poet.song.67000.json','["荆山雲蒼蒼，漢水波瀰瀰。", "山川意高澹，宜有隠君子。", "德公卧鹿門，老不踐州里。", "潔身遠憂患，豈復存慍喜。", "藐然姑射人，胡爲市門倚。", "諸郎有鳳雛，輒與卧龍起。"]'),
('9327a075-8421-40bb-9465-6ab9d870a639','過具茨諸山始達嵩少','李廌','宋','宋诗','song-poetry','','[]','初踰千峰時，千峰各呈秀。',108,'全唐诗/poet.song.67000.json','["初踰千峰時，千峰各呈秀。", "抵茲嵩高前，始覺衆山陋。", "恃此一柱力，天地敢分剖。", "四維既張弛，穹壤託高厚。", "卿雲羃上國，秀色連楚藪。", "衆峰無聳峭，配此真培塿。", "固將倍十百，何止吞八九。", "余身一草木，乃欲擅去取。", "出類復何言，聊貽澗濱叟。"]'),
('53e79883-2600-4963-a324-38a0b45f7e6e','登嵩頂','李廌','宋','宋诗','song-poetry','','[]','丈夫有奇氣，坐井直鬰鬰。',240,'全唐诗/poet.song.67000.json','["丈夫有奇氣，坐井直鬰鬰。", "朅來古嵩州，携手登太室。", "中峰到絕頂，北嶺太峭壁。", "山河在股掌，带礪何足述。", "星分九州野，塊列七雄埸。", "放懷宇宙間，想見天地闢。", "下觀雲雷變，愍爾龍鬼役。", "下方萬仞底，草樹靄蒙密。", "愈知天下小，助我浩氣直。", "平生四方志，登臨聊感激。", "嗟嗟封禪媼，遊豫朝百辟。", "誣辭與慚德，可笑乎四嶧。", "廟社尚不閱，財用遑肯恤。", "萬兵樹豐碑，數丈壓崷崒。", "豈知市朝變，輦路蔽荆棘。", "同登八仙壇，再題三醉石。", "君無笑余怯，登臨常股慄。", "爲寶千金軀，夷路猶恐失。", "存我厚蒼生，豈效伯昏逸。", "歸卧聽天雞，扶桑觀日出。"]'),
('38db8b9d-da8c-471a-8433-5232e0b9300f','求志書院詩四首陳師道履常之所居也  其一','李廌','宋','宋诗','song-poetry','','[]','癯槁巖下士，蹟隠心捷徑。',48,'全唐诗/poet.song.67000.json','["癯槁巖下士，蹟隠心捷徑。", "汗顔塵中夫，諂笑幸游騁。", "賢哉陳夫子，兩不傷厥性。", "潔身風波塗，獨若萬鈞錠。"]'),
('6bff85b4-90ca-49f6-8cf3-fede619be370','求志書院詩四首陳師道履常之所居也  其二','李廌','宋','宋诗','song-poetry','','[]','辰極不改北，滄溟日輸東。',48,'全唐诗/poet.song.67000.json','["辰極不改北，滄溟日輸東。", "聖道亦如是，昧者自異同。", "哇鄭迷世習，舍魚當取熊。", "蓍龜期吾子，此語聞先翁。"]'),
('4e163e95-eb3f-4345-83f2-51d7ef6f9676','求志書院詩四首陳師道履常之所居也  其三','李廌','宋','宋诗','song-poetry','','[]','君氣久已浩，君志復何求。',48,'全唐诗/poet.song.67000.json','["君氣久已浩，君志復何求。", "同聲久絕和，一見忘百憂。", "藜藿鄙膏粱，絺綌傲狐裘。", "德輝下可覽，安用翔九州。"]'),
('ad48013d-058b-4953-a6f0-0759c3f7f3ee','求志書院詩四首陳師道履常之所居也  其四','李廌','宋','宋诗','song-poetry','','[]','漆開辭未信，顔回恃有田。',48,'全唐诗/poet.song.67000.json','["漆開辭未信，顔回恃有田。", "爲貧仕何媿，得已非自賢。", "破褐坐窮閻，聲華飛日邊。", "苦節勿匏瓜，仲尼任蒼天。"]'),
('0b5732ab-df02-4749-98f3-d1a6da1d3620','靜齋詩題盛君明之室也','李廌','宋','宋诗','song-poetry','','[]','人生乃動物，萬事皆動端。',144,'全唐诗/poet.song.67000.json','["人生乃動物，萬事皆動端。", "陰陽造化汝，賦汝以五官。", "五官各治職，愈治當愈殘。", "非苦動所擾，烏知靜爲安。", "非惡動所戕，未貴靜爲完。", "百年夜分半，夢想仍妄瞞。", "動多靜常少，竟爲動所干。", "回光一自照，萬事無悲歡。", "居士何早達，動境能反觀。", "寧爲玉在璞，不爲珠在槃。", "虛室生朝白，青璅凝暮寒。", "聊持動時想，攝入靜中看。"]'),
('fbd43a2e-8476-4779-a1d3-35fcd8dc3cc1','寶幹山茶','李廌','宋','宋诗','song-poetry','','[]','山茶乃凡木，寶幹始爲奇。',48,'全唐诗/poet.song.67000.json','["山茶乃凡木，寶幹始爲奇。", "婉雅瑞荷花，扶疏連理枝。", "傾心相爾汝，和氣生怡怡。", "清陰亦可愛，惡木正離披。"]'),
('48f5b24a-d961-4f31-a8ec-e7675fd4d524','上姑丈閭丘通牧少卿','李廌','宋','宋诗','song-poetry','','[]','天下一大器，安危繫平傾。',288,'全唐诗/poet.song.67000.json','["天下一大器，安危繫平傾。", "哲王慎民監，措術如和羹。", "辛甘或偏長，非可制割烹。", "五味既可口，君子嘗曰平。", "方今太平君，戒欹如持盈。", "乞言用龜鑑，履德均權衡。", "庶民雖惷愚，一或非所營。", "視之如己內，涂污千仞坑。", "是用選賢德，告戒敷至誠。", "曰雖一人良，萬邦咸以貞。", "尚頼爾庶牧，裨朕來聰明。", "分符授虎節，專政千里城。", "朱車輪兩轓，畫戟門十旌。", "禮文既光華，遠煜如杕英。", "良圖沃朕心，蠲瘼求民情。", "如意運手足，乃與朕力并。", "朕所戒假樂，難慎惟守成。", "願昭先人功，奠枕臨周京。", "羣方政咸乂，惟海隅蒼生。", "魚鹽機巧利，凉德多矜爭。", "版圖庶彙徵，雉壘侵荒荆。", "矧乘薦饑後，魴鱨尾多頳。", "古既無罪歲，此獨何所令。", "明明普天下，孰非聖人氓。"]'),
('354b185f-3a8e-4788-b197-32267137a219','曉發鄧城和德麟韵','李廌','宋','宋诗','song-poetry','','[]','遙岑掣殘電，炫轉雲篩碎。',168,'全唐诗/poet.song.67000.json','["遙岑掣殘電，炫轉雲篩碎。", "長庚送曉色，澒洞初見地。", "饑馬戀櫪鳴，呞牛繫林睡。", "橫塘寸魚跳，魚跳石雙翠。", "敢嗟衣化塵，且喜風泛袂。", "蚤懷功名心，經濟豈無意。", "老軀既骯髒，柔態漸斌媚。", "棹舟江南去，白酒謀日醉。", "絲蓴芼雪鱸，欲飽三尺喙。", "半生客荆州，兩渡北津水。", "尚友有若人，獲我心所契。", "行李念淹留，感此秋蟬嘒。", "掃除向來想，漁釣真得計。", "塞翁已無心，得失無欣喟。"]'),
('c3ed79f1-f522-4f45-9dbb-681e0aa35fe5','鄧城道中懷舊時德麟相拉至江北三縣','李廌','宋','宋诗','song-poetry','','[]','昔從郡丞游，餘寒春未迴。',144,'全唐诗/poet.song.67000.json','["昔從郡丞游，餘寒春未迴。", "玄雲蔽冷日，朔風捲黄霾。", "枯榛擁殘雪，疏籬橫野梅。", "季夏方溽暑，後乘復與偕。", "青秧舞白水，赤日飛紅埃。", "牛馬暍俱喘，蜩螗嘒相哀。", "值此寒暑變，感予羈旅懷。", "行行江湖去，舉櫂向天台。", "老婦膾魴鯉，丁男滌尊罍。", "霜橙薦紫蟹，水藕浮瓊醅。", "念公復行縣，秋光當獨來。", "予時定相望，持酒上高臺。"]'),
('46f1a678-dcf5-4188-9758-4203b2c38637','石經殿','李廌','宋','宋诗','song-poetry','','[]','漆書寘蘭臺，筆削猶敢擅。',36,'全唐诗/poet.song.67000.json','["漆書寘蘭臺，筆削猶敢擅。", "真名鏤遺編，定知伯喈篆。", "未校芸閣書，成此石經殿。"]'),
('4c433ecd-2e86-4f04-a3af-ff4608addb4e','天門泉詩','李廌','宋','宋诗','song-poetry','','[]','昔聞天門泉，石竇注澄澈。',36,'全唐诗/poet.song.67000.json','["昔聞天門泉，石竇注澄澈。", "行人口生烟，可救萬夫渴。", "爲惠胡不竟，吾來值源竭。"]'),
('16dd57be-0e20-44ac-a3d9-3144cdaa12b8','捨身崖','李廌','宋','宋诗','song-poetry','','[]','蛾眉備百姓，怨女填六宮。',36,'全唐诗/poet.song.67000.json','["蛾眉備百姓，怨女填六宮。", "捐軀委崖谷，隕生因爾容。", "匹婦多白髮，婦怨實無終。"]'),
('d0ff044f-b1d2-478d-8782-1ab5182ea195','太華','李廌','宋','宋诗','song-poetry','','[]','太華復何如，名山控西極。',96,'全唐诗/poet.song.67000.json','["太華復何如，名山控西極。", "忽從天地分，屹立三萬尺。", "天維西北傾，扶持藉爲壁。", "風雷出毫末，日月轉兩腋。", "秦川散餘秀，長空借殘碧。", "支離別周甸，指掌觀禹績。", "因知方嶽重，奚睹介丘憶。", "蒼旻仰猶高，厚載真有力。"]'),
('69cc0734-bdee-413b-be1b-8e9a1c91ebfa','三岡亭在邑西南三十里秦昭王使謁者王稽使魏夜與范雎言先生待我於三岡亭之南是也','李廌','宋','宋诗','song-poetry','','[]','賤人敢圖柄，時哉天步艱。',48,'全唐诗/poet.song.67000.json','["賤人敢圖柄，時哉天步艱。", "相爾簀中意，三亭寧靦顔。", "佩印能幾時，網成已入關。", "宣言往代汝，天道真可還。"]'),
('6d588cdc-07cb-40c5-875a-9a9fccfd3c78','東津夜飲送岑穰彥休赴闕  其一','李廌','宋','宋诗','song-poetry','','[]','東門何煌煌，驪駒絡金羈。',48,'全唐诗/poet.song.67000.json','["東門何煌煌，驪駒絡金羈。", "朱顔照秋鞠，炯炯青雲姿。", "往登芸香閣，編書給隃麋。", "予方滯江漢，發軔將安之。"]'),
('b22d69f4-cb26-4e8f-8744-b76a28504748','東津夜飲送岑穰彥休赴闕  其二','李廌','宋','宋诗','song-poetry','','[]','風林舞危葉，霜畦殺青蕡。',48,'全唐诗/poet.song.67000.json','["風林舞危葉，霜畦殺青蕡。", "車馬如上州，朝天逐高雲。", "行邁豈不勞，欲書竹帛勳。", "歲晏重感慨，我獨念離羣。"]'),
('ec7fdbb6-261c-45ad-a524-3c4a1669943a','曹華國之子贈詩次韵答之','李廌','宋','宋诗','song-poetry','','[]','平生曹華國，志意多感慨。',108,'全唐诗/poet.song.67000.json','["平生曹華國，志意多感慨。", "塵埃迷俯仰，骯髒游方外。", "余嘗賢若人，心以古人待。", "食蘗甘有味，舐蜜遇潜蠆。", "賫恨沒九原，長屯竟無泰。", "宿草揜一丘，長夜遂千載。", "喜君好男兒，贈語頗剛快。", "弓裘解傳業，門戶茲有頼。", "文章第美身，長門不須賣。"]'),
('a5599e2c-8e7b-436b-9a2e-4dcb9d003f83','邃經堂','李廌','宋','宋诗','song-poetry','','[]','男子宜讀書，讀書須五車。',156,'全唐诗/poet.song.67000.json','["男子宜讀書，讀書須五車。", "紙腐唇自裂，豈爲刳心魚。", "吾子少年時，青雲得意初。", "英華發清端，賦筆凌相如。", "自試文石陛，竚召承明廬。", "孝隠二十年，復與志利疏。", "軒裳不掛眼，鐘鼓悅爰居。", "歸來邃經堂，志惟與道俱。", "架上數萬卷，偃仰時卷舒。", "使彼夙昔人，微言幸發攄。", "春洲生蘭苕，寒溪脫紅蕖。", "逍遙適所願，未可詠歸歟。", "上方宵旰暇，夜殿誦子虛。"]'),
('78b2cc68-2d4c-4bde-b50a-f001eb41d6d0','送李德載公輔之宣城王子敏遹之寧陵秦少章之仁和','李廌','宋','宋诗','song-poetry','','[]','先生位管轄，四海在陶鈞。',144,'全唐诗/poet.song.67000.json','["先生位管轄，四海在陶鈞。", "顧我門牆士，於焉益情親。", "睠言給鼎味，旨酒侑芳珍。", "粲粲春服成，暮春及佳辰。", "載詠先生道，興懷感昔人。", "三子果藝達，從政宜牧民。", "維舟萬里流，喜色照通津。", "廌也不速肖，農圃老此身。", "同門各鶱翥，索居獨離羣。", "諸公廊廟器，行當策高勛。", "念此今日歡，無忘病且貧。", "結駟儻肯顧，促車清潁濱。"]'),
('32fa1804-907d-4f1e-8b8b-83db48446f75','送王仲求','李廌','宋','宋诗','song-poetry','','[]','飄風非焚輪，觸石生孤雲。',144,'全唐诗/poet.song.67000.json','["飄風非焚輪，觸石生孤雲。", "逍遙王真人，行行傲世紛。", "齋戒斷葷臭，日誦浮屠文。", "敝袍遊江海，耻與狐貉羣。", "吐納全真氣，鬢髮垂如銀。", "十年臨池學，自許登右軍。", "謙謙卑自牧，處約人皆忻。", "扁舟忽云徂，欲扳心殷殷。", "丈夫重訣別，兒女徒云云。", "常聞釋氏說，精進在慇懃。", "紅塵易汩沒，跋涉憊力筋。", "不如巢華山，修煉如老君。"]'),
('05369599-0399-48ad-b5ed-7eaa5593fe79','送秦少章','李廌','宋','宋诗','song-poetry','','[]','建勳各有志，而我齒已疏。',144,'全唐诗/poet.song.67000.json','["建勳各有志，而我齒已疏。", "除書喜之子，試吏東海隅。", "滿懷貯忠義，陳編陋嚴徐。", "平生困末路，龍蠖意不舒。", "定交青雲表，凜凜國士徒。", "執顔肯顧我，曾未鄙非夫。", "破愁有斯人，我鄰知不孤。", "危言解補天，决折已非圖。", "成名聊爾爾，國器自時須。", "收功從茲始，良驥騖修途。", "開樽稍黔突，慚愧飯與芻。", "閉戶待子歸，看我所著書。"]'),
('ea8ae040-c0bd-4c1e-9079-df35e7132777','同諸公餞望元因宿谷隠以何當風雨夜復此對床眠爲韵分得對此二字  其一','李廌','宋','宋诗','song-poetry','','[]','雨氣天末來，暝色江皋起。',96,'全唐诗/poet.song.67000.json','["雨氣天末來，暝色江皋起。", "層林蔽樓觀，黯淡水雲裏。", "匹馬何所從，翩翩五公子。", "異時天一方，相遇忽在此。", "溫言各慰惜，道舊半悲喜。", "熠熠螢度幃，泫泫礎流泚。", "他鄉念羈旅，况復餞行李。", "一笑未易闌，相望跡千里。"]'),
('3d9fe954-caa2-48b3-b577-dd44c9bae492','同諸公餞望元因宿谷隠以何當風雨夜復此對床眠爲韵分得對此二字  其二','李廌','宋','宋诗','song-poetry','','[]','秋江冒后土，餘潦滿溝澮。',84,'全唐诗/poet.song.67000.json','["秋江冒后土，餘潦滿溝澮。", "行人泥沒輈，腐黍亂荒薈。", "結客山中游，風雨在顛沛。", "崢嶸棟宇下，磊落宜我輩。", "還同竹溪逸，笑傲盼庭檜。", "繁陰阻杖屨，曀曀幾弦晦。", "誰能决頑雲，共此明月對。"]'),
('2e5fe223-8169-4add-a534-f6c61ee27850','大木山','李廌','宋','宋诗','song-poetry','','[]','十洲三神山，廣厚蟠地軸。',156,'全唐诗/poet.song.67000.json','["十洲三神山，廣厚蟠地軸。", "不知高幾尋，滄溟及其麓。", "游心如太空，視彼何芥粟。", "君家三木山，包裹一握足。", "銛銳曰奇鋒，坳巖云峻谷。", "攝心如蚍蜉，觀此乃陵陸。", "高庳作九地，何啻戰蠻觸。", "老蘇記木山，萬里在右蜀。", "立之置庭除，屹嶪可映屋。", "小大雖相懸，真贋此其族。", "因形生彊名，等是千歲木。", "君家襄城野，繞郭山抱綠。", "巍然複嶺外，自有真六六。"]'),
('cf345fd4-5e35-4145-b5a5-15f2842e331f','孟浩然故居','李廌','宋','宋诗','song-poetry','','[]','旰食羹不糝，肺腑窮雕鎸。',72,'全唐诗/poet.song.67000.json','["旰食羹不糝，肺腑窮雕鎸。", "襄陽妙人物，我獨憐浩然。", "禁中拜天子，布衣可逢年。", "一言類觖望，明主乃棄捐。", "凄凉鹿門道，舊隠空雲烟。", "漢水不世情，猶有槎頭鯿。"]'),
('a469a863-85bd-415f-b8ac-4a94cb036648','上山','李廌','宋','宋诗','song-poetry','','[]','登山蓋有道，迂叟真名論。',48,'全唐诗/poet.song.67000.json','["登山蓋有道，迂叟真名論。", "不困在徐行，不跌由足穩。", "斯言可銘佩，萬事爲節撙。", "推之爲躬行，天下國家本。"]'),
('b2db12f8-eadf-498f-8494-59c368c348c2','從德鄰至鄧城訪魏道輔故居懷道符','李廌','宋','宋诗','song-poetry','','[]','孟春屬佳辰，駕言從郡丞。',168,'全唐诗/poet.song.67000.json','["孟春屬佳辰，駕言從郡丞。", "蓐食戒徒御，篝火事徂征。", "方舟絕橫漢，適彼樊侯城。", "緬懷昔封君，能使晚周興。", "千齡想風概，慨嘆岸與陵。", "故城若墟落，邑屋袖可憑。", "盤飧倦舉箸，幅幅氣拂膺。", "古寺蔽榛甓，破舍餘殘僧。", "人言魏徵君，於焉常曲肱。", "窶居三十年，蔚然以詩鳴。", "人憂不改樂，信哉賢者能。", "常聞有四友，作堂在郊坰。", "我雖樗櫟材，臭味亦其朋。", "會當從飛蓋，清夜一來登。"]'),
('695c4de3-165f-4c1d-bf6d-69728dfd62aa','李良相清德碑良相百藥四世孫也天寶中爲尉氏令邑人立此碑','李廌','宋','宋诗','song-poetry','','[]','旌廉以廉寡，樹碑勵貪夫。',48,'全唐诗/poet.song.67000.json','["旌廉以廉寡，樹碑勵貪夫。", "後人慕前躅，當令德不孤。", "第無愧屋漏，斯能遠苞苴。", "番禺惟飲水，合浦自還珠。"]'),
('f2fdef8a-f081-42e1-a1c9-4d4f316bfa42','阮步兵廟','李廌','宋','宋诗','song-poetry','','[]','千齡一丘壠，誰復記主名。',48,'全唐诗/poet.song.67000.json','["千齡一丘壠，誰復記主名。", "苾芬百世祠，賢哉阮步兵。", "廟旁故墟里，竹林蔽郊坰。", "裔孫仍南北，胡能師九原。"]'),
('13a5cec8-c461-4f5a-8fda-0ad6e8ec2abb','蔡澤廟','李廌','宋','宋诗','song-poetry','','[]','從橫事捭闔，揣摩相抵巇。',48,'全唐诗/poet.song.67000.json','["從橫事捭闔，揣摩相抵巇。", "茲爲富貴術，咄嗟乃自知。", "相形直誤人，俾無百年期。", "遂汝齒肥心，廟食飽牲犧。"]'),
('d473b0d4-b985-475a-984d-746abc29d94f','羊叔子廟','李廌','宋','宋诗','song-poetry','','[]','緬懷吳晉氏，天壤非異宇。',72,'全唐诗/poet.song.67000.json','["緬懷吳晉氏，天壤非異宇。", "賢哉羊頭鎮，一用惠慈撫。", "高懷寄山水，餘事整軍旅。", "當年峴首歎，奄冉隔今古。", "遺民俎豆之，廟貌壓江滸。", "誰令望碑人，墮淚若兒女。"]'),
('8349abea-7efb-4d10-a4f9-f9c3ca806582','杜元凱廟','李廌','宋','宋诗','song-poetry','','[]','書生昧籌算，罕立橫草功。',72,'全唐诗/poet.song.67000.json','["書生昧籌算，罕立橫草功。", "征南日耽經，帷幄明指蹤。", "胸中有武庫，矧與豎儒同。", "賢哉秉節度，不制蜀阿童。", "沈碑雖好名，要是真英雄。", "寥寥萬山路，爽氣摇松風。"]'),
('a4f8e193-9939-4b55-b60d-f5cb74f07afe','和錢之道','李廌','宋','宋诗','song-poetry','','[]','仲尼聖之時，豈蔽不恭隘。',132,'全唐诗/poet.song.67000.json','["仲尼聖之時，豈蔽不恭隘。", "知命識大憂，嗣世宅已壞。", "不閱父母邦，遑及爲蒯瞶。", "依仁罕言利，執禮不語怪。", "汙墁泥中轍，脂牽速遄邁。", "難乎其有恒，取善僅餔饋。", "苟非言抑揚，大道或幾賣。", "峽有食象蛇，常苦螻蟻嘬。", "昭昭神禹功，鑿水疏九派。", "刊隨神明疲，新水螭蜃快。", "志士每喪元，時靡可究屆。"]'),
('6f52c518-d1fe-4fdf-b25f-e2e38bc90c24','薙草','李廌','宋','宋诗','song-poetry','','[]','宿草競春力，階除日青青。',48,'全唐诗/poet.song.67000.json','["宿草競春力，階除日青青。", "何心願滋茂，薙去輒復生。", "一氣養萬類，蘭葯盡勾萌。", "何當紉余佩，采采擷芳英。"]'),
('3a81b093-6d21-4f6e-ba52-88ec37f8d62b','同仲寶風雨中過德麟留宿以夜未央爲韵分得未字并和二公夜央字韵  其一','李廌','宋','宋诗','song-poetry','','[]','悲風送寒雨，遙夜俄總至。',48,'全唐诗/poet.song.67000.json','["悲風送寒雨，遙夜俄總至。", "草木雖戰秋，渠能保柔脆。", "盃盤照青燈，哦詩久無寐。", "安能决雲開，坐見參橫未。"]'),
('f0f16bfc-fb57-4252-8071-69c2f09d2b13','同仲寶風雨中過德麟留宿以夜未央爲韵分得未字并和二公夜央字韵  其二','李廌','宋','宋诗','song-poetry','','[]','秋徂風雨多，欲作雪霜迓。',96,'全唐诗/poet.song.67000.json','["秋徂風雨多，欲作雪霜迓。", "况乃地氣偏，寒暑或相借。", "溫凉久未定，裘葛易無暇。", "慚愧平原君，客至列盞斝。", "日爲文字飲，短晝繼清夜。", "嗟予寡世偶，癡甚已如霸。", "有田未歸耕，無策敢求射。", "耽詩近知味，疑從果臝化。"]'),
('b5e54f6b-244c-467a-859f-aee1cafda33c','同仲寶風雨中過德麟留宿以夜未央爲韵分得未字并和二公夜央字韵  其三','李廌','宋','宋诗','song-poetry','','[]','敢友天下士，轍環之四方。',48,'全唐诗/poet.song.67000.json','["敢友天下士，轍環之四方。", "適願得所向，偶如鐘應霜。", "交態久未定，市道良可傷。", "君看江漢水，安流日泱泱。"]'),
('50a4dfc4-445a-46ee-9cd4-8e8695209f85','張康節家西軒竹張福夷兄弟求詩','李廌','宋','宋诗','song-poetry','','[]','種花鄙弱植，種柳惡連陰。',72,'全唐诗/poet.song.67000.json','["種花鄙弱植，種柳惡連陰。", "主人種竹意，闓爽見靈襟。", "猗猗復勁節，凜凜况虛心。", "晚歲示貞操，清風應好音。", "扶疏高軒下，衆景爲蕭森。", "世襲萬戶封，奚取千畝林。"]'),
('2d29fe33-be8d-440a-8510-8019a4342e0d','夜坐','李廌','宋','宋诗','song-poetry','','[]','東郭新雨餘，日入凉氣佳。',48,'全唐诗/poet.song.67000.json','["東郭新雨餘，日入凉氣佳。", "長風吹天維，坐見參斗斜。", "默默羣動息，寒螿先秋譁。", "清談互絕倒，豈復憂過差。"]'),
('62ef4989-3339-4b79-b1b6-c44af12adaba','谷隠寺','李廌','宋','宋诗','song-poetry','','[]','挈巢江湖去，端爲山水癖。',108,'全唐诗/poet.song.67000.json','["挈巢江湖去，端爲山水癖。", "朅來谷隠遊，契我賞心適。", "寒江渺平楚，複嶺轉層壁。", "誰與龍象筵，一掃狐兔迹。", "綵雲布樓臺，迎日麗金碧。", "堂高磬聲邃，壑遠松響激。", "山光晚相照，空翠濃欲滴。", "行當就墟市，幽棲買泉石。", "日詠招隠詩，時過彌天釋。"]'),
('e20fb2d6-2c83-486e-ab4b-cd8f04a4bd73','題蔡君謨墨蹟後','李廌','宋','宋诗','song-poetry','','[]','古人托一技，身死名不滅。',132,'全唐诗/poet.song.67000.json','["古人托一技，身死名不滅。", "賢愚置不論，筆畫觀可閱。", "嶧山刻秦銘，斯篆屈金鐵。", "雖在衆憎惡，恨不頸薦鉞。", "褚令狷且直，還笏首叩血。", "魯公秉忠勤，白首抗希烈。", "獨有虞永興，當年稱四絕。", "賢哉蔡莆陽，直氣亙南粵。", "入爲楓宸侍，遇事挺奇節。", "揮毫霸當年，粲然星中月。", "非惟驚代能，乃是名世哲。"]'),
('e5e3fb6e-1d35-4db7-87fa-5ccea871a11e','嘯臺  其一','李廌','宋','宋诗','song-poetry','','[]','步兵游方外，棄禮真太簡。',48,'全唐诗/poet.song.67000.json','["步兵游方外，棄禮真太簡。", "過差生杯酒，况復能白眼。", "蘇門鸞鳳音，戲技猶赧赧。", "當知愧孫登，不獨嵇中散。"]'),
('df12636a-f66f-4678-a77a-827b4a03d37c','嘯臺  其二','李廌','宋','宋诗','song-poetry','','[]','步兵真曠達，與世故浮游。',84,'全唐诗/poet.song.67000.json','["步兵真曠達，與世故浮游。", "平時哭途窮，鬰鬰宇宙幽。", "浩氣獨不揜，築臺凌清秋。", "一嘯已望我，况乃爾汝儔。", "斯人固遺世，世亦不汝收。", "得非青白眼，鈞銖牾時流。", "聊爲招魂些，釋汝故時憂。"]'),
('ef3754eb-38d7-4b09-bba2-6274e1888edc','嘯臺  其三','李廌','宋','宋诗','song-poetry','','[]','言登阮公臺，興來聊獨游。',84,'全唐诗/poet.song.67000.json','["言登阮公臺，興來聊獨游。", "因爲爾時嘯，景物故清幽。", "奄冉古今意，凄瑟天地秋。", "阿戎迷簿領，况復五君儔。", "北眺度遐想，遺音浩難收。", "登臨感陳迹，雲散惜風流。", "軔車此裴回，何以慰百憂。"]'),
('589baa2d-535c-42ef-95f0-8894f4868120','嘯臺  其四','李廌','宋','宋诗','song-poetry','','[]','乘流忽遇坎，觸焉遘茲游。',84,'全唐诗/poet.song.67000.json','["乘流忽遇坎，觸焉遘茲游。", "紆餘上雲壘，禪房忽通幽。", "水光浮西澤，草樹颯已秋。", "豈無竹林友，腰印不我儔。", "異時東山約，興盡輒復收。", "飛蓋想清夜，華月湛西流。", "何當共巾履，一笑破羣憂。"]'),
('3477ddac-6d01-4ec1-a233-fac4f0259355','嘯臺  其五','李廌','宋','宋诗','song-poetry','','[]','我登步兵臺，緬懷昔來游。',84,'全唐诗/poet.song.67000.json','["我登步兵臺，緬懷昔來游。", "英聲入萬壑，奇氣盤九幽。", "轉盼迹已陳，况今仍千秋。", "鸞鳳吟蘇門，奚用愧彼儔。", "堪笑劉越石，幸勝功遂收。", "登高君能賦，乃是子安流。", "作詩已可人，洗我萬古憂。"]'),
('a197608d-287d-4b49-8651-e9619facdd53','七夕','李廌','宋','宋诗','song-poetry','','[]','七夕知何夕，云是牛女期。',264,'全唐诗/poet.song.67000.json','["七夕知何夕，云是牛女期。", "俚俗具瓜華，階除兒女嬉。", "繁星爛煌煌，流月湛沉輝。", "羣兒望鵲橋，橋端七寶帷。", "彷彿想言笑，薌澤疑烟霏。", "人間光陰速，天上日月遲。", "隔歲等旦暮，會遇未應稀。", "願言停笑驩，察我心所祈。", "我欲賜新巧，智術妙通微。", "金針度綵縷，寶奩卜蛛絲。", "我嗟兒女愚，勤勞徒爾爲。", "巧拙天所賦，乞憐真可嗤。", "故拙不可厭，吾寧鈍如椎。", "借云得新巧，無乃醇愈漓。", "吾觀天垂象，列星有攸司。", "牽牛常服箱，織女不下機。", "牽牛教人巧，積倉歲無饑。", "織女教人巧，笥篋餘裳衣。", "伊誰詢兒女，組繡窮毫釐。", "年年渡河漢，秋至次舍移。", "宣淫五雲上，此論乃吾欺。", "吾爲牛女辨，欲判千古疑。"]'),
('5a93bc3b-abed-4bcb-b0c1-e75b96d3eb2d','元祐六年夏自陽翟之睢陽迓翰林蘇公自杞放舟至宋','李廌','宋','宋诗','song-poetry','','[]','放舟杞國岸，汴渠正東注。',96,'全唐诗/poet.song.67000.json','["放舟杞國岸，汴渠正東注。", "湯湯舟下水，適與舟相遇。", "泛泛水上舟，與水共東去。", "舟水詎相離，曾不遷故處。", "世人迷動靜，順流疑若遡。", "不然逐流浪，汩沒爲所誤。", "吾作放舟詩，明此流水住。", "老矣耄何爲，聊用持世故。"]'),
('0309de3a-e9ca-4773-b41e-5f222b07bfaa','石棧河在洪閘','李廌','宋','宋诗','song-poetry','','[]','奔騰龍嶠麓，深壑斷如截。',144,'全唐诗/poet.song.67000.json','["奔騰龍嶠麓，深壑斷如截。", "石棧架寒溪，盤陀卧精鐵。", "從衡布方楚，片段髮文裂。", "平如中唐甓，罅密不容泄。", "南巖盡奇險，萬狀森羅列。", "或如巨獸蹲，或類巴蛇囓。", "哀泉瀉飛磴，流沫常噴雪。", "山骨靜無塵，泓澄碧潭澈。", "魚龍不敢宅，中有千古月。", "壯哉天地間，此險詎勞設。", "乃知山水心，自欲爲勝絕。", "我陪勝士游，茲名因不滅。"]'),
('0de7d6be-2c1c-4980-b635-f9a6dd2cffdd','足亭張康節南亭也臺數尺亭在其上','李廌','宋','宋诗','song-poetry','','[]','人生天地間，海中一浮漚。',288,'全唐诗/poet.song.67000.json','["人生天地間，海中一浮漚。", "欲求無厭心，無乃不勝求。", "知足有真樂，不然多悔尤。", "淺儒急名譽，夸人矜智謀。", "語默偕蟪蛄，生死等蜉蝣。", "不如知足者，澹然樂忘憂。", "袖手閱萬變，默坐觀九州。", "衆舍吾獨存，同波終異流。", "君看至足處，無得亦無修。", "萬物固皆備，反照靡不周。", "昧者彊務外，巧僞日嚮偷。", "昔饑止願飽，既飽思膳羞。", "昔寒止願溫，既溫思狐裘。", "非徒漫自苦，動輒成贅疣。", "相圃有足亭，可見好善優。", "公孫皆秉哲，克念踐先猷。", "欲種豈弟德，求異恩澤侯。", "秀嶺聳蒼玦，寒溪摇翠鈎。", "雲傳鄧林雨，月送滄浪秋。", "曉暝竹烟暗，午薰花氣浮。", "凉颸泛南榮，返照過東疇。", "所遇皆可樂，觴詠友浮丘。", "豈必朝玄圃，弭節夕瀛洲。", "永懷樹亭意，足焉此優游。"]'),
('a0991f96-385e-4b72-a915-172f4eb76b0b','鳴琴泉','李廌','宋','宋诗','song-poetry','','[]','昔聞流水操，想見流水音。',108,'全唐诗/poet.song.67000.json','["昔聞流水操，想見流水音。", "况復山泉聲，聲自如鳴琴。", "可笑山中人，强作碧沼深。", "暗流不復鳴，遺聲杳莫尋。", "近聞石鐘山，蘇辨正古今。", "酈元與李渤，地下當噤喑。", "惜乎不聞此，使我徒登臨。", "道人笑謂余，胡不求琴心。", "何勞弦上聲，况此非徽金。"]'),
('9d185fa6-20be-440f-abd4-633217ab6aa4','下第留別舍弟弼','李廌','宋','宋诗','song-poetry','','[]','繆承名卿後，煜煜贊皇裔。',180,'全唐诗/poet.song.67000.json','["繆承名卿後，煜煜贊皇裔。", "閔途遘伶俜，勉力濟顛墜。", "百年能幾何，三十已一世。", "胸中經綸策，偃蹇未獲試。", "衰殘蚤二毛，坎軻窮五技。", "探珠極溟海，耻逢驪龍睡。", "辛勤禹門浪，千仞復中躓。", "吾道有用舍，無乃天所否。", "巖廊與溝壑，榮悴同一戲。", "俱非本來物，吾無窮途淚。", "季父勉問學，弓冶付吾弟。", "營營米鹽慮，役役裘葛計。", "雖服貧賤勞，無損剛大氣。", "慎乃百勝術，早拔萬夫萃。", "老去重別離，悲歌感棠棣。"]'),
('e77e3c63-af49-4f40-ae03-aa8a2829380a','下第留別陳至','李廌','宋','宋诗','song-poetry','','[]','明緡釣香餌，彼取亦已微。',180,'全唐诗/poet.song.67000.json','["明緡釣香餌，彼取亦已微。", "金丸往抵黽，我用一何卑。", "余生宇宙間，動輒多願違。", "天王十二閑，玉勒黄金鞿。", "奈何驥與騄，不使備六蜚。", "鹽車初未脫，伯樂第興悲。", "寧甘生芻餓，不爲場藿嘶。", "京都足風埃，士氣隨亦淄。", "君於萬夫間，獨若三秀芝。", "浩氣久已定，得喪亮難移。", "對之忘忿戾，澹然移安夷。", "論交有斯人，是用久敬之。", "吾生三十年，二十九年非。", "末路各相望，奮庸會有時。", "貴如未可求，守余北山薇。"]'),
('08dd6c96-0f35-4118-b361-e9c419a230cb','嵩陽書院詩','李廌','宋','宋诗','song-poetry','','[]','束髮從政事，佩綬曳長裾。',288,'全唐诗/poet.song.67000.json','["束髮從政事，佩綬曳長裾。", "守令有民社，裂地皆分符。", "問之爾何由，必曰因業儒。", "自致或世賞，因儒升仕塗。", "一朝希斗祿，輒與故步殊。", "佞夫專媚竈，要路事馳驅。", "俗夫抗塵容，勾校迷墨朱。", "自謂尚市道，不若效賈區。", "何必念故業，易地有蘧廬。", "嵩陽敞儒宮，遠自唐之盧。", "章聖旌隠君，此地搆宏居。", "崇堂講遺文，寶樓藏賜書。", "賞田逾千畝，負笈昔雲趨。", "勸農桑使者，利心巧阿諛。", "飛書檄大農，鬻此奉時須。", "垣牆聚蓬蒿，觀殿巢鳶烏。", "二紀無人迹，荒榛誰掃除。", "桑羊固可烹，縣令亦安乎。", "今主尚仁政，美利四海敷。", "仁賢任阿衡，天地一朝蘇。", "已責復蠲斂，肉骨生膏腴。", "疲民悉按堵，此地尚荒蕪。", "淮西高夫子，爲政多美譽。", "百里政肅雍，民不困追胥。"]'),
('0bb7643f-3f34-42a2-b6a6-ec2ad1c27fd9','史次仲錢子武與余在報恩寺納凉分題各以姓爲韵','李廌','宋','宋诗','song-poetry','','[]','天地怒氣散，凱風若顛喜。',96,'全唐诗/poet.song.67000.json','["天地怒氣散，凱風若顛喜。", "吹彼枳棘墟，不入邃屋裏。", "北風何其凉，雨雪雱不止。", "卒歲無衣裘，穴處猶凍死。", "六月如蒸炊，執扇猶秉燬。", "芃芃黍苗花，吹落不結子。", "老農悲不穫，飛鳥喜自恣。", "雖難答天恩，願天投木李。"]'),
('2f9777ac-3f81-4ed3-802d-4fc8a7752a9c','廌寓龍興仁王佛舍德麟公定道輔仲寶携酒肴納凉聯句十六韵','李廌','宋','宋诗','song-poetry','','[]','宿雨旦初霽，微凉吹廣庭。',192,'全唐诗/poet.song.67000.json','["宿雨旦初霽，微凉吹廣庭。", "嘉賓忽相遇，午夢驚扣扃。", "長松森翠影，修竹參青冥。", "飄雲度空急，殘日穿林明。", "幽牆隔江浦，遠嶼定風舲。", "城市厭煩暑，山樊念伶俜。", "角巾代公紱，草具踰侯鯖。", "園實摘的皪，厨醖斟晶熒。", "烹鮮縮頸大，海錯著器腥。", "笑談得真樂，採擷逢幽馨。", "雲陰剝初霽，夕嵐收遠青。", "窗卧憶元亮，詩成懷景升。", "日須河朔飲，當解高陽酲。", "煩襟頓忘釋，嘉詠不少停。", "闉闍發嚴鼓，穹碧垂繁星。", "一笑跨鞍去，奚論楚人醒。"]'),
('36ea536d-8524-46bb-9488-2bdf56677827','啄木鳥','李廌','宋','宋诗','song-poetry','','[]','小蟲蠹堅木，自意吻頰剛。',120,'全唐诗/poet.song.67000.json','["小蟲蠹堅木，自意吻頰剛。", "蟠身宅幽竇，心期千歲藏。", "爾非虎而翼，何乃巧取將。", "剝啄繞樹腹，卷舌利鈎芒。", "一身禍衆命，曾未厭饑吭。", "流怨入胡琴，美人借餘商。", "鵜鴂相唯和，次第歇芬芳。", "吾生獨何事，有喙三尺長。", "富歲常苦饑，不能饜糟糠。", "寧饑忍效汝，豈復思隨陽。"]'),
('937cd833-a70f-4eeb-a3a5-607b48b917d0','己卯春許昌湖上酬王實仲弓作','李廌','宋','宋诗','song-poetry','','[]','紫荷媚曲塘，青秧舞平畦。',36,'全唐诗/poet.song.67000.json','["紫荷媚曲塘，青秧舞平畦。", "晨光泫晞露，衆木含華滋。", "咸驚物外慕，歸休及良時。"]'),
('8d8a4013-beb4-4bf8-857d-c41520e60eb2','封禪碑','李廌','宋','宋诗','song-poetry','','[]','魏公如管仲，封禪止文皇。',36,'全唐诗/poet.song.67000.json','["魏公如管仲，封禪止文皇。", "侈心晚猶在，厥婦故敢猖。", "誣彼七十君，哀哉爲民殃。"]'),
('85402d9c-27cf-4543-9dcb-321e5b957230','文選樓','李廌','宋','宋诗','song-poetry','','[]','申轅應楚聘，鄒枚適梁苑。',84,'全唐诗/poet.song.67000.json','["申轅應楚聘，鄒枚適梁苑。", "藩侯喜賓客，賢賢易鷹犬。", "黄綺遊漢廷，羽翼矰繳遠。", "秦府十八公，攀附名益顯。", "昭明衆才子，文囿俾蒐選。", "高齋切浮雲，雉堞俯晴巘。", "尚應媿河間，筆削非大典。"]'),
('7cf924ee-e438-4c60-a868-f4bea4d0a844','汝州王學士射弓行','李廌','宋','宋诗','song-poetry','','[]','汝陽使君如孫武，文章絕人喜軍旅。',384,'全唐诗/poet.song.67000.json','["汝陽使君如孫武，文章絕人喜軍旅。", "要知談笑能治兵，戲教紅粧樂營女。", "白㲲新袍錦臂鞲，條脫掛弓腰白羽。", "綵錯旌旗照地明，傍花映柳陳部伍。", "須臾觀者如堵牆，彷彿如臨矍相圃。", "一人中的萬人呼，絲管呶嘈間鉦鼓。", "臂弓上爲使君壽，遍及四筵樂具舉。", "使君一笑萬衆喜，堂上酒行堂下舞。", "錦段銀荷翠玉鈿，意氣揚揚皆自許。", "儻令被甲執蛇矛，恐可橫行擒贊普。", "大勝吳宮申令嚴，兩隊宮娃啼且怖。", "闔閭臺上呼罷休，將軍雖賢亦觕鹵。", "豈知使君不忘戰，聊以戎容娛罇俎。", "夕陽卷旗去翩翩，使君要客登畫船。", "美人不暇別粧洗，戰士結束圍華筵。", "皆疑征南漢將帥，樓船下瀨方凱還。", "軍中不應有女子，偏裨校尉何其儇。", "使君湖光照樓觀，一碧不辨水與天。", "漸看暝色著疏柳，已見白蘋浮暮烟。", "銀漢斜橫北斗淡，明月碧玉疏星聯。", "舟人罷唱時弄笛，艇子趁魚行扣舷。", "隔浦熒熒見漁火，意中竹籬青旆懸。", "雖無荻花與楓葉，全似送客湓江壖。", "亟令周娘作新曲，周娘琵琶京洛傳。"]'),
('16ad7e1b-9251-41ff-9172-6640608fc18f','題郭功甫詩卷','李廌','宋','宋诗','song-poetry','','[]','山人跨魚天上來，識者珍重愚者猜。',384,'全唐诗/poet.song.67000.json','["山人跨魚天上來，識者珍重愚者猜。", "或呼文舉異童子，林宗獨謂王佐材。", "蚩蚩衆目如瞽矇，白馬羽雪皆皚皚。", "古有仁賢不愚者，舉足疐路心徘徊。", "桐城明府住姑孰，襟裾蕭灑天與才。", "讒言屢改耻自雪，政事報成羞援媒。", "臨川先生久知己，十年執政居公台。", "橫飛後生盡豪俊，往往拔越自草萊。", "洪爐造化豈一端，如何不與珽填坯。", "盛朝能詩可屈指，少師僕射蘇與梅。", "少師新爲地下客，蘇梅骨化成塵灰。", "金陵僕射今已老，班班絲雪侵頤腮。", "當今儒生迂此道，如使杞柳爲棬杯。", "好古愛詩惟有君，獨使筆力驚風雷。", "清音繞齒嚼鳴玉，爛光滿紙如瓊瑰。", "古原夜燒光奪月，立使萬物有灰煤。", "清泉潄石白鑿鑿，湍落急瀨成淵洄。", "才雄句險駭人膽，九月秋水灧澦堆。", "有時清貞叩玄關，至誠直可歆郊禖。", "公才穎栗公望異，牢落下位命何乖。", "豈無白虹夜貫斗，猶使寶劍豐城埋。", "幾年令尉困下國，板簡青衫趨郡階。", "猶將富貴委脫轂，苟不知命安爲懷。", "竹溪逸人杜陵翁，當年得意稱壯哉。"]'),
('d5f71077-1190-46a7-92fc-8ac23bc1abcf','三月三日','李廌','宋','宋诗','song-poetry','','[]','柳眼脫殻花將飛，麥梢弄黄青穗肥。',64,'全唐诗/poet.song.67000.json','["柳眼脫殻花將飛，麥梢弄黄青穗肥。", "鵓鴣翩翩避舟去，燕泥悞落沾人衣。", "樹外浮陽湖水淥，漠漠不動含晴暉。", "沙暖浴鳬遺翠羽，岸深老蚌吐明璣。"]'),
('dd4baeba-0771-4f32-bc20-9f00d301ce1c','黄河','李廌','宋','宋诗','song-poetry','','[]','昔我初爲入秦客，殘雪埋關閉長陌。',96,'全唐诗/poet.song.67000.json','["昔我初爲入秦客，殘雪埋關閉長陌。", "黄河二月凍初銷，萬里凌澌流劍戟。", "西風細卷浪花催，日射寒光明瑟瑟。", "歸時細雨正溟濛，冷落關河已秋色。", "驚沙慘慘塞雲黄，遠樹昏昏秋水白。", "濟川壯志愈衰遲，日送烟波問河伯。"]'),
('b3bfd707-05c7-4672-b57d-24e5725a051e','自陝州渡黄河歌','李廌','宋','宋诗','song-poetry','','[]','流浪滄浪二十年，三江五湖一釣船。',124,'全唐诗/poet.song.67000.json','["流浪滄浪二十年，三江五湖一釣船。", "江神海若諳忠信，此身常在蛟龍淵。", "欲渡黄河濱，小兒語相玩。", "鯨鯢嗜人正饕餮，忠信難憑彼方悍。", "我嘗夜泛子胥灣，錢塘大浪如銀山。", "崇明海門水如墨，况此相望一葦間。", "爲吾鼓槳爲君歌，氣凌河伯驚黿鼉。", "醉披紫綺傲風波，濟川遲暮奈天何。"]'),
('0a424a7c-358d-4e49-a3d1-6044c3c06623','上林道','李廌','宋','宋诗','song-poetry','','[]','憶昔驅車度函谷，解鞍訪古驪山麓。',80,'全唐诗/poet.song.67000.json','["憶昔驅車度函谷，解鞍訪古驪山麓。", "華清雖有亡國恨，繡嶺猶存舊時木。", "無情草木競爭春，不問興亡自紅綠。", "漢家上林更蕭瑟，宮殿荒基走麋鹿。", "可憐喬木亦已無，五柞長楊今樸樕。"]'),
('55d07e50-2c25-4fb7-a839-991c6fffed33','琴臺','李廌','宋','宋诗','song-poetry','','[]','廣陵散成不忍傳，淵明援琴葛爲弦。',96,'全唐诗/poet.song.67000.json','["廣陵散成不忍傳，淵明援琴葛爲弦。", "乃知此樂潜聖賢，直與天地通其玄。", "我兄能琴人所先，我非知音知自然。", "或聞一曲山月前，輕颺如坐春水船。", "逆隨河源上青天，口膠不語生醴泉。", "鼓舞和氣如陶埏，至樂默默坐忘年。"]'),
('a0dd276b-ec19-4c0f-8dfb-e3a88fbf6390','少華山','李廌','宋','宋诗','song-poetry','','[]','少華連延翠烟永，細路緣雲上高頂。',128,'全唐诗/poet.song.67000.json','["少華連延翠烟永，細路緣雲上高頂。", "奇峰西奔入秦蜀，幽谷南通接荆郢。", "昔年蛟龍忽變化，怒蹙山巔壓州境。", "山靈吐怪助豪彊，地軸狂推如轉梗。", "盤龍七社萬戶餘，卵覆巢傾伸臂猛。", "近來又說神羊嶺，六里橫開罅如井。", "居民惴惴已憂疑，惟恐蛟龍怒還逞。", "勿令岸谷復顛移，鼓鑄神功煩禹鼎。"]'),
('e828208f-7866-4800-8878-09d301669a7b','回心嶺','李廌','宋','宋诗','song-poetry','','[]','萬仞嵩峰接天遠，妖武登封艱步輦。',96,'全唐诗/poet.song.67000.json','["萬仞嵩峰接天遠，妖武登封艱步輦。", "初登峻嶺已回心，何事艱難能黽勉。", "亦似徽之泛剡溪，想見王陽臨蜀坂。", "老子山林興不淺，興盡中塗猶欲返。", "古人戒在末路難，九十常爲百里半。", "世上風波更可憎，心不可回聊自勸。"]'),
('a023daba-ae7a-4fdd-aa07-75da161cd3b3','次韵答張誾張閣見寄','李廌','宋','宋诗','song-poetry','','[]','我思佳人在何許，太行之陽濟川上。',162,'全唐诗/poet.song.67000.json','["我思佳人在何許，太行之陽濟川上。", "結茆賦詩臨清流，我情摇摇日西嚮。", "盤谷秋來陰復晴，谷口與誰來耦耕。", "賣刀買犢便能爾，功名付之勃與平。", "嗟余追逐老閭里，吟詩作賦不直水。", "韋編鉛槧幸忘憂，甘與牛衣同卧起。", "相從當及壯年時，莫年多感定多悲。", "此身安歸送歸客，豈堪登臨行路岐。", "萬事紛紛戰蠻觸，不須白眼憎時俗。", "但願如公無榮亦無辱，臨流賦詩老亦足。"]'),
('5e70ef8e-55e0-4501-ae07-3b3d9cb8946f','田舍女','李廌','宋','宋诗','song-poetry','','[]','田家女兒不識羞，草花竹葉插滿頭。',96,'全唐诗/poet.song.67000.json','["田家女兒不識羞，草花竹葉插滿頭。", "紅眉紫襜青絹襖，領頸麤糙流黑油。", "日午擔禾上場曬，也喜年豐欲還債。", "傭工出力當一男，長大過笄不會拜。", "有者四十猶無家，東村定昏來送茶。", "翁嫗喫茶不肯嫁，今年種稻留踏車。"]'),
('a45b8096-f8b1-4caf-8661-69a11cea5946','蚩蚩','李廌','宋','宋诗','song-poetry','','[]','氓之蚩蚩不足數，四月五月濛鬆雨。',32,'全唐诗/poet.song.67000.json','["氓之蚩蚩不足數，四月五月濛鬆雨。", "閉門縣榻二十年，不見孺子與文舉。"]'),
('f49fe448-c7c2-4c00-bc65-854098d444b5','趙令畤德麟作襄陽從事丁丑季冬出行南山三邑某同謝公定曾仲成潘仲寶携酒自大悲寺登舟過峴山宿鹿門明日復自峴首目送緣絕壁而往上船山下相與酌酒而去德麟賦詩次韵和之','李廌','宋','宋诗','song-poetry','','[]','鄒湛葛疆往過此，幕中佐曹畏簡書。',256,'全唐诗/poet.song.67000.json','["鄒湛葛疆往過此，幕中佐曹畏簡書。", "習池峴首自今古，故時悲喜成空虛。", "越王之孫府從事，惡人亦作俗吏呼。", "日從雲間二三子，醉吟嘯傲相携扶。", "王孫才高倦羈束，濕紙詎可包於菟。", "興來鼓櫂碧江去，把酒賦詩聊與娛。", "野人相逄荷傾蓋，坐上作客慚食魚。", "紅塵化衣對玉樹，白髮茁鬚如霜蕪。", "飽聞襄陽好風土，喜見山水相盤紆。", "久憐消髀厭羈旅，便欲卜隠如林逋。", "著書雖可自覆醤，志怪猶爲鬼董狐。", "茲游起我丘壑興，豈復自爲形迹拘。", "山中一廛可托足，裘葛略具便有餘。", "結茆耒耜老巖谷，豈學少室隨駕盧。", "老妻汲澗芼葵蕨，丁男負芻仍掃除。", "諸公富貴或肯顧，結駟野服來吾居。"]'),
('991e2a9b-022d-4b27-8f2b-5246b617406a','謝公定所寶蕃客入朝圖貞觀中閻立本所作筆墨奇古許贈趙德麟而未予廌作此詩取以送德麟','李廌','宋','宋诗','song-poetry','','[]','君不見燕然易水波桑乾，東連鴨綠西賀蘭。',355,'全唐诗/poet.song.67000.json','["君不見燕然易水波桑乾，東連鴨綠西賀蘭。", "古來戰地骨成土，赤棘白草沙漫漫。", "漢築朔方置上郡，晚歲欵塞惟呼韓。", "貞觀文皇力馴制，諸蕃君長充王官。", "玉門不關障無候，驛道入參天可汗。", "蠻夷邸中諸國使，旃裘椎髻游長安。", "我恨不爲典屬國，望古遙集真可歎。", "今觀此圖寫職貢，要荒種落蒙衣冠。", "獸蹄鳥喙或鬼色，想見膜拜皆盤跚。", "聖朝賢良謝夫子，勁氣烈烈霜風寒。", "目眵脣焦萬卷爛，筆頭成塚墨成灘。", "南陽勸駕一封傳，入對三道朝金鑾。", "萬言階對萬乘喜，聲名一日青雲端。", "行當遨遊廟堂上，坐令四國相交歡。", "羽書不馳烽火冷，鳴雞吠犬何敢干。", "借令跳梁出巢穴，當用斧斤摧髀髖。", "戎亭喋血無噍類，藁街縣首如狐貛。", "君當自畫凌烟閣，縱有此圖何必觀。", "同僚華原貴公子，求公此畫公無難。", "乃知功名丈夫志，不惑玩好勞肺肝。", "憐渠孜孜畫成癖，心欲速得如羽翰。", "不如遣佐篋中品，猶勝棄捐終不看。"]'),
('6d3452c7-f2cd-4a19-8cea-9333f1de0d85','德麟自南邑至酇相會作詩次其韵','李廌','宋','宋诗','song-poetry','','[]','脂車欲入南山路，馬首忽西真有數。',128,'全唐诗/poet.song.67000.json','["脂車欲入南山路，馬首忽西真有數。", "此生兀兀老江山，曩事紛紛過風雨。", "君行嶺上正穿雲，我向津頭欲呼渡。", "石門秀絕冠荆楚，萬壑千巖供指顧。", "赴澗哀泉咽復流，出岫閒雲散還聚。", "遙應寫懷遠憐我，瘦馬饑童傍江霧。", "平時追隨若形影，異縣相望忽如許。", "他年兩翁各賦歸，思山便可拏舟去。"]'),
('a5fd373d-5b91-458c-9620-f66b8b3c3dc7','千齡檜','李廌','宋','宋诗','song-poetry','','[]','岡頭老檜不記年，古父約以千齡傳。',128,'全唐诗/poet.song.67000.json','["岡頭老檜不記年，古父約以千齡傳。", "高枝凌兢倚北斗，低枝猶藏萬歲烟。", "蟠根直與地爭固，不許蚓穴通黄泉。", "陰森古怪神物附，雨晦每見蛟龍騫。", "賢哉樂天真逸者，手植蒼檜今宛然。", "元和元豐五十紀，婆娑下委纔及肩。", "信此千齡尚虛云，幾見海變丘陵遷。", "乃知不爲斤斧夭，不在澗底與山巔。"]'),
('f88c41fe-d3ab-4239-9562-39a6ad0163fd','鼎足檜','李廌','宋','宋诗','song-poetry','','[]','巨根盤亙幾百尺，高幹植立參天長。',128,'全唐诗/poet.song.67000.json','["巨根盤亙幾百尺，高幹植立參天長。", "蕭蕭氣清霜月白，雲根桂子飄秋香。", "松陵高士風骨奇，灑然臨流傲滄浪。", "油雲委地墨欲滴，霾風拂雨炎天凉。", "酇留執策信秉鉞，軍中舞劍語激昂。", "幽林俯見皆樸樕，反視茂質獨蒼蒼。", "樂圃先生最珍玩，如神偉象豈等常。", "夢松蓋有三公兆，蒼檜鼎峙寧非祥。"]'),
('c0dceae5-cb2b-41ae-8b76-6ef7e3300cca','樛枝檜','李廌','宋','宋诗','song-poetry','','[]','檜今老矣何兢兢，樛枝下屈如不勝。',88,'全唐诗/poet.song.67000.json','["檜今老矣何兢兢，樛枝下屈如不勝。", "左松右栢非爾朋，繁霜茂雪徒驕矜。", "鞠躬不敢騫其肱，午陰凄凄綠鬅鬙。", "六月爽氣飛秋冰，縈紆茂密羅附藤。", "猿猱臂絕愁難升，老龍銜雨將飛騰，矯首欲舉逄饑鵬。"]'),
('c7780d5c-fd62-4028-899b-dcd531f18def','題王摩詰曲江春遊圖','李廌','宋','宋诗','song-poetry','','[]','咸雍山河互王霸，涇渭爲隍城塹華。',208,'全唐诗/poet.song.67000.json','["咸雍山河互王霸，涇渭爲隍城塹華。", "曲江臺沼備豫游，秪與畫師供入畫。", "長安城西山萬重，昆明烟浪繞新宮。", "新蒲細柳春風裏，萬戶千門佳氣中。", "我生不及開元時，猶喜此圖今見之。", "蒼莽烟綃橫短幅，眼中終南倒溪淥。", "傾城士女巷無人，三月三時曲江曲。", "老稚妍媸賤或貴，來者携壺歸者醉。", "筆端造化有能事，各肖人人樂遊意。", "如今此地空塵迹，石鯨縱在如銅狄。", "宜春五柞更蕭條，無復榛中得遺甓。", "我願吾王明六符，不蹈漢唐耳目娛。", "池籞假民任畋漁，無令畫師爲畫圖。"]'),
('5f3b0187-eb15-47f0-980d-5ff719537d81','王實洗兒歌','李廌','宋','宋诗','song-poetry','','[]','昔聞吉夢占羆熊，今見得子如阿戎。',96,'全唐诗/poet.song.67000.json','["昔聞吉夢占羆熊，今見得子如阿戎。", "先正舉世稱至忠，垂慶百世皆萬鍾。", "山川秀氣久結融，今復俾君生此雄。", "五侯七貂十八公，當有八元爲八龍。", "愧我塵埃非太真，難使此兒名作溫。", "勸君大作容駟門，作詩聊代添金盆。"]'),
('3f5794da-308f-46a8-aa87-14d935d01ddd','盧泉之水次韵晁克民贈隠人','李廌','宋','宋诗','song-poetry','','[]','盧泉之水名何長，裂臍不到空莽蒼。',96,'全唐诗/poet.song.67000.json','["盧泉之水名何長，裂臍不到空莽蒼。", "讀君詩句心已凉，便覺滿耳清浪浪。", "彼方逐臭如竊香，肝膈鼠飽神鷹揚。", "有客飲水衣朝陽，睥睨不語中何傷。", "過從得君想更樂，直欲造化窮微茫。", "何當相從老此水，桀跖夷齊均是死。"]'),
('407eb676-1c1e-499a-9b2a-e37eb9afedc1','邊城四時曲送盛瑋東玉之官平凉','李廌','宋','宋诗','song-poetry','','[]','邊城冬，日日黄埃飛朔風。',76,'全唐诗/poet.song.67000.json','["邊城冬，日日黄埃飛朔風。", "葱嶺雪深埋古道，河岸冰厚與天通。", "可汗牙帳青海東，壯士卷甲趨奇功。", "公孫卿材名將種，橫槊賦詩海濤湧。", "作吏宜思故家勇，早取靈鹽隸秦隴。"]'),
('92925dd9-c39a-41d3-808f-1b158ff8c5be','詠齋詩','李廌','宋','宋诗','song-poetry','','[]','古昔詩客長風騷，雲間野鶴鳴九皋。',144,'全唐诗/poet.song.67000.json','["古昔詩客長風騷，雲間野鶴鳴九皋。", "六丁極天十萬遭，攝提執策窮牛毛。", "玄珠罔象誰能及，或長壯麗稱雄豪。", "九原殺氣橫天高，朔風吹雪沾霜刀。", "銜枚束甲夜渡洮，軍中壯士秉白旄。", "忿怒不可拔一毫，白狐幾腋成一袍。", "東溟一釣連六鼇，二長不同各有勞。", "吟咏至審公譏褒，詠齋之樂真陶陶。", "君毋獨樂愈自高，亦當以手援兒曹。"]'),
('27939132-773e-4902-811b-fd0de43426be','寄楊十三虞卿','李廌','宋','宋诗','song-poetry','','[]','前年君去時，覆水坳堂中。',88,'全唐诗/poet.song.67000.json','["前年君去時，覆水坳堂中。", "三年君不歸，昨夜風雨驚破屋，不知生蛟龍。", "壯士恥隠忍，拔劍刺潰癰。", "三杯然諾許君死，魚腹置匕首，直入吳王宮。", "扼鐔靂火飛，吐氣成長虹。", "義名如皦日，英氣凌秋風。"]'),
('831f957b-f223-4047-bda3-2504632fa57c','秦覯少章寄寂齋','李廌','宋','宋诗','song-poetry','','[]','臣門如市心如水，漢宮解識尚書履。',96,'全唐诗/poet.song.67000.json','["臣門如市心如水，漢宮解識尚書履。", "形若槁木心死灰，東郭子綦初隠几。", "明珠走盤丸走坂，性不遷遷常止止。", "蚍蜉戰聲如雷霆，渠自紛紛相我爾。", "達人大觀觀萬有，區中狹隘真一瞇。", "磨堅涅白自古然，不必飲牛憎洗耳。"]'),
('d1c8990b-0cfd-4457-8df6-4a70053fb439','無渡河','李廌','宋','宋诗','song-poetry','','[]','無渡河，無渡河，中有龍門之雪浪，天池之洪波。',94,'全唐诗/poet.song.67000.json','["無渡河，無渡河，中有龍門之雪浪，天池之洪波。", "上有碧崖之岌嶪，下有暗石之嵯峨。", "蛙蚓得志相譏訶，况復龍蜃與黿鼉。", "崇朝一舍即我郊，黎民一葦平可過。", "無渡河，無渡河，招招舟子不足信，彼亡維楫將奈何。"]'),
('183a3e70-0180-4548-83c1-344013a6043e','自山中歸至登封遂諷高宰令取峻極中院厨前石鐘板蓋唐人寺記字甚奇麗也','李廌','宋','宋诗','song-poetry','','[]','吳砧已碎樂生論，京江昔沈瘞鶴銘。',272,'全唐诗/poet.song.67000.json','["吳砧已碎樂生論，京江昔沈瘞鶴銘。", "半裁紫陽立砆石，考擊化度求金籯。", "乃知金石有厄會，名碑舊疊長安城。", "頃年醴泉有賢令，政譽藹藹多流馨。", "爲憐文星足人傑，昔皆祔葬陪昭陵。", "壞垣糞壤得顔碣，榛丘棘壠求魏徵。", "史訛遂正沖遠字，石闕再樹六駿形。", "板圖列籍示過客，龜趺螭首羅齊廷。", "後來謬令類俗子，輒去其籍人皆懲。", "昔到般舟訪遺跡，季海寺記今彫零。", "曉聞晨鐘呼僧粥，石磬嘹亮穿雲清。", "往觀乃是唐短碣，大窮索縛乘前楹。", "字形崢嶸筆蕭散，遠過名殿諸題經。", "勸僧拂拭置高壁，安知野僧不我聽。", "十年再游尚如昔，擊拊刻劃將俱平。", "急歸入城諷縣令，立使舁至無久停。", "此碑復立非我力，奇物久廢天須興。"]'),
('02b5c148-1fa7-450c-9af0-581abd2b849e','有懷都下寒食','李廌','宋','宋诗','song-poetry','','[]','上國茲晨每豫遊，仙仗繚繞來瀛洲。',128,'全唐诗/poet.song.67000.json','["上國茲晨每豫遊，仙仗繚繞來瀛洲。", "天王高御寶津樓，侍臣壁立環諸侯。", "簫韶引風摇樹羽，晴波飛影動宸旒。", "闌干仙人深霧縠，樓前彩纜繫龍舟。", "錦標霞舉奪日精，萬楫競渡馳蛟虬。", "天顔一解四海春，樂歲已忘凶年憂。", "况今持盈戒欹器，不使逸豫常從流。", "錦帆高張亦佳耳，清汴東注貫揚州。"]'),
('404aa3de-dff4-4a72-9236-7e0df8f5814d','真君觀','李廌','宋','宋诗','song-poetry','','[]','嵩山勝地神仙宅，真君獨作嵩山伯。',112,'全唐诗/poet.song.67000.json','["嵩山勝地神仙宅，真君獨作嵩山伯。", "昔聞解職扣帝閽，厭此塵寰年已百。", "天上百年一瞬間，下土衮衮多腥羶。", "勞神應念日月走，瞑目深哀膏火然。", "潘公欲代復誰舉，仙籍題名今幾傳。", "憶昔元豐己未遊，僊泉猶作雨深湫。", "十年新事還堪笑，廟貌今祠靈惠侯。"]'),
('a30363be-7307-49e9-a4e1-05c3c4db57a1','經史閣','李廌','宋','宋诗','song-poetry','','[]','隠君扁舟離五湖，初聞邑子驚陶朱。',176,'全唐诗/poet.song.67000.json','["隠君扁舟離五湖，初聞邑子驚陶朱。", "多金不用五㹀術，高閣惟藏萬卷書。", "牙籤玉軸比四庫，縹帙錦囊過五車。", "河間闕遺應復購，汲冢蠹簡嗟無餘。", "碧山學士解傳業，黄卷古人相與居。", "謝庭芝蘭信靈秀，竇家椿桂皆芬敷。", "朱欄翠瓦照空碧，秋山晚林共扶疏。", "寒溪送月出幽谷，白雲因風生坐隅。", "道山三館限清禁，山中此樂彼所無。", "異時聯華陟嚴近，白虎東觀文石渠。", "願待善本校中祕，毋令後儒爭魯魚。"]'),
('5b22d712-1c3b-4153-9505-49edc2d799fd','求茶戲丘公美','李廌','宋','宋诗','song-poetry','','[]','公美方自靈隠來，面上灰土衣塵埃。',105,'全唐诗/poet.song.67000.json','["公美方自靈隠來，面上灰土衣塵埃。", "自言夜借僧榻眠，白日買酒不惜錢。", "半月等得頭水茶，欲求善價先還家。", "君不見邊孝先，瞌睡晝多眠。", "點茶追清興，誠與真性便。", "聞君結交素奇偉，朋友須求無逆意。", "苟惠上品一斤來，庶全見利而思義。"]'),
('afad2486-12a7-44af-a6f8-06013e7e7691','王彥溫多恕許惠葉縣石方尊將以貯酒作詩取之','李廌','宋','宋诗','song-poetry','','[]','葉山堅石如水蒼，斲爲大尊重且方。',96,'全唐诗/poet.song.67000.json','["葉山堅石如水蒼，斲爲大尊重且方。", "斟酌胡能問罍恥，獻酬不解隨觶揚。", "勿言研材用非稱，麴糵文章皆伐性。", "請看毛穎不中書，寧及時時一中聖。", "月巖老子飲山村，但惜田家老瓦盆。", "已刳匏瓜代杯飲，願君持此比窊尊。"]'),
('4e68a8a6-db30-4966-8644-1ef3991ff21a','相逢行','李廌','宋','宋诗','song-poetry','','[]','平生不爲輕薄遊，故亦未作相逢行。',251,'全唐诗/poet.song.67000.json','["平生不爲輕薄遊，故亦未作相逢行。", "尋常木彊畏犯義，直欲端彥規後生。", "有客性不羈，謂我何泥固。", "太上立德次立功，癡兒乃爲功名悞。", "顔回窮凍終何成，東山餓夫適自苦。", "君不見白楊依依北邙墓，斷碣滅裂礙行路。", "髑髏物化今何爲，劍鉞雖存委爲土，癡兒胡爲不早悟。", "我聞是言笑不顧，摳衣布武出門去。", "杳如乘鸞向烟霧，精神流離不自據。", "想像彷彿若神遇，果見姣姬拾翠羽。", "縠袂障日揚輕素，芙蕖倒影碧波媚，薄雲映日光未吐。", "冶容異公行，聯娟美無度。", "驚翩翩，下烟渚。", "游翔嫷，將高舉。", "爲憐牽牛久獨處，欲解明璫贈交甫。", "臨行惠我不語意，定駕星軿爲暮雨。"]'),
('668031f1-4f1c-4ac2-b334-f06c00d37b77','崇福宮','李廌','宋','宋诗','song-poetry','','[]','上都太一臨天街，千乘萬騎頻往迴。',112,'全唐诗/poet.song.67000.json','["上都太一臨天街，千乘萬騎頻往迴。", "神崧太一古所治，曷日屬車游豫來。", "昔年章聖奉玄寂，離宮萬堵臨崔嵬。", "定陵弓劍隔重嶺，金碧渝暗翬鴛摧。", "重門銅獸閉永日，靈囿御坐生蒼苔。", "達官乞開奉祠事，肉食罔知真可咍。", "小臣作詩非望幸，欲寫萬壑松風哀。"]'),
('898b5221-4517-43dd-b2e5-f44147e5847c','壁間所掛山水圖','李廌','宋','宋诗','song-poetry','','[]','老驥無能空在閑，苜蓿既飽思行山。',128,'全唐诗/poet.song.67000.json','["老驥無能空在閑，苜蓿既飽思行山。", "誰知八幅分向背，恍如百里隨躋攀。", "雲烟濛濛心共遠，草樹陰陰日將晚。", "一聲幽鳥隔前溪，萬古回春來疊巘。", "凉風彷彿飛清霜，奉身九折思王陽。", "嗟我胡爲不自愛，逐物顛倒輕餘光。", "瓜籬活計知何日，相對無言搔短髮。", "芒鞋竹杖請自在，皎皎吾身真匪石。"]'),
('f4e0283b-e5fd-4d0e-be4a-48e813b9a667','聞角歎','李廌','宋','宋诗','song-poetry','','[]','晚角吟，聲正悲。',177,'全唐诗/poet.song.67000.json','["晚角吟，聲正悲。", "嗟爾行道遲遲兮中心有違，女心憂傷之人未歸。", "臨岐滿掬淚，輕埃變污泥，壯夫安爾爲。", "日月挂兩臆，厲聲長嗟咨。", "噫吁嘻！季世無良臣，禦戎無上策。", "輔桀盜貨財，稽功數俘馘。", "安知閟國步，且要高官職。", "勇如漢將軍，詭道作無益。", "角本胡地樂，相聞地遼邈。", "漢家豈無大呂與黄鐘，豈無鼙鼓與鉦鐲。", "且欲震軍聲，安用胡地角。", "胡不嚴，秋關弓。", "莫使胡人來，莫使琵琶之聲過河朔。"]'),
('4c6d9792-be43-477e-818f-25be62c2f459','作塞上射獵行','李廌','宋','宋诗','song-poetry','','[]','塞雲委地如潑墨，惡風吹沙變黄黑。',309,'全唐诗/poet.song.67000.json','["塞雲委地如潑墨，惡風吹沙變黄黑。", "紫髯將軍柳葉甲，銀騣護闌白玉勒。", "鐵林子弟八九千，飲馬渡橋過河北。", "沙漠黓地古戰場，寸草不生地皮赤。", "將軍指呼令鼓鼙，旌旆悠悠動堅壁。", "壯夫露股挾纊溫，蕃馬鞘脚寒有力。", "龜手荷戈指欲墜，氣結冰凌滿須歷。", "前驅蕭蕭近林翳，軍聲業業震金革。", "怪狐跳梁罔兩避，虎豹驚駭喪膽魄。", "山根淺草枯槎枒，隠隠葉下見兔跡。", "武夫張罝四散逐，雙兔雌雄中金鏑。", "自云舍矢不失馳，手持雙兔有德色。", "凱旋如殪大兕歸，喜非詭遇無所獲。", "常聞武功貴時習，忘戰必危欲定國。", "蒐田以時選車徒，士卒素練務嚴翼。", "季冬物成農事休，民閒庶類亦蕃殖。", "泮上虎臣獻俘馘，淮夷攸服遠人格。", "悲夫王澤寖熄多鬼蜮，蒙恬白起爲民賊。", "君不見長平鬼哭萬人塚，擊破秦坑髑髏白。"]'),
('77ae8435-1a68-4a7b-83c6-fd3ae76789c5','贈卜者張生歌張歷陽人也','李廌','宋','宋诗','song-poetry','','[]','我憶扁舟昔南渡，江心忽值蛟龍怒。',384,'全唐诗/poet.song.67000.json','["我憶扁舟昔南渡，江心忽值蛟龍怒。", "大浪崩騰舞我舟，尾脅蜿蜒束吾櫓。", "怒聲如雷雷火烈，腥風鼓天天如霧。", "我觀蛟龍等一戲，衆面倉惶獨無怖。", "平生忠信天自知，死葬江魚未應悞。", "須臾水天碧鏡浄，順風入帆風若御。", "歷陽古岸艤荒亭，寒雲澹澹依江樹。", "江南山水天下奇，更在江山奇險處。", "朱門玉窗带青嶂，想見君家傍烟嶼。", "我今西來二十年，夢寐江南見幽趣。", "夫君何爲抱奇術，輕去故鄉踏長路。", "胸中秀氣未甘蟄，欲繼君平齊季主。", "術高不肯等閑售，惟喜遨遊卜卿輔。", "爾來山郭坐空館，憐我困窮爲推數。", "閱人多矣君自信，歸去來兮余已悟。", "少年飛動已知非，老來憂患寧堪顧。", "壯時猶愧不如人，豈復衰殘彊馳騖。", "儻來軒冕任去留，縱有功名逼遲暮。", "箕山之陰潁水湄，二頃荒田安𤱶畝。", "曲肱飲水吾自樂，乘堅齒肥烏足慕。", "吾生貧賤吾自知，不解脅肩求貴富。", "我如富貴當蚤得，已可通侯封萬戶。", "惟有退身可自如，造物哀憐應不拒。", "扁舟常繫屋南溪，會當乘興江南去。"]'),
('e7727ec9-f7e7-40b3-b392-35114aa4a3af','胡爲乎行贈丘公美','李廌','宋','宋诗','song-poetry','','[]','吁嗟憧憧之民兮，何終身不靈耶。',163,'全唐诗/poet.song.67000.json','["吁嗟憧憧之民兮，何終身不靈耶。", "不能揮毫縻青天耀白日，胡爲乎布衣韋带事讀書。", "不能坐窮廬運籌算，胡爲乎騎馬試劍輕其軀。", "項籍耻作百夫勇，禹行舜趣猶賤儒。", "憊乎四支愁五臟，不能成功竟何如，胡爲乎直待臨老空嗟吁。", "盍歸乎來，盍歸乎來。", "長橋繫白鯉，擺尾向天台。", "風流李北海，雄望摩九垓。", "長卿向窮時，尚爲臨邛咍。", "北邙古墓空蒿萊，胡爲乎須上黄金臺。"]'),
('78d2986b-dcb1-4f5a-9668-ba10cfa4f6fd','趙德麟中秋生日','李廌','宋','宋诗','song-poetry','','[]','中秋月，風露凄清光倍潔。',296,'全唐诗/poet.song.67000.json','["中秋月，風露凄清光倍潔。", "皓氣澄霄萬象沉，孤光散彩繁星滅。", "中秋潮，江海鯨波此日高。", "倒卷東溟蕩平陸，逆撼九江翻怒濤。", "治平初年歲執徐，越王國邸生英儒。", "虎腰燕頷巖電目，鳳準犀顱冰雪膚。", "九天月華爲爽氣，識照古今窺聖秘。", "胸中洞達不容塵，瑩似太華無滓濊。", "浙江潮頭爲駿聲，名滿宇縣高崢嶸。", "詞源落筆波濤動，馮夷陽侯皆震驚。", "裕陵求人如不足，蒐選羣材起巖谷。", "網羅英雄至四海，晚獲天麟在王族。", "除書令上芸香閣，中秘校讎專筆削。", "辭榮寧作卿寺僚，外遷肯入諸侯幕。", "人嗟官冷久淹回，我知解養王佐才。", "聖朝方欲相宗室，黑頭作公坐三台。", "年年特班謝明主，寶床禮物來傍午。", "兩軍戲伎候掖門，馬首迎歸入公府。", "我雖無能世或取，尚可與君爲詔語。"]'),
('bea614d3-c004-4504-816a-b37d0edabcc6','以古畫觀音易眉子石硯歌','李廌','宋','宋诗','song-poetry','','[]','疇昔翰林蘇謫仙，溪藤寫贈眉石篇。',152,'全唐诗/poet.song.67000.json','["疇昔翰林蘇謫仙，溪藤寫贈眉石篇。", "欲尋此硯副此什，婺源烟水空茫然。", "君家寶硯多奇石，一一玄圭與蒼璧。", "此硯初來衆硯疑，厠居末品真可惜。", "寶林大士千億身，吾家古畫妙入神。", "欲持吾畫易君硯，庶幾速證西來因。", "我持君硯復何爲，嵩山之陽潁水湄。", "茹藜咀藿坐蓬蓽，潄流枕石書新詩。", "萬事推遷皆傳舍，世間孰是常存者，畫硯伊余聊稅駕。"]'),
('f10df335-4c77-4df8-87e0-a3eecfaee488','冽泉亭詩','李廌','宋','宋诗','song-poetry','','[]','古井嵌空下如屋，寒泉馥冽甘如飴。',64,'全唐诗/poet.song.67000.json','["古井嵌空下如屋，寒泉馥冽甘如飴。", "昔人傳是龍蜃窟，睡未千歲人不疑。", "雲蒸每見飛靂火，沉綆或惹髯間氂。", "安得海奴秉犀炬，乘月夜照窺端倪。"]'),
('525a0d28-082e-4698-bd35-0cf93004fea4','東湖詩','李廌','宋','宋诗','song-poetry','','[]','翠荇弄水時出沒，紫蓴浸滑涎蜿蜒。',80,'全唐诗/poet.song.67000.json','["翠荇弄水時出沒，紫蓴浸滑涎蜿蜒。", "川光遙接行潦前，野氣空闊浮寒烟。", "常思郢客解刺舡，豈解乘槎上青天。", "又思吾兒能測淵，豈能奪得驪頷蠙。", "上昇却回復入海，只恐澄海爲桑田。"]'),
('c14011c7-8c6e-4903-b0e1-d0e79ca764d6','對春二首  其一','李廌','宋','宋诗','song-poetry','','[]','半陰半晴惱亂我，不禁春意惟殢春。',80,'全唐诗/poet.song.67000.json','["半陰半晴惱亂我，不禁春意惟殢春。", "黄鶯丁寧舌初轉，楊花輕盈來弄人。", "東家鞦韆多美女，舞腰娉婷衣金縷。", "彩索徘徊漸漸高，牆頭見人羞欲住。", "柳下誰家薄媚郎，立馬昂頭不肯去。"]'),
('1a473f84-7ab0-43d0-8dfc-b7c86ab01b88','對春二首  其二','李廌','宋','宋诗','song-poetry','','[]','一點兩點催花雨，章臺走馬無塵土。',96,'全唐诗/poet.song.67000.json','["一點兩點催花雨，章臺走馬無塵土。", "少年去老能幾時，買笑金錢不須數。", "高陽酒徒多白髮，長安佳妓今老嫗。", "共君把酒莫厭多，作意彊作青春主。", "文章放行多氣焰，筆畫把捉無精神。", "願得神王如六通，日寫萬卷酬青春。"]'),
('d11b9c18-3bb4-4ba1-a57e-dfe1dca78641','某頃元祐三年春禮部不第蒙東坡先生送之以詩黄魯直諸公皆有和詩今年秋復下第將歸耕潁川輒次前韵上呈編史內翰先生及乞諸公一篇以榮林泉不勝幸甚','李廌','宋','宋诗','song-poetry','','[]','半生虛老太平日，一日不知人不識。',96,'全唐诗/poet.song.67000.json','["半生虛老太平日，一日不知人不識。", "鬢毛斑斑黑無幾，漸與布衣爲一色。", "平時功名衆所料，數奇辜負師友責。", "世爲長物窮且忍，靜看諸公樹勛德。", "欲持牛衣歸潁川，結廬抱耒箕隗前。", "祇將殘齡學農圃，試問瀛洲紫府仙。"]'),
('c9fa76b6-1053-4ce0-91ec-14dace5a756d','精思觀崔道士授劍柏中劍常吼若雷','李廌','宋','宋诗','song-poetry','','[]','陰陰老栢森庭牖，外脫中空若虛缶。',128,'全唐诗/poet.song.67000.json','["陰陰老栢森庭牖，外脫中空若虛缶。", "崔仙授劍栢遂神，劍氣騰天劍聲吼。", "頃年天師受丹訣，此地精思歲華久。", "玉函金匱發靈崖，因使陰符誣虎口。", "殿中真人道玄筆，筆妙飛揚傳不朽。", "霜髮羽人逢白叟，間歲已聞踰九九。", "神游八極吾所願，道骨仙風愧無有。", "欲賦大鵬思子微，恐爾年齡亦爲偶。"]'),
('ebbbd1b7-254d-4985-9e91-d810f862b28a','張居士歌','李廌','宋','宋诗','song-poetry','','[]','凡夫冥冥不知曉，劫塵流浪如沙掃。',272,'全唐诗/poet.song.67000.json','["凡夫冥冥不知曉，劫塵流浪如沙掃。", "上天宮闕隔青雲，九原壠墓空秋草。", "神仙有意憐下土，獨取飆車出三島。", "張翁陋巷貧且賢，簞餉瓢漿久懷寶。", "羽客飛來自何所，蓬蓽相迎笑相勞。", "高談妙理妙道本，定是青牛度關老。", "仙丹無形有真氣，一視傳靈入凡棗。", "聊分七棗遺張翁，一餌云充千歲飽。", "張公不食今幾年，齒如兒童顔色好。", "我聞神仙本無滓，諸漏皆空體玄道。", "姑射神人飲風露，淮南鷄犬依丹竈。", "真詮自然本簡易，不在勞形勤補腦。", "封山航海漫殫費，葉衣草茹空枯槁。", "况乃紛紛五濁世，粒食火化常熱惱。", "余苦風塵衰太早，綠髮蒼蒼半玄縞。", "青春堂堂暗中去，常恐餘生似潢潦。", "何當刀圭借殘齡，相與神游超八表。"]'),
('f75ae9e5-6b1f-4fae-9d5c-e246a3878362','鍾山鐘','李廌','宋','宋诗','song-poetry','','[]','延平雙劍朝豐城，鍾山之鐘挾以行。',96,'全唐诗/poet.song.67000.json','["延平雙劍朝豐城，鍾山之鐘挾以行。", "延平春浪拂天地，左右兩龍雷火鳴。", "建隆真人君八極，河伯效珍寶鐘出。", "不似汾睢發鼎光，泛泛逆流浮萬鎰。", "詔賜閶闔濯龍宮，聲掩景陽聞九重。", "吾聞此鐘亦神物，獨肯寒溪就埋沒。"]'),
('71d3c28b-da3b-4129-8e39-8695771160d5','舞陽令祝樂天再任','李廌','宋','宋诗','song-poetry','','[]','庚寅十月二十五，曉分黑帝臨丹府。',96,'全唐诗/poet.song.67000.json','["庚寅十月二十五，曉分黑帝臨丹府。", "怒來鞭掠玉麒麟，下降英靈佐明主。", "廬江從此生奇賢，便是奇人祝樂天。", "鼎沸弦歌一百里，雙鳬舞水又三年。", "部民共獻長生酒，鸞鶴莊椿只依舊。", "我詠蟠桃別有春，何須更祝人間壽。"]'),
('15665d1b-6707-488c-b2a9-59deef21e520','元祐六年夏自陽翟之睢陽迓翰林蘇公自杞放舟至宋','李廌','宋','宋诗','song-poetry','','[]','發軔嵩麓背烟巖，解維水程仍二三。',64,'全唐诗/poet.song.67000.json','["發軔嵩麓背烟巖，解維水程仍二三。", "杞邦想見舊風烈，許邑自知誠子男。", "天地憂懷真過計，文獻不足良可慚。", "放舟適未覯君子，白頭終期老江潭。"]'),
('f5d93a59-8184-42ce-9b16-b84779026593','擬楚詞','李廌','宋','宋诗','song-poetry','','[]','匠執斤兮道周，稱百尋以弗用兮谷之幽。',239,'全唐诗/poet.song.67000.json','["匠執斤兮道周，稱百尋以弗用兮谷之幽。", "屈輪囷以爲杯兮，孰謂賢於杞柳。", "揉吾性以矯真兮，寧全天以爲壽。", "樂吾樂兮，樂不汝違。", "樂不汝違兮，盍歸乎來哉。", "犀何尤兮以角累，象何咎兮齒爲災。", "童牛夭兮，職騂剛而繭栗。", "龜告猶以灼兆兮，寧泥中以曳尾。", "珠綴旒兮，悔夜光不祥。", "玉爲圭瑞兮，痛山輝之爲殃。", "樂吾樂兮，樂不汝違。", "樂不汝違兮，盍歸乎來哉。", "蘭九畹兮芬薌，芝三秀兮焜煌。", "山嵷嵷兮呈姿，川溶溶兮摇光。", "風駃駃兮歷楯，雲繽繽兮度梁。", "葯爲衣兮薜爲裳，椒爲醴兮桂爲漿。", "樂吾樂兮，樂不汝違。", "樂不汝違兮，盍歸乎來哉。"]'),
('7ef2d08b-4a29-4e81-a938-1dd51d809941','嗟美人詞','李廌','宋','宋诗','song-poetry','','[]','嗟美人兮何之，撫千祀兮增悲。',291,'全唐诗/poet.song.67000.json','["嗟美人兮何之，撫千祀兮增悲。", "咎司命之匪仁兮，弗庇下民。", "故嗇數於令人兮，俾弗儷乎常期。", "既闓端之引大，復柅止而縶維。", "仰天衢而願騁兮，羌爲惠之罔終，嗟美人兮懷思。", "閟靈修而自珍兮，寧燕婉而倚巾。", "彼鵜鴂之早鳴兮，欲衆芳之隕衰。", "亮汝懷之匪良兮，喜佳卉之具腓。", "靈芝遑恤汝以自芳兮，亦三秀而呈姿。", "候蟲呻吟而競秋兮，熠燿夕飛而流光。", "蚊角翼而虎噬兮，或負岳而成雷。", "俄歲運之徂征兮，復爾齡之幾何。", "彼大椿之先秋兮，意松栢之後凋。", "屬歲寒之太甚兮，雪霜窘而煩威。", "春歸來兮暘谷溫，條風發兮百卉菲。", "土泉閉兮崔嵬，獨玄黄兮就萎。", "委長年兮澗濱，匠初顧兮弗辰。", "感佳時兮嗟美人，蛻遺榮兮上賓天。", "我籲天兮九閽，如可贖兮百身。"]'),
('faf8e51e-96b9-41fe-8ac0-cfde20b6f3b6','驪山歌','李廌','宋','宋诗','song-poetry','','[]','君門如天深九重，君王如帝坐法宮。',192,'全唐诗/poet.song.67000.json','["君門如天深九重，君王如帝坐法宮。", "人生難處是安穩，何爲來此驪山中。", "複道連雲接金闕，樓觀隠隠橫翠紅。", "林深谷暗迷八駿，朝東暮西勞六龍。", "六龍西幸峨眉棧，悲風便入華清院。", "霓裳蕭散羽衣空，麋鹿來遊墟市變。", "我上朝元春半老，滿地落花人不掃。", "羯鼓樓高掛夕陽，長生殿古生青草。", "可憐吳楚兩醯雞，築臺未就已堪悲。", "長楊五柞漢幸免，江都樓成隋自迷。", "由來流連多喪德，宴安鴆毒因奢惑。", "三風十愆古所戒，不必驪山可亡國。"]'),
('8e03ba3e-6358-4dad-a4dd-213ca598235a','觀吳正獻真','李廌','宋','宋诗','song-poetry','','[]','次公不許畫麒麟，孝宣妙選知名臣。',197,'全唐诗/poet.song.67000.json','["次公不許畫麒麟，孝宣妙選知名臣。", "拜公之像想風度，乃是雲臺子顔之文孫。", "元豐天子建原廟，玉宇萬棟臨端門。", "累朝名臣儼冠劍，列聖御坐開乾坤。", "修廊祕殿鎖春色，彷彿音容皆駿奔。", "相君相業皆元元，旂常彝鼎定書勛。", "儀形在歿侍神考，英氣噩噩凝天閽。", "嗣皇方思服盛美，欲考辟公觀列文。", "君傳茲圖落人世，世人遂得知瑜璠。", "吾知袁公固有後，能平楚獄竟無冤。", "召公甘棠猶不伐，衛武之德誰能諼。", "君不見溫公之像滿人間，願廣此圖令並傳。"]'),
('8c3b93d0-70d9-45d4-834a-6de4640c3050','方竹杖和功遠','李廌','宋','宋诗','song-poetry','','[]','性稟方外正，人憐節瘦輕。',48,'全唐诗/poet.song.67000.json','["性稟方外正，人憐節瘦輕。", "持携防水潦，殺活奈山精。", "直以中圓稱，名因義類清。", "若將靈壽比，未可賤書生。"]'),
('dd7f4bd3-2570-4220-8fa1-21d77da156e7','同張公碩梅耕道訪董畸老郊居  其一','李廌','宋','宋诗','song-poetry','','[]','白水弄青秧，晨烟著柳行。',48,'全唐诗/poet.song.67000.json','["白水弄青秧，晨烟著柳行。", "羈懷正飄泊，陂路轉微茫。", "蘋際鷺鷗下，塍邊菱荇香。", "相從尋勝事，蕭颯興何長。"]'),
('2e5e51e0-7297-4670-8c54-de0d582d211b','同張公碩梅耕道訪董畸老郊居  其二','李廌','宋','宋诗','song-poetry','','[]','㶏水官橋路，將軍甲第新。',48,'全唐诗/poet.song.67000.json','["㶏水官橋路，將軍甲第新。", "綠沉閒結鏽，棐几浄無塵。", "下榻喜賓至，問田憐我貧。", "相逢便傾倒，晚歲定情親。"]'),
('895475fb-7609-4638-987e-96fe727617ca','同張公碩梅耕道訪董畸老郊居  其三','李廌','宋','宋诗','song-poetry','','[]','青雲兩高士，肯伴老夫游。',48,'全唐诗/poet.song.67000.json','["青雲兩高士，肯伴老夫游。", "方駕相追逐，通宵復獻酬。", "詩書嗟失計，農圃話良謀。", "日後耦耕伴，懸知總白頭。"]'),
('30603555-a0d4-4c30-a2ac-6f82ac5f7dcf','秋菊','李廌','宋','宋诗','song-poetry','','[]','春花富紅紫，黄菊與秋宜。',48,'全唐诗/poet.song.67000.json','["春花富紅紫，黄菊與秋宜。", "風勁幽香怯，露晞寒艷滋。", "孤標雖獨步，呈秀此何遲。", "欲待羣芳歇，專榮占一時。"]'),
('f4d50ff4-f8a3-48fb-adc1-0b9165af1594','秋郊','李廌','宋','宋诗','song-poetry','','[]','郊原千里望，好是暮秋時。',48,'全唐诗/poet.song.67000.json','["郊原千里望，好是暮秋時。", "欲盡登臨興，惟應杖屨宜。", "鶚鵰方得意，燕雀彼焉知。", "黄犬蒼鷹去，誰家年少兒。"]'),
('9afc5c06-6103-49f4-9b5a-94a0c01b330c','出城','李廌','宋','宋诗','song-poetry','','[]','岸走舟安穩，逍遙若步虛。',48,'全唐诗/poet.song.67000.json','["岸走舟安穩，逍遙若步虛。", "晴烟迷白鷺，春水見浮魚。", "桑樹連坡種，人家夾水居。", "年豐村舍好，稚子學詩書。"]'),
('f1093a77-c359-485b-abd7-14f03741c287','秋山','李廌','宋','宋诗','song-poetry','','[]','山色带晴雲，雲山遠莫分。',48,'全唐诗/poet.song.67000.json','["山色带晴雲，雲山遠莫分。", "寒林迥蕭散，秀氣自氤氳。", "定有丘園士，彼同麋鹿羣。", "弓旌訪巖谷，誰爲上方聞。"]'),
('c02517a2-3d1c-400c-ac77-b1d4f00c7a26','寂歷古關道二首  其一','李廌','宋','宋诗','song-poetry','','[]','寂歷古關道，早秋生曉寒。',48,'全唐诗/poet.song.67000.json','["寂歷古關道，早秋生曉寒。", "空濛朝雨細，憔悴客衣單。", "事逐烟鴻遠，情隨雪鬢閒。", "蕭蕭倦游意，天際路漫漫。"]'),
('60ea778c-0bf9-44b6-800b-8b02812336e1','寂歷古關道二首  其二','李廌','宋','宋诗','song-poetry','','[]','寂歷古關道，曉烟寒未分。',48,'全唐诗/poet.song.67000.json','["寂歷古關道，曉烟寒未分。", "愁情滿秋草，歸思隔黄雲。", "客路自多感，宿酲猶带醺。", "蕭蕭倦游意，况乃久離羣。"]'),
('d133a1a1-dba6-4ed8-9045-508e45346a4f','秋鶯詩','李廌','宋','宋诗','song-poetry','','[]','秋日生春意，林間聞曉鶯。',48,'全唐诗/poet.song.67000.json','["秋日生春意，林間聞曉鶯。", "奈何時序晚，不及候蟲鳴。", "摇落無多感，芳菲會滿城。", "好音宜自默，反舌可無聲。"]'),
('5b9ce1f8-9d55-48cf-bc84-07b85b99ace0','秋扇和之道','李廌','宋','宋诗','song-poetry','','[]','過時悲既往，適用復相先。',48,'全唐诗/poet.song.67000.json','["過時悲既往，適用復相先。", "世事蓂生隕，人情月晦圓。", "寒凉非爾適，衰歇豈余捐。", "歲事待秋斂，農夫期有年。"]'),
('d854f47c-68ef-4b62-8412-b149ba21ced4','續題郭功甫詩卷','李廌','宋','宋诗','song-poetry','','[]','詩道今蕭索，騷人古困窮。',48,'全唐诗/poet.song.67000.json','["詩道今蕭索，騷人古困窮。", "夜寒金殿冷，秋靜蜀關空。", "廄隸縻宛馬，壇巫誄守宮。", "採珠探水府，絲黍慎蛟龍。"]'),
('282367d7-b494-4ae6-a5ba-f6a7f9850708','戲贈史次仲','李廌','宋','宋诗','song-poetry','','[]','世俗匪吾謀，嘉篇常見投。',48,'全唐诗/poet.song.67000.json','["世俗匪吾謀，嘉篇常見投。", "舊交皆炫曜，夫子獨淹留。", "禮樂尚虛器，衣冠何自囚。", "秪應凉冷後，蕭颯更清秋。"]'),
('6433fdad-3b0d-477c-9cfe-e9720e17fcd5','秋曉','李廌','宋','宋诗','song-poetry','','[]','秋色已飄零，凄凄曉更清。',48,'全唐诗/poet.song.67000.json','["秋色已飄零，凄凄曉更清。", "蕪城宿殘靄，雲日遞微明。", "瓦冷寒霜色，庭空槁葉聲。", "悲歡更盈耳，簫鼓和鐃鉦。"]'),
('2adb79bd-cef9-4cae-b831-0aa0bd0aade5','青泥雪中和德麟韵','李廌','宋','宋诗','song-poetry','','[]','君笑吾癡絕，吾知自不癡。',48,'全唐诗/poet.song.67000.json','["君笑吾癡絕，吾知自不癡。", "遠游陪勝士，歸橐有新詩。", "笑覺山途近，寒因酒力遲。", "相從畏嘲謔，別後復懷思。"]'),
('0f48c5c8-a653-417a-a829-a7d272f50592','秋蝶','李廌','宋','宋诗','song-poetry','','[]','粉蝶爾何知，秋深尚戲飛。',48,'全唐诗/poet.song.67000.json','["粉蝶爾何知，秋深尚戲飛。", "憐渠迷節物，猶若弄春暉。", "露葉今非昔，霜叢疇可依。", "籬邊菊無幾，薄命寄餘菲。"]'),
('6db1e196-e555-4fbc-a2f2-b6c2664b9d7b','宿路北','李廌','宋','宋诗','song-poetry','','[]','晚日明青嶂，春風送馬蹄。',48,'全唐诗/poet.song.67000.json','["晚日明青嶂，春風送馬蹄。", "數朝秦嶺北，今夜洛陽西。", "禁水綠波滿，蕪城碧草齊。", "客心歸更速，解轡恨棲雞。"]'),
('f633c988-ec88-49b0-a495-b0aaea8de1c8','分題得古香爐','李廌','宋','宋诗','song-poetry','','[]','質爲浮休棄，形惟好古宜。',48,'全唐诗/poet.song.67000.json','["質爲浮休棄，形惟好古宜。", "埏陶異甓礫，香火近神祇。", "冷暖非恒德，興衰彼一時。", "舍茲何所適，爾意勿遲遲。"]'),
('a58fcaa1-86f8-4cb8-9fae-594f089b56d9','和次仲硯詩','李廌','宋','宋诗','song-poetry','','[]','聞道端溪好，疑應爲土風。',48,'全唐诗/poet.song.67000.json','["聞道端溪好，疑應爲土風。", "彼人非博識，此語未爲公。", "野客雖云美，才華恐未同。", "濡毫滋墨外，文渙亦徒空。"]'),
('1cf3fc35-0f40-424f-aa79-1578bd9d8ba1','秋溪','李廌','宋','宋诗','song-poetry','','[]','秋溪已澄徹，山色貯溪中。',48,'全唐诗/poet.song.67000.json','["秋溪已澄徹，山色貯溪中。", "雲度前洲白，霞生別嶠紅。", "波瀾寒自鑑，魚雁共遊空。", "棄置功名念，羊裘作釣翁。"]'),
('30c757a9-8eb8-42a1-87ba-670938fa2608','釣臺  其一','李廌','宋','宋诗','song-poetry','','[]','釣國固有術，直鈎寧漫勞。',48,'全唐诗/poet.song.67000.json','["釣國固有術，直鈎寧漫勞。", "吾常鄙龍伯，豈復羨琴高。", "濯足風波地，遊心虎豹韜。", "誰云無是子，天下自囂囂。"]'),
('b61e6d38-ce89-4375-9f74-698ebcf5a07e','釣臺  其二','李廌','宋','宋诗','song-poetry','','[]','此地有天險，雙臺千仞岡。',48,'全唐诗/poet.song.67000.json','["此地有天險，雙臺千仞岡。", "眼寬知世窄，望極使神傷。", "慘澹諸峰立，縈紆一水長。", "振衣懷古罷，新句入斜陽。"]'),
('2138c671-a214-42a9-b808-824583a00ae3','秋風','李廌','宋','宋诗','song-poetry','','[]','萬籟靜中起，扶摇風怒號。',48,'全唐诗/poet.song.67000.json','["萬籟靜中起，扶摇風怒號。", "半天鳴劍戟，平地卷波濤。", "鷁退宋都疾，鵬摶溟海高。", "賀蘭吹不盡，何用戰蓬蒿。"]'),
('3df97f9e-2b7c-4851-bf37-1fc12ca95a3e','范蜀公挽詩  其一','李廌','宋','宋诗','song-poetry','','[]','蚤歲青雲近，英聲四海馳。',48,'全唐诗/poet.song.67000.json','["蚤歲青雲近，英聲四海馳。", "能懷天下寶，獨讓月中枝。", "既已登龍坂，咸觀入鳳池。", "如何老清禁，偃蹇卧明時。"]'),
('565e8713-c53b-469c-96e8-c469c17b303c','范蜀公挽詩  其二','李廌','宋','宋诗','song-poetry','','[]','仁人宜有勇，無欲故能剛。',48,'全唐诗/poet.song.67000.json','["仁人宜有勇，無欲故能剛。", "凜凜回天力，危危極諫章。", "一言扶日御，萬古正乾綱。", "首犯龍鱗意，淵衷亮未忘。"]'),
('179cf0e1-1dc0-41e1-b0ca-4c9fc489f9b3','范蜀公挽詩  其三','李廌','宋','宋诗','song-poetry','','[]','慶寧雖首議，濮廟一何公。',48,'全唐诗/poet.song.67000.json','["慶寧雖首議，濮廟一何公。", "君子初無黨，賢臣惟盡忠。", "死生全大節，社稷倚元功。", "疾彼梁丘子，依違秪尚同。"]'),
('fa827ef6-e2e7-46ce-a6a1-50bceec877c8','范蜀公挽詩  其四','李廌','宋','宋诗','song-poetry','','[]','荆舒昔未懲，抗疏誓身爭。',48,'全唐诗/poet.song.67000.json','["荆舒昔未懲，抗疏誓身爭。", "衛鞅雖難屈，桑羊屢請烹。", "危言知不用，脫屣謝浮榮。", "豈戀三台近，全無萬世清。"]'),
('cc54f46d-982e-4b78-a12e-f213285f2e0d','范蜀公挽詩  其五','李廌','宋','宋诗','song-poetry','','[]','直氣犯荆舒，承明下玉除。',48,'全唐诗/poet.song.67000.json','["直氣犯荆舒，承明下玉除。", "禁林餘諫藁，蜀道擁安車。", "自謂三宜去，吾知衆莫如。", "誰爲忠義傳，事事舉堪書。"]'),
('c70f336b-6725-4264-bc3d-ff22a64a5a7c','范蜀公挽詩  其六','李廌','宋','宋诗','song-poetry','','[]','嗣皇思故老，趣詔侍筵經。',48,'全唐诗/poet.song.67000.json','["嗣皇思故老，趣詔侍筵經。", "駟馬空頻駕，高鴻本自冥。", "蒼生雖絕望，盛德愈流馨。", "出處俱全節，輝光並日星。"]'),
('9bd9e13f-4764-4385-b24b-0b529d65fb58','范蜀公挽詩  其七','李廌','宋','宋诗','song-poetry','','[]','關雎久盈耳，魏闕亦游心。',48,'全唐诗/poet.song.67000.json','["關雎久盈耳，魏闕亦游心。", "不廢江湖樂，親調鐘磬音。", "九重初擊拊，千代正哇淫。", "器在人亡矣，哀哉淚滿襟。"]'),
('65009c88-0ee1-4a98-bfb5-4d112027bf5d','范蜀公挽詩  其八','李廌','宋','宋诗','song-poetry','','[]','重望晉隨會，清明越大夫。',48,'全唐诗/poet.song.67000.json','["重望晉隨會，清明越大夫。", "忘身安社稷，寄傲老江湖。", "黼冕固已遠，黄金猶可模。", "旌賢宜異數，願上孝宣圖。"]'),
('d5539e8f-237c-43d0-b241-dd967aad70d4','范蜀公挽詩  其九','李廌','宋','宋诗','song-poetry','','[]','八十雖云壽，吾嗟未及期。',48,'全唐诗/poet.song.67000.json','["八十雖云壽，吾嗟未及期。", "方之昔衛武，猶不至期頤。", "幸處仁人里，叨膺國士知。", "空餘戀軒想，况復九原悲。"]'),
('f20faa7c-078c-40f0-87e3-e4a7e1e893e6','范蜀公挽詩  其一○','李廌','宋','宋诗','song-poetry','','[]','衆樂西南圃，從公數共游。',48,'全唐诗/poet.song.67000.json','["衆樂西南圃，從公數共游。", "清無馬融帳，榮預李膺舟。", "河漢德星隕，山川英氣收。", "孤生築場意，索寞向新丘。"]'),
('5bf95b3e-d0d7-4a47-98b7-917af11c2296','光祿朱卿挽詞  其一','李廌','宋','宋诗','song-poetry','','[]','自信仁由己，深知道滿門。',48,'全唐诗/poet.song.67000.json','["自信仁由己，深知道滿門。", "才華輝日域，嘉譽達天閽。", "坦腹方趨進，亨衢迓駿奔。", "欲令唐晉後，不獨美姚溫。"]'),
('cf567965-b68d-4d54-bb5f-fe2cfedfe2f2','光祿朱卿挽詞  其二','李廌','宋','宋诗','song-poetry','','[]','要路多知己，期公集有庸。',48,'全唐诗/poet.song.67000.json','["要路多知己，期公集有庸。", "行趨青瑣闥，榮拜紫泥封。", "帝室常虛席，侯邦久卧龍。", "空餘遺愛頌，安得鏤斯鏞。"]'),
('0947928f-66de-4dd6-b2ed-51d3be4fa81e','光祿朱卿挽詞  其三','李廌','宋','宋诗','song-poetry','','[]','省寺官聯貴，曾升社稷臣。',48,'全唐诗/poet.song.67000.json','["省寺官聯貴，曾升社稷臣。", "雙瞻觀日月，接跡望星辰。", "錫爵雖開國，封侯未富民。", "天扉如可到，直擬問通津。"]'),
('eb43748b-1ff4-4a48-a387-edeb58dfee67','光祿朱卿挽詞  其四','李廌','宋','宋诗','song-poetry','','[]','南國舊書生，今誰老更榮。',48,'全唐诗/poet.song.67000.json','["南國舊書生，今誰老更榮。", "朱轓頻補郡，白首到名卿。", "牧守惟司命，官曹任老成。", "道孚姑已矣，何患不聲名。"]'),
('bfa08fed-95f4-48af-833e-2db11eaad8c4','光祿朱卿挽詞  其五','李廌','宋','宋诗','song-poetry','','[]','疇昔始龍館，能聲到海隅。',48,'全唐诗/poet.song.67000.json','["疇昔始龍館，能聲到海隅。", "兆民方菜色，境政獨蒲盧。", "尚頼德彌邵，安知今也無。", "猶聞江左郡，荒政徯來蘇。"]'),
('e1cc7566-e5e2-4399-b8f9-55cb7e66fd89','光祿朱卿挽詞  其六','李廌','宋','宋诗','song-poetry','','[]','七十古云稀，公忠况未衰。',48,'全唐诗/poet.song.67000.json','["七十古云稀，公忠况未衰。", "言常思悟主，老更惜明時。", "雪髮丹心被，君恩寶劍知。", "如何天不憗，直道竟何施。"]'),
('8d2417a8-b6c7-4338-962a-cc018a7b3990','光祿朱卿挽詞  其七','李廌','宋','宋诗','song-poetry','','[]','樂圃林泉好，藤蘿蔭古臺。',48,'全唐诗/poet.song.67000.json','["樂圃林泉好，藤蘿蔭古臺。", "仰攀高節處，豫約掛冠來。", "凉月空堂影，新霜百草荄。", "凄清行樂地，履跡滿蒼苔。"]'),
('7511bd61-7125-44b1-b281-509117025e98','光祿朱卿挽詞  其八','李廌','宋','宋诗','song-poetry','','[]','滄海夢悠悠，關河壯氣收。',48,'全唐诗/poet.song.67000.json','["滄海夢悠悠，關河壯氣收。", "魂歸傷委蛻，壑迥失虛舟。", "月暗菰蒲夜，山空木葉秋。", "可堪頻悵望，松梓繄新丘。"]'),
('77cb5f73-d760-4fb1-ac46-119e009b2d41','光祿朱卿挽詞  其九','李廌','宋','宋诗','song-poetry','','[]','五十雖非壽，休嗟不憗遺。',48,'全唐诗/poet.song.67000.json','["五十雖非壽，休嗟不憗遺。", "賞延姑可待，子貴竟何遲。", "異鵲驚蟬蛻，凄風落木芝。", "乘驄千里客，歌罷不勝悲。"]'),
('7ed97b30-58dd-4066-a1ea-a6f821f7b509','光祿朱卿挽詞  其一○','李廌','宋','宋诗','song-poetry','','[]','蚤悟多金累，惟修儉與仁。',48,'全唐诗/poet.song.67000.json','["蚤悟多金累，惟修儉與仁。", "考終雖罔愧，直道未容伸。", "地想流謙德，天惟賚善人。", "昭昭錫繁祉，餘慶在振振。"]'),
('4411e627-7f3d-454c-b845-2ad8df0607e3','賀蘭先生詩同陳恬叔易和節度使王漢忠韵','李廌','宋','宋诗','song-poetry','','[]','陿隘區中世，殷勤招隠篇。',48,'全唐诗/poet.song.67000.json','["陿隘區中世，殷勤招隠篇。", "應居小有洞，幾見大椿年。", "菴廢雲埋谷，琴亡聲在泉。", "至言曾悟主，持此合昇天。"]'),
('6834798b-ff78-460c-95cb-f57ac8c046c5','顔魯公祠堂詩','李廌','宋','宋诗','song-poetry','','[]','朅來游汝海，初識魯公真。',288,'全唐诗/poet.song.67000.json','["朅來游汝海，初識魯公真。", "盛德宜蒙祀，英姿儼若神。", "典刑雖異代，勛績在蒸民。", "憶昔艱難際，生逢歷數屯。", "羯胡來薊漠，戎馬度咸秦。", "河朔皆朝虜，平原獨挺身。", "蠟書通帝所，羽檄論邦鄰。", "許國心無二，孤軍氣復振。", "弟兄同義烈，生死劇酸辛。", "已怪酬庸薄，那聞左降頻。", "江湖銷歲月，省闥牾經綸。", "相國心多忌，軍容憤復伸。", "同朝緣妬媢，啗賊俾邅迍。", "輒墮姦邪計，剛期跋扈馴。", "咥凶令履尾，納諫爲嬰鱗。", "假手雖云智，擠賢太不仁。", "茹氈蘇武餒，决眥藺生嗔。", "誤問長安使，寧爲叛將賓。", "一時全大節，千古仰清塵。", "緬想神如在，推遷跡已陳。", "謀謨存汗簡，字畫徧蒼珉。", "論世吾求友，之人德可親。", "詎云黄壤隔，猶勝白頭新。", "端欲希忠義，常期齒搢紳。"]'),
('b3b55dec-cca5-436d-93ba-c464d2ba2ad5','程高承議赴夔路轉運判官求詩','李廌','宋','宋诗','song-poetry','','[]','聖主躬仁政，羣方布詔條。',168,'全唐诗/poet.song.67000.json','["聖主躬仁政，羣方布詔條。", "洪恩溫海嶠，嘉頌滿芻蕘。", "聚斂除姦吏，依違屏具僚。", "鈞衡無碩鼠，城社絕餘妖。", "皇化思無外，王心遠欲昭。", "咨詢黄閣老，選命紫宸朝。", "丹禁傳天詔，飛星下使軺。", "書旌分蜀道，攬轡步烟霄。", "急峽瞿塘險，孤城白帝遙。", "巴山連浪遠，漢節拂雲飄。", "按部清時好，觀風樂事饒。", "詩成思老杜，鬼哭想殘蕭。", "已佩黄金印，當簪七葉貂。", "不應淹僻陋，從此上扶摇。"]'),
('a3dc7386-c7bd-478c-80bd-b095fac0b1ba','上翰林眉山先生蘇公','李廌','宋','宋诗','song-poetry','','[]','佑聖生賢佐，天心在撫民。',264,'全唐诗/poet.song.67000.json','["佑聖生賢佐，天心在撫民。", "昌期膺治運，穀旦降元臣。", "四序功成晚，三台耀拱辰。", "嚴凝氣剛勁，謇諤性忠純。", "凜凜風霜操，優優雨露仁。", "高才映今古，妙學洞天人。", "黼黻文華國，淵源德潤身。", "四朝師令望，百辟仰清塵。", "射策明三道，觀光耀九賓。", "咸知帝賚說，復誦嶽生申。", "視草金鑾殿，登庸鳳詔春。", "夔龍名不隕，魯衛政相因。", "交蔭槐陰茂，聯華棣萼親。", "廟堂熙帝載，衮繡並天倫。", "政柄勞無憚，侯邦逸久均。", "偃藩心固樂，調鼎味宜新。", "上宰虛黄閣，除書下紫宸。", "百神懷景福，萬化入鴻鈞。", "陰德施黎庶，休功格昊旻。", "自當侔带礪，詎止約松椿。", "賤士睎高躅，趨風愧下陳。", "願言千萬壽，獻頌敢辭頻。"]'),
('12b854e5-817c-4039-bd63-6f86be225ec3','小蘇先生九三丈自司諫拜起居郎權中書舍人廌作詩以賀','李廌','宋','宋诗','song-poetry','','[]','孝治依文母，皇圖錫聖王。',144,'全唐诗/poet.song.67000.json','["孝治依文母，皇圖錫聖王。", "虛心思啟沃，妙選盡忠良。", "近侍崇儒術，先生被寵光。", "周邦柱下史，魏闕紫微郎。", "禁殿聯常棣，天池浴鳳凰。", "揮毫青瑣闥，簪筆御爐香。", "德鎮千鈞重，文輝萬丈長。", "昌時逢式穀，吾道喜彌彰。", "視草嚴宸暮，論思子夜央。", "槐邊星轉角，花底鷺分行。", "豈但居華省，行聞上玉堂。", "終期衮衣拜，慰此士夫望。"]'),
('3d937208-7963-44bd-bb54-ad731c4ac4ba','贈錢之道子武昆仲','李廌','宋','宋诗','song-poetry','','[]','青冥聯翼鵠，志節傲雲機。',288,'全唐诗/poet.song.67000.json','["青冥聯翼鵠，志節傲雲機。", "凶變家多難，年荒歲愈饑。", "運乖生事拙，貧病壯心違。", "蚤歲憂虞少，今春弟妹歸。", "氣悲縻駱馬，心感動摇徽。", "命矣無傷已，時哉歎式微。", "自從中夏瘦，半減去年肥。", "氣槩摩天鷙，文華耀日翬。", "飲川容鼴鼠，障日讓犁犩。", "南畝時躬稼，虛堂晝掩扉。", "有秋緣力穡，高節本知幾。", "路入東城遠，人行北道稀。", "樹頭雲藹藹，草際蝶馡馡。", "古岸連樊圃，秋城秀蕨薇。", "斷洪流滓濘，獨木過欹巍。", "䆉稏香紛馥，菰蒲綠映圍。", "訪君非旦旦，相見亦依依。", "爲問奚爲樂，言他復謂譩。", "孝思誠辟色，傃隠始深譏。", "不見前賢者，何嘗慮世非。", "浩歌行拾蕙，雩詠浴于沂。", "儼雅誠詩社，凄凉近釣磯。", "夜階鳴蟋蟀，秋砌響蛜蝛。", "竹塢留殘月，林虹带落暉。"]'),
('513043f4-82da-449a-9c54-8cc798ec8dff','和楊元忠主簿觀魚','李廌','宋','宋诗','song-poetry','','[]','輕瀾沔滿带維舟，新雨羣魚藻際浮。',64,'全唐诗/poet.song.67000.json','["輕瀾沔滿带維舟，新雨羣魚藻際浮。", "既亦非知梁上樂，敢嗟彼有釜中憂。", "漢江水濁斑衣獺，楚岸烟深雪色鷗。", "未作金鼇莫驚惕，月澄清海漫如鈎。"]'),
('06a8abe5-c667-4180-83fa-929ea4466e34','過昆陽城','李廌','宋','宋诗','song-poetry','','[]','昆陽城下黍苗稀，寂歷荒墟隠翠微。',64,'全唐诗/poet.song.67000.json','["昆陽城下黍苗稀，寂歷荒墟隠翠微。", "遠想龍蛇方鬭野，解驅虎豹使成圍。", "烏知將擁河流斷，定喜能令屋瓦飛。", "白水真人今物化，舂陵惟有荷鋤歸。"]'),
('f058d63d-b919-411d-86f5-ec7693c5ad1c','和錢之道遊虎丘二首  其一','李廌','宋','宋诗','song-poetry','','[]','輕雲細雨放花時，才過清明已夾衣。',64,'全唐诗/poet.song.67000.json','["輕雲細雨放花時，才過清明已夾衣。", "拚得酒時教盡醉，可題詩處莫空歸。", "丁寧鶯語機關巧，輕薄楊花氣力微。", "閶闔晚來行客盡，稚烏相趁入城飛。"]'),
('8a9d7551-b210-449c-9d2c-c75a4f0138d3','和錢之道遊虎丘二首  其二','李廌','宋','宋诗','song-poetry','','[]','石頭槎牙占官道，松樹老怪枿斷雲。',64,'全唐诗/poet.song.67000.json','["石頭槎牙占官道，松樹老怪枿斷雲。", "驪龍睡隠潭水黑，雨積糞壤生朝菌。", "山光繚繞林樸樕，野氣空闊雲氤氳。", "歸來月落天色莫，水邊游女濺紅裙。"]'),
('21816e0e-40a2-4502-9937-3e629e6d146c','商高宗陵廟詩','李廌','宋','宋诗','song-poetry','','[]','築巖胥靡繼甘盤，此道寥寥不復存。',64,'全唐诗/poet.song.67000.json','["築巖胥靡繼甘盤，此道寥寥不復存。", "古廟秋風塵黯黯，故陵烟樹月昏昏。", "君臣難遇真千載，岸谷誰知舊九原。", "魏尚端能似頗牧，獨無新夢到天閽。"]'),
('aaf08a10-eea7-4194-a198-61f4032dc24b','厄臺','李廌','宋','宋诗','song-poetry','','[]','今古俱無忌憚情，厄臺猶敢尚爲名。',64,'全唐诗/poet.song.67000.json','["今古俱無忌憚情，厄臺猶敢尚爲名。", "裔孫不復重瞳聖，俗目俱同瞽叟盲。", "見慍仲由空骯髒，膾肝盜跖尚彭亨。", "聖人道大故難用，誰聽弦歌兕虎聲。"]'),
('e418e74d-d743-4a23-bac0-6665423ea28a','宿大賈村僧寮','李廌','宋','宋诗','song-poetry','','[]','行過橫烟杳靄中，低低茆舍繞蒿蓬。',64,'全唐诗/poet.song.67000.json','["行過橫烟杳靄中，低低茆舍繞蒿蓬。", "譍門見客僧如鹿，席地圍爐火自紅。", "隙壁射床千里月，破窗吟紙一川風。", "僕夫密勸休安枕，聞道穿窬是主翁。"]'),
('c2075f95-3d99-4ba0-b6d3-f6952e009f60','哀都官王申','李廌','宋','宋诗','song-poetry','','[]','壠上弓旌降鶴書，戔戔璧帛賁鄉閭。',64,'全唐诗/poet.song.67000.json','["壠上弓旌降鶴書，戔戔璧帛賁鄉閭。", "漢宮入奏賢臣頌，蜀道榮觀駟馬車。", "誰謂諸侯老賓客，歸來華髮伴樵漁。", "泮宮陳迹神游否，絳帳門生多石渠。"]'),
('dd7a1c05-8595-4636-b2f4-bbecde4e63a0','大雨中遊嶽寺','李廌','宋','宋诗','song-poetry','','[]','忽見微雲別嶠生，急緣危磴下崢嶸。',64,'全唐诗/poet.song.67000.json','["忽見微雲別嶠生，急緣危磴下崢嶸。", "勢傾海岱千巖黑，力卷江湖萬葉聲。", "碧瓦依稀人暗喜，急溪湍漲馬初驚。", "老僧宴坐朱門底，應笑狂夫冒險行。"]'),
('6c2d62f1-c4e9-4a49-803a-c16794c10855','鏡屏詩二首  其一','李廌','宋','宋诗','song-poetry','','[]','曲玉回輝瑩可觀，秋冰壁立動涵瀾。',64,'全唐诗/poet.song.67000.json','["曲玉回輝瑩可觀，秋冰壁立動涵瀾。", "每嗟許國酬身晚，忽覺餘光照膽寒。", "映座未容華表客，整簪空慕鵔鸃冠。", "雲車一去橋山晚，寶鎮于今下古壇。"]'),
('e7ddff88-fa66-4910-91fa-f5ac68ea8e66','鏡屏詩二首  其二','李廌','宋','宋诗','song-poetry','','[]','凝澄不動水淵槃，風拂泉生或細瀾。',64,'全唐诗/poet.song.67000.json','["凝澄不動水淵槃，風拂泉生或細瀾。", "月影透簾朝日薄，龍輝繞匣夜光寒。", "玄冥借魄知神物，男子無聞已弱冠。", "照我精誠至麟閣，緩隨弓劍上仙壇。"]'),
('ad36a0f6-8cb5-4f0e-b47c-839411184a79','和二兄書事三首  其一','李廌','宋','宋诗','song-poetry','','[]','年少看書恥未多，壯心今歲沛中歌。',64,'全唐诗/poet.song.67000.json','["年少看書恥未多，壯心今歲沛中歌。", "带江黄幟有蹻跖，舉國白頭無絳何。", "爲我忠謀能有幾，匪人阿比敢言他。", "手攀荆葛藤蘿近，敢把新凉取次過。"]'),
('c89fc053-e829-4e3b-ba10-37986686361c','和二兄書事三首  其二','李廌','宋','宋诗','song-poetry','','[]','逋逃內潰古云多，楚塞羣雄尚感歌。',64,'全唐诗/poet.song.67000.json','["逋逃內潰古云多，楚塞羣雄尚感歌。", "血饗彼猖神苟幸，廟謀非壯士誰何。", "將軍威信當詢衆，决勝神機豈謂他。", "試把香囊問少子，淝川投策夜潜過。"]'),
('efc4afe2-e521-44e2-884e-d3b0670f822d','和二兄書事三首  其三','李廌','宋','宋诗','song-poetry','','[]','功名於我實何多，祇爲浮華未浩歌。',64,'全唐诗/poet.song.67000.json','["功名於我實何多，祇爲浮華未浩歌。", "兩月病痁誠已甚，半頭白髮似無何。", "詔惟選籲將從衆，學貴師心在匪他。", "當世聞人知不少，片言敢謂衆難過。"]'),
('0cd79a51-e7c3-447f-8b36-f298ca1fa636','和鄭十三東齋言事二首  其一','李廌','宋','宋诗','song-poetry','','[]','爲貧軒冕未忘情，寧使棲遲抱六經。',64,'全唐诗/poet.song.67000.json','["爲貧軒冕未忘情，寧使棲遲抱六經。", "安得神仙斷鯨劍，拂開雲翳露天青。", "霧濃玄豹終朝隠，冰薄猜狐抵夜聽。", "昏墊直疑皆飲鴆，沉冥何苦辨清醒。"]'),
('136e9895-05cd-4c2d-9d74-50cad4da23b5','和鄭十三東齋言事二首  其二','李廌','宋','宋诗','song-poetry','','[]','春光故故惱人情，新葺茆茨欲醉經。',64,'全唐诗/poet.song.67000.json','["春光故故惱人情，新葺茆茨欲醉經。", "積雨水衣龍頷滑，晚晴山翠佛螺青。", "月邊柳色疏疏見，風外梅花細細聽。", "半夜白雲生石枕，潤珠蒸濕醉魂醒。"]'),
('8b3a942d-0331-4e87-8e72-4e26c8bd6c20','答孔榘處度見贈','李廌','宋','宋诗','song-poetry','','[]','我似羈縻遐徼州，君如霸府大諸侯。',64,'全唐诗/poet.song.67000.json','["我似羈縻遐徼州，君如霸府大諸侯。", "如何鼎食素烹飪，乃謂溪毛堪薦羞。", "駑馬但能追十駕，鉛刀奚可斷千牛。", "鄙人粗亦知臧否，敢誚東家故日丘。"]'),
('fd8931b1-ea10-4261-a550-9d842d23b97f','嵩頂六月芍藥初發','李廌','宋','宋诗','song-poetry','','[]','誰言天地一無私，底事陽和到頂遲。',64,'全唐诗/poet.song.67000.json','["誰言天地一無私，底事陽和到頂遲。", "暑氣已交五六月，雲中初見兩三枝。", "可憐下土炎蒸日，却是青霄爛漫時。", "第有榮心莫嗟晚，物情先盛復先衰。"]'),
('fa5ca75b-d0dd-4687-823b-3378fe27df65','和人寄寇昌朝韵','李廌','宋','宋诗','song-poetry','','[]','久料騰驤空冀北，如何留滯困周南。',64,'全唐诗/poet.song.67000.json','["久料騰驤空冀北，如何留滯困周南。", "聞君載酒訪狂客，把酒爲君當劇談。", "上國分携今已久，丹砂未就我懷慚。", "六蜚駕馭須天馬，吾恐驊騮備兩驂。"]'),
('0044fa01-5d6d-407e-b2bc-c75ec3520387','楊十三虞卿在希顔上人房納凉余時在村舍歸和諸公韵','李廌','宋','宋诗','song-poetry','','[]','土渴山焦獨在阿，考槃孰與世相過。',64,'全唐诗/poet.song.67000.json','["土渴山焦獨在阿，考槃孰與世相過。", "皇皇夫子猶傷鳳，碌碌蒼生尚執柯。", "頭白已驚爲學晚，日長贏得讀書多。", "北禪釋子應相笑，樹癭多年變木鵝。"]'),
('4d71cf5e-0579-43a6-9b86-6e5fb1f35d39','曉行聞鶯','李廌','宋','宋诗','song-poetry','','[]','花梢未動雨中聽，催徧園林百果成。',64,'全唐诗/poet.song.67000.json','["花梢未動雨中聽，催徧園林百果成。", "六月不知春色盡，五更來伴夏雞聲。", "樹頭蕭瑟長風過，馬上瞢騰短夢驚。", "勸汝無言歸舊谷，先秋番次候蟲鳴。"]'),
('9e5595b2-9dd8-43ef-88bf-3a31e226b347','雨中游法王寺詩','李廌','宋','宋诗','song-poetry','','[]','雨脚如麻未肯收，雨中還作法王游。',64,'全唐诗/poet.song.67000.json','["雨脚如麻未肯收，雨中還作法王游。", "雲埋輦路烟初合，水濺松巖雪亂流。", "心畏險途常恐失，寒侵病骨已知秋。", "羣峰聳峭猶無畏，爲語山僧不用留。"]'),
('f16fe6ed-ad98-40d7-8e1e-f3e90fc7136a','少林寺詩','李廌','宋','宋诗','song-poetry','','[]','禪老家風古少林，道場遺跡蔽烟岑。',64,'全唐诗/poet.song.67000.json','["禪老家風古少林，道場遺跡蔽烟岑。", "山遮石脚斜陽早，雲礙鐘聲出谷深。", "隻履度關天杳杳，九年面壁海沉沉。", "欲知苗裔能傳法，柏樹猶明聖主心。"]'),
('e9c3c987-2e97-40b4-b168-e8e22e8179d0','習池詩','李廌','宋','宋诗','song-poetry','','[]','陳迹相推今古同，池邊倚杖送歸鴻。',64,'全唐诗/poet.song.67000.json','["陳迹相推今古同，池邊倚杖送歸鴻。", "童山尚接千巖秀，穉樹猶傳萬壑風。", "春意物情迷野興，水光天影共青空。", "雍門有淚應承睫，繞墓行吟弔習公。"]'),
('7fdee93c-262a-451e-9dc9-2d8842cc35d7','次韵劉厚之久陰未雨','李廌','宋','宋诗','song-poetry','','[]','欲和豐年幾日霖，密雲委地結繁陰。',64,'全唐诗/poet.song.67000.json','["欲和豐年幾日霖，密雲委地結繁陰。", "莫疑造物收功晚，自是陽和著意深。", "且具黄雞傾白酒，更求青李與來禽。", "掃除萬古窮通想，付與南薰一弄琴。"]'),
('41b6f272-6d08-482d-a145-2836ba536623','過閻氏橋亭','李廌','宋','宋诗','song-poetry','','[]','綠芰紅蕖照眼新，池塘風軟起青蘋。',64,'全唐诗/poet.song.67000.json','["綠芰紅蕖照眼新，池塘風軟起青蘋。", "遠山碧映重林暮，委徑香傳別洞春。", "五月獨爲長道客，滄浪自有濯纓人。", "誰知雅意在丘壑，慚對箕嵩愧路塵。"]'),
('1cb3ebda-75f4-40bb-8a53-711994960f7b','范蜀公得請再致仕蜀公作詩命某次韵','李廌','宋','宋诗','song-poetry','','[]','老戀林泉拒衮衣，高山景行衆思齊。',64,'全唐诗/poet.song.67000.json','["老戀林泉拒衮衣，高山景行衆思齊。", "久膺重任當先覺，獨以清風激衆迷。", "越相家聲千載後，商公舊隠白雲西。", "坐令貪懦趨忠厚，寄語狂童勿芥雞。"]'),
('0d4ec482-063a-4e14-9f84-45327f034c7e','謝王生贈弓矢','李廌','宋','宋诗','song-poetry','','[]','將軍材氣舊無雙，老矣猶思强挽强。',64,'全唐诗/poet.song.67000.json','["將軍材氣舊無雙，老矣猶思强挽强。", "金廄願乘千里馬，玉關歸奉萬年觴。", "受降城下沙場雪，無定河邊木葉霜。", "贈我良弓借餘勇，君應真勝楚人亡。"]'),
('dcf7bf6a-b125-4db7-bebf-d2d63fc8c316','和人九日詩','李廌','宋','宋诗','song-poetry','','[]','三徑就荒陶令宅，兩峰高並杜翁情。',64,'全唐诗/poet.song.67000.json','["三徑就荒陶令宅，兩峰高並杜翁情。", "悲秋不奈黄花好，落帽誰憐白髮生。", "遠岫薄雲收細雨，晚林丹葉弄新晴。", "登臨俯仰寰區隘，欲駕風輪更上征。"]'),
('cc45357b-623c-440a-ae81-d4402e1f3397','表高氏石公之墓','李廌','宋','宋诗','song-poetry','','[]','黄金照地晉將軍，劍履盈門萬石君。',64,'全唐诗/poet.song.67000.json','["黄金照地晉將軍，劍履盈門萬石君。", "獨以德名追遠裔，盡將富貴比浮雲。", "璚田種藥期公壽，夜壑移舟忽夢分。", "彷彿平生阻瞻覿，一詩三嘆漫殷勤。"]'),
('8dee1d04-5d1e-4dcf-8b53-ed3d4fd63f2a','再上閭丘通牧少卿','李廌','宋','宋诗','song-poetry','','[]','東邦濱海帝憂勞，慎迪名卿禮意褒。',64,'全唐诗/poet.song.67000.json','["東邦濱海帝憂勞，慎迪名卿禮意褒。", "板簡拜旌前憲掾，雲駢驂馭舊仙曹。", "庭柯露下回春色，夜浦珠還息海濤。", "陰惠日隆天眷異，蓬萊東去近金鰲。"]'),
('a48c0893-f1dc-467d-bd64-b99fdc1818c4','呂朝散挽詩二首  其一','李廌','宋','宋诗','song-poetry','','[]','殊重平生邴曼容，退身能勇自爲雄。',64,'全唐诗/poet.song.67000.json','["殊重平生邴曼容，退身能勇自爲雄。", "盛衰付與枕中夢，福祿猶嗤塞上翁。", "松菊漸荒三徑合，鶴猿悞怨故山空。", "蒼苔滿地塵凝席，惟有蕭蕭蕙帳風。"]'),
('b1c63d71-1232-4ad2-97cb-e2f68c4652bb','呂朝散挽詩二首  其二','李廌','宋','宋诗','song-poetry','','[]','金馬玉堂高步宜，中年遂與水雲期。',64,'全唐诗/poet.song.67000.json','["金馬玉堂高步宜，中年遂與水雲期。", "太沖早擅三都賦，叔度難量萬頃陂。", "夜壑藏舟今孰在，白駒過隙事堪悲。", "南園從此無行跡，老檜高松知未知。"]'),
('603052c3-de98-48b3-98b5-ed2d0308d4ea','送黄集虛赴任知州','李廌','宋','宋诗','song-poetry','','[]','桐廬古郡淛江東，山色溪光藻鏡中。',64,'全唐诗/poet.song.67000.json','["桐廬古郡淛江東，山色溪光藻鏡中。", "後夜相思千里月，高懷爲寄一襟風。", "欲紆龜紐黄金印，且學羊裘老釣翁。", "忠義傳家君勉勉，清名不必問窮通。"]'),
('2d9d46a9-e8cf-43c1-95f1-a34ee9c487eb','楊元忠和葉祕校臘茶詩相率偕賦','李廌','宋','宋诗','song-poetry','','[]','風駕已馳供御品，霜郊未卷喊山旂。',64,'全唐诗/poet.song.67000.json','["風駕已馳供御品，霜郊未卷喊山旂。", "七閩地産猶爲寶，兩府官高故不遺。", "須藉水簾泉勝乳，也容雙井白過磁。", "東堂退食公宮晚，金鼎新烹欲沁脾。"]'),
('c6cbd631-faf5-498b-9f7c-99807cd294cd','宋英寶宣德自杞至邑將復東還見遺途中詩次韵和之以見惜別','李廌','宋','宋诗','song-poetry','','[]','思君仍歲此相逢，後夜夢魂無復東。',64,'全唐诗/poet.song.67000.json','["思君仍歲此相逢，後夜夢魂無復東。", "白紵淚痕何處恨，故園花信幾番風。", "歸來可喜似新燕，惜別預愁如去鴻。", "老矣奈何春半老，悠悠萬事付盃中。"]'),
('e475ee17-5936-4015-b1a8-dd172410c13c','又過陳叔易隠居相拉同遊超化寺詩','李廌','宋','宋诗','song-poetry','','[]','文範今亡見嗣卿，潁川應聚異時星。',64,'全唐诗/poet.song.67000.json','["文範今亡見嗣卿，潁川應聚異時星。", "清風特爲吾曹至，畏景寧憂日御停。", "踏雪曾穿東郭履，移文今忤北山靈。", "烹茶且酌南溪水，第欠金山第二𤃩。"]'),
('9d4352a4-a32d-4dd5-be8a-780cca8e7b26','次韵東坡還自嶺南','李廌','宋','宋诗','song-poetry','','[]','憑陵歲月固難堪，食蘗多來味却甘。',64,'全唐诗/poet.song.67000.json','["憑陵歲月固難堪，食蘗多來味却甘。", "時雨纔聞徧中外，卧龍相繼起東南。", "天邊鶴駕瞻仙袂，雲裏詩牋带海嵐。", "重見門生應不識，雪髯霜鬢兩毿毿。"]'),
('ac6a9295-6cca-4772-ae26-cd94dffb98c2','谷隠寺書事詩','李廌','宋','宋诗','song-poetry','','[]','雲如戲我舒還卷，雨似欺人去復來。',64,'全唐诗/poet.song.67000.json','["雲如戲我舒還卷，雨似欺人去復來。", "學道忘憂從老至，持盃得意使顔開。", "驪駒喜飽嘶猶戀，猘犬誇獰吠欲催。", "三日山中果何有，賦詩滿得錦囊迴。"]'),
('fb94fef6-e016-45db-89e8-36a232b12895','某與鮮于綽元勛共約同習制科','李廌','宋','宋诗','song-poetry','','[]','趙括癡兒漫喜兵，他年自料困長平。',64,'全唐诗/poet.song.67000.json','["趙括癡兒漫喜兵，他年自料困長平。", "將軍各有萬人敵，下士難先二子鳴。", "盧駱楊王何足算，江黄六蓼豈勞征。", "英雄少貶雖慚愧，且徇區區月旦評。"]'),
('11818f17-1565-4c34-b69c-ae498cf4e987','謁中嶽祠','李廌','宋','宋诗','song-poetry','','[]','嶽鎮中天司下土，名山宮殿鎖雲扃。',64,'全唐诗/poet.song.67000.json','["嶽鎮中天司下土，名山宮殿鎖雲扃。", "固知正直作威福，豈徇往來惟醉醒。", "封禪今無秦漢侈，降生誰是甫申靈。", "何當弭節朝雙闕，一曲鈞天夢帝庭。"]'),
('3db9b702-bfb0-45c0-8a61-a1565c69f266','諸葛菜','李廌','宋','宋诗','song-poetry','','[]','武侯戰地記他年，戰後猶當似率然。',64,'全唐诗/poet.song.67000.json','["武侯戰地記他年，戰後猶當似率然。", "會向渭原驚仲達，尚應江磧感桓玄。", "背山左澤甘如彼，傍砌繞籬今可憐。", "莫問興亡進羹茹，書生贏取腹便便。"]'),
('e91412bd-7502-467b-b3cb-fa5baeda5a8e','將至嵩山遠觀瀑布','李廌','宋','宋诗','song-poetry','','[]','晚晴紫翠溢平川，三十六峰凝霽烟。',64,'全唐诗/poet.song.67000.json','["晚晴紫翠溢平川，三十六峰凝霽烟。", "匹練依稀分秀嶺，玉虹摇曳舞危巔。", "寒光定是連明漢，清氣都疑貫九淵。", "可笑夜來風吹後，亂溝斜澗亦涓涓。"]'),
('2af1b4b6-722d-4991-a180-71a58d934fc5','和人游嵩韵','李廌','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','嵩高峻極壓三川，周視方輿見廣員。',64,'全唐诗/poet.song.67000.json','["嵩高峻極壓三川，周視方輿見廣員。", "絕頂固知天下小，泰山爲占海隅偏。", "白雲散盡千林月，急雨收回萬壑烟。", "莫笑層巒高似岸，舉頭一握是玄天。"]'),
('1cd34330-0999-475a-bc1a-7a56b74817f8','友人董耘饋長沙貓筍廌以享太史公太史公輒作詩爲貺因筍寓意且以爲贈耳廌即和之亦以寓自興之意且述前相知之情焉','李廌','宋','宋诗','song-poetry','','[]','節藏泥滓氣凌空，薦俎寧知肉味重。',64,'全唐诗/poet.song.67000.json','["節藏泥滓氣凌空，薦俎寧知肉味重。", "未許韋編充簡策，已勝絲黍誑蛟龍。", "短萌任逐霜刀重，美榦須煩雪壤封。", "他日要令高士愛，不應常共宰夫供。"]'),
('8d30dde9-018c-4748-9721-0c81c296c8f2','遊寶應寺','李廌','宋','宋诗','song-poetry','','[]','雨後秋風入翠微，我來仍值晚凉時。',64,'全唐诗/poet.song.67000.json','["雨後秋風入翠微，我來仍值晚凉時。", "山遮日脚斜陽早，雲礙鐘聲出谷遲。", "故國空餘烟冉冉，舊宮何在黍離離。", "興亡滿眼無人語，獨倚欄干默自知。"]'),
('ef5c97b1-28af-481f-9609-7fb46c0ea431','賀小蘇先生','李廌','宋','宋诗','song-poetry','','[]','柱史承恩正紫微，玉皇優詔碧雲詞。',160,'全唐诗/poet.song.67000.json','["柱史承恩正紫微，玉皇優詔碧雲詞。", "欲知伯仲文章職，對掌絲綸內外司。", "雨露偏濃常棣萼，烟霞常駐鳳凰池。", "共扶吾道邪歸正，同振斯文盛不衰。", "白首並逢千載運，登庸皆是十年遲。", "靖共介福由神聽，告爾多方代帝咨。", "膴仕初逢賢者貴，德名當問國人宜。", "夷齊抗世清何早，元凱登庸事可期。", "貧賤久思楊得意，龍光今喜鄭當時。", "應憐下客塵埃甚，慚愧雷門獻此詩。"]'),
('754ed0ea-be53-4e86-90cc-e3c18993eb6f','崔先生所守甚高其爲人表裏澹泊然其文曄如有自然之美可喜也因還其詩卷題其末','李廌','宋','宋诗','song-poetry','','[]','別久相思今見君，近詩盈軸語彌新。',160,'全唐诗/poet.song.67000.json','["別久相思今見君，近詩盈軸語彌新。", "雄妍不用近時律，溫厚初還上世淳。", "少與多仇身踽踽，樂天知命志申申。", "才高所寓皆高趣，氣古斯能似古人。", "句有萬鍾辭祿意，衣無一點污人塵。", "中山可鄙魏公子，谷口全如鄭子真。", "珍重遺音清廟瑟，蕭條寡和郢中春。", "誰同杜老知無敵，會有君山謂絕倫。", "白首定交雖自愧，夜光投我豈無因。", "欲知慰此無聊頼，萬斛愁懷爲一伸。"]'),
('27aadbc2-5d56-472c-9016-98c85918a5ce','二士石榻在中院之北巨石如榻有自然石枕可卧二士和大受韵','李廌','宋','宋诗','song-poetry','','[]','憶昔登封日，山蹊困六飛。',24,'全唐诗/poet.song.67000.json','["憶昔登封日，山蹊困六飛。", "我來猶舍杖，共坐拂雲衣。"]'),
('6afb0d61-0b1a-4fcc-97f3-0c2403de021a','荼䕷洞','李廌','宋','宋诗','song-poetry','','[]','無華真國色，有韵自天香。',24,'全唐诗/poet.song.67000.json','["無華真國色，有韵自天香。", "臨風難自持，爲舞白霓裳。"]'),
('de91a175-6bde-4f79-8dee-c12ced10e70f','春日即事九首  其一','李廌','宋','宋诗','song-poetry','','[]','藹藹花絮亂，紛紛蜂蝶多。',24,'全唐诗/poet.song.67000.json','["藹藹花絮亂，紛紛蜂蝶多。", "今年春復爾，不飲奈愁何。"]'),
('823cbb52-afb6-4515-8990-5fdfaa5fb31a','春日即事九首  其二','李廌','宋','宋诗','song-poetry','','[]','新綠陰將就，殘紅在亦稀。',24,'全唐诗/poet.song.67000.json','["新綠陰將就，殘紅在亦稀。", "雨中千點絮，來伴落花飛。"]'),
('ed3ad57f-5b6f-4609-abc9-2a3422f60161','春日即事九首  其三','李廌','宋','宋诗','song-poetry','','[]','怒風吹老屋，急雨鬧空庭。',24,'全唐诗/poet.song.67000.json','["怒風吹老屋，急雨鬧空庭。", "莫歎林花盡，懸知隴麥青。"]'),
('022b9a50-732a-40f9-b757-a3452824d737','春日即事九首  其四','李廌','宋','宋诗','song-poetry','','[]','毛桃猶带蘂，青杏已團枝。',24,'全唐诗/poet.song.67000.json','["毛桃猶带蘂，青杏已團枝。", "老不禁春惱，應知老易欺。"]'),
('e9002648-46a2-4d5e-b92f-cc0d8cd53daf','春日即事九首  其五','李廌','宋','宋诗','song-poetry','','[]','但喜朝朝醉，那知夜夜風。',24,'全唐诗/poet.song.67000.json','["但喜朝朝醉，那知夜夜風。", "老人貪睡美，春夢五更中。"]'),
('f88234ad-a3cb-4c6a-8fcc-d0c9c1f5842b','春日即事九首  其六','李廌','宋','宋诗','song-poetry','','[]','化國有餘暇，豐年多醉人。',24,'全唐诗/poet.song.67000.json','["化國有餘暇，豐年多醉人。", "典衣謀一飲，對酒却慚春。"]'),
('2e8b70a4-5484-424b-aa9a-8928e40cb47a','春日即事九首  其七','李廌','宋','宋诗','song-poetry','','[]','悵望白銅鞮，醉聽金縷衣。',24,'全唐诗/poet.song.67000.json','["悵望白銅鞮，醉聽金縷衣。", "花間愁落日，老更惜春歸。"]'),
('75b41d02-a85e-4a1e-8a53-228183a2c4f6','春日即事九首  其八','李廌','宋','宋诗','song-poetry','','[]','嬌馬寧馨郎，氈車薄媚娘。',24,'全唐诗/poet.song.67000.json','["嬌馬寧馨郎，氈車薄媚娘。", "蕭蕭兩蓬鬢，愁入少年場。"]'),
('75ce65fa-712b-4733-bbcd-aecf60dcbfda','春日即事九首  其九','李廌','宋','宋诗','song-poetry','','[]','逃閒閉關坐，忽有賣花聲。',24,'全唐诗/poet.song.67000.json','["逃閒閉關坐，忽有賣花聲。", "老大自多感，依然京洛情。"]'),
('8fc8f4bd-4803-4e45-9fb7-b14d47440a3d','雪','李廌','宋','宋诗','song-poetry','','[]','紙窗明晃晃，雲日暗暾暾。',24,'全唐诗/poet.song.67000.json','["紙窗明晃晃，雲日暗暾暾。", "半夜寒添被，清晨雪擁門。"]'),
('2639bcf5-8b93-4574-b0b7-3de3588b2a1d','晚晴  其一','李廌','宋','宋诗','song-poetry','','[]','微陽掛木杪，孤鳥下雲淀。',24,'全唐诗/poet.song.67000.json','["微陽掛木杪，孤鳥下雲淀。", "廣墟遺稻粱，鸛鶴伴鳬雁。"]'),
('c1463e7d-4523-4672-8784-3c6567a05abb','晚晴  其二','李廌','宋','宋诗','song-poetry','','[]','陰壑留殘雪，林虹带晚霞。',24,'全唐诗/poet.song.67000.json','["陰壑留殘雪，林虹带晚霞。", "孤烟障漁市，不見兩三家。"]'),
('00c90ca6-73be-406b-9667-c763d3ab8488','臨潁縣','李廌','宋','宋诗','song-poetry','','[]','日永行人漸困，路長饑馬頻嘶。',28,'全唐诗/poet.song.67000.json','["日永行人漸困，路長饑馬頻嘶。", "驚起一雙白鷺，背人飛向前溪。"]'),
('aa36853b-f055-4a4d-8e4a-7241a2e5c7c8','楊花詞三首  其一','李廌','宋','宋诗','song-poetry','','[]','特地飛來有意，等閑却去無情。',28,'全唐诗/poet.song.67000.json','["特地飛來有意，等閑却去無情。", "若比邇來時態，秪應時態猶輕。"]'),
('d1b3fb6c-e91f-46aa-a314-cad2e81ca135','楊花詞三首  其二','李廌','宋','宋诗','song-poetry','','[]','全似秋空白雲，不應日墮紅塵。',28,'全唐诗/poet.song.67000.json','["全似秋空白雲，不應日墮紅塵。", "樓上何人遠望，黯然無語銷魂。"]'),
('d28f2df2-783e-4a63-b56e-0481f4453e3f','楊花詞三首  其三','李廌','宋','宋诗','song-poetry','','[]','苦恨紅梅結子，生憎榆莢悠悠。',28,'全唐诗/poet.song.67000.json','["苦恨紅梅結子，生憎榆莢悠悠。", "解送十分春色，能添萬斛新愁。"]'),
('5b774315-88ff-4bab-a18b-c02d537c9b9d','夜坐','李廌','宋','宋诗','song-poetry','','[]','且喜屋無穿隙雪，未愁漏盡滿靴霜。',32,'全唐诗/poet.song.67000.json','["且喜屋無穿隙雪，未愁漏盡滿靴霜。", "紙幃布被從牢落，頼有希牙齒頰香。"]'),
('71c43323-8a32-46b5-b5e1-723f54df56b0','道中即事呈岑使君吏部次和德麟韵三首  其一','李廌','宋','宋诗','song-poetry','','[]','日射西山爛爛光，低雲遮岸水風凉。',32,'全唐诗/poet.song.67000.json','["日射西山爛爛光，低雲遮岸水風凉。", "從來鞍馬倦行役，笑語不知岐路長。"]'),
('687a1ad9-b5e2-4ec8-a49f-7cf2fd08da62','道中即事呈岑使君吏部次和德麟韵三首  其二','李廌','宋','宋诗','song-poetry','','[]','稻塍粟壠綠相連，野老欣逢大有年。',32,'全唐诗/poet.song.67000.json','["稻塍粟壠綠相連，野老欣逢大有年。", "人意物情俱自適，溶溶佳氣滿江天。"]'),
('3b23e32a-7db2-4028-baec-7198c022b71f','道中即事呈岑使君吏部次和德麟韵三首  其三','李廌','宋','宋诗','song-poetry','','[]','白叟黄童話使君，買牛買犢諭邦人。',32,'全唐诗/poet.song.67000.json','["白叟黄童話使君，買牛買犢諭邦人。", "今年菽粟倉箱滿，仁政常爲七縣春。"]'),
('5ae1674e-66b2-4baa-aeeb-e15756ea49ed','春日偶題寄友人','李廌','宋','宋诗','song-poetry','','[]','低雲不斷風仍急，細雨無聲晚更稠。',32,'全唐诗/poet.song.67000.json','["低雲不斷風仍急，細雨無聲晚更稠。", "千里思君常在眼，黄昏天意自春愁。"]'),
('b2ae2a4b-261f-4c06-a59b-82e1eda23d56','呂顔野飲醉中寄五絕句次其韵  其一','李廌','宋','宋诗','song-poetry','','[]','醉鄉天地一何寬，不問金壺與玉山。',32,'全唐诗/poet.song.67000.json','["醉鄉天地一何寬，不問金壺與玉山。", "暫得陶陶太古意，醒來應亦惡人間。"]'),
('5d73d8f1-8bfb-42fb-a971-7af25001b2c5','呂顔野飲醉中寄五絕句次其韵  其二','李廌','宋','宋诗','song-poetry','','[]','酒在盃中惟恐盡，事來眼底只嫌多。',32,'全唐诗/poet.song.67000.json','["酒在盃中惟恐盡，事來眼底只嫌多。", "一壺醉倒春風裏，萬斛窮愁奈我何。"]'),
('1798b66e-f5b0-4159-96b9-d3d839bfa41e','呂顔野飲醉中寄五絕句次其韵  其三','李廌','宋','宋诗','song-poetry','','[]','醉後詩成筆似椽，客來傾酒酒如泉。',32,'全唐诗/poet.song.67000.json','["醉後詩成筆似椽，客來傾酒酒如泉。", "憐君常得酒中趣，愧我經春只慘然。"]'),
('94d6e778-001e-406c-aac3-79828c33a950','呂顔野飲醉中寄五絕句次其韵  其四','李廌','宋','宋诗','song-poetry','','[]','手持金盞灧斜暉，目送歸鴻萬里飛。',32,'全唐诗/poet.song.67000.json','["手持金盞灧斜暉，目送歸鴻萬里飛。", "還似習家池上日，醉中倒載接䍦歸。"]'),
('8e2c42db-6fa9-4c11-b86d-b9fa7949729e','呂顔野飲醉中寄五絕句次其韵  其五','李廌','宋','宋诗','song-poetry','','[]','醉倒南山卧白雲，滿天詩思不勝春。',32,'全唐诗/poet.song.67000.json','["醉倒南山卧白雲，滿天詩思不勝春。", "黄雞白酒真堪樂，誰道蓬蒿有此人。"]'),
('c01b0785-1f52-460c-bab4-eedc80403b7f','題孔氏東園三首  其一','李廌','宋','宋诗','song-poetry','','[]','何處移來薝蔔花，琢成玉葉靜無瑕。',32,'全唐诗/poet.song.67000.json','["何處移來薝蔔花，琢成玉葉靜無瑕。", "天香不合人間有，只是祇園居士家。"]'),
('f545fdb7-f784-4701-bb72-5bbae5106efd','題孔氏東園三首  其二','李廌','宋','宋诗','song-poetry','','[]','桐已參天栢已蒼，昔年曾見似人長。',32,'全唐诗/poet.song.67000.json','["桐已參天栢已蒼，昔年曾見似人長。", "樹猶如此人休怪，賓主相逢鬢各霜。"]'),
