('09e0a8a5-505f-4f9a-8393-053a175108df','和李端叔大夫從參寥子游許昌西湖十絕  其二','李廌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','草已芊綿柳已柔，落花重疊不須愁。',32,'全唐诗/poet.song.67000.json','["草已芊綿柳已柔，落花重疊不須愁。", "風光流轉等閒過，又是一年春事休。"]'),
('b141f936-0eb3-4331-bcd6-6372594534ea','和李端叔大夫從參寥子游許昌西湖十絕  其三','李廌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百物爭春竟可憐，清池綠浄但沉天。',32,'全唐诗/poet.song.67000.json','["百物爭春竟可憐，清池綠浄但沉天。", "浮萍細碎從渠長，憎見差池點荇錢。"]'),
('7b275a47-aa53-41b2-92ad-30e7e7d138a6','和李端叔大夫從參寥子游許昌西湖十絕  其四','李廌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西疇新買數塍田，便掃空囷俟有年。',32,'全唐诗/poet.song.67000.json','["西疇新買數塍田，便掃空囷俟有年。", "欲坐瓜菴吹豆葉，風翻黄浪麥秋天。"]'),
('24ad8cc4-aa82-4682-a844-8566bee879f2','和李端叔大夫從參寥子游許昌西湖十絕  其五','李廌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風頭皺浪開還促，雨點圓紋亂更多。',32,'全唐诗/poet.song.67000.json','["風頭皺浪開還促，雨點圓紋亂更多。", "何似無風亦無雨，碧天千里在澄波。"]'),
('045b656f-072d-4f4b-b9ae-e93eb3fb067e','和李端叔大夫從參寥子游許昌西湖十絕  其六','李廌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','癡兒插地栽楊柳，楊柳無根插便生。',32,'全唐诗/poet.song.67000.json','["癡兒插地栽楊柳，楊柳無根插便生。", "我亦無根常作客，四年漂泊大梁城。"]'),
('8c29d1ff-6569-45ce-b0e4-730e7fed981d','和李端叔大夫從參寥子游許昌西湖十絕  其七','李廌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','股大如腰立已憂，不須登閣始三休。',32,'全唐诗/poet.song.67000.json','["股大如腰立已憂，不須登閣始三休。", "道人尊足元無病，莫取形骸向裏求。"]'),
('4f105adb-ba46-4fdf-a659-8ac71986426d','和李端叔大夫從參寥子游許昌西湖十絕  其八','李廌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夢爲蝴蝶恣飛飛，飛入花叢處處迷。',32,'全唐诗/poet.song.67000.json','["夢爲蝴蝶恣飛飛，飛入花叢處處迷。", "不是提壺强呼起，尚應栩栩展江西。"]'),
('8a8588b0-3b6d-44f2-8d91-ad6def5f9752','和李端叔大夫從參寥子游許昌西湖十絕  其九','李廌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','詩翁詩思與春爭，落筆風雷紙上生。',32,'全唐诗/poet.song.67000.json','["詩翁詩思與春爭，落筆風雷紙上生。", "雪棘滿頤心尚壯，君看巖電射人明。"]'),
('e06033ca-2a69-4371-8fcc-eb053a9b70b9','和李端叔大夫從參寥子游許昌西湖十絕  其一○','李廌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','池南池北亂蛙聲，不問官私處處鳴。',32,'全唐诗/poet.song.67000.json','["池南池北亂蛙聲，不問官私處處鳴。", "昨夜一犁新雨足，無煩科斗更滋生。"]'),
('6340fed1-1594-4fd6-b345-19daa40d1d59','釣臺  其一','李廌','宋','宋诗','song-poetry','','[]','竹岡深貯一溪雲，溪灣路盡釣磯新。',32,'全唐诗/poet.song.67000.json','["竹岡深貯一溪雲，溪灣路盡釣磯新。", "魚鳥相忘自相樂，使君元是狎鷗人。"]'),
('80e4c92e-a0a3-4783-8a7c-00d93129f9ea','釣臺  其二','李廌','宋','宋诗','song-poetry','','[]','山東太白謫仙人，筆捲天河氣拂雲。',32,'全唐诗/poet.song.67000.json','["山東太白謫仙人，筆捲天河氣拂雲。", "百代公卿嘲哂徧，清溪石上想嚴君。"]'),
('e22eb83f-05cf-42ee-ac9c-678fed780ca5','釣臺  其三','李廌','宋','宋诗','song-poetry','','[]','興王不患無功業，賊亂常憂在歲寒。',32,'全唐诗/poet.song.67000.json','["興王不患無功業，賊亂常憂在歲寒。", "能緩阿瞞移鼎手，長鋋此日愧漁竿。"]'),
('5d4d362c-4dc8-42e5-97b7-5bf6a2ec5d8d','中春','李廌','宋','宋诗','song-poetry','','[]','輕挨殘花香簌簌，旋剝新筍白纖纖。',32,'全唐诗/poet.song.67000.json','["輕挨殘花香簌簌，旋剝新筍白纖纖。", "傷春煮筍買春酒，短褐破碎人家嫌。"]'),
('f43d89a3-ffb7-41d1-8922-5bc9e3bd568f','王子立寄三絕句云常詣夏頤吉卜云宜見君子子立作詩廌次韵  其一','李廌','宋','宋诗','song-poetry','','[]','久依鳳翼與龍鱗，萬里青雲可致身。',32,'全唐诗/poet.song.67000.json','["久依鳳翼與龍鱗，萬里青雲可致身。", "聖主求賢如不及，夜光豈復怒無因。"]'),
('baae3b30-4989-42c4-a9b7-b8174e721ee5','王子立寄三絕句云常詣夏頤吉卜云宜見君子子立作詩廌次韵  其二','李廌','宋','宋诗','song-poetry','','[]','富貴自知當自信，耆鮐福併固脩長。',32,'全唐诗/poet.song.67000.json','["富貴自知當自信，耆鮐福併固脩長。", "陰陽可測非天理，男子人知亦易量。"]'),
('07d37f88-d351-44c9-9bec-92ffa4619935','王子立寄三絕句云常詣夏頤吉卜云宜見君子子立作詩廌次韵  其三','李廌','宋','宋诗','song-poetry','','[]','三首新詩慰病軀，萬金何必是家書。',32,'全唐诗/poet.song.67000.json','["三首新詩慰病軀，萬金何必是家書。", "隔年已有游嵩約，玉趾何時過敝廬。"]'),
('3b09a2e8-f339-4d3f-8815-aa521372a72d','寒食','李廌','宋','宋诗','song-poetry','','[]','千株蜜炬出嚴闉，走馬天街賜近臣。',32,'全唐诗/poet.song.67000.json','["千株蜜炬出嚴闉，走馬天街賜近臣。", "我亦茅檐自鑽燧，煨鍼燒艾檢銅人。"]'),
('2dddc378-3518-461e-be77-d04b74b9bbdf','飲襄陽沈氏家醉題侍兒小瑩裙带','李廌','宋','宋诗','song-poetry','','[]','旋剪香羅列地垂，嬌紅嫩綠寫珠璣。',32,'全唐诗/poet.song.67000.json','["旋剪香羅列地垂，嬌紅嫩綠寫珠璣。", "花前欲作重重結，繫定春光不放歸。"]'),
('d929aa46-084a-40cb-aea1-a330de8622ee','興安道中雪晴見羣山偶成','李廌','宋','宋诗','song-poetry','','[]','關山千里湧銀濤，晚日烘雲欲動摇。',32,'全唐诗/poet.song.67000.json','["關山千里湧銀濤，晚日烘雲欲動摇。", "滕六自知遷客近，前驅一洗瘴烟消。"]'),
('162a67b8-5c18-4e2e-9cd6-68e799b55635','雪晴','李廌','宋','宋诗','song-poetry','','[]','山凝秀色螺成髻，溪走寒光珠在盤。',32,'全唐诗/poet.song.67000.json','["山凝秀色螺成髻，溪走寒光珠在盤。", "更欲呈姿作清巧，暫粧梅柳雪中看。"]'),
('ade64169-9555-460f-a499-6a37efa48eac','飛閣','李廌','宋','宋诗','song-poetry','','[]','飛閣凌波浮渺茫，碧山白雲坐相忘。',32,'全唐诗/poet.song.67000.json','["飛閣凌波浮渺茫，碧山白雲坐相忘。", "好風歷楯泛我袂，興來取纓濯滄浪。"]'),
('136adb53-3dbe-4851-8559-da25d76d59de','未曉出雙池小雪作','李廌','宋','宋诗','song-poetry','','[]','匆匆蓐食過重丘，炬影通林見遠流。',32,'全唐诗/poet.song.67000.json','["匆匆蓐食過重丘，炬影通林見遠流。", "雲物瀾翻烟羃歷，細風吹霰上征裘。"]'),
('2a243d05-43ba-41a1-89f2-4e6ec7b2435e','瓦廟','李廌','宋','宋诗','song-poetry','','[]','柱側簷欹瓦欲飄，斷垣苔澀樹蕭蕭。',32,'全唐诗/poet.song.67000.json','["柱側簷欹瓦欲飄，斷垣苔澀樹蕭蕭。", "滿庭荒草無香火，惟有禽聲伴寂寥。"]'),
('4b81108d-bb05-458c-8350-a513335ffd52','登楚山絕頂','李廌','宋','宋诗','song-poetry','','[]','新雨路少人，公子有佳招。',240,'全唐诗/poet.song.67000.json','["新雨路少人，公子有佳招。", "下馬語未竟，西城趨連鑣。", "初云眺江閣，忽欲登山椒。", "陟巘踐蹺踊，舍鞍升岧嶢。", "濈濈雲屨濕，翩翩風袂飄。", "廣隰綠交映，蕪城遠無囂。", "带繚江路永，隙光溪影摇。", "他山若聚米，亂壠疑翻潮。", "岸巾歎鬢槁，撫髀憐肉消。", "欲攄紆鬰懷，自恨痀僂腰。", "心知中峰近，意怯老步遙。", "班荆坐危磴，植杖臨高苗。", "注目送三士，綠蘿凌九霄。", "風流蹔雲散，箕踞還獨謠。", "仰答順風呼，俯聽深澗樵。", "山靈或聳誚，谷友如遷喬。", "雖同仙凡隔，亦覺神爽超。", "毋比抱腸鼠，已異枝巢鷯。", "夕曛下歸徑，平林有鳴蜩。", "回瞻已陳迹，青靄烟寥寥。"]'),
('2f11300c-6125-46c5-a289-d24de6489eda','老歎','李廌','宋','宋诗','song-poetry','','[]','此身常恐竟無成，憂患頻更已不驚。',64,'全唐诗/poet.song.67000.json','["此身常恐竟無成，憂患頻更已不驚。", "下第但能供酒令，他時何意主文盟。", "耽經謾有春秋癖，閉戶猶防月旦評。", "獨對秋風歎華髮，暮雲蕭瑟歲崢嶸。"]'),
('d79010b2-20b5-4c23-a409-429b559270b3','孔北海堂','李廌','宋','宋诗','song-poetry','','[]','卯金自中葉，已若子南周。',264,'全唐诗/poet.song.67000.json','["卯金自中葉，已若子南周。", "阿瞞制威福，九鼎若綴旒。", "餘子不復忌，多士例爲仇。", "嶄然見芒角，已坐錮與鈎。", "誰知英雄彀，翻令作罝罘。", "假手陷正平，謔玩戮楊修。", "小慧尚必除，偉人那得留。", "凜凜孔北海，胸次包九州。", "倘令坐廟堂，大盜當寢謀。", "專誅及斯人，遂負壑與舟。", "當時同朝士，苟生盍包羞。", "身死名亦滅，白骨委山丘。", "先生雖千載，生氣尚橫秋。", "當時眼中意，付與一醉休。", "文人具文行，來作東諸侯。", "尚友天下士，復于古人求。", "作亭俯層城，持杯想風流。", "壁間妙著述，騰光昏斗牛。", "文存人亦亡，應從文舉游。", "我生真碌碌，與世甘沉浮。", "思爲坐上客，揚觶和南謳。", "無成老岩谷，哀哉空白頭。"]'),
('8fc1a416-6c63-435f-8f2a-3c385c510c2f','光化霽景樓','李廌','宋','宋诗','song-poetry','','[]','層樓壓清漢，初上便忘歸。',48,'全唐诗/poet.song.67000.json','["層樓壓清漢，初上便忘歸。", "夕靄藏平野，晴烟漏翠微。", "城昏晚鴉集，江靜野鷗飛。", "何日賦招隠，行吟傍釣磯。"]'),
('16e9ff3e-0d3d-4837-9333-f894b2adbaf1','詩一首','李廌','宋','宋诗','song-poetry','','[]','江皋草茅軟，馬首路平寬。',48,'全唐诗/poet.song.67000.json','["江皋草茅軟，馬首路平寬。", "歎老龍鍾態，傷春料峭寒。", "月簷茅影亂，風瓦竹聲乾。", "喜從佳公子，詩成槊在鞍。"]'),
('2903ecf9-1f59-4b47-b4d4-790d6c28125c','社日書懷','李廌','宋','宋诗','song-poetry','','[]','社公沐髮望年豐，豈謂雨餘仍苦風。',64,'全唐诗/poet.song.67000.json','["社公沐髮望年豐，豈謂雨餘仍苦風。", "未報田間禾穎秀，但驚堂上燕巢空。", "里人分胙祈微福，稚子爬溝擬乞聰。", "老病不知秋過半，謾芻新釀要治聾。"]'),
('208c2dba-95ac-4030-afa9-01740db6d2d2','句  其一','李廌','宋','宋诗','song-poetry','','[]','文林換却山林興，誰道山人索價高。',16,'全唐诗/poet.song.67000.json','["文林換却山林興，誰道山人索價高。"]'),
('51f5af4b-04c7-4eec-b772-488c2cea0565','句  其二','李廌','宋','宋诗','song-poetry','','[]','可笑陳孟公，好客常投轄。',12,'全唐诗/poet.song.67000.json','["可笑陳孟公，好客常投轄。"]'),
('f2ece770-96e6-4be6-aa3e-a3fb6bb8e49e','句  其三','李廌','宋','宋诗','song-poetry','','[]','安得吾皇四百州，皆如此邦二千石。',16,'全唐诗/poet.song.67000.json','["安得吾皇四百州，皆如此邦二千石。"]'),
('3af5bb89-9dfc-4e32-b5fd-d7c3aa79b937','存目','李廌','宋','宋诗','song-poetry','','[]','詩題：再領玉局昔東坡在翰林……後自嶺外歸遂領玉局予復官亦得之坡今亡矣悵然有懷首句：東坡因地夙相親。',49,'全唐诗/poet.song.67000.json','["詩題：再領玉局昔東坡在翰林……後自嶺外歸遂領玉局予復官亦得之坡今亡矣悵然有懷首句：東坡因地夙相親。"]'),
('10a5c2b2-a6a0-4dbe-b943-ef993872824d','題申王畫馬圖','蔡肇','宋','宋诗','song-poetry','','[]','天寶諸王愛名馬，千金爭致華軒下。',160,'全唐诗/poet.song.67000.json','["天寶諸王愛名馬，千金爭致華軒下。", "當時不獨玉花驄，飛電流雲絕瀟灑。", "兩方岐薛寧與申，憑陵內廐多清新。", "肉騣汗血盡龍種，紫袍玉带真天人。", "驪山射獵包原隰，御前急詔穿圍入。", "揚鞭一蹙破霜蹄，萬騎如風不能入。", "雁飛兔走驚絃開，翠華按轡從天回。", "五家錦繡徧山谷，百里舄珥遺塵埃。", "青騾蜀棧西超忽，高準濃蛾散荆棘。", "苜蓿連山鳥自飛，五陵佳氣春蕭瑟。"]'),
('e6e5c4dd-aef6-4477-83e4-7446bd6a1364','冬日遊甘露寺','蔡肇','宋','宋诗','song-poetry','','[]','漕河膠舟水流咽，水關著鍵行者歇。',96,'全唐诗/poet.song.67000.json','["漕河膠舟水流咽，水關著鍵行者歇。", "大江伏槎卧長劍，萬頃濕銀寒不結。", "蓬萊諸仙亦避寒，海門冥冥凍欲坼。", "朔風吹晚雁叫空，蓬巷松杉崖石裂。", "道人丈室最高處，地爐蒲團穩坐熱。", "我來乘閒不問道，方牀相對無言說。"]'),
('0f950bd9-0f1d-40e1-b52c-2d1779118aa4','立春日焦山留宿','蔡肇','宋','宋诗','song-poetry','','[]','歲爲茲山一再登，渡頭飛閣獨相凭。',64,'全唐诗/poet.song.67000.json','["歲爲茲山一再登，渡頭飛閣獨相凭。", "雲生江海交流處，人在松蘿最上層。", "殘雪既能留野客，春風先與報山僧。", "憑誰邀上東巖宿，更約花時命杖藤。"]'),
('5ec508f7-03ca-4f8d-abe0-deaee3d45a84','題畫授李伯時','蔡肇','宋','宋诗','song-poetry','','[]','鴻雁歸時水拍天，平岡老木尚依然。',32,'全唐诗/poet.song.67000.json','["鴻雁歸時水拍天，平岡老木尚依然。", "借君餘地安漁艇，乞我寒江聽雨眠。"]'),
('3413a7b5-99ea-43d9-a678-8704d717cc25','汎舟橫塘遇雨','蔡肇','宋','宋诗','song-poetry','','[]','平野風烟入夢思，殷勤作畫更題詩。',32,'全唐诗/poet.song.67000.json','["平野風烟入夢思，殷勤作畫更題詩。", "扁舟卧聽橫塘雨，恰遇江南歸雁時。"]'),
('375de768-fe55-43ad-89f0-963c86294c74','題李世南畫扇','蔡肇','宋','宋诗','song-poetry','','[]','野水潺潺平落澗，秋風瑟瑟細吹林。',32,'全唐诗/poet.song.67000.json','["野水潺潺平落澗，秋風瑟瑟細吹林。", "逢人抱甕知村近，隔塢聞鐘覺寺深。"]'),
('45878191-2fdc-4c74-855d-cadc96fde53b','過邢惇夫墓下作','蔡肇','宋','宋诗','song-poetry','','[]','人物於今歎渺然，孤墳宿草已生煙。',32,'全唐诗/poet.song.67000.json','["人物於今歎渺然，孤墳宿草已生煙。", "日暮行人道傍會，應逢年少與談玄。"]'),
('953a14e0-2697-4bcc-8fa5-a898566e33f2','至學省作','蔡肇','宋','宋诗','song-poetry','','[]','平生擾擾復膠膠，學省重來歲又交。',64,'全唐诗/poet.song.67000.json','["平生擾擾復膠膠，學省重來歲又交。", "騎馬醉遭官長駡，讀書慚被學生嘲。", "何爲眷戀米三斗，便可經營宅一茅。", "好買江干千个竹，待看煙雨長春梢。"]'),
('3b2bab01-8eba-453f-98d9-ed0c6ed3b8cb','送洞元法師歸茅山三首  其一','蔡肇','宋','宋诗','song-poetry','','[]','絳節飄飄下紫清，更參隠訣制頹齡。',32,'全唐诗/poet.song.67000.json','["絳節飄飄下紫清，更參隠訣制頹齡。", "若逢方丈龐眉叟，來愛囊中赤甲經。"]'),
('5b0e8c1b-deee-4ad3-83a9-b3c27fcb5ca3','送洞元法師歸茅山三首  其二','蔡肇','宋','宋诗','song-poetry','','[]','崇寧新閣連雲起，天篆浮空寶氣飛。',32,'全唐诗/poet.song.67000.json','["崇寧新閣連雲起，天篆浮空寶氣飛。", "帝遣羣龍常護守，池潭風雨夜深歸。"]'),
('933c4321-cc1a-4362-80de-5138f2e35e12','送洞元法師歸茅山三首  其三','蔡肇','宋','宋诗','song-poetry','','[]','一菴疇昔共嶔崟，古木垂陰歲月深。',32,'全唐诗/poet.song.67000.json','["一菴疇昔共嶔崟，古木垂陰歲月深。", "恐是三生房次律，要隨藤杖去重尋。"]'),
('82fd565b-a3d3-43e2-9333-3f4b9e1e24bd','題三茅風雨圖','蔡肇','宋','宋诗','song-poetry','','[]','筆間雲氣生毫末，紙上松聲聽有無。',32,'全唐诗/poet.song.67000.json','["筆間雲氣生毫末，紙上松聲聽有無。", "收得三茅風雨樣，高堂六月是冰壺。"]'),
('c1697b06-3248-4c78-9c7c-4a18dc5c849a','𠙶亭山頂白龍穴','蔡肇','宋','宋诗','song-poetry','','[]','南山鼕鼕天作鼓，號召諸龍盡行雨。',32,'全唐诗/poet.song.67000.json','["南山鼕鼕天作鼓，號召諸龍盡行雨。", "惟有禿角最先到，潑墨雲中鱗鬣舞。"]'),
('a7bd6b0f-141f-4cdf-9a6c-751dd150d9a7','和慎思詩呈同院諸公  其一','蔡肇','宋','宋诗','song-poetry','','[]','圖書從所好，英俊此焉依。',48,'全唐诗/poet.song.67000.json','["圖書從所好，英俊此焉依。", "奎壁重開照，琳瑯盡得歸。", "地嚴宮漏轉，門掩吏人稀。", "子有詩三百，西江咀寶璣。"]'),
('8e1fd67f-8604-416f-9c52-0af447d8337d','和慎思詩呈同院諸公  其二','蔡肇','宋','宋诗','song-poetry','','[]','客去衣裳嬾，更長燈燭光。',48,'全唐诗/poet.song.67000.json','["客去衣裳嬾，更長燈燭光。", "隨身一書笈，貯腹萬雕梁。", "夢舊傳青館，封須拜皁囊。", "羽翰從此正，天步赤霄長。"]'),
('08c396f8-d725-4cc7-a4b9-4ab669ae218b','和慎思詩呈同院諸公  其三','蔡肇','宋','宋诗','song-poetry','','[]','諸彥聯翩入，斯文迤邐回。',48,'全唐诗/poet.song.67000.json','["諸彥聯翩入，斯文迤邐回。", "滔滔引溟漲，爛爛繚巖隈。", "此地身拘窘，他時心往來。", "倡酬真有味，顧我獨非才。"]'),
('6ecd5f2d-9cbf-438e-b3ba-1c801e52341f','和慎思秋日同文館詩  其一','蔡肇','宋','宋诗','song-poetry','','[]','清月看初滿，黄花吐未齊。',48,'全唐诗/poet.song.67000.json','["清月看初滿，黄花吐未齊。", "小山思隠桂，大谷憶佳梨。", "節物信可美，詩騷懶自題。", "長年諳獨宿，聽雨閉秋閨。"]'),
('63eb1a8a-225f-4997-b207-51041ec1f73e','和慎思秋日同文館詩  其二','蔡肇','宋','宋诗','song-poetry','','[]','匝合青雲幕，縱橫白羽場。',48,'全唐诗/poet.song.67000.json','["匝合青雲幕，縱橫白羽場。", "誰矜率爾對，吾念斐然章。", "名淡隃糜榜，衣飄月窟香。", "春風馬蹄疾，鞭帽散平康。"]'),
('5a96e217-4353-43fe-89c3-e539c2fc4ec4','和慎思秋日同文館詩  其三','蔡肇','宋','宋诗','song-poetry','','[]','萬里夷王子，曾聽若木雞。',48,'全唐诗/poet.song.67000.json','["萬里夷王子，曾聽若木雞。", "泛舟滄海外，授館國門西。", "琛幣來重譯，車書想舊題。", "蒼梧弓劍冷，雲雨泣芝泥。"]'),
('129c9852-5adc-4a3b-a613-75fbf80e3748','和慎思秋日同文館詩  其四','蔡肇','宋','宋诗','song-poetry','','[]','闃寂同文館，秋英綻欲齊。',48,'全唐诗/poet.song.67000.json','["闃寂同文館，秋英綻欲齊。", "禪庖分白乳，仙果破青梨。", "琴理將忘曲，詩探未賦題。", "清懽在文史，誰復夢重閨。"]'),
('2c4ad8cf-0588-482c-a09e-318b7465a2dc','和慎思秋日同文館詩  其五','蔡肇','宋','宋诗','song-poetry','','[]','明時勤選擢，間設譽髦場。',48,'全唐诗/poet.song.67000.json','["明時勤選擢，間設譽髦場。", "該學添三傳，微能及九章。", "靜無桃葉唱，清有菊花香。", "解我幽憂病，惟應頼杜康。"]'),
('337803c6-ae88-4d6a-a942-37126a7d2429','和慎思秋日同文館詩  其六','蔡肇','宋','宋诗','song-poetry','','[]','鵠卵因時化，如何赴越雞。',48,'全唐诗/poet.song.67000.json','["鵠卵因時化，如何赴越雞。", "逸羣來冀北，屏氣入淮西。", "盛事兼三物，浮辭斥百題。", "慎須精藻鑒，寵辱異雲泥。"]'),
('8a955ecc-67d0-4be7-b1d8-865c8b17b104','和慎思未試即事雜書率用秋日同文館爲首句  其一','蔡肇','宋','宋诗','song-poetry','','[]','翳翳雲生樹，翻翻風動闈。',48,'全唐诗/poet.song.67000.json','["翳翳雲生樹，翻翻風動闈。", "高秋忽如此，吾黨苦思歸。", "極目愁關塞，侵寒寄褚衣。", "少狂真喜事，回首壯心違。"]'),
('06093b3e-8712-4623-a286-5b4ba60835ec','和慎思未試即事雜書率用秋日同文館爲首句  其二','蔡肇','宋','宋诗','song-poetry','','[]','物色清秋逼，官曹靜夜長。',48,'全唐诗/poet.song.67000.json','["物色清秋逼，官曹靜夜長。", "華星披夕靄，皎露洗空凉。", "律細詩難繼，禪心夢易忘。", "依稀貪佛日，香火宿諸方。"]'),
('7295a262-9334-4bf3-bdeb-f6d34dab958c','和慎思未試即事雜書率用秋日同文館爲首句  其三','蔡肇','宋','宋诗','song-poetry','','[]','取士漁鹽出，傳經戶牖開。',48,'全唐诗/poet.song.67000.json','["取士漁鹽出，傳經戶牖開。", "驚濤簾外起，驟雨筆端來。", "人競懸金鑒，書方貴玉杯。", "太平元有象，勿遣賦良媒。"]'),
('121ac8df-2fc8-4eb1-bb33-14b6cb3fef87','再和慎思俯和少年真善事之句','蔡肇','宋','宋诗','song-poetry','','[]','百萬防秋去，軍容凜將闈。',48,'全唐诗/poet.song.67000.json','["百萬防秋去，軍容凜將闈。", "請排雲鳥出，盡獵犬羊歸。", "老息陰符讀，慵便直裰衣。", "鄧侯多衮興，時命不予違。"]'),
('a418d023-c06a-4da0-bcf6-4c9bd27a0358','和慎思詩呈同院後至諸公','蔡肇','宋','宋诗','song-poetry','','[]','文書汗牛馬，棟宇切昭回。',48,'全唐诗/poet.song.67000.json','["文書汗牛馬，棟宇切昭回。", "剸玉君曾試，吹竽我亦來。", "鑒精真有頼，詩妙不容陪。", "只憶歸山去，霜畦斸芋魁。"]'),
('a1e73ead-b697-43de-8170-722cca9a76d2','和慎思初入試院','蔡肇','宋','宋诗','song-poetry','','[]','午門鑰入斷人行，禁漏稀微出邇英。',64,'全唐诗/poet.song.67000.json','["午門鑰入斷人行，禁漏稀微出邇英。", "齊拜勅書期老仗，並驅騶御出西城。", "諠譁燈火看如夢，關鎖官曹祇寄聲。", "聊付能詩破羈旅，詩成冉冉又還生。"]'),
('78886715-9436-4f89-8bc4-aa52144752aa','和慎思重九考罷試卷書呈同院諸公','蔡肇','宋','宋诗','song-poetry','','[]','清秋官舍酒瓶空，滿袖黄花情所鍾。',64,'全唐诗/poet.song.67000.json','["清秋官舍酒瓶空，滿袖黄花情所鍾。", "忽得數篇吟可老，絕知開口笑難逢。", "浮舟有底不歸去，戲馬猶能限莫從。", "江上鱸魚三尺許，西風欹枕夢魂濃。"]'),
('5036f0d5-7e14-45d4-bc89-6fe033453e84','次韵慎思貽无咎文潜誦詩','蔡肇','宋','宋诗','song-poetry','','[]','卧聽高齋落葉風，清詩交詠想晨鐘。',64,'全唐诗/poet.song.67000.json','["卧聽高齋落葉風，清詩交詠想晨鐘。", "故人厚意論千載，正始遺音僅一逢。", "膠漆初期在俄頃，雲龍莫恨不相從。", "芸房深鎖秋香冷，鬰鬰葱葱佳氣濃。"]'),
('ec3c5558-e8ba-4028-9d82-820243d82ac9','和慎思同舍問及故山景物用鐘字韵詩以答','蔡肇','宋','宋诗','song-poetry','','[]','白鹿真人欻御風，青杉手種大如鐘。',64,'全唐诗/poet.song.67000.json','["白鹿真人欻御風，青杉手種大如鐘。", "還丹未化神應護，道骨相期子合逢。", "萬里且看騰踏去，一樽聊喜笑言從。", "攢峰列壑休南望，曉榻秋陰分外濃。"]'),
('04bfc484-9823-4ef6-abb4-71cec7278dfe','和慎思漫興成章屢蒙子方寵和更辱贈句輒用奉酬','蔡肇','宋','宋诗','song-poetry','','[]','曹公長劍一杯酒，鄧子孤雲萬里心。',64,'全唐诗/poet.song.67000.json','["曹公長劍一杯酒，鄧子孤雲萬里心。", "神駿莫辭觀馬廄，深沉久合寄書林。", "禮闈聯事幾三月，詞客悲秋共一音。", "獨有何郎詩思苦，空階點滴伴清吟。"]'),
('90f43a05-9877-4077-9c98-ad67c322115c','慎思說家山之勝用其語得詩','蔡肇','宋','宋诗','song-poetry','','[]','江清石磊磊，野曠竹修修。',48,'全唐诗/poet.song.67000.json','["江清石磊磊，野曠竹修修。", "此地有茅屋，我行尋白鷗。", "分留須物色，來往更風流。", "相對黄塵夢，詩成擁鼻謳。"]'),
('e02af7b5-51db-4106-bfc4-5f05dae8d6e3','和慎思寄次張弟','蔡肇','宋','宋诗','song-poetry','','[]','南山千畝龍蛇窟，半夜春雷起屈盤。',32,'全唐诗/poet.song.67000.json','["南山千畝龍蛇窟，半夜春雷起屈盤。", "欲釣六鼇滄海去，爲留春筍作長竿。"]'),
('50384471-4c32-4d8e-b711-0fb6f372fba2','和无咎奉答文潜戲贈','蔡肇','宋','宋诗','song-poetry','','[]','鄧子詞鋒魯孟勞，刜鍾剸玉盡鉛刀。',32,'全唐诗/poet.song.67000.json','["鄧子詞鋒魯孟勞，刜鍾剸玉盡鉛刀。", "風流陶謝枝梧困，擊節期君僕命騷。"]'),
('865002a1-8e58-4dd5-b10c-73301dc3c500','小詩戲无咎','蔡肇','宋','宋诗','song-poetry','','[]','吳山楚水未忘懷，暮雨朝雲恨已乖。',32,'全唐诗/poet.song.67000.json','["吳山楚水未忘懷，暮雨朝雲恨已乖。", "縱免摩伽能毀戒，未妨澤室會千齋。"]'),
('9ace54da-951f-4316-8647-6d3492bb26db','和慎思與文潜无咎對榻夜話達旦','蔡肇','宋','宋诗','song-poetry','','[]','窮秋天氣少晴明，雨葉風窗夜夜聲。',32,'全唐诗/poet.song.67000.json','["窮秋天氣少晴明，雨葉風窗夜夜聲。", "應爲幽人聽未足，不教驄馬出重城。"]'),
('d5c46ad3-9580-49d4-b07e-9ff2abbc3dc1','和文潜初伏大雨戲呈无咎','蔡肇','宋','宋诗','song-poetry','','[]','城中鼎食排翠釜，羊胛駝峰賤如土。',128,'全唐诗/poet.song.67000.json','["城中鼎食排翠釜，羊胛駝峰賤如土。", "青衫學士家故貧，斗米束薪炊濕雨。", "縱橫圖史照屋壁，呫囁詩騷從稚乳。", "省中無事騎馬歸，雨聲一洗茅簷苦。", "急呼南巷同舍郎，聽我臨風有凉語。", "且貪青簡事文章，未有黄金買歌舞。", "往來詩卷牛腰許，太羹玄酒並在戶。", "吾詩老澀邀使前，政坐可口收艱俎。"]'),
('ab175eb9-0272-4cf0-b42d-ef14d157659e','次韵上文潜丈','蔡肇','宋','宋诗','song-poetry','','[]','張侯胸中包覆釜，百里奔流無寸土。',128,'全唐诗/poet.song.67000.json','["張侯胸中包覆釜，百里奔流無寸土。", "玄蛟白鼉有時作，一洗乾坤三日雨。", "詩雄變怪有如此，震動猶能止啼乳。", "已傾太白酒船空，更壓少陵飯山苦。", "昨朝東門同拜勅，玉齒猶殘道中語。", "閉門十日無一事，坐對空庭秋葉舞。", "何時御史出霜臺，便假前騶辭棘戶。", "城南邀我倒餘尊，紫栗黄橙已登俎。"]'),
('3219b04b-4730-464c-8c9b-e0f9296f008f','再答文潜','蔡肇','宋','宋诗','song-poetry','','[]','羌兵昔出皋蘭路，欲鏟新城無聚土。',128,'全唐诗/poet.song.67000.json','["羌兵昔出皋蘭路，欲鏟新城無聚土。", "烟烽照夜氣如霞，鐵馬連羣歕成雨。", "東西兩關同日破，股掌嬰兒絕哺乳。", "鼓聲十日拔帳歸，至今猶說防城苦。", "當時諸將無奇策，不敢彎弓向胡語。", "橐駝西來金帛去，孽狐小鼠猶跳舞。", "王師八月盡防秋，惴惴軍興恐編戶。", "腐儒不用輒憂邊，廟堂有人制尊俎。"]'),
('4afa7b9e-1b8d-4bb6-ae01-29b6d3aa7666','用俎字韵呈樗年','蔡肇','宋','宋诗','song-poetry','','[]','墮竈一言能破釜，魔界掃空成佛土。',128,'全唐诗/poet.song.67000.json','["墮竈一言能破釜，魔界掃空成佛土。", "鍾山道場天所開，萬壑千巖沒華雨。", "白衣居士演真諦，江漢滔滔流去乳。", "自從玉髻飛上天，妙緣誰救諸有苦。", "我昔南行入定林，水鳥松風能妙語。", "六時天樂綵雲飛，百丈寒江翠綃舞。", "此地知君曾著力，雷作彈指開蟄戶。", "空山蕙帳盍思歸，秋末晚菘行可俎。"]'),
('5bfffa9b-d5dd-4261-999b-f4ff24aed74e','上呈子方鄉丈','蔡肇','宋','宋诗','song-poetry','','[]','西方殘敵魚游釜，往歲天兵收境土。',128,'全唐诗/poet.song.67000.json','["西方殘敵魚游釜，往歲天兵收境土。", "軍行旱海口生烟，沙井無泉天不雨。", "將軍意氣吞八荒，欲入凉州傾馬乳。", "堅城不下河未冰，幕中稍覺從軍苦。", "曹侯獻計取東關，帳下選鋒同此語。", "歸來塞色侵鬢毛，聯翩始閱交衢舞。", "不學行間妄校尉，盡斬孫歆封萬戶。", "人生富貴有危機，彘肩不願加雕俎。"]'),
('2a8427e8-ab0c-40a3-82d7-ea0e5513b47f','和文潜欲知歸期近','蔡肇','宋','宋诗','song-poetry','','[]','欲知歸期近，朱墨復在手。',96,'全唐诗/poet.song.67000.json','["欲知歸期近，朱墨復在手。", "出門豈無時，官事少邂逅。", "張公晚定交，千仞仰森秀。", "華堂耿青燈，夜半獅子吼。", "真龍服內閑，爽氣凜羣廄。", "新詩陳五鼎，斟酌皆可口。", "光華委行色，於我亦何有。", "緘藏不知報，刻畫無鹽醜。"]'),
('d2edf0ff-15fe-45ca-b192-1426c1d9d0a8','敬用无咎學士年兄長韵上呈子方太僕','蔡肇','宋','宋诗','song-poetry','','[]','兩河郡縣淪西方，西人思漢今未忘。',352,'全唐诗/poet.song.67000.json','["兩河郡縣淪西方，西人思漢今未忘。", "果園蕪沒白草芳，旃裘戲馬誰家郎。", "車箱峽口澗谷長，旄頭倒掛回穹蒼。", "王師西出討獝狂，六花簇壘來堂堂。", "前鋒銳頭臂兩槍，伏姦謹索收生羌。", "天聲隠轔摇姑臧，奇兵繚背斷饋糧。", "决河有聲如壞岡，城頭擊鍾聲殷床。", "萬甲幾欲漂無旁，雖有伉健誰騰驤。", "一夫不敢陵彼隍，馬首欲東促歸裝。", "緘胸有策鬚眉揚，歸來恍恍若有亡。", "劬勞累日何由償，戰鞍掛屋尋書囊。", "目隨飛鴻思帝鄉，彭城老將官橫行。", "幕中市駿收驌驦，射堂兩部奏清商。", "應弦破鏑如蜂房，談笑斥土羈名王。", "畫圖遣奏朝明光，詔書留典真乘黄。", "錦韉玉勒春風香，平池老柳高雲凉。", "神駿在目豪吟觴，跨下蹀躞驚鳬翔。", "皇居九衢天中央，我時項背聊相望。", "西城九月天隕霜，夜談關塞評文章。", "微言竊比惠與莊，和詩脫筆覺我忙。", "祝君韜養壽且祥，功名有來成堵牆。", "勿憂寒暑敗肉漿，韔弓箙矢用則張。"]'),
('63df1190-a3cb-4da2-ade3-c88c05f6f5e2','次韵上呈樗年主簿鄉兄','蔡肇','宋','宋诗','song-poetry','','[]','君家晉陵我朱方，君家易知復難忘。',352,'全唐诗/poet.song.67000.json','["君家晉陵我朱方，君家易知復難忘。", "十年不見蘭畹芳，青衫翩翩黄白郎。", "我游東南歲月長，江流洶湧山鬰蒼。", "燭龍東來尾鬣狂，烏爪真人坐高堂。", "山中旛剎森戈槍，道場法嗣通衡羌。", "大道甚夷車御臧，獨不進步誰資糧。", "脫身簿領行澗岡，青崖結茅雲繞床。", "飄颻西墮梁宋旁，至今夢想猶高驤。", "矧復約子西城隍，瓦爐梵夾隨行裝。", "形骸土木神遠揚，少狂豪氣今則亡。", "劇談軟語志頗償，模寫物象揮錦囊。", "樽前坐我烟靄鄉，憐君駮踠未著行。", "側身六合悲驌驦，即今文學可卜商。", "赤刀大訓在西房，詔書興賢利賓王。", "重闈共此燭燈光，肥羊細肋蟹著黄。", "茭蒲生白晚菘香，落月動影簾帷凉。", "夜如何其未卷觴，座間詩陣鵝鸛翔。", "卧旗蓄銳豈遽央，我堅孤壘何敢望。", "降旛欲掛月似霜，獨君一掃可得章。", "滔滔筆力抵卞莊，兩虎未捽終不忙。", "蜘蛛拂面歸有祥，便看大榜掛北牆。", "南城西寺載殽漿，背城借一猶能張。"]'),
('5f5a165c-79ea-4ff8-840a-a42a8bf7d1fb','家弟別試預薦時蒙慎思學士贈詩致慶感荷不已次韵酬謝','蔡肇','宋','宋诗','song-poetry','','[]','我家書冊代耕農，尚祝甌窶畝一鍾。',64,'全唐诗/poet.song.67000.json','["我家書冊代耕農，尚祝甌窶畝一鍾。", "再築金臺端不昧，高懸水鏡亦難逢。", "親闈動喜欣欣色，士論推公趯趯從。", "好在黄花歸薦壽，秋堂歡笑變春濃。"]'),
('99679ca9-261c-4a77-be8e-620c65073c1d','題朱之純谷陽園','蔡肇','宋','宋诗','song-poetry','','[]','陸機異時宅，故物無復迹。',156,'全唐诗/poet.song.67000.json','["陸機異時宅，故物無復迹。", "悠悠谷水陽，野水凄餘碧。", "我觀豪士賦，文字豈不白。", "一爲功名誤，末路真可惜。", "至今風雨夜，哀鶴鳴不息。", "千秋得吾人，浄眼照阡陌。", "結茅風烟際，一悟世網窄。", "古今一丘貉，貴賤百年客。", "閉門橙橘香，隠几冰凍釋。", "我慚升斗祿，矯首望八極。", "人生勞佚間，此殆天所檄。", "鵬翔赤霄動，鯨噴碧海坼。", "爲爾具扁舟，送此齒髮迫。"]'),
('977c6afb-09c1-4bb8-990f-0b62c09a19ac','書靜勝院壁留別父老','蔡肇','宋','宋诗','song-poetry','','[]','青山雲半遮，慘淡有離色。',84,'全唐诗/poet.song.67000.json','["青山雲半遮，慘淡有離色。", "溪水亦潺湲，嗚咽當枕側。", "男兒四方志，百年一行役。", "山水亦奚悲，我自本無得。", "父老挽我車，洒淚半悽惻。", "使君雖自力，慚無理人術。", "舉手謝父老，意厚難報塞。"]'),
('9036276d-351b-45bd-9472-706dd7c861c4','從孫元忠乞貓','蔡肇','宋','宋诗','song-poetry','','[]','厨廩空虛鼠亦饑，終宵咬齧近秋帷。',32,'全唐诗/poet.song.67000.json','["厨廩空虛鼠亦饑，終宵咬齧近秋帷。", "腐儒生計惟黄卷，乞取銜蟬與護持。"]'),
('8a53c7e8-af53-4bdb-86d2-818b8852323f','贈王子飛之高麗','蔡肇','宋','宋诗','song-poetry','','[]','聞君秉筆賦雞林，海怪山奇人購尋。',32,'全唐诗/poet.song.67000.json','["聞君秉筆賦雞林，海怪山奇人購尋。", "莫紀大宛多善馬，却令天子便甘心。"]'),
('a94a78d6-a1d5-462a-90ab-1892dc87104d','題李伯時照夜白馬圖','蔡肇','宋','宋诗','song-poetry','','[]','天上房星不下來，連山芻粟飽駑駘。',32,'全唐诗/poet.song.67000.json','["天上房星不下來，連山芻粟飽駑駘。", "龍姿逸駕飛騰盡，頼爾毫端力挽回。"]'),
('cbb2e323-92f9-4543-a237-f5649edd6dbf','除夜宿垂虹亭','蔡肇','宋','宋诗','song-poetry','','[]','東南勝概未忘情，老去扁舟復此行。',64,'全唐诗/poet.song.67000.json','["東南勝概未忘情，老去扁舟復此行。", "小邑歲除無市井，下田水落見農耕。", "雪消西嶺層棱出，春到重湖鱗甲生。", "橋下霜蛟貪睡美，爲槌千鼓作雷聲。"]'),
('921d1bad-5729-49dd-8480-479519fea6ba','送蔡駰守天台','蔡肇','宋','宋诗','song-poetry','','[]','天台四萬八千丈，玉京五城十二樓。',64,'全唐诗/poet.song.67000.json','["天台四萬八千丈，玉京五城十二樓。", "欲乘西風跨獨鶴，直渡南斗騎牽牛。", "麻姑長爪快搔背，巢父投竿應掉頭。", "廣文物色分留在，二妙龍詩肯罷休。"]'),
('8e0cc7a0-3c98-49bc-9217-5c2ce4b63e13','江州','蔡肇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','潯陽江上陶彭澤，五株楊柳青山宅。',48,'全唐诗/poet.song.67000.json','["潯陽江上陶彭澤，五株楊柳青山宅。", "元和之中白司馬，送客江頭明月下。", "當時盡作廬山客，林下題詩石上眠。"]'),
('3c0aadb9-cd2d-4131-9e91-3364fd40d457','杭州次周大夫韵  其一','蔡肇','宋','宋诗','song-poetry','','[]','使君詩句益超然，文陣收工是昔年。',64,'全唐诗/poet.song.67000.json','["使君詩句益超然，文陣收工是昔年。", "本是東南遺愛守，聊從巖谷甚臞仙。", "莫嫌供給難留客，只爲湖山已自賢。", "好請東封西狩頌，老來詞格似甘泉。"]'),
('a886e127-33c6-436c-9f19-1a6382f4041c','杭州次周大夫韵  其二','蔡肇','宋','宋诗','song-poetry','','[]','湖邊蓮葉已田田，聞道花開勝去年。',64,'全唐诗/poet.song.67000.json','["湖邊蓮葉已田田，聞道花開勝去年。", "君不御兮應有恨，風其吹汝未應仙。", "韵詞合繼菑公作，郡守誰如白傅賢。", "却使詩翁閒著筆，滔滔長句湧言泉。"]'),
('3c5d28e9-bbb5-457a-8db2-49d69d6bbe15','杭州次周大夫韵  其三','蔡肇','宋','宋诗','song-poetry','','["\u897f\u6e56"]','只占西湖不占田，六蓮重到欲忘年。',64,'全唐诗/poet.song.67000.json','["只占西湖不占田，六蓮重到欲忘年。", "慚無佳句追和靖，聊取幽芳薦水仙。", "對面文章能發興，脫身朝市已稱賢。", "江邊五月梅天雨，擬附齊舲過冷泉。"]'),
('d5f52a8f-4e28-4f4d-bce7-cc720be345c1','送錢齊玥倅蘇州二首  其一','蔡肇','宋','宋诗','song-poetry','','[]','一尉東南屈指中，雍容車騎舊兒童。',64,'全唐诗/poet.song.67000.json','["一尉東南屈指中，雍容車騎舊兒童。", "郎君扇枕家中晚，侍史焚香省戶空。", "十里浮梁晴卧蝀，一江春水浄磨銅。", "三年官滿東吳去，爲具扁舟破浪風。"]'),
('625aec27-a9cc-4078-b540-3c3befa4b18b','送錢齊玥倅蘇州二首  其二','蔡肇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭飛雨打湘弦，燕寢凝香思渺然。',64,'全唐诗/poet.song.67000.json','["洞庭飛雨打湘弦，燕寢凝香思渺然。", "四者難并知我老，七言俱賦爲君妍。", "雜花遶徑迎籃轝，春鳥喧洲起畫船。", "聞道山公方啟事，重看一鶚在秋天。"]'),
('dfb5984b-d6d3-4c7a-b498-c29ed782f11b','吾庵','蔡肇','宋','宋诗','song-poetry','','[]','憐吾居處似東屯，草棘荒凉郭裏村。',64,'全唐诗/poet.song.67000.json','["憐吾居處似東屯，草棘荒凉郭裏村。", "明月有情先入戶，青山無事獨當門。", "未能種秫五十畝，且爲栽桃二百根。", "不學靈雲覓知解，花時相喚倒餘尊。"]'),
('9593cbe8-eb18-49a4-b2e6-330321a7fb05','寄題君山亭送呂天衢秀才','蔡肇','宋','宋诗','song-poetry','','[]','百川赴下流，江海互吞吐。',252,'全唐诗/poet.song.67000.json','["百川赴下流，江海互吞吐。", "回瀾薄空日，老岸不立土。", "坡陀出巨石，鼇背啟窗戶。", "我來俯凝碧，萬頃過微雨。", "南沙八十里，草木盡可數。", "風聲玄冥開，松影翠蛟舞。", "昏昏魚龍氣，暝色失洲渚。", "林間古蘭若，梵放雜鳴櫓。", "不能掛長帆，破浪極幽睹。", "至今清夜夢，窈窕越修阻。", "喜君自茲來，浩浩見眉宇。", "館置古城東，淡飯忘羈旅。", "連城雖自珍，歷塊誰爲許。", "束書問東舟，了不掛一語。", "脫身少年場，清座參佛祖。", "冰顔未生髭，老氣欲冠古。", "所得豈虛名，自是慰諸呂。", "南天正炎溽，歸思亟飛羽。", "江魚已釣肥，江酒尚酤煮。", "訪子昔遊地，耿耿月沉浦。", "席龍望東南，浮雲渺吳楚。"]'),
('cc25849c-91c6-4ead-b27d-a32085d96066','江滸按舟師','蔡肇','宋','宋诗','song-poetry','','[]','江頭新晴好天氣，江上兒郎櫂船戲。',128,'全唐诗/poet.song.67000.json','["江頭新晴好天氣，江上兒郎櫂船戲。", "掉船往來西復東，畫橈掠水如飛鴻。", "清晨太尉自領客，蕩漾幕帟翻春風。", "欲標不但與民樂，約束部曲藏軍容。", "只今潯陽賊圍繞，天子耀兵未誅討。", "渠儂幸自慣水戰，駕水樓船救江表。", "朝廷逡巡領詔書，太尉不日歸西樞。", "試問兵鈐元節制，藉留歲月還何如。"]'),
('9b36d294-7522-460a-b317-49669a309976','游善權洞  其一','蔡肇','宋','宋诗','song-poetry','','[]','陰風漠漠護崔嵬，激澗脩篁翠壑開。',64,'全唐诗/poet.song.67000.json','["陰風漠漠護崔嵬，激澗脩篁翠壑開。", "何處人天盡回向，于今龍象亦堪哀。", "常星曉掛層臺冷，隕石宵飛夏屋摧。", "巖尸彭鏗聊戲擊，山中日月有奔雷。"]'),
('ee70310b-9446-4fa1-a266-2efd65157f4d','游善權洞  其二','蔡肇','宋','宋诗','song-poetry','','[]','相鮮金碧照崔嵬，殿閣園林迤邐開。',64,'全唐诗/poet.song.67000.json','["相鮮金碧照崔嵬，殿閣園林迤邐開。", "留戀白雲禪客少，寂寥青嶂曉猿哀。", "山川勝處天然巧，景象窮時石也摧。", "靖節遠公如可作，不應蓮社愧劉雷。"]'),
('2b83df7b-12dc-4360-b327-8d08fa6940f0','題天申宮','蔡肇','宋','宋诗','song-poetry','','[]','勝迹傳來不記年，昔聞曾駐漢神仙。',64,'全唐诗/poet.song.67000.json','["勝迹傳來不記年，昔聞曾駐漢神仙。", "赤烏方喜靈壇建，白馬俄驚梵宇遷。", "觀額自唐因記定，宮碑至宋有眠鎸。", "江南福地雖云衆，第一無過此洞天。"]'),
('f0746e4f-15bd-482c-97c0-c320ab676300','張公洞  其一','蔡肇','宋','宋诗','song-poetry','','[]','髯仙御氣已超昇，巖洞千秋冷不扃。',64,'全唐诗/poet.song.67000.json','["髯仙御氣已超昇，巖洞千秋冷不扃。", "若許殘鉛除白髮，敢辭長鑱斸青冥。", "壇場歲爲民祈福，蒿艾時因鬼乞靈。", "他日重來尋石髓，絳雲深坐讀黄庭。"]'),
('5d4e36c3-c492-4bba-b633-b60ce28ed661','張公洞  其二','蔡肇','宋','宋诗','song-poetry','','[]','髯仙御氣款雷扉，洞戶千秋敞翠微。',64,'全唐诗/poet.song.67000.json','["髯仙御氣款雷扉，洞戶千秋敞翠微。", "寓馬至今來秘祝，芻靈聊復借餘威。", "石房故劍龍隨勢，空竈殘丹鼠輒飛。", "欲煉刀圭留齒髮，山頭白鶴幾時歸。"]'),
('6bd83afa-bafd-4abd-9e2f-189fc768109b','次韵王彥昭昆仲題京口新居','蔡肇','宋','宋诗','song-poetry','','[]','我昔京口居，屢爲南山遊。',168,'全唐诗/poet.song.67000.json','["我昔京口居，屢爲南山遊。", "古寺滿修竹，平田漫清流。", "四升崇邱望，培塿見五州。", "人生如藝田，要待歲晚收。", "內懼寡道力，眇然念前修。", "六合不爲狹，五畝亦爲謀。", "何妨傍城邑，心遠地自悠。", "漕水應潮漲，堂下可遭周。", "葉落固有餘，柿栗不外求。", "生理如此足，豈謝巖谷幽。", "奈何不勇决，一毫輒絆留。", "余性本拙戇，涉世易悔尤。", "微官如涕唾，容易思罷休。", "三龍亦馳騁，詩好意則不。"]'),
('8cf9638b-0d07-4205-89b7-21496eebfe1a','寒江捕魚圖','蔡肇','宋','宋诗','song-poetry','','[]','海門山頭初日晴，西津渡口寒潮生。',64,'全唐诗/poet.song.67000.json','["海門山頭初日晴，西津渡口寒潮生。", "沙痕暗長島嶼沒，但見漁舟縱復橫。", "江烟漠漠飛鷗鷺，著底寒魚冷難捕。", "霜中漁父扣舷歌，明月蘆花不知處。"]'),
('fcf7e9f7-897d-4301-9d95-cd0697579f35','石排山渡行','蔡肇','宋','宋诗','song-poetry','','[]','中泠之西古石排，狂波悍浪何能摧。',128,'全唐诗/poet.song.67000.json','["中泠之西古石排，狂波悍浪何能摧。", "顛崖骨立不受土，草木堅瘦知誰栽。", "長蛇怒結花磥磈，蒼隼饑嘯寒毰毸。", "舟師雨汗渡洑水，捩舵失手遭旋雷。", "我行十月潮如落，百仞屹立青瓊瑰。", "天吳白鯨隠映沒，貝闕珠宮空洞開。", "沉沉窟宅閟奇鬼，赤衣駕馬胡爲哉。", "羣珠可燬不可照，扶桑羨門歸去來。"]'),
('d547b045-56a7-4e33-99cc-7d0d2bd7e292','得奇石於峴山','蔡肇','宋','宋诗','song-poetry','','[]','州城西南五里間，如渡鞏洛趨秦川。',291,'全唐诗/poet.song.67000.json','["州城西南五里間，如渡鞏洛趨秦川。", "土囊行盡跨山脊，雲濤萬頃江掀天。", "江南六月黄埃起，嶺上行人多暍死。", "車聲躑躅正煩冤，石縫甘寒冽清泚。", "茲山蟠伏信有靈，窮幽訪遠恨未能。", "山農告異指南麓，夜有虹氣如長繩。", "朝携長鑱剃草棘，應手鏗然逢鉅石。", "深藏疑有仙鬼護，完好不受沙土蝕。", "十夫募工挽使前，舉身洶洶爭相傳。", "置園輝澤被草木，隅坐咫尺生雲烟。", "自笑年來有師癖，摩挲剔濯窮朝夕。", "嵌形空洞出包藏，玉質青溫相靈璧。", "沙痕洗盡圭角光，卷崖透壑通中旁。", "縷分淺黛泫微雨，翠剝蒼蘚晞朝暘。", "我昔扁舟臨古汴，千金價市搜尋徧。", "蘭皋西鏁靳家園，方丈瀛洲眼中見。", "君不聞米家硯山入禁中，蕞爾卷石誰爲容。", "乃知此亦有顯晦，萬事默默由天公。"]'),
('3031e4f6-d3ee-4549-9706-dea4d4e82417','和翟忠惠游焦山','蔡肇','宋','宋诗','song-poetry','','[]','吾聞海中之山名黛輿，八紘九野水所輸。',210,'全唐诗/poet.song.67000.json','["吾聞海中之山名黛輿，八紘九野水所輸。", "沙痕蕝石記千古，堯水滔天才一濡。", "西潴七澤並淮湖，南傾百粵包荆舒。", "孤根不畏波浪沒，正氣自有神明扶。", "火輪纔升水鶴唳，地籟所作江㹠噓。", "佳氣鬰鬰崖不枯，華堂五丈安方裾。", "魚山清梵吼螺唄，水師絕叫訶龜魚。", "山靈護法踴車象，石叟衄敵峻隈隅。", "可憐蠻觸戰左右，始信婦姑勃空虛。", "大千共此華藏海，比邱無一鍼鋒居。", "君詩文采炳於菟，我行稽留類賈胡。", "何時妙語對竹榻，清夜柏子燃銅爐。", "卓錐之地雖亦無，安用更求無價珠。"]'),
('91381484-6957-472b-9c96-b974df4469dd','烟江疊障圖','蔡肇','宋','宋诗','song-poetry','','[]','瓜州東望西津山，山平水闊生寒烟。',238,'全唐诗/poet.song.67000.json','["瓜州東望西津山，山平水闊生寒烟。", "海門日出江霧破，沿江山色寒蒼然。", "五州京峴穹隆隠轔尚不見，况乃鹿跑馬跡點滴之微泉。", "中泠之南古浮玉，鐘鼓下震蛟龍川。", "樓臺明滅彩翠合，海市仙山當目前。", "興來赤脚踏鰲背，揮弄白日摩青天。", "原松芊芊雪欲盡，野氣鬰鬰春逾妍。", "三更潮生月西落，寒金萬斛流瓊田。", "江山佳處心自省，畫圖忽見猶當年。", "有如遠作美人別，耿耿獨記長眉娟。", "雙瓶買魚晚渡立，孤篷聽雨春灘眠。", "翰林東坡知此樂，至今舟上漁子談蘇仙。", "玉堂椽蠟照清夜，葦間幽夢來延緣。", "山川信羨歸未得，送行看盡且作公子思歸篇。"]'),
('0c68c38c-3c17-41cd-9316-2d21c0782df2','望海樓','蔡肇','宋','宋诗','song-poetry','','[]','城曉通霜白，樓晴映霧殘。',48,'全唐诗/poet.song.67000.json','["城曉通霜白，樓晴映霧殘。", "玉螭取噴薄，鐵鳳舞高寒。", "議敢分丹鼉，時能御馬鞍。", "腐儒江海意，菱芡得加餐。"]'),
('b184ac55-edd3-4724-8e94-434f326ffea7','甘露寺遭火','蔡肇','宋','宋诗','song-poetry','','[]','聚墨魔宮殿，毗嵐色界天。',48,'全唐诗/poet.song.67000.json','["聚墨魔宮殿，毗嵐色界天。", "劫灰迷狠石，鉛水泫銅仙。", "扁榜無佳句，華榱有勝緣。", "大江春正碧，白晝島夷船。"]'),
('e3eb5c7f-c955-49dc-8b38-56deac4e0002','登焦山二首  其一','蔡肇','宋','宋诗','song-poetry','','[]','野曠天平入，潮生海倒流。',48,'全唐诗/poet.song.67000.json','["野曠天平入，潮生海倒流。", "帆餘閩嶠色，雁带玉關秋。", "齋近烏鳶集，漁殘網罟收。", "雖云是吾土，茲日始能遊。"]'),
('3883983a-9f80-47fe-b425-32cb691f3b54','登焦山二首  其二','蔡肇','宋','宋诗','song-poetry','','[]','早鞍沾宿靄，夕楫漾晴暉。',48,'全唐诗/poet.song.67000.json','["早鞍沾宿靄，夕楫漾晴暉。", "歲稔登新穀，山寒御夾衣。", "幽威廣殿角，高遁故庵扉。", "稍悔魚竿手，頻年事鞅鞿。"]'),
('46e6bd72-ca6b-485e-b9c0-ca626794196b','京口即事和周開祖韵','蔡肇','宋','宋诗','song-poetry','','[]','模寫山川畫不如，送來我得卷還舒。',64,'全唐诗/poet.song.67000.json','["模寫山川畫不如，送來我得卷還舒。", "廢興此郡多遺事，搜索因君得盡書。", "劫壞丹青無晉舊，地窮岡塹是秦餘。", "試參故楮來真賞，定有能知近代歟。"]'),
('606add55-3e8f-4949-8f6b-532a4db75bab','送朱行中守潤','蔡肇','宋','宋诗','song-poetry','','[]','東南聞詔想風流，竹馬津亭待去舟。',64,'全唐诗/poet.song.67000.json','["東南聞詔想風流，竹馬津亭待去舟。", "夾案曾爲新右史，分符仍是古諸侯。", "大江注海吞三島，高閣臨城覽五州。", "筆力自能迴造化，鶴林神女謾來遊。"]'),
('ecba1aba-ce8c-443f-8b96-b6843dcf8cf8','寄京口新居','蔡肇','宋','宋诗','song-poetry','','[]','橘圃青黄星照屋，竹林修竦槊攙雲。',64,'全唐诗/poet.song.67000.json','["橘圃青黄星照屋，竹林修竦槊攙雲。", "千頭固不羨汝食，一日可能無此君。", "爲結茅齋依法露，欲携藤簟洗餘醺。", "要來靜處回光座，閱世真如過目蚊。"]'),
('52a59551-855d-4b64-941e-dcbc443e1c22','彭君宜江上新開軒','蔡肇','宋','宋诗','song-poetry','','[]','老至登臨興未窮，扁舟幾欲拭秋風。',64,'全唐诗/poet.song.67000.json','["老至登臨興未窮，扁舟幾欲拭秋風。", "能開勝地留連我，只在高人指顧中。", "暮靄先昏瓜步港，寒潮猶打蒜山宮。", "請君剩汲中泠水，客至何妨酒屢空。"]'),
('d67a706c-bb3a-4723-98ac-a6ce10af8a75','登多景樓','蔡肇','宋','宋诗','song-poetry','','[]','卧病江邊一釣舟，江光晚色浄淹留。',64,'全唐诗/poet.song.67000.json','["卧病江邊一釣舟，江光晚色浄淹留。", "山蟠京峴城隨仄，水合中泠海共浮。", "席有笙簫吹井陌，齋餘鐘梵到林邱。", "道人說合龍天出，未暇燃犀照九幽。"]'),
('5855d7b9-7f0b-4439-957f-81e1ab5355cb','游浮玉三首  其一','蔡肇','宋','宋诗','song-poetry','','[]','百川日夜赴清潯，此地朝宗見本心。',64,'全唐诗/poet.song.67000.json','["百川日夜赴清潯，此地朝宗見本心。", "蒼鶻養雛歸絕壁，老蛟伏卵護寒金。", "江昏潭火何從起，歲旱豪牛或可沉。", "誰把孤根擲天外，免令游客費閑吟。"]'),
('8e1ac373-41a9-4730-823f-ff2e45476e1c','游浮玉三首  其二','蔡肇','宋','宋诗','song-poetry','','[]','中𤃩南畔大叢林，龍象初排四衆欽。',64,'全唐诗/poet.song.67000.json','["中𤃩南畔大叢林，龍象初排四衆欽。", "一月遍收銀色界，兩山相擊海潮音。", "安心已竟元無法，舉意全拋莫浪尋。", "且使後來誰措手，樂天贏得掉頭吟。"]'),
('6ddbb9bc-f94d-4599-ae99-617b52d1214c','游浮玉三首  其三','蔡肇','宋','宋诗','song-poetry','','[]','曾訪山中支遁林，厭聞鐘鼓日欽欽。',64,'全唐诗/poet.song.67000.json','["曾訪山中支遁林，厭聞鐘鼓日欽欽。", "百川赴海通三島，萬籟逢秋共一音。", "折戟戰痕誰共弔，浮杯足跡杳難尋。", "魚峰梵唄隨曹植，試聽雲閒鸞鳳吟。"]'),
('6b4b5dfc-c62e-435a-a0d7-95dd9c34f296','登城見古陵墓','蔡肇','宋','宋诗','song-poetry','','[]','諸豪衰季此并吞，形勢當時苦未論。',64,'全唐诗/poet.song.67000.json','["諸豪衰季此并吞，形勢當時苦未論。", "不見江山開北戶，竟隨玉駕走中原。", "雄心尚記蒼崖石，戰血今消折戟痕。", "枯冢至今餘拱木，夾城風雨有孤魂。"]'),
('c14ed277-ba76-409f-8f42-b71ca62f98f3','次韵周開祖九日登金山','蔡肇','宋','宋诗','song-poetry','','[]','恨不從公此日遊，憑陵天塹櫂黄頭。',64,'全唐诗/poet.song.67000.json','["恨不從公此日遊，憑陵天塹櫂黄頭。", "江回巨浸吞三島，雲破危欄覽數州。", "故事能追彭澤亮，清談思對漆園周。", "黄花白酒鱸魚晚，別有江南一段秋。"]'),
('22622a3e-fb30-4017-a82e-217555a44225','北固山','蔡肇','宋','宋诗','song-poetry','','[]','一徑杉松駐晚烟，漸看臺影入雲間。',64,'全唐诗/poet.song.67000.json','["一徑杉松駐晚烟，漸看臺影入雲間。", "江拖縞带縈危堞，地注青螺出遠山。", "當日英雄無復見，此時簫鼓有誰閒。", "我來應被藤蘿笑，塵滿衣冠盍厚顔。"]'),
('28a1b956-b9bc-4dd7-ad96-3aee1daea0d1','雨中游西庵','蔡肇','宋','宋诗','song-poetry','','[]','夾岸鳴鐘早渡回，冥冥江色未全開。',32,'全唐诗/poet.song.67000.json','["夾岸鳴鐘早渡回，冥冥江色未全開。", "西庵要看千峰碧，更有江南半月梅。"]'),
('108f8772-1682-4ec0-afef-828853684680','大港即事次韵  其一','蔡肇','宋','宋诗','song-poetry','','[]','村落家家有酒沽，黄童白叟醉相扶。',32,'全唐诗/poet.song.67000.json','["村落家家有酒沽，黄童白叟醉相扶。", "恨無韓滉丹青手，更作豐年幾幅圖。"]'),
('b8e2da84-7c84-4ad7-8edf-8863034035f8','大港即事次韵  其二','蔡肇','宋','宋诗','song-poetry','','[]','野草追隨岸接籬，紫荆門巷日平西。',32,'全唐诗/poet.song.67000.json','["野草追隨岸接籬，紫荆門巷日平西。", "自言今歲春耕早，臘雪消來水一犁。"]'),
('ff689c43-5bbf-4a51-a834-9c088abdfde8','送王左丞五絕  其一','蔡肇','宋','宋诗','song-poetry','','[]','德星行斗牛，人物東西夥。',24,'全唐诗/poet.song.67000.json','["德星行斗牛，人物東西夥。", "太史告占書，發春朝玉座。"]'),
('ec062cc8-ba06-4065-8377-c7a58b597fed','送王左丞五絕  其二','蔡肇','宋','宋诗','song-poetry','','[]','江左名父子，風流適茲還。',24,'全唐诗/poet.song.67000.json','["江左名父子，風流適茲還。", "而宗有勝韵，覺在正始間。"]'),
('1396d32e-fd70-4b38-84d9-ca6ff40fadc0','送王左丞五絕  其三','蔡肇','宋','宋诗','song-poetry','','[]','浮名渺吳會，耿耿千里淮。',24,'全唐诗/poet.song.67000.json','["浮名渺吳會，耿耿千里淮。", "朔風吹高鴻，安得與人偕。"]'),
('ee2a90a4-29c4-4bae-ac16-02558c76c86d','送王左丞五絕  其四','蔡肇','宋','宋诗','song-poetry','','[]','三堅真得象，九師遂亡羊。',24,'全唐诗/poet.song.67000.json','["三堅真得象，九師遂亡羊。", "寥寥千載餘，煥發天地藏。"]'),
('0a6d8611-e103-4156-b21b-ab4c9605ce88','送王左丞五絕  其五','蔡肇','宋','宋诗','song-poetry','','[]','歲晏風落木，野陰水增波。',24,'全唐诗/poet.song.67000.json','["歲晏風落木，野陰水增波。", "齋舲如傅翼，一舉君謂何。"]'),
('c6969b6a-1035-40e1-b3fa-a2cc3721aad4','句  其一','蔡肇','宋','宋诗','song-poetry','','[]','願同籍湜輩，終老韓公門。',12,'全唐诗/poet.song.67000.json','["願同籍湜輩，終老韓公門。"]'),
('f62d2003-9a03-4e97-a60d-9fc2165b0e22','句  其二','蔡肇','宋','宋诗','song-poetry','','[]','疊嶂巧分丁字水，臘梅遲見二年花。',16,'全唐诗/poet.song.67000.json','["疊嶂巧分丁字水，臘梅遲見二年花。"]'),
('87f10703-8e5e-4ca3-8dc8-b922d275d92e','句  其三','蔡肇','宋','宋诗','song-poetry','','[]','莫嫌供給難酬客，祇爲湖山已自賢。',16,'全唐诗/poet.song.67000.json','["莫嫌供給難酬客，祇爲湖山已自賢。"]'),
('ad2af04b-767d-4039-9681-3ade50ca5cae','句  其四','蔡肇','宋','宋诗','song-poetry','','[]','城中十月雨濛濛，遙看句驪半山雪。',16,'全唐诗/poet.song.67000.json','["城中十月雨濛濛，遙看句驪半山雪。"]'),
('b6c83e76-79b3-4724-8c2a-5936fb7de083','句  其五','蔡肇','宋','宋诗','song-poetry','','[]','三峽橋邊春見雪，落星寺裏暮聞鐘。',16,'全唐诗/poet.song.67000.json','["三峽橋邊春見雪，落星寺裏暮聞鐘。"]'),
('df976fe4-c81f-4b00-822e-3bdd5566b685','句  其六','蔡肇','宋','宋诗','song-poetry','','[]','城響濤頭入，江昏雨脚斜。',12,'全唐诗/poet.song.67000.json','["城響濤頭入，江昏雨脚斜。"]'),
('3c8540f9-2c35-43e3-8c2a-523afa69a83d','句  其七','蔡肇','宋','宋诗','song-poetry','','[]','柳間黄鳥路，波底白頭天。',12,'全唐诗/poet.song.67000.json','["柳間黄鳥路，波底白頭天。"]'),
('478603d4-1275-4a91-baaa-8906ec708a93','句  其八','蔡肇','宋','宋诗','song-poetry','','[]','斷蓬帆影天平入，夾鏡波光水到流。',16,'全唐诗/poet.song.67000.json','["斷蓬帆影天平入，夾鏡波光水到流。"]'),
('8c7682b9-38f9-4212-be80-fe71b9c0466d','句  其九','蔡肇','宋','宋诗','song-poetry','','[]','先生萬古名何用，博士三年冗不治。',16,'全唐诗/poet.song.67000.json','["先生萬古名何用，博士三年冗不治。"]'),
('bf372462-deb7-411a-95fa-4b851cbe6903','東上辭松楸一首','宗澤','宋','宋诗','song-poetry','','[]','八年坐親黨，泯伏長安城。',108,'全唐诗/poet.song.67000.json','["八年坐親黨，泯伏長安城。", "甘心傍松楸，申我兒子情。", "閉戶慨岩廊，讀書笑金籯。", "力田固爲政，課童乃司兵。", "深病骨相寒，不蒙軒冕榮。", "維天臨萬邦，搜羅世豪英。", "我友挽出之，大人今繼明。", "古無忠孝全，泣涕去丘塋。", "爲翁大門閭，翻然以東征。"]'),
('1e429bdc-d7c6-4000-9612-0b7bcc8e4ad2','感時','宗澤','宋','宋诗','song-poetry','','[]','卿士辱多壘，天王憤蒙塵。',168,'全唐诗/poet.song.67000.json','["卿士辱多壘，天王憤蒙塵。", "御戎要虓將，謀國須雋臣。", "百戰取封侯，未必亡其身。", "懷奸廢忠義，胡顔以爲人。", "吁嗟世道衰，大僇加搢紳。", "平居事奔競，梁汴分雲屯。", "一旦國步艱，四迸如星繁。", "輔相已擇栖，守令仍踰藩。", "冠蓋陸西竄，舳艫水南奔。", "鄙夫用慨然，策馬趨修門。", "勤王羞尺柄，悟主期片言。", "時來倘雲龍，峨冠拜臨軒。", "逶迤上玉除，造膝伸元元。", "措世于泰寧，歸來守丘樊。"]'),
('73547a31-52cb-4359-93ac-c6b69fb07ffc','曉渡','宗澤','宋','宋诗','song-poetry','','[]','小雨疏風轉薄寒，駝裘貂帽過秦關。',32,'全唐诗/poet.song.67000.json','["小雨疏風轉薄寒，駝裘貂帽過秦關。", "道逢一澗兵徒涉，赤脛相扶獨厚顔。"]'),
('788652a8-3e6d-430f-99ea-baaa4419c89f','華陰道中三首  其一','宗澤','宋','宋诗','song-poetry','','[]','烟遮晃白初疑雪，日映斕斑却是花。',32,'全唐诗/poet.song.67000.json','["烟遮晃白初疑雪，日映斕斑却是花。", "馬渡急流行小崦，柳絲如織映人家。"]'),
('a38201d8-b079-430e-bfa2-6648a66dbec9','華陰道中三首  其二','宗澤','宋','宋诗','song-poetry','','[]','菅茆作屋細家居，雲碓風帘路不紆。',32,'全唐诗/poet.song.67000.json','["菅茆作屋細家居，雲碓風帘路不紆。", "坡側杏花溪畔柳，分明摩詰輞川圖。"]'),
('b57236dc-be80-4189-836e-b0c467cab81c','華陰道中三首  其三','宗澤','宋','宋诗','song-poetry','','[]','寧王畫作金盆鴿，韓愈詩誇玉井蓮。',32,'全唐诗/poet.song.67000.json','["寧王畫作金盆鴿，韓愈詩誇玉井蓮。", "瓦缶泥泓村落小，亂茅羣雀不堪傳。"]'),
('766d0e2a-7e70-444a-8ba1-462b690331c8','雨晴渡關二首  其一','宗澤','宋','宋诗','song-poetry','','[]','燕北靜胡塵，河南濯我兵。',48,'全唐诗/poet.song.67000.json','["燕北靜胡塵，河南濯我兵。", "風雲朝會合，天地晝清明。", "泣涕收橫潰，焦枯頼發生。", "不辭關路遠，辛苦向都城。"]'),
('a40b83d4-93e0-4e27-9bfb-999e5422fca7','雨晴渡關二首  其二','宗澤','宋','宋诗','song-poetry','','[]','蕩滌真成快，氛霾不敢陰。',48,'全唐诗/poet.song.67000.json','["蕩滌真成快，氛霾不敢陰。", "萬花恩澤了，二麥寵光深。", "地勢瞻仙掌，河源識帝心。", "馬頭迎霽色，詩句日邊尋。"]'),
('a4938c59-a0cb-4326-8ae4-5ddc27de8954','道逢散遣之卒云講和退師無所用之矣輒以二十六句道胸臆','宗澤','宋','宋诗','song-poetry','','[]','翁擁麾幢我爲兒，剽聞竊睹皆兵機。',208,'全唐诗/poet.song.67000.json','["翁擁麾幢我爲兒，剽聞竊睹皆兵機。", "其中襲擊不容瞬，飆行電掣猶逶迤。", "戎人長驅越大河，天下震驚觀闕危。", "肉食之謀殊未臧，我憤切骨其誰知。", "慨然奏疏金馬門，力陳盟賂損國威。", "嚴尤下策尤可笑，晁錯上書亦奚爲。", "道路荆棘初剪除，花如步障吾東之。", "八年閉戶尺蠖屈，一旦渡關匹馬馳。", "行行側身聽戎捷，忽聞募士詔遣歸。", "濃書大墨榜教詔，曰敵悔過今退師。", "羽檄向來召貔虎，乃詠出車歌杕杜。", "櫜兵銷刃兵猶怒，却把鉏犁農歌舞。", "君王神武今藝祖，爾如不歸污我斧。"]'),
('7c760291-52cd-4f7e-bc9a-f366a7154273','又賦一律','宗澤','宋','宋诗','song-poetry','','[]','罷兵洵上策，試問可誠然。',48,'全唐诗/poet.song.67000.json','["罷兵洵上策，試問可誠然。", "竟棄三軍力，空拋半壁天。", "上林無旅雁，絕域有啼鵑。", "羞見龍泉劍，飛光牛斗前。"]'),
('decce017-a80c-439f-92b7-627ba537e5ca','至洛','宗澤','宋','宋诗','song-poetry','','[]','都人士女各紛華，列肆飛樓事事嘉。',32,'全唐诗/poet.song.67000.json','["都人士女各紛華，列肆飛樓事事嘉。", "政恐皇都無此致，萬家流水一城花。"]'),
('6983139b-4ac9-4c0b-9455-1d5e014c9f19','華下','宗澤','宋','宋诗','song-poetry','','[]','千巖層出亂雲飛，失我平生洞府期。',32,'全唐诗/poet.song.67000.json','["千巖層出亂雲飛，失我平生洞府期。", "夜據征鞍不交睫，舉頭彈指睡希夷。"]'),
('168b88bb-133d-4556-9bf9-6af5f814ce5b','過潼關','宗澤','宋','宋诗','song-poetry','','[]','一雨崤函底，風沙放我過。',48,'全唐诗/poet.song.67000.json','["一雨崤函底，風沙放我過。", "嶽神猶假借，官吏莫誰何。", "塹斷思航渡，城堅戒石摩。", "一夫工墨守，寧怯萬夫多。"]'),
('49cd9869-9509-4345-9afc-efeb8873a25e','道逢鄉人笑僕騶馬之瘦','宗澤','宋','宋诗','song-poetry','','[]','生笑長裾曳，仍羞下澤奔。',48,'全唐诗/poet.song.67000.json','["生笑長裾曳，仍羞下澤奔。", "據鞍非馬援，叱馭豈王尊。", "汗血能觀國，的盧終感恩。", "莫欺騶馬瘦，揮策諸金門。"]'),
('26b07906-955a-4693-8df4-a810413ec977','盤豆鋪南李翁園','宗澤','宋','宋诗','song-poetry','','[]','李翁卧亭午，春深掩柴荆。',24,'全唐诗/poet.song.67000.json','["李翁卧亭午，春深掩柴荆。", "忽聞風雨響，疑是勤王兵。"]'),
('24c13978-eb84-4e13-9e88-78582c6dd09e','題趙園  其一','宗澤','宋','宋诗','song-poetry','','[]','瑶瑛夾侍梅臺，琴瑟自鳴松島。',28,'全唐诗/poet.song.67000.json','["瑶瑛夾侍梅臺，琴瑟自鳴松島。", "山中野服相羊，足以亡憂遣老。"]'),
('88321019-8177-475b-adf5-698e752e77df','題趙園  其二','宗澤','宋','宋诗','song-poetry','','[]','鑿池智有泉源，種木胸無芥蔕。',28,'全唐诗/poet.song.67000.json','["鑿池智有泉源，種木胸無芥蔕。", "螭頭吐水涓涓，端是銀潢一派。"]'),
('4a2142ed-ab22-412f-97b0-9bccef2ac5aa','馬上口占','宗澤','宋','宋诗','song-poetry','','[]','龍興虎視詫周秦，王氣東遊作汴京。',32,'全唐诗/poet.song.67000.json','["龍興虎視詫周秦，王氣東遊作汴京。", "陰祝巨靈移此險，大河爲塹嶽爲城。"]'),
('e4180988-848c-4335-bbbc-b13f3dcd2092','早發','宗澤','宋','宋诗','song-poetry','','["\u6218\u4e89"]','繖幄垂垂馬踏沙，水長山遠路多花。',32,'全唐诗/poet.song.67000.json','["繖幄垂垂馬踏沙，水長山遠路多花。", "眼中形勢胸中策，緩步徐行靜不譁。"]'),
('e373f752-8ad6-47d2-a55a-57ad7f0fa928','謁華嶽','宗澤','宋','宋诗','song-poetry','','["\u534e\u5c71"]','楊賜嶽所挺，嚴武金天晶。',168,'全唐诗/poet.song.67000.json','["楊賜嶽所挺，嚴武金天晶。", "二子爲時出，顧我非炳靈。", "維嶽鎮四方，氣秀天骨青。", "巀嶭立千仞，力能産公卿。", "降神詠崧高，讖緯仍反經。", "取象到執珪，譎怪如洞冥。", "平生笑窮奇，立語心自驚。", "我質培塿耳，胸中固崢嶸。", "誰言華岳高，我山摩玉京。", "是中所包藏，丹碧參瑰瓊。", "平居蟄雲雷，飛雨溢四溟。", "此豈真有之，落筆紛縱橫。", "發我文物祕，象渠膏澤傾。", "太華屹不摇，我山身載行。"]'),
('3d2d709f-c75c-4fb1-b12b-3f19f6958665','贈雞山陳七四秀才','宗澤','宋','宋诗','song-poetry','','[]','渥洼生駿駒，丹山生鳳雛。',84,'全唐诗/poet.song.67000.json','["渥洼生駿駒，丹山生鳳雛。", "家有寧馨子，慶自積善餘。", "粹然秀眉宇，瑩徹真璠璵。", "高聲誦論語，健腕學大書。", "頭頭欲第一，氣已淩空虛。", "想其顧復意，何止掌上珠。", "更期速騰達，爾祖立以須。"]'),
('2151a4ec-e399-4b8c-b508-be3d7ae11101','憩全節鋪愛其稱爲駐馬久之','宗澤','宋','宋诗','song-poetry','','[]','回車勝母避柏人，不飲貪泉惡其名。',32,'全唐诗/poet.song.67000.json','["回車勝母避柏人，不飲貪泉惡其名。", "道逢一鋪榜全節，繫馬呼奬臣子情。"]'),
('b4e52f7e-0fa9-40c1-bd69-58449a6a9b43','渭南道中逢二蜀兵出印本手詔司馬溫公范文正公贈太師外祖丞相贈太保悲喜交集慨然賦詩','宗澤','宋','宋诗','song-poetry','','[]','我君肇當陽，憸佞畢退聽。',204,'全唐诗/poet.song.67000.json','["我君肇當陽，憸佞畢退聽。", "示民以好惡，觀此第一政。", "恭惟司馬范，二老文且正。", "堂堂外王父，九牧稱無盡。", "宸章粲褒賁，倬彼雲漢盛。", "昭回天下來，光生萬象俊。", "小臣行抱憂，中路得此慶。", "慨然夷望歸，欣聞比干贈。", "傷心外王父，三黜坐諫爭。", "未爲召公保，亟上丞相印。", "羣邪肆欺誣，不死仗元聖。", "閹童裂茅土，儇子執魁柄。", "十載卧江湖，齎志目不瞑。", "誰言墮黄壤，廟象飾繡衮。", "石槨安用營，金縢渠不信。", "因知日月星，雖晦終不泯。", "一旦遇雷風，浮雲豈能病。"]'),
('c0377929-1318-4b6a-b587-518f5b995d24','千手眼大悲偈','宗澤','宋','宋诗','song-poetry','','[]','千手一手用，千眼一眼觀。',24,'全唐诗/poet.song.67000.json','["千手一手用，千眼一眼觀。", "用觀無差殊，何必許多般。"]'),
('90165fda-e822-4f6f-b5b7-db42790f8de4','覽鏡偈','宗澤','宋','宋诗','song-poetry','','[]','覽鏡影還在，掩鏡影還去。',24,'全唐诗/poet.song.67000.json','["覽鏡影還在，掩鏡影還去。", "試問鏡中人，却歸什麽處。"]'),
('d0d92070-d7fa-4f19-a4c3-dcaa82af95a4','佛說偈','宗澤','宋','宋诗','song-poetry','','[]','後學要說禪，教人學團謎。',24,'全唐诗/poet.song.67000.json','["後學要說禪，教人學團謎。", "佛祖意分明，但爲傳衣偈。"]'),
('fe2d4790-388a-45d3-80cf-360a948ec8ec','舊作感懷','宗澤','宋','宋诗','song-poetry','','[]','關中黄壤黑壤，大是邦家利源。',42,'全唐诗/poet.song.67000.json','["關中黄壤黑壤，大是邦家利源。", "古者畝收十一，誰興歲取十千。", "不用府無虛月，藏之斯民裕然。"]'),
('1234ec6c-4afd-4bac-b85c-f72a2f1a149a','述懷二首  其一','宗澤','宋','宋诗','song-poetry','','[]','憂國心如奔馬，勤王筆有奇兵。',28,'全唐诗/poet.song.67000.json','["憂國心如奔馬，勤王筆有奇兵。", "一旦立誅禍亂，千載坐視太平。"]'),
('c2ef7ed6-95b7-4e8a-b150-7f40824255bb','述懷二首  其二','宗澤','宋','宋诗','song-poetry','','[]','黄屋肇新巍巍，四方豪傑雲來。',28,'全唐诗/poet.song.67000.json','["黄屋肇新巍巍，四方豪傑雲來。", "片言之悞天也，一見而决時哉。"]'),
('8dc7f4ef-4377-467d-b667-db5353227d18','盧行者偈','宗澤','宋','宋诗','song-poetry','','[]','休問東西南北，莫說之乎者也。',28,'全唐诗/poet.song.67000.json','["休問東西南北，莫說之乎者也。", "直饒神秀文□，不似老盧行者。"]'),
('82bf116b-bc0e-43ee-9aa7-c1c32f75d568','題獨樂園','宗澤','宋','宋诗','song-poetry','','[]','范公之樂後天下，維師溫公乃獨樂。',128,'全唐诗/poet.song.67000.json','["范公之樂後天下，維師溫公乃獨樂。", "二老致意出處間，殊塗同歸兩不惡。", "鄙夫杖藜訪公隠，步無石砌登無閣。", "堂卑不受有美奪，地僻寧遭景華拓。", "始知前輩稽古力，晏子蕭何非妄作。", "細讀隸碑增慷慨，端正似之甘再拜。", "種藥作畦醫國手，澆花成林膏澤大。", "見山臺上飛嵩高，高山仰止如公在。"]'),
('a6b84c0f-2ee2-4e9e-943b-1cb6cda27fb3','葬妻京峴山結廬龍目湖上','宗澤','宋','宋诗','song-poetry','','[]','一對龍湖青眼開，乾坤倚劍獨徘徊。',32,'全唐诗/poet.song.67000.json','["一對龍湖青眼開，乾坤倚劍獨徘徊。", "白雲是處堪埋骨，京峴山頭夢未迴。"]'),
('7052bab2-84d6-46e1-9351-d9d0af60b2c7','題珣師休牧軒  其一','宗澤','宋','宋诗','song-poetry','','[]','青居曾露一絲頭，謾示人能解牧牛。',32,'全唐诗/poet.song.67000.json','["青居曾露一絲頭，謾示人能解牧牛。", "究竟本來無一物，未知能使阿誰休。"]'),
('8c58c532-f250-40a8-a90c-021757d321af','題珣師休牧軒  其二','宗澤','宋','宋诗','song-poetry','','[]','一乘休去已忘機，恰似當初未牧時。',32,'全唐诗/poet.song.67000.json','["一乘休去已忘機，恰似當初未牧時。", "雲起雲消本無迹，有爲全體是無爲。"]'),
('8f9db7d6-9b26-4214-ade5-325d326d7e59','題珣師休牧軒  其三','宗澤','宋','宋诗','song-poetry','','[]','空餘短笠與輕蓑，道著休時事早多。',32,'全唐诗/poet.song.67000.json','["空餘短笠與輕蓑，道著休時事早多。", "更向中間問消息，夜深無奈月明何。"]'),
('03d6e076-bfc1-404e-b8e0-05c88fb07672','對月偶成','晁說之','宋','宋诗','song-poetry','','[]','我屋天之東，月從海西來。',72,'全唐诗/poet.song.67000.json','["我屋天之東，月從海西來。", "不解傳消息，起舞興悠哉。", "千里玉繩斷，萬頃金波開。", "爲我清皮骨，憐我兀塵埃。", "座有玉山人，欣然共徘徊。", "談笑喜復喜，詎必蝦頭杯。"]'),
('f6ad3b92-3d4a-4a43-8b18-8b67adc92bd8','還資道斯立詩卷  其一','晁說之','宋','宋诗','song-poetry','','[]','秋風吹一葉，送我過東山。',60,'全唐诗/poet.song.67000.json','["秋風吹一葉，送我過東山。", "山高日出遲，露重衣裳單。", "爰到濟南郡，端士茝與蘭。", "扁舟八月水，唱酬清且閒。", "憐非郭李客，便了取詩看。"]'),
('15d8f8bf-e43d-44f8-b0d4-e4254e2da3db','還資道斯立詩卷  其二','晁說之','宋','宋诗','song-poetry','','[]','馥馨蘭茝語，令人有愧顔。',36,'全唐诗/poet.song.67000.json','["馥馨蘭茝語，令人有愧顔。", "未見半豹書，安敢道一斑。", "分在婢子科，何以能追攀。"]'),
('178a553f-8b9e-4cdb-9e05-30ea99fcc493','和斯立見還詩卷','晁說之','宋','宋诗','song-poetry','','[]','神仙劉子夏，不愧許遠遊。',96,'全唐诗/poet.song.67000.json','["神仙劉子夏，不愧許遠遊。", "今日秋風客，襟度更爲優。", "如何琅玕紙，亦作李相投。", "釋之還在手，愛涎隨不收。", "霜渚望何限，鳬鵠遠嘯儔。", "金篦識清揚，玉麈見風流。", "新知雖云喜，果作新故不。", "相期不用名，散盡人間憂。"]'),
('5ba22029-6dda-44ed-a487-24e82000e7d9','和資道讀王績傳','晁說之','宋','宋诗','song-poetry','','[]','飛亷有醜馬，卒歲得肥遊。',72,'全唐诗/poet.song.67000.json','["飛亷有醜馬，卒歲得肥遊。", "先生用自況，散髮汾水頭。", "時時到醉鄉，萬彙如蝸牛。", "板築杜康廟，配饗酒家流。", "此意誰能解，空令兒女羞。", "爲問關夫子，若何爲獻酬。"]'),
('22353207-c9ac-479e-86e3-bc62f4701198','和資道讀賀知章傳','晁說之','宋','宋诗','song-poetry','','[]','少陵愛賀公，爽氣不可致。',108,'全唐诗/poet.song.67000.json','["少陵愛賀公，爽氣不可致。", "寧向水底眠，不作塵中士。", "謫仙見長安，狂言隨意至。", "換酒解金龜，安知天王賜。", "二子少可人，欣然得朋類。", "我實異世客，遺編勞補綴。", "念昔遊稽山，頗愛石上字。", "再拜式畫像，物來見真意。", "翰林有諸孫，能與我同契。"]'),
('11c53afa-5939-4bc7-9125-ee1a54663880','馬上睡','晁說之','宋','宋诗','song-poetry','','[]','前驛得駑馬，據鞍可天隱。',48,'全唐诗/poet.song.67000.json','["前驛得駑馬，據鞍可天隱。", "青山隨我行，夢寐亦清省。", "此樂世所無，蝶化猶未甚。", "須信忘機者，在在得安穩。"]'),
('202a4f4c-9c3d-4600-8ba6-18733fcf9997','宿會真宮靈休廳','晁說之','宋','宋诗','song-poetry','','[]','我雖養佛胎，未必有仙骨。',72,'全唐诗/poet.song.67000.json','["我雖養佛胎，未必有仙骨。", "如何羽衣人，而亦容我宿。", "岱岳若宗社，徂徠隱敵國。", "沈沈兩山間，真會駕白鹿。", "仙子嘯清風，玉女佩金籙。", "擾擾人間人，悠悠欲五欲。"]'),
('cab73102-12fa-416d-bde2-fe9c79eda3c2','送斯立入京','晁說之','宋','宋诗','song-poetry','','[]','我見劉潁川，昏困不暇寐。',96,'全唐诗/poet.song.67000.json','["我見劉潁川，昏困不暇寐。", "忽遇便娟兒，白日思寢被。", "此頭各未白，相逢當有地。", "詎惜草草别，但嗟言負意。", "是時菊正花，迸散青鉛淚。", "搖策如騎電，到國何容易。", "萊衣媚家府，芳樽延國士。", "相知問阿儂，爲言只爾耳。"]'),
('009620e5-a17c-44ee-b442-7e130907e1b7','贈别蓬萊簿林希孟子醇','晁說之','宋','宋诗','song-poetry','','[]','吾友陳無己，文會班生廬。',132,'全唐诗/poet.song.67000.json','["吾友陳無己，文會班生廬。", "是時與林侯，有若同隊魚。", "相見元無約，相别詎有謨。", "那知數歲後，聚首如當初。", "眷言二三子，今來安穩無。", "意氣充眉宇，比昔姣且都。", "乃見松與柏，不似柳與蒲。", "憐我守枯禪，談笑使甘腴。", "何如又爲别，淚下青霜俱。", "男兒志四海，不辱黄金軀。", "試看習主簿，窮悴能著書。"]'),
('a2eb2f04-2a4d-4032-9c53-d5117ef747d4','擬古與韓集叙别','晁說之','宋','宋诗','song-poetry','','[]','燕雀常相隨，鴻鵠中路迷。',72,'全唐诗/poet.song.67000.json','["燕雀常相隨，鴻鵠中路迷。", "豈無岳與海，不如瓜與葛。", "食梅令人酸，食冰令人寒。", "一聞布帛語，結髮得儔侣。", "黄蘗染素絲，苦浸爲别離。", "别離近不遠，後會猶未期。"]'),
('c7b6e656-4a83-4e2b-9021-1d0f770bf18b','資道俾予賦試劍山詩馬上承命作','晁說之','宋','宋诗','song-poetry','','[]','青山羣若好，此山何清特。',156,'全唐诗/poet.song.67000.json','["青山羣若好，此山何清特。", "如見孫登輩，高聳不可及。", "山神亦喜我，輕風鳴馬勒。", "馬上欲高哦，才窘開口澀。", "城墉半夜深，樓闕中天闢。", "六曲屏風張，五兩布帆屹。", "蓮柄生旱陸，松角自空植。", "偏將司斥侯，中軍羅矛戟。", "道冠不著簪，女鬟未勞櫛。", "碧衣翼而趨，青童拱以立。", "風雨若可搖，日月去無迹。", "出此摹寫語，敢謂得百一。", "亦欲縱筆書，南山詩見嫉。"]'),
('0b3b6448-89cb-4c48-afaf-7bc90ef30b68','和資道故山驛早行','晁說之','宋','宋诗','song-poetry','','[]','欲識混沌初，請君觀曉山。',48,'全唐诗/poet.song.67000.json','["欲識混沌初，請君觀曉山。", "浩蕩有而無，雲烟往復還。", "流水意更新，四顧復聯攀。", "日馭慎莫出，我要常蕭閒。"]'),
('39e4ad92-64f7-43b1-9b4d-ed19c962adaa','和資道山路見菊雜言','晁說之','宋','宋诗','song-poetry','','[]','桃李不如菊，露下花開意自足。',92,'全唐诗/poet.song.67000.json','["桃李不如菊，露下花開意自足。", "菊亦謝桃李，妖葩艷萼能入俗。", "把菊比君君更清，愛菊肯教陶令獨。", "君今漸作富貴家，平頭奴子紅腰束。", "人誰敢號髯參軍，見者面柔辭氣曲。", "惟有禪翁向晚秋，東籬細步想風流。"]'),
('21a71f8e-24fa-4092-be0d-9db0d12a40ca','遊靈巖山寺','晁說之','宋','宋诗','song-poetry','','[]','昔愛屏作山，今愛山作屏。',204,'全唐诗/poet.song.67000.json','["昔愛屏作山，今愛山作屏。", "還曲不可數，兩目徒熒熒。", "須臾背負巘，恍惝面對陘。", "屯聚陣脚馬，羅列仙女軿。", "秀色非有無，花氣自芳馨。", "翠麓下靡靡，危峰上亭亭。", "借問深幾何，飛鳥中暫停。", "衆異者明孔，白晝觀辰星。", "霜令殊未酷，黄蘂間青青。", "連岫鏁寶符，重壁藏修靈。", "世俗那得見，見形不識形。", "言念朗法師，於此老禪扃。", "應化今何到，空餘虎上經。", "我如夢中遊，夢夢入杳冥。", "爾來塵滓醉，不覺一朝醒。", "下山如夢斷，獨疑在茅廳。", "朝雲到人世，飄飄細雨零。"]'),
('d3be8c65-9cda-4572-985b-9c5a002a899b','和資道巖巖亭二首  其一','晁說之','宋','宋诗','song-poetry','','[]','我來遊此亭，豈羨高陽里。',48,'全唐诗/poet.song.67000.json','["我來遊此亭，豈羨高陽里。", "形神既生生，吉祥斯止止。", "我無古人愁，古人無我喜。", "頗恨桑苧翁，不來嘗此水。"]'),
('80a6c7c4-8cfb-45d2-a3e1-e8e44f188d26','和資道巖巖亭二首  其二','晁說之','宋','宋诗','song-poetry','','[]','昔年蜀武侯，泣下蕩陰里。',48,'全唐诗/poet.song.67000.json','["昔年蜀武侯，泣下蕩陰里。", "何如無事人，一亭欣所止。", "悠然太山岑，相對真可喜。", "不須樽中物，且酌巖下水。"]'),
('6c5f4a7d-976b-44e9-94b4-398958e26f71','奉高道中作','晁說之','宋','宋诗','song-poetry','','[]','雲埋樹林遠，雨添山色重。',48,'全唐诗/poet.song.67000.json','["雲埋樹林遠，雨添山色重。", "我馬自知行，秋風更相送。", "悠悠鄒魯間，此意將誰共。", "明朝是别離，想此如殘夢。"]'),
('80794e59-2081-4ac6-874d-d44b7b333674','望山作','晁說之','宋','宋诗','song-poetry','','[]','望山山在背，不覺首屢回。',84,'全唐诗/poet.song.67000.json','["望山山在背，不覺首屢回。", "策馬欲倒行，道路良艱哉。", "白雲尚相寄，爲带山色來。", "昨日登臨處，今日誰徘徊。", "安得玉女水，爲我洗塵埃。", "不解伴松老，寧忍被鷗猜。", "日與物爲遘，此眼向誰開。"]'),
('585e1b13-0216-41dd-ba52-2affb83a49e1','晚日','晁說之','宋','宋诗','song-poetry','','[]','晚日勸我行，我欲留晚日。',48,'全唐诗/poet.song.67000.json','["晚日勸我行，我欲留晚日。", "長途行不近，僕馬有倦色。", "人生爲客多，誰解老一室。", "果有桃源人，應遭渠笑叱。"]'),
('098332d4-2b78-43dc-bb49-cdf214287ba9','贈江子和兄弟','晁說之','宋','宋诗','song-poetry','','[]','聞道去年大雨雪，今年園林著花遲。',112,'全唐诗/poet.song.67000.json','["聞道去年大雨雪，今年園林著花遲。", "梅已寂寞桃淺深，膠序閉門那得知。", "故人南來將二季，屋裡衣香生春姿。", "黄蜂紫蝶自顛倒，從容却話初别時。", "二季未幾能許大，我曹諱老寧非癡。", "酥酪醍醐俱可口，何但療我渴與饑。", "本朝亦有江金紫，誰道陳留人物衰。"]'),
('6b9f703c-ac45-4ede-82db-9aecc5fa881d','有客從伯父大夫問說之者伯父報之曰吾姪家中焚香讀楚辭耳因得詩一首拜呈','晁說之','宋','宋诗','song-poetry','','[]','蘭菊不易糗，孔鸞難與儀。',84,'全唐诗/poet.song.67000.json','["蘭菊不易糗，孔鸞難與儀。", "春事漫嬋媛，焚香讀楚辭。", "北斗仰欲援，南征俯自悲。", "胡爲不痛飲，未肯歠其醨。", "君之門九重，舉世莫余知。", "世父誤見賞，中情自有奇。", "更願媒美蓉，遠舉驂白螭。"]'),
('886563d4-0304-4fce-9449-1eac2c104520','元符二年十一月十六日趙德麟檢校諸邑李方叔自鄼來會中廬游靈溪寺觀飛泉窮水所出涉龍潭遂至上洞尋火而入路窮乃回歸息巖下巖洞泉潭前此未名嘗見襄沔記郭璞游仙詩謂青溪道士鬼谷子所隱在義清縣義清今其地也巖勢天巧如觀音大士所居潭抱石而曲泉懸級掛空若衝牙珩璜垂而有聲遂名洞曰清溪巖曰補陀潭曰玉玦泉曰珠佩說之寄題四絕句 青溪洞','晁說之','宋','宋诗','song-poetry','','[]','不到清溪路，人間千過春。',24,'全唐诗/poet.song.67000.json','["不到清溪路，人間千過春。", "青溪人不老，應憐郭景純。"]'),
('2c8624cd-f4df-4e1b-9844-08250c91fefb','元符二年十一月十六日趙德麟檢校諸邑李方叔自鄼來會中廬游靈溪寺觀飛泉窮水所出涉龍潭遂至上洞尋火而入路窮乃回歸息巖下巖洞泉潭前此未名嘗見襄沔記郭璞游仙詩謂青溪道士鬼谷子所隱在義清縣義清今其地也巖勢天巧如觀音大士所居潭抱石而曲泉懸級掛空若衝牙珩璜垂而有聲遂名洞曰清溪巖曰補陀潭曰玉玦泉曰珠佩說之寄題四絕句 補陀巖','晁說之','宋','宋诗','song-poetry','','[]','補陀風月在，處處得真居。',24,'全唐诗/poet.song.67000.json','["補陀風月在，處處得真居。", "一六同妙湛，三千皆宴如。"]'),
('0cd9bdd8-d968-485d-97f3-7f35c50dd289','元符二年十一月十六日趙德麟檢校諸邑李方叔自鄼來會中廬游靈溪寺觀飛泉窮水所出涉龍潭遂至上洞尋火而入路窮乃回歸息巖下巖洞泉潭前此未名嘗見襄沔記郭璞游仙詩謂青溪道士鬼谷子所隱在義清縣義清今其地也巖勢天巧如觀音大士所居潭抱石而曲泉懸級掛空若衝牙珩璜垂而有聲遂名洞曰清溪巖曰補陀潭曰玉玦泉曰珠佩說之寄題四絕句 玉玦潭','晁說之','宋','宋诗','song-poetry','','[]','大夫既授玦，捐之湘江中。',24,'全唐诗/poet.song.67000.json','["大夫既授玦，捐之湘江中。", "彼波到此潭，寂寂睡蛟龍。"]'),
('432d79e5-0ae6-4909-91eb-29492b8f3cfd','元符二年十一月十六日趙德麟檢校諸邑李方叔自鄼來會中廬游靈溪寺觀飛泉窮水所出涉龍潭遂至上洞尋火而入路窮乃回歸息巖下巖洞泉潭前此未名嘗見襄沔記郭璞游仙詩謂青溪道士鬼谷子所隱在義清縣義清今其地也巖勢天巧如觀音大士所居潭抱石而曲泉懸級掛空若衝牙珩璜垂而有聲遂名洞曰清溪巖曰補陀潭曰玉玦泉曰珠佩說之寄題四絕句 珠佩泉','晁說之','宋','宋诗','song-poetry','','[]','佳人諒誠素，嗚佩若可取。',24,'全唐诗/poet.song.67000.json','["佳人諒誠素，嗚佩若可取。", "王孫忘情事，不學鄭交甫。"]'),
('fb86f882-12b0-4238-ada3-4bf7f43177c9','客有傳黄戎州三絕句者因次韻  其一','晁說之','宋','宋诗','song-poetry','','[]','朝歎烏皮几，暮歎木樨床。',24,'全唐诗/poet.song.67000.json','["朝歎烏皮几，暮歎木樨床。", "勞我情不堪，念君罪不涼。"]'),
('785d6aa3-5acc-4d75-8939-b5c61e014994','客有傳黄戎州三絕句者因次韻  其二','晁說之','宋','宋诗','song-poetry','','[]','驢技已過目，戎衣方駭心。',24,'全唐诗/poet.song.67000.json','["驢技已過目，戎衣方駭心。", "文章端自誤，痛悔空在今。"]'),
('b61dc7ac-0b51-4191-b1c2-c6f50c877cd5','客有傳黄戎州三絕句者因次韻  其三','晁說之','宋','宋诗','song-poetry','','[]','名大不忍殺，罪大不以赦。',24,'全唐诗/poet.song.67000.json','["名大不忍殺，罪大不以赦。", "荔子紅滿山，身落鄉人社。"]'),
('fbe89f8b-67ee-4a30-848d-80c4e23a3a64','喜魯直還用前韻再作  其一','晁說之','宋','宋诗','song-poetry','','[]','梵志問故鄰，木蘭坐舊床。',24,'全唐诗/poet.song.67000.json','["梵志問故鄰，木蘭坐舊床。", "去恨已斷絕，歸意更淒涼。"]'),
('92869ad4-b2d2-4e64-bdd4-ff4f71a5cd34','喜魯直還用前韻再作  其二','晁說之','宋','宋诗','song-poetry','','[]','鷓鴣不入饌，松柏有常心。',24,'全唐诗/poet.song.67000.json','["鷓鴣不入饌，松柏有常心。", "歸來應未老，但道古猶今。"]'),
('7f8775b1-e79d-45a0-b86b-5e50234679a1','喜魯直還用前韻再作  其三','晁說之','宋','宋诗','song-poetry','','[]','君有非常罪，幸此非常赦。',24,'全唐诗/poet.song.67000.json','["君有非常罪，幸此非常赦。", "收身黑水西，重入白蓮社。"]'),
('79653742-6073-489a-8ece-be094d28622a','又再作  其一','晁說之','宋','宋诗','song-poetry','','[]','多情楊畔兒，芙蓉生繞床。',24,'全唐诗/poet.song.67000.json','["多情楊畔兒，芙蓉生繞床。", "舊屋君未歸，蒲池已淒涼。"]'),
('40a10521-81e7-4181-a0bf-75af89f0dfc9','又再作  其二','晁說之','宋','宋诗','song-poetry','','[]','世人不我與，自契黄龍心。',24,'全唐诗/poet.song.67000.json','["世人不我與，自契黄龍心。", "竟復何遠近，一瞬萬古今。"]'),
('43c8f27e-6a07-413c-8bb8-a2f014451cad','又再作  其三','晁說之','宋','宋诗','song-poetry','','[]','負罪臣宗元，移書數問赦。',24,'全唐诗/poet.song.67000.json','["負罪臣宗元，移書數問赦。", "僅如鴈往來，羨君還里社。"]'),
('d11a0c79-a156-4ce4-821b-95e6ae631573','君莫惡行','晁說之','宋','宋诗','song-poetry','','[]','寂寂山城已過春，黄鸝紫椹意相親。',96,'全唐诗/poet.song.67000.json','["寂寂山城已過春，黄鸝紫椹意相親。", "天公奈何不肯雨，小麥含秀安得吐。", "聞道天公大仁聖，風伯何能回雨令。", "恐是風伯老兒凶，長塗未許騁羣龍。", "前年流草有餘胔，誰言今朝尚憂此。", "內降白麻出上閣，新相爲霖君莫惡。"]'),
('643c2ac5-f661-4583-8d5a-7c8f90f28ed6','縣樓對山作','晁說之','宋','宋诗','song-poetry','','[]','山色日夕改，我樂豈獨今。',72,'全唐诗/poet.song.67000.json','["山色日夕改，我樂豈獨今。", "相羊非一意，開簟枕遙岑。", "楞伽懶焚香，離騷幸可吟。", "吏隱兩已適，虎鼠都不任。", "詩酒客亦惡，樓下那足尋。", "可憐謝玄暉，惝恍論此心。"]');
